function parseCorsExtraOrigins() {
    const raw = String(process.env.CORS_EXTRA_ORIGINS || '').trim();
    if (!raw) return new Set();
    return new Set(raw.split(/[\s,]+/).map(s => s.trim()).filter(Boolean));
}
const CORS_EXTRA_ORIGINS = parseCorsExtraOrigins();

function corsOriginAllowed(origin) {
    if (!origin || typeof origin !== 'string') return true;
    if (origin.startsWith('http://localhost') || origin.startsWith('http://127.0.0.1')) return true;
    if (origin.endsWith('azurewebsites.net')) return true;
    if (CORS_EXTRA_ORIGINS.has(origin)) return true;
    const suf = String(process.env.CORS_ALLOWED_HOST_SUFFIXES || '').trim();
    if (suf) {
        try {
            const host = new URL(origin).hostname.toLowerCase();
            for (const part of suf.split(/[\s,]+/).map(s => s.trim().replace(/^\./, '')).filter(Boolean)) {
                if (host === part || host.endsWith('.' + part)) return true;
            }
        } catch (e) { /* ignore */ }
    }
    return false;
}

app.use(cors({
    origin: (origin, cb) => {
        if (corsOriginAllowed(origin)) return cb(null, true);
        return cb(null, false);
    }
}));
app.use(express.json({ limit: '10mb' }));

