function normalizeRoleKey(roleKey, actorType = 'staff') {
    const raw = String(roleKey || '').trim().toLowerCase();
    if (!raw) return actorType === 'tenant' ? 'kepala_sppg' : 'admin';
    const mapped = MBG_ROLE_ALIAS[raw] || raw;
    if (MBG_ROLE_CANONICAL[mapped]) return mapped;
    return actorType === 'tenant' ? 'kepala_sppg' : 'admin';
}

