function getPlatformDbFile() {
    const envFile = String(process.env.PLATFORM_DB_FILE || '').trim();
    if (envFile) return envFile;
    // If the Azure mount directory exists, always use DB inside it (create-on-first-open).
    // Requiring an existing file caused fallback to /app/database.sqlite and SQLITE_CANTOPEN.
    if (fs.existsSync(PLATFORM_DB_DIR_AZURE)) {
        return path.join(PLATFORM_DB_DIR_AZURE, 'database.sqlite');
    }
    return path.join(__dirname, 'database.sqlite');
}

function getTenantDbDir() {
    if (fs.existsSync(TENANT_DB_DIR_AZURE)) return TENANT_DB_DIR_AZURE;
    return path.join(__dirname, 'tenant_dbs');
}

/**
 * Resolve Face API host/port for http.request.
 * Order avoids common misconfigs: non-loopback FACE_API_HOST, then FACE_API_URL, then explicit loopback,
 * then Docker/Azure heuristics (localhost inside a container points at the wrong place → instant 502).
 */
function getFaceApiConnect() {
    const portFromEnv = () => parseInt(process.env.FACE_API_PORT || '5000', 10);
    const urlEnv = String(process.env.FACE_API_URL || '').trim();
    let fromUrl = null;
    if (urlEnv) {
        try {
            const u = new URL(urlEnv);
            fromUrl = {
                hostname: u.hostname,
                port: u.port ? parseInt(u.port, 10) : portFromEnv()
            };
        } catch (e) { /* ignore */ }
    }
    const hostEnv = String(process.env.FACE_API_HOST || '').trim();
    const loopback = (h) => h === '127.0.0.1' || /^localhost$/i.test(String(h || ''));

    if (hostEnv && !loopback(hostEnv)) {
        return { hostname: hostEnv, port: portFromEnv() };
    }
    if (fromUrl && !loopback(fromUrl.hostname)) {
        return fromUrl;
    }
    if (hostEnv) {
        return { hostname: hostEnv, port: portFromEnv() };
    }
    if (fromUrl) {
        return fromUrl;
    }
    let inDocker = false;
    try {
        inDocker = fs.existsSync('/.dockerenv');
    } catch (e) { /* ignore */ }
    const onAzureApp = !!process.env.WEBSITE_INSTANCE_ID;
    const azureDbLayout = fs.existsSync(TENANT_DB_DIR_AZURE);
    if (inDocker || onAzureApp || azureDbLayout) {
        return { hostname: 'face_api', port: portFromEnv() };
    }
    return { hostname: 'localhost', port: portFromEnv() };
}

