/** Optional: FACEREC_DEBUG=1 (console) and/or DEBUG_NDJSON_LOG=/path/to.ndjson — off by default for speed. */
function appendAgentDebugNdjson(payload) {
    const file = String(process.env.DEBUG_NDJSON_LOG || '').trim();
    const dbg = process.env.FACEREC_DEBUG === '1';
    if (!file && !dbg) return;
    const line = JSON.stringify({ t: Date.now(), ...payload }) + '\n';
    if (dbg) console.log('[FACEREC_DEBUG]', line.trimEnd());
    if (file) {
        try {
            fs.mkdirSync(path.dirname(file), { recursive: true });
            fs.appendFileSync(file, line);
        } catch (_) { /* ignore */ }
    }
}

// #region agent log
function handleFaceApiUpstreamError(res, route, err, target) {
    const code = err && err.code ? String(err.code) : '';
    const msg = err && err.message ? String(err.message) : String(err);
    console.error(`[FACE_API] ${route} → ${target.hostname}:${target.port} — ${code} ${msg}`);
    appendAgentDebugNdjson({
        hypothesisId: 'H502',
        location: `server.js:${route}`,
        message: 'face_api http.request error',
        data: {
            route,
            hostname: target.hostname,
            port: target.port,
            errCode: code,
            errMsg: msg.slice(0, 240)
        }
    });
    if (!res.headersSent) {
        res.status(502).json({ error: 'Face API tidak dapat dijangkau', detail: msg, code: code || undefined });
    }
}
