function sanitizeTenantId(tenantId) {
    return String(tenantId || '')
        .trim()
        .replace(/[^a-zA-Z0-9_\-]/g, '_')
        .slice(0, 120);
}

function tenantDbPath(tenantId) {
    const safe = sanitizeTenantId(tenantId);
    return path.join(TENANT_DB_DIR, `${safe}.sqlite`);
}

function shouldUsePlatformDbForApiPath(apiPath) {
    const p = String(apiPath || '');
    // Platform-wide: subscription/admin/tenants/auth/activation-requests
    if (p.startsWith('/admin')) return true;
    if (p.startsWith('/subscription')) return true;
    if (p.startsWith('/tenants')) return true;
    if (p.startsWith('/auth')) return true;
    if (p.startsWith('/activation-requests')) return true;
    if (p.startsWith('/suppliers')) return true;
    if (p.startsWith('/api/suppliers')) return true;
    if (p.startsWith('/supplier-portal')) return true;
    return false;
}

function execOnDb(db, sql, params = []) {
    return new Promise((resolve, reject) => {
        db.run(sql, params, function (err) {
            if (err) return reject(err);
            return resolve(this);
        });
    });
}

function allOnDb(db, sql, params = []) {
    return new Promise((resolve, reject) => {
        db.all(sql, params, (err, rows) => {
            if (err) return reject(err);
            return resolve(rows);
        });
    });
}

function getOnDb(db, sql, params = []) {
    return new Promise((resolve, reject) => {
        db.get(sql, params, (err, row) => {
            if (err) return reject(err);
            return resolve(row);
        });
    });
}

/**
 * Resolve kitchen from platform DB for Face API paths (must be canonical tenant UUID).
 * Uses platformDb directly so /api/facerec/* never depends on AsyncLocalStorage tenant context.
 * Matches: id, exact name, case-insensitive name, no-space name, slug (no space/-/_.).
 */
async function resolvePlatformTenantForFacerecInput(rawInput) {
    const raw = String(rawInput || '').trim();
    if (!raw) return null;
    if (raw === 'default') return { id: 'default', name: 'default' };
    const norm = raw.toLowerCase();
    const noSpaces = norm.replace(/\s+/g, '');
    const compact = noSpaces.replace(/-/g, '').replace(/_/g, '').replace(/\./g, '');
    const sql = `SELECT id, name FROM tenants WHERE id = ? OR name = ? OR LOWER(TRIM(COALESCE(name,''))) = ? OR LOWER(REPLACE(COALESCE(name,''), ' ', '')) = ? OR LOWER(REPLACE(REPLACE(REPLACE(REPLACE(COALESCE(TRIM(name),''), ' ', ''), '-', ''), '_', ''), '.', '')) = ?`;
    try {
        return await getOnDb(platformDb, sql, [raw, raw, norm, noSpaces, compact]);
    } catch (e) {
        return null;
    }
}

/** If exactly one ACTIVE/PRO/TRIAL kitchen, use it when client sends no tenant (kiosk). */
async function resolveSoleActiveKitchenForFacerec() {
    try {
        const rows = await allOnDb(
            platformDb,
            "SELECT id, name FROM tenants WHERE UPPER(COALESCE(TRIM(status),'')) IN ('ACTIVE','PRO','TRIAL','TRIALING') ORDER BY name"
        );
        if (rows.length === 1) return rows[0];
    } catch (e) { /* ignore */ }
    return null;
}

/**
 * Face API derives staff_id from gallery filename; DeepFace paths may use .JPG/.jpeg; DB rows use lowercase UUIDs.
 */
function normalizeFacerecStaffId(raw) {
    let s = String(raw || '')
        .replace(/\uFEFF/g, '')
        .replace(/[\u200B-\u200D]/g, '')
        .trim();
    if (!s) return '';
    const low = s.toLowerCase();
    if (low.endsWith('.jpg') || low.endsWith('.jpeg')) {
        s = s.slice(0, s.lastIndexOf('.'));
    }
    if (/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(s)) {
        return s.toLowerCase();
    }
    return s;
}

/**
 * Platform DB also has a `staff` table (migrations). Tenant shards can be empty/out-of-sync while platform still holds the row — causes verified face + 404.
 * H8: Row may exist with same id but tenant_id NULL or different from resolved kitchen — strict AND misses; loose id-only + force tenant_id to kiosk context.
 */
async function lookupStaffOnPlatformForFacerec(staffId, tenantId) {
    const sid = String(staffId || '').trim();
    const tid = String(tenantId || '').trim();
    if (!sid || !tid) return null;
    try {
        const strict = await getOnDb(
            platformDb,
            'SELECT id, tenant_id, name, role, staff_code, division_id FROM staff WHERE id = ? COLLATE NOCASE AND tenant_id = ? COLLATE NOCASE',
            [sid, tid]
        );
        if (strict) return strict;

        const rows = await allOnDb(
            platformDb,
            'SELECT id, tenant_id, name, role, staff_code, division_id FROM staff WHERE id = ? COLLATE NOCASE',
            [sid]
        );
        if (!rows || rows.length === 0) return null;
        if (rows.length > 1) {
            // #region agent log
            appendAgentDebugNdjson({
                hypothesisId: 'H8',
                location: 'server.js:lookupStaffOnPlatformForFacerec:ambiguousId',
                message: 'multiple platform staff rows for same id',
                data: { staffId: sid, count: rows.length }
            });
            // #endregion
            return null;
        }
        const row = rows[0];
        const rowTid = row.tenant_id != null ? String(row.tenant_id).trim() : '';
        // #region agent log
        appendAgentDebugNdjson({
            hypothesisId: 'H8',
            location: 'server.js:lookupStaffOnPlatformForFacerec:looseById',
            message: 'platform staff matched by id only; tenant_id normalized to resolved kitchen',
            data: {
                staffId: sid,
                resolvedTenantId: tid,
                rowTenantId: rowTid || null,
                tenantIdsMatch: rowTid === tid
            }
        });
        // #endregion
        return { ...row, tenant_id: tid };
    } catch (e) {
        // #region agent log
        appendAgentDebugNdjson({
            hypothesisId: 'H7',
            location: 'server.js:lookupStaffOnPlatformForFacerec:error',
            message: 'platform staff query failed',
            data: { staffId: sid, err: String(e && e.message ? e.message : e).slice(0, 200) }
        });
        // #endregion
        return null;
    }
}

async function filterTenantDataInTenantDb(tenantId) {
    const pth = tenantDbPath(tenantId);
    const tempDb = new sqlite3.Database(pth);
    try {
        // Best-effort: prune tables that have a tenant_id column.
        // Also prune `tenants` so the tenant db doesn't contain other tenants at all.
        await execOnDb(tempDb, 'PRAGMA foreign_keys=OFF');
        try {
            // tenant DB (ops-only): owner/account data not kept here.
            await execOnDb(tempDb, 'DELETE FROM tenants');
        } catch (e) { }

        const tables = await allOnDb(
            tempDb,
            "SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%'"
        );

        for (const t of tables) {
            const tableName = t.name;
            let cols = [];
            try {
                cols = await allOnDb(tempDb, `PRAGMA table_info(${tableName})`);
            } catch (e) { }
            const hasTenantId = (cols || []).some(c => c.name === 'tenant_id');
            if (!hasTenantId) continue;
            try {
                await execOnDb(tempDb, `DELETE FROM ${tableName} WHERE tenant_id != ?`, [tenantId]);
            } catch (e) { }
        }

        // Reclaim space so file size reflects the tenant workload.
        try {
            await execOnDb(tempDb, 'VACUUM');
        } catch (e) { }
    } finally {
        try { tempDb.close(); } catch (e) { }
    }
}

async function ensureTenantDb(tenantId) {
    const key = String(tenantId);
    if (tenantDbConnections.has(key)) return tenantDbConnections.get(key);
    if (tenantDbInitPromises.has(key)) return tenantDbInitPromises.get(key);

    const initPromise = (async () => {
        const pth = tenantDbPath(tenantId);
        if (!fs.existsSync(pth)) {
            fs.copyFileSync(PLATFORM_DB_FILE, pth);
            await filterTenantDataInTenantDb(tenantId);
        }
        const conn = new sqlite3.Database(pth);
        conn.run("PRAGMA journal_mode = WAL;");
        tenantDbConnections.set(key, conn);
        return conn;
    })();

    tenantDbInitPromises.set(key, initPromise);
    try {
        const conn = await initPromise;
        return conn;
    } finally {
        tenantDbInitPromises.delete(key);
    }
}

/** Jalankan callback dengan AsyncLocalStorage mengarah ke DB operasional tenant (sama seperti /api/*). */
async function withTenantDatabase(tenantId, asyncFn) {
    const tid = String(tenantId);
    const tenantDb = await ensureTenantDb(tid);
    const active = await getActiveSubscription(tid);
    const planCode = String(active?.plan?.code || '').toUpperCase();
    const rawMb = active?.plan?.limits?.max_db_mb;
    let maxMb = Number(rawMb);
    if (!Number.isFinite(maxMb) || maxMb <= 0) {
        const fallback = { FREE: 50, TRIAL: 200, PRO: 1024, ENTERPRISE: 5000 };
        maxMb = fallback[planCode] || 1024;
    }
    const maxDbBytes = Math.floor(maxMb * 1024 * 1024);
    return dbContext.run(
        { db: tenantDb, tenantId: tid, maxDbBytes, tenantDbPath: tenantDbPath(tid) },
        asyncFn
    );
}

const DEV_AUTH_ENABLED = String(process.env.DEV_AUTH_ENABLED || '').toLowerCase() !== 'false';
const DEMO_SEED_ENABLED = String(process.env.DEMO_SEED || 'true').toLowerCase() !== 'false';
const RATE_BUCKETS = new Map();

function rateAllow(key, limit, windowMs) {
    const now = Date.now();
    const it = RATE_BUCKETS.get(key);
    if (!it || now >= it.resetAt) {
        RATE_BUCKETS.set(key, { count: 1, resetAt: now + windowMs });
        return true;
    }
    if (it.count >= limit) return false;
    it.count += 1;
    return true;
}

function rateLimit(limit, windowMs) {
    return (req, res, next) => {
        const ip = String(req.headers['x-forwarded-for'] || req.socket.remoteAddress || '').split(',')[0].trim();
        const key = `${req.path}:${ip}`;
        if (!rateAllow(key, limit, windowMs)) return res.status(429).json({ error: 'Too many requests' });
        next();
    };
}

function isEmail(s) {
    const v = String(s || '').trim();
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
}

function base64url(buf) {
    return Buffer.from(buf).toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/g, '');
}

function sha256Hex(input) {
    return crypto.createHash('sha256').update(String(input)).digest('hex');
}

function isScryptHash(stored) {
    return typeof stored === 'string' && stored.startsWith('scrypt$');
}

async function hashPassword(password) {
    const pw = String(password || '');
    const salt = crypto.randomBytes(16);
    const params = { N: 16384, r: 8, p: 1, dkLen: 64 };
    const key = await new Promise((resolve, reject) => {
        crypto.scrypt(pw, salt, params.dkLen, { N: params.N, r: params.r, p: params.p, maxmem: 64 * 1024 * 1024 }, (err, derivedKey) => {
            if (err) reject(err);
            else resolve(derivedKey);
        });
    });
    return `scrypt$${params.N}$${params.r}$${params.p}$${salt.toString('base64')}$${Buffer.from(key).toString('base64')}`;
}

async function verifyPassword(password, stored) {
    const pw = String(password || '');
    if (!stored) return false;
    if (!isScryptHash(stored)) {
        const a = Buffer.from(String(stored));
        const b = Buffer.from(pw);
        if (a.length !== b.length) return false;
        return crypto.timingSafeEqual(a, b);
    }
    const parts = String(stored).split('$');
    if (parts.length !== 6) return false;
    const N = parseInt(parts[1], 10);
    const r = parseInt(parts[2], 10);
    const p = parseInt(parts[3], 10);
    const salt = Buffer.from(parts[4], 'base64');
    const expected = Buffer.from(parts[5], 'base64');
    const key = await new Promise((resolve, reject) => {
        crypto.scrypt(pw, salt, expected.length, { N, r, p, maxmem: 64 * 1024 * 1024 }, (err, derivedKey) => {
            if (err) reject(err);
            else resolve(derivedKey);
        });
    });
    if (key.length !== expected.length) return false;
    return crypto.timingSafeEqual(Buffer.from(key), expected);
}

/** JWT HS256 untuk portal supplier (kompatibel dengan jsonwebtoken Rust / HS256). */
function supplierPortalJwtSecret() {
    return String(process.env.JWT_SECRET || 'super_secure_secret_key_generated_by_system_admin_2026');
}

function supplierPortalB64UrlToBuf(s) {
    const str = String(s || '').replace(/-/g, '+').replace(/_/g, '/');
    const pad = str.length % 4 ? 4 - (str.length % 4) : 0;
    return Buffer.from(str + '='.repeat(pad), 'base64');
}

function supplierPortalJwtSign(supplierId, email, ttlHours = 48) {
    const secret = supplierPortalJwtSecret();
    const header = { alg: 'HS256', typ: 'JWT' };
    const exp = Math.floor(Date.now() / 1000) + ttlHours * 3600;
    const payload = {
        sub: String(supplierId),
        email: String(email || '').toLowerCase(),
        role: 'supplier',
        exp,
    };
    const h = base64url(Buffer.from(JSON.stringify(header)));
    const p = base64url(Buffer.from(JSON.stringify(payload)));
    const sig = crypto.createHmac('sha256', secret).update(`${h}.${p}`).digest();
    return `${h}.${p}.${base64url(sig)}`;
}

function supplierPortalJwtVerify(token) {
    try {
        const secret = supplierPortalJwtSecret();
        const parts = String(token || '').split('.');
        if (parts.length !== 3) return null;
        const msg = `${parts[0]}.${parts[1]}`;
        const expected = crypto.createHmac('sha256', secret).update(msg).digest();
        const got = supplierPortalB64UrlToBuf(parts[2]);
        if (got.length !== expected.length || !crypto.timingSafeEqual(got, expected)) return null;
        const payload = JSON.parse(supplierPortalB64UrlToBuf(parts[1]).toString('utf8'));
        if (payload.role !== 'supplier' || !payload.sub) return null;
        const now = Math.floor(Date.now() / 1000);
        if (!payload.exp || now > Number(payload.exp)) return null;
        return payload;
    } catch (_) {
        return null;
    }
}

function supplierPortalBearer(req) {
    const auth = req.headers['authorization'] || '';
    const m = String(auth).match(/^Bearer\s+(.+)$/i);
    return m ? m[1].trim() : '';
}

async function portalSupplierEnsurePeriodRow(row) {
    if (!row || !row.id) return row;
    const id = row.id;
    const tier = String(row.subscription_tier || 'free').toLowerCase();
    let taken = Number(row.orders_taken_this_period);
    if (!Number.isFinite(taken)) taken = 0;
    const now = new Date();
    const nowIso = now.toISOString();
    if (!row.period_reset_at) {
        await execOnDb(platformDb, 'UPDATE portal_suppliers SET period_reset_at = ? WHERE id = ?', [nowIso, id]).catch(() => {});
        row.period_reset_at = nowIso;
        return { ...row, orders_taken_this_period: taken };
    }
    const resetAt = new Date(String(row.period_reset_at));
    if (Number.isNaN(resetAt.getTime())) {
        await execOnDb(platformDb, 'UPDATE portal_suppliers SET period_reset_at = ? WHERE id = ?', [nowIso, id]).catch(() => {});
        row.period_reset_at = nowIso;
        return { ...row, orders_taken_this_period: taken };
    }
    let shouldReset = false;
    if (tier === 'free') {
        shouldReset = now.getUTCMonth() !== resetAt.getUTCMonth() || now.getUTCFullYear() !== resetAt.getUTCFullYear();
    } else if (tier === 'pro') {
        shouldReset = (now.getTime() - resetAt.getTime()) / 86400000 >= 7;
    }
    if (shouldReset) {
        await execOnDb(platformDb, 'UPDATE portal_suppliers SET orders_taken_this_period = 0, period_reset_at = ? WHERE id = ?', [
            nowIso,
            id,
        ]).catch(() => {});
        row.orders_taken_this_period = 0;
        row.period_reset_at = nowIso;
        taken = 0;
    }
    return { ...row, orders_taken_this_period: taken };
}

async function portalSupplierSubscriptionLimits(row) {
    const r = await portalSupplierEnsurePeriodRow({ ...row });
    const tier = String(r.subscription_tier || 'free').toLowerCase();
    const taken = Number(r.orders_taken_this_period) || 0;
    let limit = 0;
    let canBid = false;
    if (tier === 'free') {
        limit = 2;
        canBid = taken < 2;
    } else if (tier === 'pro') {
        limit = 4;
        canBid = taken < 4;
    } else if (tier === 'ultra') {
        limit = null;
        canBid = true;
    } else {
        limit = 0;
        canBid = false;
    }
    return {
        tier,
        orders_taken_this_period: taken,
        period_reset_at: r.period_reset_at || null,
        limit_per_period: limit,
        can_bid: canBid,
    };
}

async function createSession({ actor_type, actor_id, tenant_id, role, ttlSeconds }) {
    const token = base64url(crypto.randomBytes(32));
    const tokenHash = sha256Hex(token);
    const now = new Date();
    const expires = new Date(now.getTime() + (ttlSeconds * 1000));
    const id = crypto.randomUUID();
    await run(
        `INSERT INTO sessions (id, token_hash, actor_type, actor_id, tenant_id, role, created_at, expires_at, revoked_at)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, NULL)`,
        [id, tokenHash, actor_type, actor_id, tenant_id || null, role || null, now.toISOString(), expires.toISOString()]
    );
    return token;
}

async function getSessionFromReq(req) {
    const auth = req.headers['authorization'] || '';
    const m = String(auth).match(/^Bearer\s+(.+)$/i);
    if (!m) return null;
    const token = m[1].trim();
    if (!token) return null;
    const tokenHash = sha256Hex(token);
    const now = new Date().toISOString();
    const s = await get(
        `SELECT * FROM sessions WHERE token_hash = ? AND revoked_at IS NULL AND expires_at > ?`,
        [tokenHash, now]
    );
    return s || null;
}

function requirePlatform(roles = []) {
    const allowed = Array.isArray(roles) ? roles : [];
    return async (req, res, next) => {
        if (!req.auth) return res.status(401).json({ error: 'Unauthorized' });
        if (req.auth.actor_type !== 'platform') return res.status(403).json({ error: 'Forbidden' });
        if (allowed.length && !allowed.includes(req.auth.role)) return res.status(403).json({ error: 'Forbidden' });
        if (typeof next === 'function') await Promise.resolve(next());
    };
}

function requireTenantOrPlatform() {
    return async (req, res, next) => {
        if (!req.auth) return res.status(401).json({ error: 'Unauthorized' });
        if (req.auth.actor_type === 'platform') return next();
        if (req.auth.actor_type === 'tenant' || req.auth.actor_type === 'staff') return next();
        return res.status(403).json({ error: 'Forbidden' });
    };
}

function requireCanonicalRoles(allowedRoles = []) {
    const allowed = new Set((Array.isArray(allowedRoles) ? allowedRoles : []).map((r) => normalizeRoleKey(r)));
    return async (req, res, next) => {
        if (!req.auth) return res.status(401).json({ error: 'Unauthorized' });
        if (req.auth.actor_type === 'platform') return next();
        const roleKey = normalizeRoleKey(req.auth.role, req.auth.actor_type);
        if (allowed.size > 0 && !allowed.has(roleKey)) {
            return res.status(403).json({ error: 'Forbidden', role: roleKey, allowed_roles: Array.from(allowed) });
        }
        next();
    };
}

// Normalize legacy plan module tokens into the current granular module system.
// This keeps backward compatibility with existing rows in `subscription_plans`.
function normalizeSubscriptionModules(modules) {
    const set = new Set(Array.isArray(modules) ? modules : []);

    // Legacy: `core` previously meant "basic + inventory + purchases + finance + staff + tasks + routes + pricing"
    if (set.has('core')) {
        set.add('basic');
        set.add('inventory');
        set.add('purchases');
        set.add('finance');
        set.add('staff');
        set.add('tasks');
        set.add('routes');
        set.add('pricing');
    }

    // Legacy: `ops` previously meant "production + tasks"
    if (set.has('ops')) {
        set.add('production');
        set.add('tasks');
    }

    // Keep premium tokens as-is (reports/integrations)
    if (set.size === 0) set.add('basic');
    return set;
}

function requireSubscriptionModule(moduleName) {
    return async (req, res, next) => {
        if (SUBSCRIPTION_DISABLED) return next();
        if (!req.auth) return res.status(401).json({ error: 'Unauthorized' });
        if (req.auth.actor_type === 'platform') return next();

        const tenantId = getTenantIdFromReq(req);
        if (!tenantId) return res.status(400).json({ error: 'Missing tenant scope' });

        const sub = await getActiveSubscription(tenantId);
        const activeStates = ['ACTIVE', 'GRACE'];
        const state = sub?.state || 'NONE';
        if (!activeStates.includes(state)) {
            return res.status(402).json({ error: 'Subscription required', state, module: moduleName });
        }

        const modulesRaw = sub?.plan?.features?.modules;
        const modules = normalizeSubscriptionModules(modulesRaw);
        if (!modules || modules.size === 0) {
            return res.status(403).json({ error: 'No available modules on this plan', module: moduleName });
        }
        if (!modules.has(moduleName)) {
            return res.status(403).json({
                error: 'Feature not available for your plan',
                module: moduleName,
                plan: sub?.plan?.code || sub?.subscription?.plan_code || 'UNKNOWN'
            });
        }
        next();
    };
}

