/**
 * Normalisasi satuan bahan ke enum `gram` | `pcs`.
 * - Ambil semua baris dengan unit lama (kg, liter, ml, buah, ikat, sdm, dll)
 * - Convert qty: kg -> g (×1000), liter -> g (×1000 asumsi density 1.0), ml -> g (×1)
 * - Pcs family: buah/btr/bungkus/sachet/ikat/lembar -> pcs
 * - Idempoten via flag `_units_normalized_v1` di tabel `schema_flags`.
 */
const UNIT_NORMALIZATION_MAP = {
    'kg': { to: 'gram', mul: 1000 },
    'kilogram': { to: 'gram', mul: 1000 },
    'kilo': { to: 'gram', mul: 1000 },
    'g': { to: 'gram', mul: 1 },
    'gr': { to: 'gram', mul: 1 },
    'gram': { to: 'gram', mul: 1 },
    'liter': { to: 'gram', mul: 1000 },
    'l': { to: 'gram', mul: 1000 },
    'ltr': { to: 'gram', mul: 1000 },
    'ml': { to: 'gram', mul: 1 },
    'cc': { to: 'gram', mul: 1 },
    'pcs': { to: 'pcs', mul: 1 },
    'pc': { to: 'pcs', mul: 1 },
    'buah': { to: 'pcs', mul: 1 },
    'biji': { to: 'pcs', mul: 1 },
    'btr': { to: 'pcs', mul: 1 },
    'butir': { to: 'pcs', mul: 1 },
    'bks': { to: 'pcs', mul: 1 },
    'bungkus': { to: 'pcs', mul: 1 },
    'sachet': { to: 'pcs', mul: 1 },
    'ikat': { to: 'pcs', mul: 1 },
    'lembar': { to: 'pcs', mul: 1 },
    'porsi': { to: 'pcs', mul: 1 },
    'unit': { to: 'pcs', mul: 1 },
    'sdm': { to: 'gram', mul: 15 },
    'sdt': { to: 'gram', mul: 5 },
    'gelas': { to: 'gram', mul: 240 }
};
function normalizeUnitAndQty(rawUnit, rawQty) {
    const u = String(rawUnit || '').trim().toLowerCase();
    const q = Number(rawQty);
    const map = UNIT_NORMALIZATION_MAP[u];
    if (!map) {
        if (u === 'gram' || u === 'pcs') return { unit: u, qty: Number.isFinite(q) ? q : rawQty };
        return { unit: 'pcs', qty: Number.isFinite(q) ? q : rawQty };
    }
    return { unit: map.to, qty: Number.isFinite(q) ? q * map.mul : rawQty };
}

async function ensureUnitNormalizationInCurrentDb() {
    try {
        await run(`CREATE TABLE IF NOT EXISTS schema_flags (key TEXT PRIMARY KEY, value TEXT, updated_at TEXT)`);
        const flag = await get("SELECT value FROM schema_flags WHERE key = '_units_normalized_v1'").catch(() => null);
        if (flag && flag.value === 'done') return;

        // ingredients
        try {
            const rows = await all("SELECT id, unit FROM ingredients WHERE unit IS NOT NULL AND unit NOT IN ('gram','pcs')").catch(() => []);
            for (const r of rows) {
                const norm = normalizeUnitAndQty(r.unit, 1);
                await run("UPDATE ingredients SET unit = ? WHERE id = ?", [norm.unit, r.id]).catch(() => {});
            }
        } catch (e) { /* ignore */ }

        // operational_materials
        try {
            const rows = await all("SELECT id, unit, qty_per_portion FROM operational_materials WHERE unit IS NOT NULL AND unit NOT IN ('gram','pcs')").catch(() => []);
            for (const r of rows) {
                const norm = normalizeUnitAndQty(r.unit, r.qty_per_portion || 1);
                await run("UPDATE operational_materials SET unit = ?, qty_per_portion = ? WHERE id = ?", [norm.unit, norm.qty, r.id]).catch(() => {});
            }
        } catch (e) { /* ignore */ }

        // food_menu_ingredients (legacy - qty_unit field)
        try {
            const rows = await all("SELECT id, qty_unit, qty_per_portion FROM food_menu_ingredients WHERE qty_unit IS NOT NULL AND qty_unit NOT IN ('gram','pcs')").catch(() => []);
            for (const r of rows) {
                const norm = normalizeUnitAndQty(r.qty_unit, r.qty_per_portion || 1);
                await run("UPDATE food_menu_ingredients SET qty_unit = ?, qty_per_portion = ? WHERE id = ?", [norm.unit, norm.qty, r.id]).catch(() => {});
            }
        } catch (e) { /* ignore */ }

        // kitchen_equipment (cuma normalisasi unit label, tanpa convert quantity karena alat)
        try {
            const rows = await all("SELECT id, unit FROM kitchen_equipment WHERE unit IS NOT NULL AND unit NOT IN ('gram','pcs')").catch(() => []);
            for (const r of rows) {
                const norm = normalizeUnitAndQty(r.unit, 1);
                await run("UPDATE kitchen_equipment SET unit = ? WHERE id = ?", [norm.unit, r.id]).catch(() => {});
            }
        } catch (e) { /* ignore */ }

        await run("INSERT OR REPLACE INTO schema_flags (key, value, updated_at) VALUES ('_units_normalized_v1', 'done', ?)", [new Date().toISOString()]).catch(() => {});
        console.log('[MIGRATION] Unit normalization v1 completed');
    } catch (e) {
        console.warn('[MIGRATION] Unit normalization failed:', e.message);
    }
}

