/**
 * Fase 7: Migrasi data lama ke model baru.
 * - recipe_steps → workflow_steps (linear DAG) + menu.workflow_id
 * - recipes.packaging_type + recipes.extra_packing_json → menu.packaging_stack_json
 * - food_menus + food_menu_ingredients → recipes + menu (jika belum ada)
 * Idempotent via tabel `migration_meta`.
 */
async function ensureLegacyProductionMigrationInCurrentDb() {
    try { await ensureProductionLibrarySchemaInCurrentDb(); } catch (e) { }
    await run(`CREATE TABLE IF NOT EXISTS migration_meta (
        key TEXT PRIMARY KEY,
        done INTEGER DEFAULT 0,
        done_at TEXT,
        notes TEXT
    )`);
    const FLAG = 'legacy_production_migration_v1';
    const existing = await get("SELECT done FROM migration_meta WHERE key = ?", [FLAG]).catch(() => null);

    const report = { workflowsCreated: 0, stepsMigrated: 0, packagingMigrated: 0, foodMenusMigrated: 0 };

    function inferActivityTypeFromTitle(title) {
        const t = String(title || '').toLowerCase();
        if (/masak|cook|goreng|rebus|kukus|panggang|tumis/.test(t)) return 'cook';
        if (/pack|packing|kemas|pemorsian|porsi/.test(t)) return 'pack';
        if (/sortir|sortasi/.test(t)) return 'sortir';
        if (/qc|cek|quality|inspeksi/.test(t)) return 'qc';
        if (/dingin|chill|pending/.test(t)) return 'chill';
        if (/delivery|kirim|antar/.test(t)) return 'delivery';
        if (/potong|cuci|kupas|prep|persiapan/.test(t)) return 'prep';
        return 'prep';
    }

    // ---- Migration A: recipe_steps → workflow_steps ----
    try {
        const menusNeedingWf = await all("SELECT id, name, recipe_id FROM menu WHERE (workflow_id IS NULL OR workflow_id = '') AND recipe_id IS NOT NULL AND recipe_id <> ''").catch(() => []);
        for (const m of menusNeedingWf) {
            const steps = await all("SELECT * FROM recipe_steps WHERE recipe_id = ? ORDER BY step_order", [m.recipe_id]).catch(() => []);
            if (!steps || !steps.length) continue;
            const wfId = crypto.randomUUID();
            const now = new Date().toISOString();
            await run(
                "INSERT INTO workflows (id, tenant_id, name, category, description, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?)",
                [wfId, null, `Workflow ${m.name || 'Menu'}`, 'auto-migrated', 'Migrated from recipe_steps', now, now]
            );
            report.workflowsCreated += 1;
            const newIds = [];
            for (let i = 0; i < steps.length; i++) {
                const s = steps[i];
                const newId = crypto.randomUUID();
                const deps = i === 0 ? [] : [newIds[i - 1]];
                await run(
                    `INSERT INTO workflow_steps (id, tenant_id, workflow_id, step_order, title, description, activity_type, duration_minutes_per_batch, batch_capacity, required_resource_type, required_skill_level, depends_on_step_ids, parallelizable, qc_required, temperature_celsius, hygiene_level, ingredient_refs, ingredient_group, notes)
                     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                    [
                        newId, null, wfId,
                        Number(s.step_order || i + 1),
                        s.title || `Step ${i + 1}`,
                        null,
                        inferActivityTypeFromTitle(s.title),
                        Number(s.duration_minutes || 0),
                        s.batch_capacity != null ? Number(s.batch_capacity) : null,
                        s.required_resource_type || null,
                        null,
                        JSON.stringify(deps),
                        0, 0,
                        null, 'medium',
                        JSON.stringify([]),
                        'main',
                        'Migrated from recipe_steps'
                    ]
                );
                newIds.push(newId);
                report.stepsMigrated += 1;
            }
            await run("UPDATE menu SET workflow_id = ? WHERE id = ?", [wfId, m.id]);
        }
    } catch (e) { console.error('[MIGRATE_LEGACY_A]', e.message); }

    // Blok B/C hanya sekali (flag). Blok A di atas tetap jalan agar menu baru yang punya recipe_steps
    // tetap mendapat workflow_id setelah migrasi awal tenant sudah ditandai selesai.
    if (existing && existing.done) {
        return { ...report, skipped_bc: true };
    }

    // ---- Migration B: recipes.packaging_type+extra_packing_json → menu.packaging_stack_json ----
    try {
        const menusNoPack = await all("SELECT m.id AS menu_id, m.recipe_id, r.packaging_type, r.extra_packing_json FROM menu m LEFT JOIN recipes r ON r.id = m.recipe_id WHERE (m.packaging_stack_json IS NULL OR m.packaging_stack_json = '' OR m.packaging_stack_json = 'null')").catch(() => []);
        for (const row of menusNoPack) {
            const main = [];
            const extra = [];
            if (row.packaging_type) {
                main.push({ material: row.packaging_type, quantity: 1, duration_minutes: 2 });
            }
            if (row.extra_packing_json) {
                try {
                    const parsed = JSON.parse(row.extra_packing_json);
                    if (Array.isArray(parsed)) {
                        parsed.forEach(p => extra.push({
                            material: p.material || p.name || 'extra',
                            quantity: Number(p.quantity || 1),
                            duration_minutes: Number(p.duration_minutes || p.duration || 1)
                        }));
                    }
                } catch (e) { }
            }
            if (main.length || extra.length) {
                await run("UPDATE menu SET packaging_stack_json = ? WHERE id = ?", [JSON.stringify({ main, extra }), row.menu_id]);
                report.packagingMigrated += 1;
            }
        }
    } catch (e) { console.error('[MIGRATE_LEGACY_B]', e.message); }

    // ---- Migration C: food_menus + food_menu_ingredients → recipes + menu ----
    try {
        const fmRows = await all("SELECT * FROM food_menus").catch(() => []);
        for (const fm of fmRows) {
            const already = await get("SELECT id FROM menu WHERE (name = ? AND (food_id = ? OR food_id IS NULL)) LIMIT 1", [fm.name, fm.food_id]).catch(() => null);
            if (already) continue;

            const ings = await all("SELECT ingredient_id, qty_per_portion, qty_unit FROM food_menu_ingredients WHERE menu_id = ?", [fm.id]).catch(() => []);
            const ingredientsJson = JSON.stringify((ings || []).map(i => ({
                ingredient_id: i.ingredient_id,
                quantity: Number(i.qty_per_portion || 0),
                unit: i.qty_unit || 'gram'
            })));
            const recipeId = crypto.randomUUID();
            await run(
                "INSERT INTO recipes (id, name, instructions, ingredients, cooking_time, batch_capacity, portion_size) VALUES (?, ?, ?, ?, ?, ?, ?)",
                [recipeId, fm.name || 'Migrated', '', ingredientsJson, fm.cooking_time || 0, fm.batch_capacity || 0, fm.portion_size || 0]
            );

            const main = [];
            const extra = [];
            if (fm.packaging_type) main.push({ material: fm.packaging_type, quantity: 1, duration_minutes: 2 });
            if (fm.extra_packing_json) {
                try {
                    const parsed = JSON.parse(fm.extra_packing_json);
                    if (Array.isArray(parsed)) parsed.forEach(p => extra.push({
                        material: p.material || p.name || 'extra',
                        quantity: Number(p.quantity || 1),
                        duration_minutes: Number(p.duration_minutes || p.duration || 1)
                    }));
                } catch (e) { }
            }
            const packagingStack = (main.length || extra.length) ? JSON.stringify({ main, extra }) : null;

            const newMenuId = crypto.randomUUID();
            await run(
                "INSERT INTO menu (id, name, recipe_id, food_id, workflow_id, packaging_stack_json) VALUES (?, ?, ?, ?, ?, ?)",
                [newMenuId, fm.name || 'Migrated', recipeId, fm.food_id || null, null, packagingStack]
            );
            report.foodMenusMigrated += 1;
        }
    } catch (e) { console.error('[MIGRATE_LEGACY_C]', e.message); }

    await run("INSERT OR REPLACE INTO migration_meta (key, done, done_at, notes) VALUES (?, 1, ?, ?)", [FLAG, new Date().toISOString(), JSON.stringify(report)]);
    console.log('[MIGRATE_LEGACY] selesai:', report);
    return report;
}

