        await run(`CREATE TABLE IF NOT EXISTS kitchen_config (
            id TEXT PRIMARY KEY,
            config TEXT
        )`);
        const defaultDivisions = [
            { id: 'receiving', name: 'Divisi Penerimaan', capabilities: ['receive', 'sortir'], max_parallel_batches: 1, notes: '' },
            { id: 'prep',      name: 'Divisi Persiapan',  capabilities: ['prep', 'sortir'],    max_parallel_batches: 2, notes: '' },
            { id: 'cooking',   name: 'Divisi Pengolahan', capabilities: ['cook', 'qc'],        max_parallel_batches: 3, notes: 'Pemilik semua kitchen_equipment. Prep bahan baku di Divisi Persiapan.' },
            { id: 'packing',   name: 'Divisi Pemorsian',  capabilities: ['plate', 'pack', 'qc'], max_parallel_batches: 4, notes: '' },
            { id: 'driver',    name: 'Divisi Driver',     capabilities: ['dist'],              max_parallel_batches: 2, notes: '' },
            { id: 'cleaning',  name: 'Divisi Kebersihan', capabilities: ['cleaning'],          max_parallel_batches: 2, notes: '' },
            { id: 'security',  name: 'Divisi Keamanan',   capabilities: [],                     max_parallel_batches: 1, notes: '' },
            { id: 'ompreng',   name: 'Divisi Ompreng',    capabilities: ['cleaning'],           max_parallel_batches: 2, notes: 'Cuci ompreng bekas distribusi' }
        ];
        const DEFAULT_CUSTOM_CAPABILITIES = [];
        try {
            const row = await get("SELECT config FROM kitchen_config WHERE id = 1");
            let cfg = (row && row.config) ? JSON.parse(row.config) : {};
            const byId = new Map(defaultDivisions.map(d => [String(d.id).toLowerCase(), d]));
            const existing = Array.isArray(cfg.divisions) ? cfg.divisions : [];
            const merged = [];
            const seen = new Set();
            for (const d of existing) {
                if (!d || !d.id) continue;
                const key = String(d.id).toLowerCase();
                const canonical = byId.get(key);
                const base = canonical ? { id: canonical.id, name: canonical.name } : { id: d.id, name: d.name };
                merged.push({
                    ...base,
                    capabilities: Array.isArray(d.capabilities) ? d.capabilities : (canonical ? canonical.capabilities : []),
                    max_parallel_batches: Number.isFinite(Number(d.max_parallel_batches)) ? Number(d.max_parallel_batches) : (canonical ? canonical.max_parallel_batches : 1),
                    notes: typeof d.notes === 'string' ? d.notes : ''
                });
                seen.add(key);
            }
            for (const d of defaultDivisions) {
                if (!seen.has(String(d.id).toLowerCase())) merged.push({ ...d });
            }
            cfg.divisions = merged.length ? merged : defaultDivisions.map(d => ({ ...d }));
            if (!Array.isArray(cfg.custom_capabilities)) cfg.custom_capabilities = DEFAULT_CUSTOM_CAPABILITIES.slice();
            if (row) await run("UPDATE kitchen_config SET config = ? WHERE id = 1", [JSON.stringify(cfg)]);
            else await run("INSERT INTO kitchen_config (id, config) VALUES (1, ?)", [JSON.stringify(cfg)]);
        } catch (e) { }

