            const end = t.subscription_end_at || now;
            const planCode = (t.plan_type || '').toUpperCase() === 'PRO' ? 'PRO' : ((t.plan_type || '').toUpperCase() === 'TRIAL' ? 'TRIAL' : 'FREE');
