            await run("ALTER TABLE food_menu_ingredients ADD COLUMN cutting_duration_minutes REAL DEFAULT 0");
            await run("ALTER TABLE food_menu_ingredients ADD COLUMN cutting_output_per_duration REAL DEFAULT 0");
            await run("ALTER TABLE food_menu_ingredients ADD COLUMN washing_enabled INTEGER DEFAULT 0");
            await run("ALTER TABLE food_menu_ingredients ADD COLUMN washing_duration_minutes REAL DEFAULT 0");
            await run("ALTER TABLE food_menu_ingredients ADD COLUMN washing_output_per_duration REAL DEFAULT 0");
