app.get('/api/health/backend', (req, res) => {
    const base = getSupplierPortalRustBase();
    try {
        const url = new URL('/health', base);
        const lib = url.protocol === 'https:' ? https : http;
        const pReq = lib.request({
            hostname: url.hostname,
            port: url.port || (url.protocol === 'https:' ? 443 : 80),
            path: url.pathname,
            method: 'GET',
            timeout: 5000
        }, pRes => {
            let body = '';
            pRes.on('data', d => body += d);
            pRes.on('end', () => {
                res.json({ 
                    status: 'ok', 
                    backend_status: body, 
                    backend_url: base,
                    statusCode: pRes.statusCode 
                });
            });
        });
        pReq.on('error', e => {
            res.status(502).json({ error: 'Backend unreachable', message: e.message, target: base });
        });
        pReq.on('timeout', () => {
            pReq.destroy();
            res.status(504).json({ error: 'Backend timeout', target: base });
        });
        pReq.end();
    } catch (e) {
        res.status(500).json({ error: 'Invalid backend URL configuration', message: e.message });
    }
});

// Proxy configuration for Rust backend
const INTERNAL_SECRET = process.env.MBG_INTERNAL_SKIP_AUTH || process.env.JWT_SECRET || 'super_secure_secret_key_generated_by_system_admin_2026';

// ─── Supplier portal (Node + SQLite portal_suppliers): auth & subscription tanpa Rust ───
// Order/bid/claim tetap dari Postgres — di bawah stub [] / 404 / 503 jika Rust tidak jalan.
async function handleSupplierPortalSignup(req, res) {
    try {
        const b = req.body || {};
        const email = String(b.email || '').trim().toLowerCase();
        const password = String(b.password || '');
        const name = String(b.name || '').trim();
        if (!email || !password || !name) {
            return res.status(400).json({ error: 'Email, password, and name are required' });
        }
        if (password.length < 6) {
            return res.status(400).json({ error: 'Password minimal 6 karakter' });
        }
        const dup = await getOnDb(platformDb, 'SELECT id FROM portal_suppliers WHERE LOWER(TRIM(email)) = ?', [email]);
        if (dup) return res.status(409).json({ error: 'Email already registered' });
        const id = crypto.randomUUID();
        const now = new Date().toISOString();
        const ph = await hashPassword(password);
        const company_name = b.company_name != null ? String(b.company_name).trim() || null : null;
        const contact_phone =
            b.contact_phone != null
                ? String(b.contact_phone).trim() || null
                : b.phone != null
                  ? String(b.phone).trim() || null
                  : null;
        const address = b.address != null ? String(b.address).trim() || null : null;
        await execOnDb(
            platformDb,
            `INSERT INTO portal_suppliers (id, email, name, company_name, contact_phone, address, password_hash, subscription_tier, is_active, created_at, orders_taken_this_period, period_reset_at)
             VALUES (?, ?, ?, ?, ?, ?, ?, 'free', 0, ?, 0, ?)`,
            [id, email, name, company_name, contact_phone, address, ph, now, now]
        );
        res.json({
            id,
            message: 'Signup successful. Your account is pending admin approval.',
        });
    } catch (e) {
        res.status(500).json({ error: e.message || 'Signup failed' });
    }
}

async function handleSupplierPortalLogin(req, res) {
    try {
        const b = req.body || {};
        const email = String(b.email || '').trim().toLowerCase();
        const password = String(b.password || '');
        if (!email || !password) {
            return res.status(400).json({ error: 'Email and password required' });
        }
        const row = await getOnDb(platformDb, 'SELECT * FROM portal_suppliers WHERE LOWER(TRIM(email)) = ?', [email]);
        if (!row) return res.status(401).json({ error: 'Invalid credentials' });
        if (!Number(row.is_active)) {
            return res.status(403).json({ error: 'Account is pending approval or deactivated' });
        }
        if (!row.password_hash || !String(row.password_hash).trim()) {
            return res.status(401).json({ error: 'Account not initialized' });
        }
        const ok = await verifyPassword(password, row.password_hash);
        if (!ok) return res.status(401).json({ error: 'Invalid credentials' });
        const token = supplierPortalJwtSign(row.id, row.email);
        res.json({
            token,
            supplier: {
                id: row.id,
                email: row.email,
                name: row.name,
                company_name: row.company_name,
                subscription_tier: String(row.subscription_tier || 'free').toLowerCase(),
                is_active: !!Number(row.is_active),
            },
        });
    } catch (e) {
        res.status(500).json({ error: e.message || 'Login failed' });
    }
}

