async function supplierPortalCanViewOrder(supplierId, row) {
    if (!row || !supplierId) return false;
    if (String(row.status || '').toUpperCase() !== 'OPEN') return false;
    const v = String(row.visibility || '').toLowerCase().trim();
    if (v === 'public' || v === 'fixed_price') return true;
    if (v === 'private') {
        const hit = await getOnDb(
            platformDb,
            'SELECT 1 AS x FROM portal_supply_order_invites WHERE po_id = ? AND supplier_id = ?',
            [row.id, supplierId]
        );
        return !!(hit && hit.x);
    }
    return false;
}

/** Detail order: setelah AWARDED supplier pemenang / yang pernah bid masih bisa buka ringkasan. */
async function supplierPortalCanViewOrderDetail(supplierId, row) {
    if (!row || !supplierId) return false;
    const st = String(row.status || '').toUpperCase();
    if (st === 'OPEN') return supplierPortalCanViewOrder(supplierId, row);
    if (st === 'AWARDED') {
        if (String(row.awarded_supplier_id || '') === supplierId) return true;
        const hit = await getOnDb(
            platformDb,
            'SELECT 1 AS x FROM portal_supply_bids WHERE po_id = ? AND supplier_id = ? LIMIT 1',
            [row.id, supplierId]
        );
        return !!(hit && hit.x);
    }
    if (st === 'CLAIMED' && String(row.claimed_by_supplier_id || '') === supplierId) return true;
    return false;
}

async function handleSupplierPortalOrdersList(req, res) {
    try {
        const claims = supplierPortalJwtVerify(supplierPortalBearer(req));
        if (!claims) return res.status(401).json({ error: 'Unauthorized' });
        await mbgEnsurePortalSupplyOrderTables();
        const sid = String(claims.sub || '').trim();
        const rows = await allOnDb(
            platformDb,
            `SELECT o.* FROM portal_supply_orders o
             WHERE UPPER(TRIM(COALESCE(o.status,''))) = 'OPEN'
               AND (
                 LOWER(TRIM(COALESCE(o.visibility,''))) IN ('public', 'fixed_price')
                 OR EXISTS (
                   SELECT 1 FROM portal_supply_order_invites i
                   WHERE i.po_id = o.id AND i.supplier_id = ?
                 )
               )
             ORDER BY datetime(o.created_at) DESC`,
            [sid]
        );
        const out = (rows || []).map(r => {
            let n = 0;
            try {
                const arr = JSON.parse(r.materials_json || '[]');
                n = Array.isArray(arr) ? arr.length : 0;
            } catch (e) {
                n = 0;
            }
            return {
                po_id: r.id,
                po_number: r.po_number,
                tenant_name: r.tenant_name || r.tenant_id,
                visibility: String(r.visibility || 'public').toLowerCase(),
                material_count: n,
                delivery_deadline: r.delivery_deadline,
                notes: r.notes,
                created_at: r.created_at,
            };
        });
        res.json(out);
    } catch (e) {
        res.status(500).json({ error: e.message || 'Orders list failed' });
    }
}

async function handleSupplierPortalOrderDetail(req, res) {
    try {
        const claims = supplierPortalJwtVerify(supplierPortalBearer(req));
        if (!claims) return res.status(401).json({ error: 'Unauthorized' });
        await mbgEnsurePortalSupplyOrderTables();
        const sid = String(claims.sub || '').trim();
        const poId = String(req.params.poId || '').trim();
        const row = await getOnDb(platformDb, 'SELECT * FROM portal_supply_orders WHERE id = ?', [poId]);
        if (!row) return res.status(404).json({ error: 'Not found' });
        const can = await supplierPortalCanViewOrderDetail(sid, row);
        if (!can) return res.status(404).json({ error: 'Not found', message: 'Order tidak tersedia untuk akun Anda.' });

        let materials = [];
        try {
            materials = JSON.parse(row.materials_json || '[]');
        } catch (e) {
            materials = [];
        }
        if (!Array.isArray(materials)) materials = [];
        const bid = await getOnDb(
            platformDb,
            `SELECT * FROM portal_supply_bids WHERE po_id = ? AND supplier_id = ? ORDER BY datetime(created_at) DESC LIMIT 1`,
            [poId, sid]
        );
        let my_bid = null;
        if (bid) {
            let items = [];
            try {
                items = JSON.parse(bid.items_json || '[]');
            } catch (e) {
                items = [];
            }
            const nameByMid = new Map(materials.map(m => [m.id, m.material_name]));
            my_bid = {
                status: String(bid.status || 'pending').toLowerCase(),
                total_amount: Number(bid.total_amount) || 0,
                notes: bid.notes || null,
                items: (Array.isArray(items) ? items : []).map(it => ({
                    ...it,
                    material_name: it.material_name || nameByMid.get(it.material_id) || '-',
                })),
            };
        }
        res.json({
            po_number: row.po_number,
            tenant_name: row.tenant_name || row.tenant_id,
            visibility: String(row.visibility || 'public').toLowerCase(),
            status: String(row.status || 'OPEN').toLowerCase(),
            notes: row.notes,
            delivery_deadline: row.delivery_deadline,
            materials,
            my_bid,
        });
    } catch (e) {
        res.status(500).json({ error: e.message || 'Detail failed' });
    }
}

async function handleSupplierPortalOrderBid(req, res) {
    try {
        const claims = supplierPortalJwtVerify(supplierPortalBearer(req));
        if (!claims) return res.status(401).json({ error: 'Unauthorized' });
        await mbgEnsurePortalSupplyOrderTables();
        const sid = String(claims.sub || '').trim();
        const poId = String(req.params.poId || '').trim();
        const row = await getOnDb(platformDb, 'SELECT * FROM portal_supply_orders WHERE id = ?', [poId]);
        if (!row) return res.status(404).json({ error: 'Not found' });
        if (String(row.status || '').toUpperCase() !== 'OPEN') {
            return res.status(409).json({
                error: 'PO tidak menerima bid',
                message: 'Tenant sudah memilih pemenang atau PO sudah ditutup.',
            });
        }
        if (String(row.visibility || '').toLowerCase() === 'fixed_price') {
            return res.status(400).json({
                error: 'Bid tidak berlaku',
                message: 'PO fixed price: gunakan Claim order, bukan bid.',
            });
        }
        const can = await supplierPortalCanViewOrder(sid, row);
        if (!can) return res.status(403).json({ error: 'Forbidden' });

        const body = req.body || {};
        const itemsIn = Array.isArray(body.items) ? body.items : [];
        let matById = new Map();
        try {
            const mats = JSON.parse(row.materials_json || '[]');
            (Array.isArray(mats) ? mats : []).forEach(m => matById.set(m.id, m));
        } catch (e) {
            matById = new Map();
        }

        const items = [];
        let total = 0;
        for (const it of itemsIn) {
            const mid = String(it.material_id || '').trim();
            const qty = Number(it.offered_qty);
            const price = Number(it.offered_price_per_unit);
            if (!mid || !Number.isFinite(qty) || qty <= 0 || !Number.isFinite(price) || price < 0) continue;
            const meta = matById.get(mid);
            const material_name = meta ? meta.material_name : '';
            total += qty * price;
            items.push({ material_id: mid, material_name, offered_qty: qty, offered_price_per_unit: price });
        }
        if (!items.length) {
            return res.status(400).json({ error: 'Bid kosong', message: 'Isi minimal satu item dengan qty dan harga valid.' });
        }

        const bidId = crypto.randomUUID();
        const now = new Date().toISOString();
        const noteStr = body.notes != null ? String(body.notes).slice(0, 2000) : null;
        await execOnDb(
            platformDb,
            `INSERT INTO portal_supply_bids (id, po_id, supplier_id, status, notes, total_amount, items_json, created_at)
             VALUES (?, ?, ?, 'pending', ?, ?, ?, ?)`,
            [bidId, poId, sid, noteStr, total, JSON.stringify(items), now]
        );
        res.json({ ok: true, bid_id: bidId, total_amount: total });
    } catch (e) {
        res.status(500).json({ error: e.message || 'Bid failed' });
    }
}

async function handleSupplierPortalOrderClaim(req, res) {
    try {
        const claims = supplierPortalJwtVerify(supplierPortalBearer(req));
        if (!claims) return res.status(401).json({ error: 'Unauthorized' });
        await mbgEnsurePortalSupplyOrderTables();
        const sid = String(claims.sub || '').trim();
        const poId = String(req.params.poId || '').trim();
        const row = await getOnDb(platformDb, 'SELECT * FROM portal_supply_orders WHERE id = ?', [poId]);
        if (!row) return res.status(404).json({ error: 'Not found' });
        if (String(row.visibility || '').toLowerCase() !== 'fixed_price') {
            return res.status(400).json({ error: 'Claim hanya untuk PO fixed price' });
        }
        const can = await supplierPortalCanViewOrder(sid, row);
        if (!can) return res.status(403).json({ error: 'Forbidden' });
        const r = await execOnDb(
            platformDb,
            `UPDATE portal_supply_orders SET status = 'CLAIMED', claimed_by_supplier_id = ?
             WHERE id = ? AND UPPER(TRIM(COALESCE(status,''))) = 'OPEN' AND LOWER(TRIM(COALESCE(visibility,''))) = 'fixed_price'`,
            [sid, poId]
        );
        if (!r || !r.changes) {
            return res.status(409).json({ error: 'Sudah di-claim supplier lain', message: 'PO ini tidak lagi tersedia.' });
        }
        await execOnDb(
            platformDb,
            'UPDATE portal_suppliers SET orders_taken_this_period = COALESCE(orders_taken_this_period,0) + 1 WHERE id = ?',
            [sid]
        ).catch(() => {});
        res.json({ ok: true });
    } catch (e) {
        res.status(500).json({ error: e.message || 'Claim failed' });
    }
}

async function handleSupplierPortalMyBids(req, res) {
    try {
        const claims = supplierPortalJwtVerify(supplierPortalBearer(req));
        if (!claims) return res.status(401).json({ error: 'Unauthorized' });
        await mbgEnsurePortalSupplyOrderTables();
        const sid = String(claims.sub || '').trim();
        const rows = await allOnDb(
            platformDb,
            `SELECT b.*, o.po_number, o.tenant_name
             FROM portal_supply_bids b
             JOIN portal_supply_orders o ON o.id = b.po_id
             WHERE b.supplier_id = ?
             ORDER BY datetime(b.created_at) DESC`,
            [sid]
        );
        const out = (rows || []).map(r => ({
            po_id: r.po_id,
            po_number: r.po_number,
            tenant_name: r.tenant_name,
            total_amount: Number(r.total_amount) || 0,
            status: String(r.status || 'pending').toLowerCase(),
            submitted_at: r.created_at,
        }));
        res.json(out);
    } catch (e) {
        res.status(500).json({ error: e.message || 'My bids failed' });
    }
}

