// Catatan: JANGAN pasang proxy global untuk /api/plans, /api/tasks, /api/drafts, /api/procurement (seluruh prefix),
// dll. di sini — urutan Express membuat proxy itu menang SEBELUM middleware /api + handler SQLite di bawah,
// sehingga UI memanggil Node tapi request dialihkan ke Rust di 127.0.0.1:8080 (ECONNREFUSED jika Rust tidak jalan).
// Procurement selain operational-materials tetap di-proxy setelah handler SQLite (lihat setelah app.use('/api', ...)).

// --- FACE RECOGNITION API (Placed above global /api middleware) ---
app.post('/api/facerec/register', rateLimit(10, 60 * 1000), async (req, res) => {
    const { tenant_id, name, division, pin, image_data } = req.body || {};
    try {
        const missing = [];
        if (!tenant_id) missing.push('tenant_id');
        if (!name) missing.push('name');
        if (!division) missing.push('division');
        if (!pin) missing.push('pin');
        if (!image_data) missing.push('image_data');

        if (missing.length > 0) {
            return res.status(400).json({ error: `Data pendaftaran tidak lengkap: missing ${missing.join(', ')}` });
        }

        // 1. Verify Tenant (platform DB, slug-safe — same rules as /api/facerec/recognize).
        const tr = String(tenant_id || '').trim();
        let t = await resolvePlatformTenantForFacerecInput(tenant_id);
        if (!t && tr === 'default') {
            t = await resolveSoleActiveKitchenForFacerec();
        }
        if (!t && tr === 'default') {
            t = { id: 'default', name: 'default' };
        }
        if (!t) return res.status(404).json({ error: 'Kitchen/Tenant tidak ditemukan' });

        // 2. Perform operations in Tenant DB context
        const newStaffId = crypto.randomUUID();
        const staff_code = (name.split(' ')[0] + Math.floor(1000 + Math.random() * 9000)).toUpperCase();
        
        try {
            await withTenantDatabase(t.id, async () => {
                // Get dedicated Registration PIN from kitchen_config (Tenant DB)
                const confRow = await get("SELECT config FROM kitchen_config WHERE id = '1'").catch(() => null);
                const config = confRow ? JSON.parse(confRow.config) : {};
                const portalPin = config.portal_pin || 'panji123';

                if (pin !== portalPin) {
                    throw new Error('PIN Tenant salah. Silakan hubungi manajemen.');
                }

                // Check if Staff with same Name and Division already exists (Case-insensitive & Trimmed)
                const existing = await get(
                    "SELECT id FROM staff WHERE tenant_id = ? AND LOWER(TRIM(name)) = LOWER(TRIM(?)) AND LOWER(TRIM(division_id)) = LOWER(TRIM(?))", 
                    [t.id, name, division]
                ).catch(() => null);
                
                if (existing) {
                    throw new Error(`Data Relawan **${name}** pada divisi **${division}** sudah terdaftar.`);
                }

                // Generate a random 6-digit PIN for the staff
                const plainPin = Math.floor(100000 + Math.random() * 900000).toString();
                const pinHash = await hashPassword(plainPin);

                // Create NEW Staff Record (Inside Tenant DB)
                // Default role: 'relawan' — staff yang didaftarkan via face register akan login
                // melalui Portal Relawan (staff.html) menggunakan Kode Staff + PIN / Face.
                await run(
                    "INSERT INTO staff (id, tenant_id, name, role, division_id, staff_code, pin_hash, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
                    [newStaffId, t.id, name, 'relawan', division, staff_code, pinHash, new Date().toISOString(), new Date().toISOString()]
                );
                
                // Attach plainPin to the context so it can be returned in response
                req.generatedStaffPin = plainPin;
            });
        } catch (err) {
            let status = 500;
            if (err.message.includes('PIN')) status = 401;
            if (err.message.includes('terdaftar')) status = 409;
            return res.status(status).json({ error: err.message });
        }

        // 3. Proxy to Python Face API
        const _face = getFaceApiConnect();
        const pyReq = http.request({
            hostname: _face.hostname,
            port: _face.port,
            path: '/register',
            method: 'POST',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
        }, pyRes => {
            let body = '';
            pyRes.on('data', d => body += d);
            pyRes.on('end', async () => {
                if (pyRes.statusCode === 409) {
                    // Face already exists, rollback staff creation
                    await withTenantDatabase(t.id, async () => {
                        await run("DELETE FROM staff WHERE id = ?", [newStaffId]).catch(() => {});
                    });
                    
                    let errorDetail = `Data Relawan **${name}**, **${division}**, dan **Wajah** sudah terdaftar pada Tenan **${t.name}**`;
                    try {
                        const parsed = JSON.parse(body);
                        if (parsed.detail && parsed.detail.message) errorDetail = parsed.detail.message;
                    } catch (e) {}
                    
                    return res.status(409).json({ error: errorDetail });
                }

                if (pyRes.statusCode >= 400) {
                    // Other errors (e.g., no face detected), rollback staff creation
                    await withTenantDatabase(t.id, async () => {
                        await run("DELETE FROM staff WHERE id = ?", [newStaffId]).catch(() => {});
                    });
                    return res.status(pyRes.statusCode).json({ error: 'Gagal mendaftar wajah: ' + body });
                }
                
                // 4. Mark face as registered in DB
                await withTenantDatabase(t.id, async () => {
                    await run("UPDATE staff SET face_registered = 1, face_updated_at = ? WHERE id = ?", [new Date().toISOString(), newStaffId]).catch(() => {});
                });
                res.json({ message: 'Registrasi Berhasil', staff_id: newStaffId, staff_code, generated_pin: req.generatedStaffPin });
            });
        });
        pyReq.on('error', e => handleFaceApiUpstreamError(res, 'facerec/register', e, _face));
        pyReq.write(`staff_id=${newStaffId}&image_data=${encodeURIComponent(image_data)}&tenant_id=${t.id}`);
        pyReq.end();
    } catch (e) {
        console.error('Registration Error:', e);
        res.status(500).json({ error: e.message });
    }
});

const FACEREC_RECOGNIZE_RPM = Math.max(30, parseInt(process.env.FACEREC_RECOGNIZE_RPM || '120', 10) || 120);
app.post('/api/facerec/recognize', rateLimit(FACEREC_RECOGNIZE_RPM, 60 * 1000), async (req, res) => {
    const { image_data, tenant_id } = req.body || {};
    try {
        if (!image_data) return res.status(400).json({ error: 'Missing image_data' });

        // Gallery folders on Face API must use canonical tenant UUID (never raw slug like SPPGNgraket).
        const rawTenant = String(tenant_id || '').trim();
        let t = null;
        if (!rawTenant) {
            t = await resolveSoleActiveKitchenForFacerec();
            if (!t) {
                return res.json({
                    verified: false,
                    message: 'Pilih dapur terlebih dahulu atau buka halaman dengan ?tenant=... / login ulang.'
                });
            }
        } else if (rawTenant === 'default') {
            t = await resolveSoleActiveKitchenForFacerec();
            if (!t) {
                t = await resolvePlatformTenantForFacerecInput('default');
            }
        } else {
            t = await resolvePlatformTenantForFacerecInput(rawTenant);
        }
        if (!t) {
            console.log(`[DEBUG] facerec tenant unresolved raw="${rawTenant}"`);
            return res.json({ verified: false, message: 'Kitchen/Tenant tidak ditemukan' });
        }
        const resolvedTenantId = t.id;
        console.log(
            `[DEBUG] facerec recognize tenant raw="${rawTenant || '(empty)'}" -> id="${resolvedTenantId}" name="${String(t.name || '').slice(0, 80)}"`
        );
        // #region agent log
        appendAgentDebugNdjson({
            hypothesisId: 'H5',
            location: 'server.js:facerec/recognize:resolved',
            message: 'tenant resolved for recognize',
            data: {
                rawTenant: rawTenant || null,
                resolvedTenantId,
                tenantDbFile: tenantDbPath(resolvedTenantId),
                tenantDbExists: fs.existsSync(tenantDbPath(resolvedTenantId))
            }
        });
        // #endregion

        const _faceRec = getFaceApiConnect();

        const pyReq = http.request({
            hostname: _faceRec.hostname,
            port: _faceRec.port,
            path: '/recognize',
            method: 'POST',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
        }, pyRes => {
            let body = '';
            pyRes.on('data', d => body += d);
            pyRes.on('end', async () => {
                try {
                    console.log(`[DEBUG] Face API raw body: ${body}`);
                    if (pyRes.statusCode >= 400) return res.status(pyRes.statusCode).send(body);
                    
                    const result = JSON.parse(body);
                    if (result.verified === false) {
                        return res.json({ verified: false, message: result.message || 'Face not recognized' });
                    }
                    
                    const staffIdRaw = (result.staff_id || '').trim();
                    const staffId = normalizeFacerecStaffId(staffIdRaw);
                    console.log(`[DEBUG] Extracted staffId: "${staffId}" (raw="${staffIdRaw}") distance=${result.distance}`);
                    // #region agent log
                    appendAgentDebugNdjson({
                        hypothesisId: 'H9',
                        location: 'server.js:facerec/recognize:staffIdNorm',
                        message: 'staff_id from Face API normalized for DB lookup',
                        data: {
                            staffIdRaw: staffIdRaw.slice(0, 80),
                            staffId: staffId.slice(0, 80),
                            normalized: staffIdRaw !== staffId
                        }
                    });
                    // #endregion

                    if (!staffId) return res.status(404).json({ error: 'Face matched but staff_id is empty' });
                    
                    // If tenant was resolved, verify staff in that tenant DB first; else global lookup.
                    let staff;
                    if (resolvedTenantId) {
                        const facerecTdb = await ensureTenantDb(resolvedTenantId);
                        await ensureStaffSchemaForTenantId(resolvedTenantId);
                        staff = await getOnDb(
                            facerecTdb,
                            'SELECT *, ? as tenant_id FROM staff WHERE id = ? COLLATE NOCASE',
                            [resolvedTenantId, staffId]
                        );
                        // #region agent log
                        appendAgentDebugNdjson({
                            hypothesisId: 'H16',
                            location: 'server.js:facerec/recognize:explicitShardQuery',
                            message: 'staff lookup uses explicit tenant sqlite connection (ALS-safe after http callback)',
                            data: { resolvedTenantId, staffId: staffId.slice(0, 80), found: !!staff }
                        });
                        // #endregion
                        if (
                            staff &&
                            String(staff.id).toLowerCase() === String(staffId).toLowerCase() &&
                            String(staff.id) !== String(staffId)
                        ) {
                            // #region agent log
                            appendAgentDebugNdjson({
                                hypothesisId: 'H15',
                                location: 'server.js:facerec/recognize:scopedNocaseHit',
                                message: 'staff row matched with different id casing than Face API',
                                data: {
                                    resolvedTenantId,
                                    dbId: String(staff.id).slice(0, 80),
                                    queryId: String(staffId).slice(0, 80)
                                }
                            });
                            // #endregion
                        }
                        // #region agent log
                        appendAgentDebugNdjson({
                            hypothesisId: 'H1',
                            location: 'server.js:facerec/recognize:scopedResult',
                            message: 'scoped staff lookup result',
                            data: {
                                resolvedTenantId,
                                staffId,
                                found: !!staff,
                                staffName: staff ? String(staff.name || '').slice(0, 60) : null
                            }
                        });
                        // #endregion
                    } else {
                        staff = await getStaffGlobal(staffId);
                    }
                    if (!staff && staffId) {
                        console.log(`[DEBUG] facerec scoped miss tenant_id=${resolvedTenantId || '(none)'} staffId=${staffId} — trying getStaffGlobal`);
                        // #region agent log
                        appendAgentDebugNdjson({
                            hypothesisId: 'H1',
                            location: 'server.js:facerec/recognize:scopedMiss',
                            message: 'scoped staff lookup missed, calling getStaffGlobal',
                            data: {
                                resolvedTenantId: resolvedTenantId || null,
                                staffId,
                                staffIdLen: staffId.length
                            }
                        });
                        // #endregion
                        staff = await getStaffGlobal(staffId);
                    }

                    if (!staff && staffId && resolvedTenantId) {
                        staff = await lookupStaffOnPlatformForFacerec(staffId, resolvedTenantId);
                        if (staff) {
                            console.log(`[DEBUG] facerec staff from platform DB staffId=${staffId} tenant=${resolvedTenantId}`);
                            try {
                                const tn = await getOnDb(platformDb, 'SELECT name FROM tenants WHERE id = ?', [resolvedTenantId]);
                                staff.tenant_name = tn?.name || resolvedTenantId;
                            } catch (e) {
                                staff.tenant_name = resolvedTenantId;
                            }
                            // #region agent log
                            appendAgentDebugNdjson({
                                hypothesisId: 'H6',
                                location: 'server.js:facerec/recognize:platformStaffFallback',
                                message: 'staff row loaded from platform DB after shard/global miss',
                                data: { staffId, resolvedTenantId, name: String(staff.name || '').slice(0, 60) }
                            });
                            // #endregion
                        }
                    }

                    if (!staff) {
                        console.log(`[DEBUG] Staff NOT found in DB search (tenant_id=${resolvedTenantId || '(none)'})`);
                        // #region agent log
                        appendAgentDebugNdjson({
                            hypothesisId: 'H2',
                            location: 'server.js:facerec/recognize:notFound',
                            message: 'staff row not found after scoped+global+platform',
                            data: {
                                resolvedTenantId: resolvedTenantId || null,
                                staffId,
                                staffIdRaw: staffIdRaw.slice(0, 80),
                                staffIdLen: staffId.length
                            }
                        });
                        // #endregion
                        return res.status(404).json({
                            error: 'Staff not found in DB',
                            hint: 'Wajah cocok di galeri tetapi data staf tidak ada di basis data dapur. Coba daftar ulang wajah atau hubungi admin.'
                        });
                    }
                    
                    console.log(`[DEBUG] Recognition Success: ${staff.name} (${staff.tenant_id})`);
                    res.json({ staff, distance: result.distance, verified: true });
                } catch (e) {
                    console.error('Face Login Proxy Error:', e);
                    res.status(502).json({ error: 'Invalid response from Face API: ' + e.message });
                }
            });
        });
        pyReq.on('error', e => handleFaceApiUpstreamError(res, 'facerec/recognize', e, _faceRec));
        pyReq.write(`image_data=${encodeURIComponent(image_data)}&tenant_id=${encodeURIComponent(resolvedTenantId)}`);
        pyReq.end();
    } catch (e) { res.status(500).json({ error: e.message }); }
});

app.post('/auth/staff/face-login', async (req, res) => {
    const { tenant_id, staff_id } = req.body || {};
    try {
        if (!tenant_id || !staff_id) return res.status(400).json({ error: 'Missing tenant/staff' });
        const staff = await withTenantDatabase(tenant_id, async () => {
            return await get("SELECT id, name, role FROM staff WHERE id = ? AND tenant_id = ?", [staff_id, tenant_id]);
        });
        if (!staff) return res.status(401).json({ error: 'Unauthorized access' });

        const token = await createSession({ actor_type: 'staff', actor_id: staff.id, tenant_id, role: staff.role || 'staff', ttlSeconds: 60 * 60 * 12 });
        res.json({ token, tenant_id, staff });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

/**
 * Apply minimal staff DDL on a concrete sqlite connection (no AsyncLocalStorage).
 * http.request callbacks can run outside route ALS; run()/get() would otherwise hit platformDb.
 */
async function ensureStaffSchemaOnDb(db) {
    await execOnDb(
        db,
        `CREATE TABLE IF NOT EXISTS staff (
        id TEXT PRIMARY KEY,
        tenant_id TEXT,
        name TEXT,
        role TEXT,
        division_id TEXT,
        staff_code TEXT,
        pin_hash TEXT,
        skills_json TEXT,
        created_at TEXT,
        updated_at TEXT
    )`
    );
    await execOnDb(db, `CREATE INDEX IF NOT EXISTS idx_staff_tenant ON staff(tenant_id)`);
    try {
        await execOnDb(db, 'ALTER TABLE staff ADD COLUMN division_id TEXT');
    } catch (e) { /* exists */ }
    try {
        await execOnDb(db, 'ALTER TABLE staff ADD COLUMN staff_code TEXT');
    } catch (e) { /* exists */ }
    try {
        await execOnDb(db, 'ALTER TABLE staff ADD COLUMN pin_hash TEXT');
    } catch (e) { /* exists */ }
}

/**
 * Minimal `staff` DDL for tenant shards (e.g. copied from platform) — facerec only needs this table.
 * Uses ensureTenantDb + execOnDb so schema/query targets the shard file even when ALS is missing (e.g. Face API callback).
 */
async function ensureStaffSchemaForTenantId(tenantId) {
    const schemaKey = `tenant:${tenantId}`;
    if (staffSchemaReadyKeys.has(schemaKey)) return;
    const tdb = await ensureTenantDb(tenantId);
    await ensureStaffSchemaOnDb(tdb);
    staffSchemaReadyKeys.add(schemaKey);
}

async function getStaffGlobal(staffId) {
    console.log(`[DEBUG] getStaffGlobal for staffId: "${staffId}"`);
    // Align with resolveSoleActiveKitchenForFacerec: ACTIVE, PRO, TRIAL, TRIALING; omitting PRO skipped whole tenant DBs.
    // Omit `default`: its shard is often a minimal platform copy without ops `staff` rows; searching it caused SQLITE_ERROR spam.
    const fromSql = await allOnDb(
        platformDb,
        "SELECT id, name FROM tenants WHERE UPPER(COALESCE(TRIM(status),'')) IN ('ACTIVE','PRO','TRIAL','TRIALING')"
    );
    const seen = new Set(fromSql.map(t => t.id));
    const tenants = [...fromSql];
    let diskExtra = 0;
    // Also scan tenant sqlite files on disk (status drift, TRIALING, or missing platform row) — same dir ensureTenantDb uses.
    try {
        if (fs.existsSync(TENANT_DB_DIR)) {
            for (const f of fs.readdirSync(TENANT_DB_DIR)) {
                if (!f.endsWith('.sqlite')) continue;
                const id = f.slice(0, -'.sqlite'.length);
                if (!id || id === 'default' || seen.has(id)) continue;
                seen.add(id);
                diskExtra += 1;
                tenants.push({ id, name: id });
            }
        }
    } catch (e) {
        console.error(`[DEBUG] getStaffGlobal tenant dir scan: ${e.message}`);
    }
    // #region agent log
    appendAgentDebugNdjson({
        hypothesisId: 'H3',
        location: 'server.js:getStaffGlobal:tenantList',
        message: 'tenant list built for global staff search',
        data: {
            staffId,
            staffIdLen: String(staffId || '').length,
            sqlTenantCount: fromSql.length,
            diskExtraTenants: diskExtra,
            totalTenants: tenants.length,
            sampleTenantIds: tenants.slice(0, 8).map(x => x.id)
        }
    });
    // #endregion
    console.log(`[DEBUG] Found ${tenants.length} tenants to search`);
    for (const t of tenants) {
        try {
            const tdb = await ensureTenantDb(t.id);
            await ensureStaffSchemaForTenantId(t.id);
            const s = await getOnDb(
                tdb,
                'SELECT id, tenant_id, name, role, staff_code, division_id FROM staff WHERE id = ? COLLATE NOCASE',
                [staffId]
            );
            if (s) {
                console.log(`[DEBUG] Found staff "${staffId}" in tenant "${t.name}" (${t.id})`);
                // #region agent log
                appendAgentDebugNdjson({
                    hypothesisId: 'H3',
                    location: 'server.js:getStaffGlobal:found',
                    message: 'staff found in shard',
                    data: { staffId, tenantId: t.id, tenantName: String(t.name || '').slice(0, 80) }
                });
                // #endregion
                s.tenant_name = t.name || t.id;
                return s;
            }
        } catch (e) {
            console.error(`[DEBUG] Error searching in tenant ${t.id}:`, e);
            // #region agent log
            appendAgentDebugNdjson({
                hypothesisId: 'H4',
                location: 'server.js:getStaffGlobal:shardError',
                message: 'error querying tenant shard',
                data: { staffId, tenantId: t.id, err: String(e && e.message ? e.message : e).slice(0, 200) }
            });
            // #endregion
        }
    }
    // #region agent log
    appendAgentDebugNdjson({
        hypothesisId: 'H3',
        location: 'server.js:getStaffGlobal:miss',
        message: 'staff not in any searched shard',
        data: { staffId, searchedTenantCount: tenants.length }
    });
    // #endregion
    console.log(`[DEBUG] Staff "${staffId}" NOT FOUND in any tenant db`);
    return null;
}

app.use('/api', async (req, _res, next) => {
    try {
        if (req.headers['x-bypass-auth'] === 'true') {
            const isPlatform = req.headers['x-tenant-id'] === 'platform' || req.headers['x-tenant-id'] === 'internal';
            req.auth = {
                actor_type: isPlatform ? 'platform' : 'tenant',
                tenant_id: isPlatform ? null : req.headers['x-tenant-id'],
                role: 'admin',
                email: 'bypass@test.local'
            };
        } else {
            req.auth = await getSessionFromReq(req);
        }
        const apiPath = String(req.path || '');
        if (shouldUsePlatformDbForApiPath(apiPath)) {
            return dbContext.run({ db: platformDb, tenantId: null, maxDbBytes: null, tenantDbPath: null }, () => next());
        }

        // Determine tenant_id for operational endpoints.
        // Platform actor must pass `x-tenant-id`.
        // Tenant/staff: pakai tenant di sesi; jika kosong (sesi lama / edge case), fallback ke header
        // `x-tenant-id` yang sama seperti client kirim — supaya INSERT/SELECT tidak salah DB (platform vs shard).
        let tenantId = null;
        if (req.auth?.actor_type === 'platform') {
            tenantId = String(req.headers['x-tenant-id'] || '').trim() || null;
        } else {
            const authTid = req.auth?.tenant_id ? String(req.auth.tenant_id).trim() : '';
            const headerTid = String(req.headers['x-tenant-id'] || '').trim();
            tenantId = authTid || headerTid || null;
        }

        if (!tenantId) {
            // Fallback: keep platform db (safer than selecting a random tenant).
            return dbContext.run({ db: platformDb, tenantId: null, maxDbBytes: null, tenantDbPath: null }, () => next());
        }

        const tenantDb = await ensureTenantDb(tenantId);

        // Compute storage limit (max_db_mb) from active subscription on the platform DB.
        // If the plan doesn't include max_db_mb, we use a fallback based on plan code.
        const active = await getActiveSubscription(tenantId);
        const planCode = String(active?.plan?.code || '').toUpperCase();
        const rawMb = active?.plan?.limits?.max_db_mb;
        let maxMb = Number(rawMb);
        if (!Number.isFinite(maxMb) || maxMb <= 0) {
            const fallback = { FREE: 50, TRIAL: 200, PRO: 1024, ENTERPRISE: 5000 };
            maxMb = fallback[planCode] || 1024;
        }
        const maxDbBytes = Math.floor(maxMb * 1024 * 1024);
        const tenantDbPathValue = tenantDbPath(tenantId);

        return dbContext.run(
            { db: tenantDb, tenantId, maxDbBytes, tenantDbPath: tenantDbPathValue },
            () => next()
        );
    } catch (e) {
        next(e);
    }
});

// --- Supplier management (Developer Console / dev.html): SQLite platform DB; tidak butuh Rust :8080 ---
function mapPortalSupplierRow(r) {
    if (!r) return null;
    const phone = r.contact_phone || null;
    const hasPwCol = r.has_pw != null && r.has_pw !== '';
    const hasPassword =
        Number(hasPwCol ? r.has_pw : 0) === 1 ||
        !!(r.password_hash && String(r.password_hash).trim());
    return {
        id: r.id,
        email: r.email || '',
        name: r.name || '',
        company_name: r.company_name || null,
        contact_person: r.name || '',
        phone,
        contact_phone: phone,
        address: r.address || null,
        subscription_tier: String(r.subscription_tier || 'free').toLowerCase(),
        is_active: Number(r.is_active) === 1,
        created_at: r.created_at || '',
        has_password: hasPassword,
    };
}

