app.post('/api/suppliers', async (req, res) => {
    await requirePlatform(['developer', 'admin'])(req, res, async () => {
        try {
            const b = req.body || {};
            const email = String(b.email || '').trim().toLowerCase();
            if (!email) return res.status(400).json({ error: 'Email wajib diisi' });
            const dup = await get('SELECT id FROM portal_suppliers WHERE LOWER(TRIM(email)) = ?', [email]);
            if (dup) return res.status(409).json({ error: 'Email supplier sudah terdaftar' });

            const id = crypto.randomUUID();
            const now = new Date().toISOString();
            const name = String(b.name || '').trim();
            const company_name = b.company_name != null ? String(b.company_name).trim() || null : null;
            const contact_phone = String(b.phone || b.contact_phone || '').trim() || null;
            const address = b.address != null ? String(b.address).trim() || null : null;
            let tier = String(b.subscription_tier || 'free').toLowerCase().trim();
            if (!['free', 'pro', 'ultra'].includes(tier)) tier = 'free';
            const pw = String(b.password || '').trim();
            if (pw.length < 8) {
                return res.status(400).json({ error: 'Password akun supplier minimal 8 karakter (wajib untuk login portal supplier).' });
            }
            const password_hash = await hashPassword(pw);

            await run(
                `INSERT INTO portal_suppliers (id, email, name, company_name, contact_phone, address, password_hash, subscription_tier, is_active, created_at)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, 1, ?)`,
                [id, email, name, company_name, contact_phone, address, password_hash, tier, now]
            );
            res.json({ id });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

app.put('/api/suppliers/:id', async (req, res) => {
    await requirePlatform(['developer', 'admin'])(req, res, async () => {
        try {
            const id = String(req.params.id || '').trim();
            const existing = await get('SELECT * FROM portal_suppliers WHERE id = ?', [id]);
            if (!existing) return res.status(404).json({ error: 'Supplier not found' });

            const b = req.body || {};
            let email = existing.email;
            if (b.email !== undefined) {
                email = String(b.email || '').trim().toLowerCase();
                if (!email) return res.status(400).json({ error: 'Email tidak boleh kosong' });
                const dup = await get(
                    'SELECT id FROM portal_suppliers WHERE LOWER(TRIM(email)) = ? AND id != ?',
                    [email, id]
                );
                if (dup) return res.status(409).json({ error: 'Email supplier sudah dipakai lain' });
            }

            const name = b.name !== undefined ? String(b.name).trim() : existing.name;
            const company_name =
                b.company_name !== undefined ? (String(b.company_name).trim() || null) : existing.company_name;
            let contact_phone = existing.contact_phone;
            if (b.phone !== undefined || b.contact_phone !== undefined) {
                contact_phone = String(b.phone !== undefined ? b.phone : b.contact_phone || '').trim() || null;
            }
            const address = b.address !== undefined ? (String(b.address).trim() || null) : existing.address;

            let subscription_tier = existing.subscription_tier;
            if (b.subscription_tier !== undefined) {
                let t = String(b.subscription_tier || 'free').toLowerCase().trim();
                if (!['free', 'pro', 'ultra'].includes(t)) t = 'free';
                subscription_tier = t;
            }

            let is_active = Number(existing.is_active) === 1 ? 1 : 0;
            if (b.is_active !== undefined) {
                is_active = b.is_active === true || b.is_active === 1 || b.is_active === '1' || b.is_active === 'true' ? 1 : 0;
            }

            await run(
                `UPDATE portal_suppliers SET email = ?, name = ?, company_name = ?, contact_phone = ?, address = ?, subscription_tier = ?, is_active = ? WHERE id = ?`,
                [email, name, company_name, contact_phone, address, subscription_tier, is_active, id]
            );

            if (b.password !== undefined && String(b.password || '').trim()) {
                const npw = String(b.password).trim();
                if (npw.length < 8) {
                    return res.status(400).json({ error: 'Password baru minimal 8 karakter' });
                }
                const password_hash = await hashPassword(npw);
                await run('UPDATE portal_suppliers SET password_hash = ? WHERE id = ?', [password_hash, id]);
            }

            res.json({ id, updated: true });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

