async function mbgEnsureLocalProcurementTables() {
    await run(`CREATE TABLE IF NOT EXISTS local_procurement_plans (
        id TEXT PRIMARY KEY, tenant_id TEXT, status TEXT, food_id TEXT,
        plan_date TEXT, target_portions INTEGER, plan_data TEXT,
        material_total REAL, created_at TEXT
    )`);
    await run(`CREATE TABLE IF NOT EXISTS local_plan_materials (
        id TEXT PRIMARY KEY, plan_id TEXT, tenant_id TEXT, ingredient_id TEXT,
        material_name TEXT, material_type TEXT, quantity_needed REAL, unit TEXT,
        estimated_price_per_unit REAL, estimated_total REAL, price_source TEXT
    )`);
    try { await run('ALTER TABLE local_plan_materials ADD COLUMN price_unit TEXT'); } catch (e) { /* exists */ }
    await run(`CREATE TABLE IF NOT EXISTS local_purchase_orders (
        id TEXT PRIMARY KEY, plan_id TEXT, tenant_id TEXT, po_number TEXT,
        visibility TEXT, status TEXT, notes TEXT, delivery_deadline TEXT, created_at TEXT
    )`);
    try { await run('ALTER TABLE local_purchase_orders ADD COLUMN delivery_deadline TEXT'); } catch (e) { /* exists */ }
    try { await run('ALTER TABLE local_procurement_plans ADD COLUMN production_plan_id TEXT'); } catch (e) { /* exists */ }
}

