async function mbgEnsurePortalSupplyOrderTables() {
    await execOnDb(
        platformDb,
        `CREATE TABLE IF NOT EXISTS portal_supply_orders (
            id TEXT PRIMARY KEY,
            tenant_id TEXT NOT NULL,
            procurement_plan_id TEXT,
            po_number TEXT,
            visibility TEXT,
            status TEXT NOT NULL,
            notes TEXT,
            delivery_deadline TEXT,
            created_at TEXT,
            tenant_name TEXT,
            materials_json TEXT,
            claimed_by_supplier_id TEXT
        )`
    );
    await execOnDb(
        platformDb,
        `CREATE TABLE IF NOT EXISTS portal_supply_order_invites (
            po_id TEXT NOT NULL,
            supplier_id TEXT NOT NULL,
            PRIMARY KEY (po_id, supplier_id)
        )`
    );
    await execOnDb(
        platformDb,
        `CREATE TABLE IF NOT EXISTS portal_supply_bids (
            id TEXT PRIMARY KEY,
            po_id TEXT NOT NULL,
            supplier_id TEXT NOT NULL,
            status TEXT NOT NULL DEFAULT 'pending',
            notes TEXT,
            total_amount REAL,
            items_json TEXT,
            created_at TEXT
        )`
    );
    try {
        await execOnDb(platformDb, 'CREATE INDEX IF NOT EXISTS idx_portal_supply_orders_status ON portal_supply_orders(status)');
    } catch (e) { /* ignore */ }
    try {
        await execOnDb(platformDb, 'CREATE INDEX IF NOT EXISTS idx_portal_supply_bids_po ON portal_supply_bids(po_id)');
    } catch (e) { /* ignore */ }
    try {
        await execOnDb(platformDb, 'ALTER TABLE portal_supply_orders ADD COLUMN awarded_bid_id TEXT');
    } catch (e) { /* exists */ }
    try {
        await execOnDb(platformDb, 'ALTER TABLE portal_supply_orders ADD COLUMN awarded_supplier_id TEXT');
    } catch (e) { /* exists */ }
}

/** Bid supplier (platformDb) untuk satu plan pengadaan tenant — `po.id` sama dengan baris `portal_supply_orders`. */
async function mbgFetchProcurementBidsForTenantPlan(tenantId, planId) {
    await mbgEnsurePortalSupplyOrderTables();
    const po = await get(
        'SELECT id FROM local_purchase_orders WHERE plan_id = ? AND tenant_id = ? ORDER BY datetime(created_at) DESC LIMIT 1',
        [planId, tenantId]
    );
    if (!po || !po.id) return [];
    const portalPo = await getOnDb(
        platformDb,
        'SELECT id FROM portal_supply_orders WHERE id = ? AND tenant_id = ?',
        [po.id, tenantId]
    );
    if (!portalPo) return [];
    const rows = await allOnDb(
        platformDb,
        `SELECT b.*, s.name AS supplier_name, s.company_name AS supplier_company, s.email AS supplier_email
         FROM portal_supply_bids b
         LEFT JOIN portal_suppliers s ON s.id = b.supplier_id
         WHERE b.po_id = ?
         ORDER BY datetime(b.created_at) DESC`,
        [po.id]
    );
    return (rows || []).map(r => {
        let items = [];
        try {
            items = JSON.parse(r.items_json || '[]');
        } catch (e) {
            items = [];
        }
        return {
            id: r.id,
            supplier_id: r.supplier_id,
            supplier_name: r.supplier_name || r.supplier_email || r.supplier_id,
            supplier_company: r.supplier_company || null,
            supplier_email: r.supplier_email || null,
            status: String(r.status || 'pending').toLowerCase(),
            total_amount: Number(r.total_amount) || 0,
            notes: r.notes || null,
            submitted_at: r.created_at,
            items: Array.isArray(items) ? items : [],
        };
    });
}

async function mbgMirrorPurchaseOrderToPortal({
    tenantId,
    poId,
    procurementPlanId,
    poNumber,
    visibility,
    notes,
    deliveryDeadline,
    createdAtIso,
    invitedSupplierIds,
    materialsRows
}) {
    await mbgEnsurePortalSupplyOrderTables();
    const tRow = await getOnDb(platformDb, 'SELECT name FROM tenants WHERE id = ?', [tenantId]).catch(() => null);
    const tenantName = (tRow && tRow.name) ? String(tRow.name).trim() || tenantId : tenantId;
    const materials = (materialsRows || []).map(m => ({
        id: String(m.id || ''),
        material_name: m.material_name || '',
        material_type: m.material_type || 'ingredient',
        quantity_needed: Number(m.quantity_needed) || 0,
        unit: m.unit || ''
    }));
    const materialsJson = JSON.stringify(materials);
    await execOnDb(platformDb, 'DELETE FROM portal_supply_order_invites WHERE po_id = ?', [poId]);
    await execOnDb(
        platformDb,
        `INSERT OR REPLACE INTO portal_supply_orders (
            id, tenant_id, procurement_plan_id, po_number, visibility, status, notes, delivery_deadline, created_at, tenant_name, materials_json, claimed_by_supplier_id
        ) VALUES (?, ?, ?, ?, ?, 'OPEN', ?, ?, ?, ?, ?, NULL)`,
        [
            poId,
            tenantId,
            procurementPlanId || null,
            poNumber,
            visibility,
            notes || null,
            deliveryDeadline || null,
            createdAtIso || new Date().toISOString(),
            tenantName,
            materialsJson
        ]
    );
    const vis = String(visibility || '').toLowerCase();
    if (vis === 'private' && Array.isArray(invitedSupplierIds)) {
        for (const sid of invitedSupplierIds) {
            const s = String(sid || '').trim();
            if (!s) continue;
            await execOnDb(platformDb, 'INSERT OR IGNORE INTO portal_supply_order_invites (po_id, supplier_id) VALUES (?, ?)', [poId, s]);
        }
    }
}

/** Normalisasi string satuan (sinkron dengan logika backend procurement). */
function mbgNormUnitStr(u) {
    return String(u == null ? '' : u).trim().toLowerCase();
}

function mbgGramsPerQtyUnit(u) {
    switch (mbgNormUnitStr(u)) {
        case 'mg': return 0.001;
        case 'g':
        case 'gr':
        case 'gram':
        case 'grams': return 1;
        case 'kg':
        case 'kilo':
        case 'kilogram':
        case 'kilograms': return 1000;
        default: return null;
    }
}

function mbgMlPerQtyUnit(u) {
    switch (mbgNormUnitStr(u)) {
        case 'ml':
        case 'cc': return 1;
        case 'l':
        case 'lt':
        case 'ltr':
        case 'liter':
        case 'litre': return 1000;
        default: return null;
    }
}

function mbgMaterialUnitCategory(u) {
    const qu = mbgNormUnitStr(u);
    if (mbgGramsPerQtyUnit(qu) != null) return 'mass';
    if (mbgMlPerQtyUnit(qu) != null) return 'volume';
    if (['pcs', 'pc', 'piece', 'pieces', 'buah', 'unit', 'units'].includes(qu)) return 'count';
    return 'unknown';
}

function mbgCountUnitsCompatible(qtyU, priceU) {
    const q = mbgNormUnitStr(qtyU);
    const p = mbgNormUnitStr(priceU);
    if (q === p) return true;
    const piece = ['pcs', 'pc', 'piece', 'pieces', 'buah', 'unit', 'units'];
    return piece.includes(q) && piece.includes(p);
}

/** Qty dalam qtyUnit, harga dinyatakan per priceUnit (beda massa/volume → dikonversi). */
function mbgMaterialEstimatedTotal(qty, qtyUnit, pricePerUnit, priceUnit) {
    const qu = mbgNormUnitStr(qtyUnit);
    let pu = mbgNormUnitStr(priceUnit);
    if (!pu) pu = qu;
    const qCat = mbgMaterialUnitCategory(qu);
    const pCat = mbgMaterialUnitCategory(pu);
    const qn = Number(qty) || 0;
    const pn = Number(pricePerUnit) || 0;
    if (qCat === 'mass' && pCat === 'mass') {
        const gq = mbgGramsPerQtyUnit(qu);
        const gp = mbgGramsPerQtyUnit(pu);
        if (gq != null && gp != null) return qn * (gq / gp) * pn;
    }
    if (qCat === 'volume' && pCat === 'volume') {
        const mq = mbgMlPerQtyUnit(qu);
        const mp = mbgMlPerQtyUnit(pu);
        if (mq != null && mp != null) return qn * (mq / mp) * pn;
    }
    if (qCat === 'count' && pCat === 'count' && mbgCountUnitsCompatible(qu, pu)) {
        return qn * pn;
    }
    return qn * pn;
}

function mbgParseRecipeIngredientsBlob(raw) {
    if (raw == null || raw === '') return [];
    let ingredients = raw;
    try {
        ingredients = typeof raw === 'string' ? JSON.parse(raw) : raw;
    } catch (e) {
        return [];
    }
    const list = Array.isArray(ingredients)
        ? ingredients
        : (Array.isArray(ingredients?.items) ? ingredients.items
            : (Array.isArray(ingredients?.ingredients) ? ingredients.ingredients : []));
    if (!Array.isArray(list)) return [];
    return list.map(ing => ({
        ingredient_id: String(ing?.ingredient_id ?? ing?.ingredientId ?? ing?.id ?? '').trim(),
        qty_per_portion: Number(ing?.quantity_per_portion ?? ing?.qty_per_portion ?? ing?.quantity ?? ing?.qty ?? 0),
        qty_unit: ing?.unit || null
    })).filter(x => x.ingredient_id);
}

