/**
 * Buat (atau kembalikan) draft local_procurement_plans dari plan produksi yang sudah ada
 * (mis. publish War Room tanpa lewat Hitung Material). Menautkan production_plan_id + plans.source_procurement_plan_id.
 */
app.post('/api/procurement/plans/from-production-plan', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
            await mbgEnsureLocalProcurementTables();
            try { await run('ALTER TABLE plans ADD COLUMN war_room_food_id TEXT'); } catch (e) { /* exists */ }
            const productionPlanId = String((req.body || {}).production_plan_id || '').trim();
            if (!productionPlanId) return res.status(400).json({ error: 'production_plan_id wajib' });

            const planRow = await get('SELECT * FROM plans WHERE id = ? AND tenant_id = ?', [productionPlanId, tenantId]);
            if (!planRow) return res.status(404).json({ error: 'Plan produksi tidak ditemukan' });

            const srcProc = String(planRow.source_procurement_plan_id || '').trim();
            if (srcProc) {
                const existingProc = await get('SELECT * FROM local_procurement_plans WHERE id = ? AND tenant_id = ?', [srcProc, tenantId]);
                if (existingProc) {
                    let planDataOut = null;
                    try {
                        planDataOut = existingProc.plan_data ? JSON.parse(existingProc.plan_data) : null;
                    } catch (e) { planDataOut = null; }
                    return res.json({
                        id: existingProc.id,
                        plan_data: planDataOut,
                        already_linked: true,
                        message: 'Plan ini sudah punya pengadaan terkait.'
                    });
                }
            }

            const byProd = await get(
                `SELECT * FROM local_procurement_plans
                 WHERE tenant_id = ? AND production_plan_id = ?
                 ORDER BY datetime(created_at) DESC LIMIT 1`,
                [tenantId, productionPlanId]
            );
            if (byProd) {
                let planDataOut = null;
                try {
                    planDataOut = byProd.plan_data ? JSON.parse(byProd.plan_data) : null;
                } catch (e) { planDataOut = null; }
                if (!srcProc) {
                    try {
                        await run(
                            `UPDATE plans SET source_procurement_plan_id = ? WHERE id = ? AND tenant_id = ? AND (source_procurement_plan_id IS NULL OR TRIM(COALESCE(source_procurement_plan_id,'')) = '')`,
                            [byProd.id, productionPlanId, tenantId]
                        );
                    } catch (e2) { /* ignore */ }
                }
                return res.json({
                    id: byProd.id,
                    plan_data: planDataOut,
                    already_linked: true,
                    message: 'Draft pengadaan sudah ada untuk plan ini.'
                });
            }

            const dels = await all(
                `SELECT id, wave_number, delivery_time, portion_count, service_date
                 FROM order_deliveries
                 WHERE plan_id = ?
                 ORDER BY COALESCE(wave_number, 999) ASC, delivery_time ASC`,
                [productionPlanId]
            ).catch(() => []);

            const waves = [];
            for (const d of dels || []) {
                const pc = Number(d.portion_count) || 0;
                const tt = String(d.delivery_time || '').trim();
                if (pc > 0 && tt) waves.push({ portion_count: pc, target_time: tt });
            }

            if (!waves.length) {
                const tp = Number(planRow.target_portions) || 0;
                const tdt = String(planRow.target_delivery_time || '').trim();
                if (tp > 0 && tdt) {
                    waves.push({ portion_count: tp, target_time: tdt });
                }
            }

            let foodId = String(planRow.war_room_food_id || '').trim();
            if (!foodId) {
                try {
                    const b = await get(
                        `SELECT m.food_id AS food_id FROM batches b
                         JOIN menu m ON m.id = b.menu_item_id
                         WHERE b.plan_id = ? AND TRIM(COALESCE(m.food_id,'')) != ''
                         LIMIT 1`,
                        [productionPlanId]
                    );
                    if (b && b.food_id) foodId = String(b.food_id).trim();
                } catch (e) { /* ignore */ }
            }

            if (!foodId) {
                return res.status(400).json({
                    error: 'Food package tidak terdeteksi',
                    message: 'Plan ini tidak menyimpan food_id War Room. Publish ulang dari War Room setelah pilih Food, atau hubungkan menu batch ke food di Food & Menu.'
                });
            }
            if (!waves.length) {
                return res.status(400).json({
                    error: 'Tidak ada wave delivery',
                    message: 'Plan ini belum punya order_deliveries (wave). Buka detail plan / distribusi lalu pastikan wave delivery ada, atau publish ulang dari War Room.'
                });
            }

            let planDate = '';
            const tdt = String(planRow.target_delivery_time || '').trim();
            if (tdt.length >= 10) planDate = tdt.slice(0, 10);
            if (!planDate && dels && dels[0] && dels[0].service_date) planDate = String(dels[0].service_date).slice(0, 10);
            if (!planDate) planDate = String(waves[0].target_time || '').slice(0, 10);
            if (!/^\d{4}-\d{2}-\d{2}$/.test(planDate)) {
                return res.status(400).json({ error: 'Tanggal plan tidak valid', message: 'Tidak bisa menurunkan plan_date dari plan atau delivery.' });
            }

            const targetPortions = waves.reduce((a, w) => a + (Number(w.portion_count) || 0), 0);
            const planData = {
                food_id: foodId,
                plan_date: planDate,
                production_date: planDate,
                distribution_date: planDate,
                waves
            };

            const newId = crypto.randomUUID();
            const nowIso = new Date().toISOString();
            await run(
                `INSERT INTO local_procurement_plans (id, tenant_id, status, food_id, plan_date, target_portions, plan_data, created_at, production_plan_id)
                 VALUES (?, ?, 'DRAFT', ?, ?, ?, ?, ?, ?)`,
                [newId, tenantId, foodId, planDate, targetPortions, JSON.stringify(planData), nowIso, productionPlanId]
            );
            try {
                await run(
                    `UPDATE plans SET source_procurement_plan_id = ? WHERE id = ? AND tenant_id = ? AND (source_procurement_plan_id IS NULL OR TRIM(COALESCE(source_procurement_plan_id,'')) = '')`,
                    [newId, productionPlanId, tenantId]
                );
            } catch (e3) { /* ignore */ }

            res.json({ id: newId, plan_data: planData, already_linked: false });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

