app.post('/api/procurement/plans/:id/po', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
            await mbgEnsureLocalProcurementTables();
            try { await run('ALTER TABLE plans ADD COLUMN war_room_food_id TEXT'); } catch (e) { /* exists */ }
            const planId = String(req.params.id || '').trim();
            const body = req.body || {};
            const { notes, delivery_deadline } = body;
            let vis = String(body.visibility == null ? 'public' : body.visibility)
                .toLowerCase()
                .trim();
            if (!['public', 'private', 'fixed_price'].includes(vis)) vis = 'public';
            const rawInv = body.invited_supplier_ids;
            const invitedSupplierIds = Array.isArray(rawInv)
                ? rawInv.map(x => String(x || '').trim()).filter(Boolean)
                : [];
            if (vis === 'private' && invitedSupplierIds.length === 0) {
                return res.status(400).json({
                    error: 'PO private membutuhkan minimal satu supplier undangan.',
                    message: 'Pilih satu atau lebih supplier di daftar undangan.',
                });
            }
            if (vis === 'private' && invitedSupplierIds.length) {
                const ph = invitedSupplierIds.map(() => '?').join(',');
                const okRows = await allOnDb(
                    platformDb,
                    `SELECT id FROM portal_suppliers WHERE COALESCE(is_active,0) = 1 AND id IN (${ph})`,
                    invitedSupplierIds
                );
                if (!okRows || okRows.length !== invitedSupplierIds.length) {
                    return res.status(400).json({
                        error: 'Supplier undangan tidak valid',
                        message: 'Pastikan semua supplier terpilih aktif dan terdaftar di portal.',
                    });
                }
            }
            const poId = crypto.randomUUID();
            const poNum = 'PO-' + poId.slice(0, 8).toUpperCase();
            const dl = delivery_deadline ? String(delivery_deadline) : null;
            const createdAtIso = new Date().toISOString();
            await run(
                `INSERT INTO local_purchase_orders (id, plan_id, tenant_id, po_number, visibility, status, notes, delivery_deadline, created_at)
                 VALUES (?, ?, ?, ?, ?, 'OPEN', ?, ?, ?)`,
                [poId, planId, tenantId, poNum, vis, notes || null, dl, createdAtIso]
            );
            await run(
                "UPDATE local_procurement_plans SET status = 'PO_SENT' WHERE id = ? AND tenant_id = ?",
                [planId, tenantId]
            );

            // Buat baris plan produksi (Jobdesc) agar muncul di daftar; posting task dilakukan nanti dari list.
            const procRow = await get('SELECT * FROM local_procurement_plans WHERE id = ? AND tenant_id = ?', [planId, tenantId]);
            let meta = { food_id: '', waves: [], lastDelivery: null, portionsFromWaves: 0 };
            try {
                let o = {};
                if (procRow && procRow.plan_data) {
                    try { o = JSON.parse(procRow.plan_data); } catch (e2) { o = {}; }
                }
                const wavesIn = Array.isArray(o.waves) ? o.waves : [];
                for (const w of wavesIn) {
                    const q = Number(w.portion_count || w.portionCount || 0);
                    const tt = String(w.target_time || w.delivery_datetime || w.delivery_time || '').trim();
                    if (q > 0 && tt) meta.waves.push({ portion_count: q, target_time: tt });
                }
                meta.waves.sort((a, b) => new Date(a.target_time).getTime() - new Date(b.target_time).getTime());
                meta.lastDelivery = meta.waves.length ? meta.waves[meta.waves.length - 1].target_time : null;
                meta.portionsFromWaves = meta.waves.reduce((s, w) => s + w.portion_count, 0);
                meta.food_id = String(o.food_id || procRow?.food_id || '').trim();
            } catch (e3) { /* meta default */ }
            const targetPortions = Number(procRow?.target_portions) > 0 ? Number(procRow.target_portions) : (meta.portionsFromWaves || 0);
            let targetDelivery = meta.lastDelivery;
            if (!targetDelivery && procRow?.plan_date) {
                const d = String(procRow.plan_date).slice(0, 10);
                if (d.length >= 10) targetDelivery = `${d}T12:00:00.000Z`;
            }
            let prodPlanId = null;
            let planCode = null;
            try {
                prodPlanId = crypto.randomUUID();
                planCode = (typeof generateId === 'function') ? generateId('PL') : `PL-${prodPlanId.slice(0, 8)}`;
                const nowIso = new Date().toISOString();
                await run(
                    `INSERT INTO plans (id, code, tenant_id, source_order_id, target_portions, target_delivery_time, status, created_at, source_procurement_plan_id, war_room_food_id)
                     VALUES (?, ?, ?, NULL, ?, ?, 'PO_SENT', ?, ?, ?)`,
                    [prodPlanId, planCode, tenantId, targetPortions || null, targetDelivery || null, nowIso, planId, meta.food_id || null]
                );
                await run(
                    'UPDATE local_procurement_plans SET production_plan_id = ? WHERE id = ? AND tenant_id = ?',
                    [prodPlanId, planId, tenantId]
                );
            } catch (eIns) {
                console.warn('[procurement/po] Gagal membuat plans row:', eIns && eIns.message);
                prodPlanId = null;
                planCode = null;
            }

            let materialsRows = [];
            try {
                materialsRows = await all(
                    'SELECT id, material_name, material_type, quantity_needed, unit FROM local_plan_materials WHERE plan_id = ? AND tenant_id = ?',
                    [planId, tenantId]
                );
            } catch (eMat) {
                materialsRows = [];
            }
            try {
                await mbgMirrorPurchaseOrderToPortal({
                    tenantId,
                    poId,
                    procurementPlanId: planId,
                    poNumber: poNum,
                    visibility: vis,
                    notes: notes || null,
                    deliveryDeadline: dl,
                    createdAtIso,
                    invitedSupplierIds,
                    materialsRows: materialsRows || [],
                });
            } catch (eMir) {
                console.warn('[procurement/po] Gagal mirror ke portal supplier:', eMir && eMir.message);
            }

            res.json({
                id: poId,
                po_number: poNum,
                status: 'OPEN',
                visibility: vis,
                notes: notes || null,
                delivery_deadline: dl,
                production_plan_id: prodPlanId,
                production_plan_code: planCode,
            });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.put('/api/procurement/plans/:id/po/bids/:bidId/review', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
            await mbgEnsureLocalProcurementTables();
            await mbgEnsurePortalSupplyOrderTables();
            const planId = String(req.params.id || '').trim();
            const bidId = String(req.params.bidId || '').trim();
            const decision = String((req.body && req.body.decision) || '').toLowerCase().trim();
            if (!planId || !bidId || !['approve', 'reject'].includes(decision)) {
                return res.status(400).json({ error: 'decision wajib: approve atau reject' });
            }

            const po = await get(
                'SELECT id, visibility FROM local_purchase_orders WHERE plan_id = ? AND tenant_id = ? ORDER BY datetime(created_at) DESC LIMIT 1',
                [planId, tenantId]
            );
            if (!po || !po.id) return res.status(404).json({ error: 'Tidak ada PO untuk plan ini' });

            const vis = String(po.visibility || '').toLowerCase();
            if (vis === 'fixed_price') {
                return res.status(400).json({
                    error: 'PO fixed price',
                    message: 'Pemenang ditentukan lewat Claim di portal supplier, bukan review bid.',
                });
            }

            const portalPo = await getOnDb(
                platformDb,
                'SELECT * FROM portal_supply_orders WHERE id = ? AND tenant_id = ?',
                [po.id, tenantId]
            );
            if (!portalPo) return res.status(404).json({ error: 'PO tidak ditemukan di portal' });

            const bid = await getOnDb(platformDb, 'SELECT * FROM portal_supply_bids WHERE id = ? AND po_id = ?', [bidId, po.id]);
            if (!bid) return res.status(404).json({ error: 'Bid tidak ditemukan' });

            const bidStatus = String(bid.status || '').toLowerCase();
            if (bidStatus !== 'pending') {
                return res.status(400).json({ error: 'Hanya bid berstatus pending yang bisa direview' });
            }

            if (decision === 'reject') {
                await execOnDb(platformDb, `UPDATE portal_supply_bids SET status = 'rejected' WHERE id = ?`, [bidId]);
                return res.json({ ok: true, decision: 'reject', bid_id: bidId });
            }

            const poSt = String(portalPo.status || '').toUpperCase();
            if (poSt !== 'OPEN') {
                return res.status(409).json({ error: 'PO sudah tidak terbuka untuk pemilihan bid' });
            }

            const existingWin = await getOnDb(
                platformDb,
                `SELECT id FROM portal_supply_bids WHERE po_id = ? AND LOWER(TRIM(COALESCE(status,''))) = 'approved' LIMIT 1`,
                [po.id]
            );
            if (existingWin) {
                return res.status(409).json({ error: 'Sudah ada bid yang disetujui untuk PO ini' });
            }

            await execOnDb(platformDb, `UPDATE portal_supply_bids SET status = 'rejected' WHERE po_id = ? AND id != ?`, [po.id, bidId]);
            await execOnDb(platformDb, `UPDATE portal_supply_bids SET status = 'approved' WHERE id = ?`, [bidId]);
            await execOnDb(
                platformDb,
                `UPDATE portal_supply_orders SET status = 'AWARDED', awarded_bid_id = ?, awarded_supplier_id = ? WHERE id = ? AND tenant_id = ?`,
                [bidId, bid.supplier_id, po.id, tenantId]
            );
            await run(`UPDATE local_purchase_orders SET status = 'AWARDED' WHERE id = ? AND tenant_id = ?`, [po.id, tenantId]);

            const bidsOut = await mbgFetchProcurementBidsForTenantPlan(tenantId, planId);
            res.json({
                ok: true,
                decision: 'approve',
                bid_id: bidId,
                awarded_supplier_id: bid.supplier_id,
                bids: bidsOut,
            });
        } catch (e) {
            res.status(500).json({ error: e.message || 'Review bid gagal' });
        }
    });
});

