app.post('/api/procurement/plans/:id/materials/calculate', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
            const planId = String(req.params.id || '').trim();
            const { food_id, total_portions, price_source } = req.body || {};
            const portions = Number(total_portions || 0);
            if (!food_id || portions <= 0) return res.status(400).json({ error: 'food_id and total_portions required' });

            await mbgEnsureLocalProcurementTables();
            const plan = await get('SELECT id FROM local_procurement_plans WHERE id = ? AND tenant_id = ?', [planId, tenantId]);
            if (!plan) return res.status(404).json({ error: 'Procurement plan draft tidak ditemukan' });

            let foodRow = await get('SELECT id, name FROM foods WHERE id = ? AND tenant_id = ?', [String(food_id), tenantId]).catch(() => null);
            if (!foodRow) foodRow = await get('SELECT id, name FROM foods WHERE id = ?', [String(food_id)]).catch(() => null);
            if (!foodRow) {
                return res.status(400).json({ error: 'Food tidak ditemukan', message: `food_id=${food_id} tidak ada di tenant ini.` });
            }

            // Legacy: food_menus (per baris punya food_menu_ingredients). Tenant boleh NULL di data lama.
            let customMenus = [];
            try {
                customMenus = await all(
                    'SELECT * FROM food_menus WHERE food_id = ? AND (tenant_id IS NULL OR TRIM(COALESCE(tenant_id,\'\')) = \'\' OR tenant_id = ?)',
                    [String(food_id), tenantId]
                );
            } catch (e) {
                customMenus = await all('SELECT * FROM food_menus WHERE food_id = ?', [String(food_id)]).catch(() => []);
            }

            // Pivot food_menu_items ↔ menu (banyak baris fmi.tenant_id NULL — jangan wajibkan = tenant aktif).
            let pivotMenus = [];
            try {
                pivotMenus = await all(
                    `SELECT m.id, m.name, r.ingredients AS recipe_ingredients
                     FROM food_menu_items fmi
                     JOIN menu m ON m.id = fmi.menu_id
                     LEFT JOIN recipes r ON r.id = m.recipe_id
                     WHERE fmi.food_id = ?
                       AND (fmi.tenant_id IS NULL OR TRIM(COALESCE(fmi.tenant_id,'')) = '' OR fmi.tenant_id = ?)`,
                    [String(food_id), tenantId]
                );
            } catch (e) {
                pivotMenus = await all(
                    `SELECT m.id, m.name, r.ingredients AS recipe_ingredients
                     FROM food_menu_items fmi
                     JOIN menu m ON m.id = fmi.menu_id
                     LEFT JOIN recipes r ON r.id = m.recipe_id
                     WHERE fmi.food_id = ?`,
                    [String(food_id)]
                ).catch(() => []);
            }

            // Menu yang hanya punya menu.food_id (tanpa baris pivot) — pola umum setelah tautkan di Food & Menu.
            let directFoodMenus = [];
            try {
                directFoodMenus = await all(
                    `SELECT m.id, m.name, r.ingredients AS recipe_ingredients
                     FROM menu m
                     LEFT JOIN recipes r ON r.id = m.recipe_id
                     WHERE m.food_id = ?`,
                    [String(food_id)]
                );
            } catch (e) {
                directFoodMenus = [];
            }

            const recipeMenusById = new Map();
            for (const m of [...pivotMenus, ...directFoodMenus]) {
                const mid = String(m?.id || '').trim();
                if (mid) recipeMenusById.set(mid, m);
            }

            if (!customMenus.length && !recipeMenusById.size) {
                return res.status(400).json({
                    error: 'Food package belum punya menu',
                    message: `Food "${foodRow.name}" tidak punya menu yang terdeteksi. Di Food & Menu, tautkan menu ke Food ini (pivot), atau pastikan kolom menu mengacu ke food ini. Jika baru menambah tautan, simpan lalu hitung ulang.`
                });
            }

            const menuPortions = new Map();
            for (const m of customMenus) {
                const mid = String(m?.id || '').trim();
                if (mid) menuPortions.set(mid, portions);
            }
            for (const mid of recipeMenusById.keys()) menuPortions.set(mid, portions);

            const customMenuIds = (customMenus || []).map(m => m.id).filter(Boolean);
            let ingRows = [];
            if (customMenuIds.length) {
                try {
                    ingRows = await all(
                        `SELECT mi.* FROM food_menu_ingredients mi
                         WHERE (mi.tenant_id IS NULL OR TRIM(COALESCE(mi.tenant_id,'')) = '' OR mi.tenant_id = ?)
                           AND mi.food_menu_id IN (${customMenuIds.map(() => '?').join(',')})`,
                        [tenantId, ...customMenuIds]
                    );
                } catch (e) {
                    ingRows = await all(
                        `SELECT mi.* FROM food_menu_ingredients mi WHERE mi.food_menu_id IN (${customMenuIds.map(() => '?').join(',')})`,
                        [...customMenuIds]
                    ).catch(() => []);
                }
            }
            for (const m of recipeMenusById.values()) {
                const parsed = mbgParseRecipeIngredientsBlob(m.recipe_ingredients);
                for (const ing of parsed) {
                    ingRows.push({
                        food_menu_id: m.id,
                        ingredient_id: ing.ingredient_id,
                        qty_per_portion: ing.qty_per_portion,
                        qty_unit: ing.qty_unit
                    });
                }
            }

            if (!ingRows.length) {
                const nameList = [
                    ...(customMenus || []).map(m => String(m.name || m.id || '')),
                    ...[...recipeMenusById.values()].map(m => String(m.name || m.id || ''))
                ].filter(Boolean);
                const names = nameList.length ? nameList.join(', ') : '(tidak ada nama menu)';
                return res.status(400).json({
                    error: 'Tidak ada ingredient pada menu',
                    message: `Menu belum punya bahan baku (resep / food_menu_ingredients). Cek resep untuk: ${names}`
                });
            }

            const ingredientDemand = {};
            for (const mi of ingRows) {
                const menuPts = Number(menuPortions.get(String(mi.food_menu_id)) || 0);
                const reqQty = Number(mi.qty_per_portion || mi.quantity_per_portion || 0) * menuPts;
                if (!(reqQty > 0) || !mi.ingredient_id) continue;
                const key = String(mi.ingredient_id);
                if (!ingredientDemand[key]) {
                    let ingMeta = await get(
                        'SELECT name, unit, estimated_price FROM ingredients WHERE id = ? AND tenant_id = ?',
                        [key, tenantId]
                    ).catch(() => null);
                    if (!ingMeta) ingMeta = await get('SELECT name, unit, estimated_price FROM ingredients WHERE id = ?', [key]).catch(() => null);
                    ingredientDemand[key] = {
                        ingredient_id: key,
                        name: ingMeta?.name || 'Unknown',
                        unit: ingMeta?.unit || String(mi.qty_unit || '').trim() || 'gram',
                        qty: 0,
                        price: Number(ingMeta?.estimated_price || 0)
                    };
                }
                ingredientDemand[key].qty += reqQty;
            }

            if (!Object.keys(ingredientDemand).length) {
                return res.status(400).json({
                    error: 'Ingredient tidak valid',
                    message: 'Tidak ada quantity bahan > 0; periksa qty per porsi di resep.'
                });
            }

            await run('DELETE FROM local_plan_materials WHERE plan_id = ? AND tenant_id = ?', [planId, tenantId]);

            const results = [];
            const ps = String(price_source || 'database');
            for (const [, d] of Object.entries(ingredientDemand)) {
                let pricePerUnit = 0;
                if (ps === 'database' || ps === 'siskaperbapo') pricePerUnit = d.price;
                const priceUnit = d.unit;
                const estTotal = mbgMaterialEstimatedTotal(d.qty, d.unit, pricePerUnit, priceUnit);
                const matId = crypto.randomUUID();
                await run(
                    `INSERT INTO local_plan_materials (id, plan_id, tenant_id, ingredient_id, material_name, material_type, quantity_needed, unit, estimated_price_per_unit, estimated_total, price_source, price_unit)
                     VALUES (?, ?, ?, ?, ?, 'ingredient', ?, ?, ?, ?, ?, ?)`,
                    [matId, planId, tenantId, d.ingredient_id, d.name, d.qty, d.unit, pricePerUnit, estTotal, ps, priceUnit]
                );
                results.push({
                    id: matId, ingredient_id: d.ingredient_id, material_name: d.name,
                    material_type: 'ingredient', quantity_needed: d.qty, unit: d.unit,
                    price_unit: priceUnit,
                    estimated_price_per_unit: pricePerUnit, estimated_total: estTotal,
                    price_source: ps
                });
            }

            await ensureOperationalMaterialsSchemaInCurrentDb();
            const ops = await all(
                'SELECT id, name, unit, qty_per_portion, estimated_price FROM operational_materials WHERE tenant_id = ? ORDER BY name COLLATE NOCASE',
                [tenantId]
            ).catch(() => []);
            for (const op of ops || []) {
                const qty = (Number(op.qty_per_portion) || 0) * portions;
                const price = ps === 'manual' ? 0 : (Number(op.estimated_price) || 0);
                const u = op.unit || 'pcs';
                const estTotal = mbgMaterialEstimatedTotal(qty, u, price, u);
                const matId = crypto.randomUUID();
                await run(
                    `INSERT INTO local_plan_materials (id, plan_id, tenant_id, ingredient_id, material_name, material_type, quantity_needed, unit, estimated_price_per_unit, estimated_total, price_source, price_unit)
                     VALUES (?, ?, ?, NULL, ?, 'operational', ?, ?, ?, ?, ?, ?)`,
                    [matId, planId, tenantId, op.name, qty, u, price, estTotal, ps, u]
                );
                results.push({
                    id: matId, ingredient_id: null, material_name: op.name,
                    material_type: 'operational', quantity_needed: qty, unit: u,
                    price_unit: u,
                    estimated_price_per_unit: price, estimated_total: estTotal,
                    price_source: ps
                });
            }

            const grandTotal = results.reduce((a, m) => a + (m.estimated_total || 0), 0);
            await run(
                "UPDATE local_procurement_plans SET material_total = ?, status = 'SIMULATED' WHERE id = ? AND tenant_id = ?",
                [grandTotal, planId, tenantId]
            );

            res.json(results);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.put('/api/procurement/plans/:id/materials/:mid', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
            await mbgEnsureLocalProcurementTables();
            const planId = String(req.params.id || '').trim();
            const mid = String(req.params.mid || '').trim();
            const body = req.body || {};
            const price = Number(body.estimated_price_per_unit || 0);
            const mat = await get(
                'SELECT * FROM local_plan_materials WHERE id = ? AND plan_id = ? AND tenant_id = ?',
                [mid, planId, tenantId]
            );
            if (!mat) return res.status(404).json({ error: 'Material not found' });
            const qtyU = String(mat.unit || '').trim() || 'gram';
            let priceUnit;
            if (Object.prototype.hasOwnProperty.call(body, 'price_unit')) {
                const t = String(body.price_unit == null ? '' : body.price_unit).trim();
                priceUnit = t.length ? t : qtyU;
            } else {
                priceUnit = String(mat.price_unit == null ? '' : mat.price_unit).trim() || qtyU;
            }
            const newTotal = mbgMaterialEstimatedTotal(mat.quantity_needed, qtyU, price, priceUnit);
            await run(
                "UPDATE local_plan_materials SET estimated_price_per_unit = ?, estimated_total = ?, price_source = 'manual', price_unit = ? WHERE id = ?",
                [price, newTotal, priceUnit, mid]
            );
            const allMats = await all(
                'SELECT estimated_total FROM local_plan_materials WHERE plan_id = ? AND tenant_id = ?',
                [planId, tenantId]
            );
            const grandTotal = (allMats || []).reduce((a, m) => a + (Number(m.estimated_total) || 0), 0);
            await run(
                'UPDATE local_procurement_plans SET material_total = ? WHERE id = ? AND tenant_id = ?',
                [grandTotal, planId, tenantId]
            );
            res.json({
                id: mid,
                estimated_price_per_unit: price,
                price_unit: priceUnit,
                estimated_total: newTotal,
                plan_material_total: grandTotal
            });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

