async function buildComplianceGuardrails(tenantId) {
    const [staffCountRow, planCountRow, locationCountRow, distCountRow, dailyCountRow] = await Promise.all([
        get("SELECT COUNT(*) AS c FROM staff WHERE tenant_id = ?", [tenantId]),
        get("SELECT COUNT(*) AS c FROM plans WHERE tenant_id = ?", [tenantId]),
        get("SELECT COUNT(*) AS c FROM pm_lokasi WHERE tenant_id = ?", [tenantId]).catch(() => ({ c: 0 })),
        get("SELECT COUNT(*) AS c FROM pm_distribution_events WHERE tenant_id = ?", [tenantId]).catch(() => ({ c: 0 })),
        get("SELECT COUNT(*) AS c FROM daily_reports WHERE tenant_id = ? AND period_type = 'daily'", [tenantId]).catch(() => ({ c: 0 }))
    ]);
    const checks = [
        {
            key: 'staff_master_ready',
            ok: Number(staffCountRow?.c || 0) > 0,
            severity: 'critical',
            detail: `staff=${Number(staffCountRow?.c || 0)}`
        },
        {
            key: 'production_data_ready',
            ok: Number(planCountRow?.c || 0) > 0,
            severity: 'warning',
            detail: `plans=${Number(planCountRow?.c || 0)}`
        },
        {
            key: 'beneficiary_master_ready',
            ok: Number(locationCountRow?.c || 0) > 0,
            severity: 'critical',
            detail: `lokasi=${Number(locationCountRow?.c || 0)}`
        },
        {
            key: 'distribution_evidence_ready',
            ok: Number(distCountRow?.c || 0) > 0,
            severity: 'critical',
            detail: `distribution_events=${Number(distCountRow?.c || 0)}`
        },
        {
            key: 'daily_reporting_ready',
            ok: Number(dailyCountRow?.c || 0) > 0,
            severity: 'warning',
            detail: `daily_reports=${Number(dailyCountRow?.c || 0)}`
        }
    ];
    const hasCriticalFailure = checks.some(c => c.severity === 'critical' && !c.ok);
    const hasWarning = checks.some(c => c.severity === 'warning' && !c.ok);
    return {
        status: hasCriticalFailure ? 'FAIL' : (hasWarning ? 'WARN' : 'PASS'),
        checks
    };
}

