app.get('/api/penerima-manfaat/distribution-events', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        await requireCanonicalRoles(['kepala_sppg', 'asisten_lapangan', 'yayasan', 'admin', 'ahli_gizi'])(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const locationId = String(req.query?.lokasi_id || '').trim();
            const fromDate = String(req.query?.from_date || '').trim();
            const toDate = String(req.query?.to_date || '').trim();
            let sql = `
                SELECT e.*, l.nama AS lokasi_nama
                FROM pm_distribution_events e
                LEFT JOIN pm_lokasi l ON l.id = e.lokasi_id AND l.tenant_id = e.tenant_id
                WHERE e.tenant_id = ?
            `;
            const params = [tenantId];
            if (locationId) {
                sql += ' AND e.lokasi_id = ?';
                params.push(locationId);
            }
            if (fromDate) {
                sql += ' AND e.service_date >= ?';
                params.push(fromDate);
            }
            if (toDate) {
                sql += ' AND e.service_date <= ?';
                params.push(toDate);
            }
            sql += ' ORDER BY e.service_date DESC, e.created_at DESC LIMIT 500';
            const rows = await all(sql, params);
            res.json(rows || []);
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
        });
    });
});

app.post('/api/penerima-manfaat/distribution-events', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        await requireCanonicalRoles(['kepala_sppg', 'asisten_lapangan', 'admin'])(req, res, async () => {
        try {
            await ensureProgramReadySchema();
            const tenantId = getTenantIdFromReq(req);
            const id = crypto.randomUUID();
            const now = new Date().toISOString();
            const b = req.body || {};
            const lokasiId = String(b.lokasi_id || '').trim();
            const serviceDate = String(b.service_date || '').trim();
            if (!lokasiId || !serviceDate) return res.status(400).json({ error: 'lokasi_id dan service_date wajib diisi' });
            const targetPortions = Math.max(0, parseInt(b.target_portions || 0, 10) || 0);
            const servedPortions = Math.max(0, parseInt(b.served_portions || 0, 10) || 0);
            const returnedPortions = Math.max(0, parseInt(b.returned_portions || 0, 10) || 0);
            const evidenceStatus = String(b.evidence_status || 'PENDING').trim().toUpperCase();
            const tempLoad = b.temperature_load_c !== undefined && b.temperature_load_c !== '' && b.temperature_load_c !== null ? Number(b.temperature_load_c) : null;
            const tempDelivery = b.temperature_delivery_c !== undefined && b.temperature_delivery_c !== '' && b.temperature_delivery_c !== null ? Number(b.temperature_delivery_c) : null;
            await run(
                `INSERT INTO pm_distribution_events (
                    id, tenant_id, lokasi_id, plan_id, batch_id, wave_number, service_date,
                    target_portions, served_portions, delivered_at, evidence_status,
                    proof_photo_url, recipient_signature_json, notes, created_at, updated_at,
                    route_id, surat_jalan_id, surat_jalan_no, driver_staff_id, vehicle_id,
                    departed_at, temperature_load_c, temperature_delivery_c,
                    sla_window_start, sla_window_end, returned_portions, individu_served_json
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                [
                    id,
                    tenantId,
                    lokasiId,
                    b.plan_id ? String(b.plan_id) : null,
                    b.batch_id ? String(b.batch_id) : null,
                    parseInt(b.wave_number || 0, 10) || 0,
                    serviceDate,
                    targetPortions,
                    servedPortions,
                    b.delivered_at ? String(b.delivered_at) : null,
                    evidenceStatus,
                    b.proof_photo_url ? String(b.proof_photo_url) : null,
                    b.recipient_signature_json ? JSON.stringify(b.recipient_signature_json) : null,
                    b.notes ? String(b.notes) : '',
                    now,
                    now,
                    b.route_id ? String(b.route_id) : null,
                    b.surat_jalan_id ? String(b.surat_jalan_id) : null,
                    b.surat_jalan_no ? String(b.surat_jalan_no) : null,
                    b.driver_staff_id ? String(b.driver_staff_id) : null,
                    b.vehicle_id ? String(b.vehicle_id) : null,
                    b.departed_at ? String(b.departed_at) : null,
                    tempLoad,
                    tempDelivery,
                    b.sla_window_start ? String(b.sla_window_start) : null,
                    b.sla_window_end ? String(b.sla_window_end) : null,
                    returnedPortions,
                    b.individu_served ? JSON.stringify(b.individu_served) : null
                ]
            );
            const row = await get("SELECT * FROM pm_distribution_events WHERE id = ? AND tenant_id = ?", [id, tenantId]);
            await writeComplianceAudit(req, {
                action: 'distribution_event.create',
                entity_type: 'pm_distribution_events',
                entity_id: id,
                after: row,
                meta: { period: row?.service_date || null }
            });
            res.json(row);
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
        });
    });
});

