app.get('/api/penerima-manfaat/distribution-summary', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const fromDate = String(req.query?.from_date || '').trim();
            const toDate = String(req.query?.to_date || '').trim();
            let where = 'WHERE tenant_id = ?';
            const params = [tenantId];
            if (fromDate) {
                where += ' AND service_date >= ?';
                params.push(fromDate);
            }
            if (toDate) {
                where += ' AND service_date <= ?';
                params.push(toDate);
            }
            const agg = await get(
                `SELECT
                    COUNT(*) AS total_events,
                    COALESCE(SUM(target_portions), 0) AS target_portions,
                    COALESCE(SUM(served_portions), 0) AS served_portions,
                    COALESCE(SUM(CASE WHEN UPPER(COALESCE(evidence_status,'')) IN ('VERIFIED','SIGNED') THEN 1 ELSE 0 END), 0) AS verified_events,
                    COALESCE(SUM(CASE WHEN delivered_at IS NOT NULL THEN 1 ELSE 0 END), 0) AS delivered_events
                 FROM pm_distribution_events
                 ${where}`,
                params
            );
            const target = Number(agg?.target_portions || 0);
            const served = Number(agg?.served_portions || 0);
            const totalEvents = Number(agg?.total_events || 0);
            const verifiedEvents = Number(agg?.verified_events || 0);
            const deliveredEvents = Number(agg?.delivered_events || 0);
            res.json({
                total_events: totalEvents,
                target_portions: target,
                served_portions: served,
                beneficiary_coverage_rate: target > 0 ? served / target : 0,
                evidence_verification_rate: totalEvents > 0 ? verifiedEvents / totalEvents : 0,
                on_time_distribution_rate: totalEvents > 0 ? deliveredEvents / totalEvents : 0
            });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

// ====================================================================
// DISTRIBUSI v2: kalender libur per lokasi + distribusi per-hari (wave)
// ====================================================================

function computeDefaultPortionsForLokasi(l) {
    if (!l || typeof l !== 'object') return 0;
    const n = (v) => {
        const x = parseInt(v || 0, 10);
        return Number.isFinite(x) && x > 0 ? x : 0;
    };
    const murid = n(l.jumlah_murid) || n(l.jumlah_siswa) || (n(l.kelas_1_3) + n(l.kelas_4_6));
    const extras = n(l.balita) + n(l.ibu_hamil) + n(l.ibu_menyusui);
    const pj = n(l.pj_porsi_besar);
    return murid + extras + pj;
}

