app.post('/api/penerima-manfaat/holidays', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        await requireCanonicalRoles(['kepala_sppg', 'asisten_lapangan', 'admin'])(req, res, async () => {
        try {
            await ensureProgramReadySchema();
            const tenantId = getTenantIdFromReq(req);
            const b = req.body || {};
            const lokasiId = String(b.lokasi_id || '').trim();
            const date = String(b.date || '').trim();
            const reason = String(b.reason || '').trim();
            if (!lokasiId || !/^\d{4}-\d{2}-\d{2}$/.test(date)) {
                return res.status(400).json({ error: 'lokasi_id dan date (YYYY-MM-DD) wajib' });
            }
            const existing = await get(
                "SELECT id FROM pm_lokasi_holidays WHERE tenant_id = ? AND lokasi_id = ? AND date = ?",
                [tenantId, lokasiId, date]
            );
            if (existing) {
                await run("UPDATE pm_lokasi_holidays SET reason = ? WHERE id = ?", [reason, existing.id]);
                const row = await get("SELECT * FROM pm_lokasi_holidays WHERE id = ?", [existing.id]);
                return res.json(row);
            }
            const id = crypto.randomUUID();
            const now = new Date().toISOString();
            await run(
                "INSERT INTO pm_lokasi_holidays (id, tenant_id, lokasi_id, date, reason, created_at) VALUES (?, ?, ?, ?, ?, ?)",
                [id, tenantId, lokasiId, date, reason, now]
            );
            const row = await get("SELECT * FROM pm_lokasi_holidays WHERE id = ?", [id]);
            res.json(row);
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
        });
    });
});

