// --- Distribusi: ringkasan 1 hari -----------------------------------------
async function loadDistribusiDay(tenantId, date) {
    await ensureProgramReadySchema();
    await ensureProductionLibrarySchemaInCurrentDb();

    const lokasiRows = await all(
        "SELECT * FROM pm_lokasi WHERE tenant_id = ? ORDER BY nama ASC",
        [tenantId]
    ) || [];
    const holidayRows = await all(
        "SELECT lokasi_id, date, reason FROM pm_lokasi_holidays WHERE tenant_id = ? AND date = ?",
        [tenantId, date]
    ) || [];
    const holidaySet = new Map(holidayRows.map(h => [String(h.lokasi_id), h.reason || '']));

    // Cari plan aktif di tanggal tsb (1 hari 1 plan — ambil plan terbaru di tgl tsb).
    let plan = await get(
        `SELECT * FROM plans
         WHERE tenant_id = ? AND substr(COALESCE(target_delivery_time, ''), 1, 10) = ?
         ORDER BY created_at DESC
         LIMIT 1`,
        [tenantId, date]
    );

    // Wave dari plan (order_deliveries)
    let planWaves = [];
    if (plan) {
        planWaves = await all(
            "SELECT id, wave_number, delivery_time, portion_count FROM order_deliveries WHERE plan_id = ? ORDER BY wave_number ASC, delivery_time ASC",
            [plan.id]
        ) || [];
    }
    // Fallback: ada order_deliveries manual tanpa plan (user bikin distribusi tanpa plan War Room).
    const manualWaves = await all(
        `SELECT id, wave_number, delivery_time, portion_count
         FROM order_deliveries
         WHERE tenant_id = ? AND service_date = ? AND (plan_id IS NULL OR plan_id = '')
         ORDER BY wave_number ASC, delivery_time ASC`,
        [tenantId, date]
    ) || [];

    const waves = [];
    for (const w of planWaves) {
        waves.push({
            id: w.id,
            wave_number: Number(w.wave_number) || (waves.length + 1),
            delivery_time: w.delivery_time || null,
            portion_count: Number(w.portion_count) || 0,
            source: 'plan'
        });
    }
    for (const w of manualWaves) {
        waves.push({
            id: w.id,
            wave_number: Number(w.wave_number) || (waves.length + 1),
            delivery_time: w.delivery_time || null,
            portion_count: Number(w.portion_count) || 0,
            source: 'manual'
        });
    }
    // Renumber supaya rapi 1..N
    waves.sort((a, b) => (a.wave_number - b.wave_number) || String(a.delivery_time || '').localeCompare(String(b.delivery_time || '')));
    waves.forEach((w, i) => { w.wave_number = i + 1; });

    // Assignments = pm_distribution_events untuk tanggal tsb
    const events = await all(
        `SELECT id, lokasi_id, wave_number, target_portions, served_portions, delivered_at,
                evidence_status, menu_item_id, menu_item_name, wave_delivery_time, notes,
                proof_photo_url, recipient_signature_json, returned_portions, driver_staff_id
         FROM pm_distribution_events
         WHERE tenant_id = ? AND service_date = ?
         ORDER BY wave_number ASC, lokasi_id ASC`,
        [tenantId, date]
    ) || [];
    const assignments = events.map(e => ({
        event_id: e.id,
        lokasi_id: e.lokasi_id,
        wave_number: Number(e.wave_number) || 0,
        target_portions: Number(e.target_portions) || 0,
        served_portions: Number(e.served_portions) || 0,
        delivered_at: e.delivered_at || null,
        evidence_status: e.evidence_status || 'PENDING',
        menu_item_id: e.menu_item_id || null,
        menu_item_name: e.menu_item_name || null,
        wave_delivery_time: e.wave_delivery_time || null,
        notes: e.notes || '',
        driver_staff_id: e.driver_staff_id ? String(e.driver_staff_id) : null
    }));

    const lokasiOut = lokasiRows.map(l => {
        const defPortions = computeDefaultPortionsForLokasi(l);
        return {
            id: l.id,
            nama: l.nama,
            jenis: l.jenis || '',
            alamat: l.alamat || '',
            default_portions: defPortions,
            jumlah_murid: Number(l.jumlah_murid) || 0,
            jumlah_siswa: Number(l.jumlah_siswa) || 0,
            kelas_1_3: Number(l.kelas_1_3) || 0,
            kelas_4_6: Number(l.kelas_4_6) || 0,
            balita: Number(l.balita) || 0,
            ibu_hamil: Number(l.ibu_hamil) || 0,
            ibu_menyusui: Number(l.ibu_menyusui) || 0,
            pj_porsi_besar: Number(l.pj_porsi_besar) || 0,
            is_holiday: holidaySet.has(String(l.id)),
            holiday_reason: holidaySet.get(String(l.id)) || ''
        };
    });

    return {
        date,
        plan: plan ? {
            id: plan.id,
            code: plan.code,
            target_portions: Number(plan.target_portions) || 0,
            target_delivery_time: plan.target_delivery_time || null,
            status: plan.status || null
        } : null,
        waves,
        lokasi: lokasiOut,
        assignments,
        holidays: holidayRows
    };
}

