/**
 * Meta cetak Surat Jalan: profil SPPG dari kitchen_config (Setup Dapur → Profil SPPG)
 * + penandatangan dari staff & user pengelola.
 */
app.get('/api/distribusi/surat-jalan-meta', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            let trow = await getOnDb(platformDb, 'SELECT name FROM tenants WHERE id = ?', [tenantId]).catch(() => null);
            if (!trow || !trow.name) {
                trow = await get('SELECT name FROM tenants WHERE id = ?', [tenantId]).catch(() => null);
            }
            const tenantName = String(trow && trow.name ? trow.name : '').trim();

            let kcfg = {};
            try {
                const krow = await get("SELECT config FROM kitchen_config WHERE id = '1'").catch(() => null);
                kcfg = parseKitchenConfigRow(krow);
            } catch (e) {
                kcfg = {};
            }
            const prof = kcfg && typeof kcfg.sppg_profile === 'object' ? kcfg.sppg_profile : {};
            const namaSppg = String(
                kcfg.kitchen_name || kcfg.name || prof.nama_sppg || ''
            ).trim();
            let sppgLine = '';
            if (/^sppg\b/i.test(namaSppg)) sppgLine = namaSppg.toUpperCase();
            else if (namaSppg) sppgLine = ('SPPG ' + namaSppg).toUpperCase();
            else if (/^sppg\b/i.test(tenantName)) sppgLine = tenantName.toUpperCase();
            else if (tenantName) sppgLine = ('SPPG ' + tenantName).toUpperCase();
            else sppgLine = 'SPPG';

            const logoRaw = kcfg.logo_data_url || prof.logo_data_url || '';
            const sppg_profile = {
                nama_sppg: namaSppg,
                sppg_id: String(kcfg.sppg_id != null && kcfg.sppg_id !== '' ? kcfg.sppg_id : (prof.id_sppg || '')).trim(),
                alamat: String(kcfg.address != null ? kcfg.address : (prof.alamat || '')).trim(),
                telepon: String(kcfg.contact_phone || kcfg.contact || prof.telepon || '').trim(),
                email: String(kcfg.contact_email || prof.email || '').trim(),
                tagline: String(kcfg.kitchen_tagline != null ? kcfg.kitchen_tagline : (prof.tagline || '')).trim(),
                logo_data_url: sanitizeKitchenLogoDataUrl(logoRaw)
            };

            const firstStaffName = async (role) => {
                const rows = await all(
                    "SELECT name FROM staff WHERE tenant_id = ? AND LOWER(TRIM(COALESCE(role,''))) = ? ORDER BY name ASC LIMIT 1",
                    [tenantId, String(role || '').toLowerCase().trim()]
                ).catch(() => []);
                return rows && rows[0] && rows[0].name ? String(rows[0].name).trim() : '';
            };
            const firstUserName = async (role) => {
                const rows = await all(
                    "SELECT name FROM users WHERE tenant_id = ? AND LOWER(TRIM(COALESCE(role,''))) = ? ORDER BY name ASC LIMIT 1",
                    [tenantId, String(role || '').toLowerCase().trim()]
                ).catch(() => []);
                return rows && rows[0] && rows[0].name ? String(rows[0].name).trim() : '';
            };

            let ahliGiziDapur = await firstStaffName('ahli_gizi');
            if (!ahliGiziDapur) ahliGiziDapur = await firstUserName('ahli_gizi');

            let koordinatorLapangan = await firstStaffName('asisten_lapangan');
            if (!koordinatorLapangan) koordinatorLapangan = await firstUserName('asisten_lapangan');
            if (!koordinatorLapangan) koordinatorLapangan = await firstStaffName('koordinator_divisi');
            if (!koordinatorLapangan) koordinatorLapangan = await firstUserName('koordinator_divisi');

            let kepalaSppg = await firstUserName('kepala_sppg');
            if (!kepalaSppg) kepalaSppg = await firstStaffName('kepala_sppg');

            res.json({
                sppg_line: sppgLine,
                sppg_profile: sppg_profile,
                tenant_name: tenantName,
                ahli_gizi_dapur: ahliGiziDapur,
                koordinator_lapangan: koordinatorLapangan,
                kepala_sppg: kepalaSppg
            });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

app.get('/api/distribusi/period', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const from = String(req.query?.from || '').trim();
            const to = String(req.query?.to || '').trim();
            if (!/^\d{4}-\d{2}-\d{2}$/.test(from) || !/^\d{4}-\d{2}-\d{2}$/.test(to)) {
                return res.status(400).json({ error: 'from dan to (YYYY-MM-DD) wajib' });
            }
            await ensureProgramReadySchema();
            await ensureProductionLibrarySchemaInCurrentDb();

            const plans = await all(
                `SELECT id, code, target_portions, target_delivery_time, status,
                        substr(COALESCE(target_delivery_time, ''), 1, 10) AS service_date
                 FROM plans
                 WHERE tenant_id = ?
                   AND substr(COALESCE(target_delivery_time, ''), 1, 10) BETWEEN ? AND ?
                 ORDER BY target_delivery_time ASC`,
                [tenantId, from, to]
            ) || [];
            const planByDate = {};
            for (const p of plans) {
                if (!planByDate[p.service_date]) planByDate[p.service_date] = p;
            }

            const waves = await all(
                `SELECT wave_number, delivery_time, portion_count, plan_id, service_date
                 FROM order_deliveries
                 WHERE tenant_id = ? AND service_date BETWEEN ? AND ?
                 ORDER BY service_date ASC, wave_number ASC`,
                [tenantId, from, to]
            ) || [];
            const wavesByDate = {};
            for (const w of waves) {
                const d = w.service_date;
                if (!d) continue;
                (wavesByDate[d] = wavesByDate[d] || []).push(w);
            }

            const events = await all(
                `SELECT service_date, wave_number, lokasi_id, target_portions, served_portions, evidence_status, delivered_at
                 FROM pm_distribution_events
                 WHERE tenant_id = ? AND service_date BETWEEN ? AND ?`,
                [tenantId, from, to]
            ) || [];
            const eventsByDate = {};
            for (const e of events) {
                (eventsByDate[e.service_date] = eventsByDate[e.service_date] || []).push(e);
            }

            const holidays = await all(
                `SELECT lokasi_id, date, reason
                 FROM pm_lokasi_holidays
                 WHERE tenant_id = ? AND date BETWEEN ? AND ?`,
                [tenantId, from, to]
            ) || [];
            const holidaysByDate = {};
            for (const h of holidays) {
                (holidaysByDate[h.date] = holidaysByDate[h.date] || []).push(h);
            }

            // Build hari-by-hari
            const out = [];
            const start = new Date(from + 'T00:00:00Z');
            const end = new Date(to + 'T00:00:00Z');
            for (let d = new Date(start); d <= end; d.setUTCDate(d.getUTCDate() + 1)) {
                const dateStr = d.toISOString().slice(0, 10);
                const evs = eventsByDate[dateStr] || [];
                const ws = wavesByDate[dateStr] || [];
                const hs = holidaysByDate[dateStr] || [];
                const dayOfWeek = d.getUTCDay();
                out.push({
                    date: dateStr,
                    day_of_week: dayOfWeek,
                    plan: planByDate[dateStr] || null,
                    wave_count: ws.length,
                    total_portion_plan: ws.reduce((a, w) => a + (Number(w.portion_count) || 0), 0),
                    assignment_count: evs.length,
                    distinct_lokasi_assigned: new Set(evs.map(e => e.lokasi_id)).size,
                    served_portions: evs.reduce((a, e) => a + (Number(e.served_portions) || 0), 0),
                    target_portions: evs.reduce((a, e) => a + (Number(e.target_portions) || 0), 0),
                    verified_events: evs.filter(e => ['VERIFIED', 'SIGNED'].includes(String(e.evidence_status || '').toUpperCase())).length,
                    delivered_events: evs.filter(e => !!e.delivered_at).length,
                    holiday_count: hs.length,
                    holiday_lokasi_ids: hs.map(h => h.lokasi_id)
                });
            }
            res.json({ from, to, days: out });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

app.put('/api/distribusi/day', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        await requireCanonicalRoles(['kepala_sppg', 'asisten_lapangan', 'admin'])(req, res, async () => {
        try {
            await ensureProgramReadySchema();
            await ensureProductionLibrarySchemaInCurrentDb();
            const tenantId = getTenantIdFromReq(req);
            const b = req.body || {};
            const date = String(b.date || '').trim();
            if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
                return res.status(400).json({ error: 'date (YYYY-MM-DD) wajib' });
            }
            const wavesIn = Array.isArray(b.waves) ? b.waves : [];
            if (wavesIn.length > 3) {
                return res.status(400).json({ error: 'Maksimum 3 wave per hari' });
            }

            // Cari plan aktif untuk tanggal tsb (opsional; bila ada semua wave terkait plan itu)
            const plan = await get(
                `SELECT * FROM plans
                 WHERE tenant_id = ? AND substr(COALESCE(target_delivery_time, ''), 1, 10) = ?
                 ORDER BY created_at DESC
                 LIMIT 1`,
                [tenantId, date]
            );
            const planId = plan ? plan.id : null;

            // Validasi: satu lokasi hanya boleh di 1 wave
            const seenLokasi = new Set();
            for (const w of wavesIn) {
                const lokasi = Array.isArray(w?.lokasi_ids) ? w.lokasi_ids : [];
                for (const lid of lokasi) {
                    const key = String(lid || '').trim();
                    if (!key) continue;
                    if (seenLokasi.has(key)) {
                        return res.status(400).json({ error: `Lokasi ${key} ditetapkan di lebih dari 1 wave` });
                    }
                    seenLokasi.add(key);
                }
            }

            // Ambil lokasi detail utk default portions
            const lokasiRows = await all(
                "SELECT * FROM pm_lokasi WHERE tenant_id = ?",
                [tenantId]
            ) || [];
            const lokasiById = new Map(lokasiRows.map(l => [String(l.id), l]));

            // Ambil holiday hari itu — lokasi libur tidak boleh di-assign
            const holidayRows = await all(
                "SELECT lokasi_id FROM pm_lokasi_holidays WHERE tenant_id = ? AND date = ?",
                [tenantId, date]
            ) || [];
            const holidaySet = new Set(holidayRows.map(h => String(h.lokasi_id)));
            for (const w of wavesIn) {
                const lokasi = Array.isArray(w?.lokasi_ids) ? w.lokasi_ids : [];
                for (const lid of lokasi) {
                    if (holidaySet.has(String(lid))) {
                        return res.status(400).json({ error: `Lokasi ${lid} sedang libur pada ${date}; hapus tanda libur dulu untuk meng-assign.` });
                    }
                }
            }

            const now = new Date().toISOString();

            // 1) Replace order_deliveries utk tanggal ini + plan ini
            //    Hapus yang belong ke (tenant, service_date) – semua karena kita rekonstruksi ulang.
            await run(
                `DELETE FROM order_deliveries WHERE tenant_id = ? AND service_date = ?`,
                [tenantId, date]
            );

            const waveRecords = [];
            let waveNo = 0;
            for (const w of wavesIn) {
                waveNo += 1;
                const wid = crypto.randomUUID();
                const dt = String(w?.delivery_time || '').trim();
                const lokasiIds = Array.isArray(w?.lokasi_ids) ? w.lokasi_ids.map(x => String(x).trim()).filter(Boolean) : [];
                const lokasiPortions = (w && typeof w.lokasi_portions === 'object' && w.lokasi_portions) ? w.lokasi_portions : {};
                // portion_count = sum override/default
                let portionTotal = 0;
                const perLokasi = [];
                for (const lid of lokasiIds) {
                    const loc = lokasiById.get(String(lid));
                    if (!loc) continue;
                    let portions = Number(lokasiPortions[lid]);
                    if (!Number.isFinite(portions) || portions < 0) portions = computeDefaultPortionsForLokasi(loc);
                    perLokasi.push({ lokasi_id: lid, portions: Math.round(portions) });
                    portionTotal += Math.round(portions);
                }
                await run(
                    `INSERT INTO order_deliveries (id, order_id, delivery_time, portion_count, status, lokasi_id, wave_number, plan_id, tenant_id, service_date)
                     VALUES (?, ?, ?, ?, 'PENDING', NULL, ?, ?, ?, ?)`,
                    [wid, planId || null, dt, portionTotal, waveNo, planId, tenantId, date]
                );
                waveRecords.push({ wave_number: waveNo, delivery_time: dt, perLokasi, portionTotal });
            }

            // 2) Upsert pm_distribution_events.
            //    Ambil event existing: yang tidak di-assign lagi → hanya hapus bila belum delivered & status PENDING.
            const existingEvents = await all(
                `SELECT * FROM pm_distribution_events
                 WHERE tenant_id = ? AND service_date = ?`,
                [tenantId, date]
            ) || [];
            const existingByKey = new Map();
            for (const ev of existingEvents) {
                existingByKey.set(`${ev.lokasi_id}`, ev);
            }

            const newAssignmentKeys = new Set();
            for (const wr of waveRecords) {
                for (const pair of wr.perLokasi) {
                    const key = `${pair.lokasi_id}`;
                    newAssignmentKeys.add(key);
                    const prev = existingByKey.get(key);
                    if (prev) {
                        // update wave + target portions + delivery_time snapshot — jangan sentuh served/evidence jika sudah delivered.
                        await run(
                            `UPDATE pm_distribution_events
                             SET wave_number = ?, target_portions = ?, wave_delivery_time = ?, plan_id = ?, updated_at = ?
                             WHERE id = ? AND tenant_id = ?`,
                            [wr.wave_number, pair.portions, wr.delivery_time || null, planId || null, now, prev.id, tenantId]
                        );
                    } else {
                        await run(
                            `INSERT INTO pm_distribution_events (
                                id, tenant_id, lokasi_id, plan_id, batch_id, wave_number, service_date,
                                target_portions, served_portions, delivered_at, evidence_status,
                                proof_photo_url, recipient_signature_json, notes, created_at, updated_at,
                                wave_delivery_time
                             ) VALUES (?, ?, ?, ?, NULL, ?, ?, ?, 0, NULL, 'PENDING', NULL, NULL, '', ?, ?, ?)`,
                            [crypto.randomUUID(), tenantId, pair.lokasi_id, planId || null, wr.wave_number, date, pair.portions, now, now, wr.delivery_time || null]
                        );
                    }
                }
            }

            // Delete events yang tidak di-assign lagi, asalkan belum delivered dan status PENDING.
            for (const ev of existingEvents) {
                if (newAssignmentKeys.has(`${ev.lokasi_id}`)) continue;
                const locked = !!ev.delivered_at || ['VERIFIED', 'SIGNED'].includes(String(ev.evidence_status || '').toUpperCase());
                if (locked) {
                    // Tidak kami hapus; biarkan (mungkin user keliru unassign lokasi yang sudah terkirim).
                    continue;
                }
                await run("DELETE FROM pm_distribution_events WHERE id = ? AND tenant_id = ?", [ev.id, tenantId]);
            }

            try {
                await writeComplianceAudit(req, {
                    action: 'distribusi.day.update',
                    entity_type: 'pm_distribution_events',
                    entity_id: date,
                    after: { date, waves: waveRecords.length, total_assignments: newAssignmentKeys.size },
                    meta: { period: date }
                });
            } catch (e) { }

            const data = await loadDistribusiDay(tenantId, date);
            res.json({ success: true, ...data });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
        });
    });
});

// --- AUTH ---
app.get('/auth/dev/status', async (_req, res) => {
    if (!DEV_AUTH_ENABLED) return res.status(404).json({ error: 'Not found' });
    try {
        const row = await get("SELECT COUNT(*) as count FROM platform_users");
        res.json({ setup_required: (row?.count || 0) === 0 });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

app.post('/auth/dev/setup', rateLimit(5, 60 * 1000), async (req, res) => {
    if (!DEV_AUTH_ENABLED) return res.status(404).json({ error: 'Not found' });
    const { email, password, name } = req.body || {};
    try {
        const row = await get("SELECT COUNT(*) as count FROM platform_users");
        if ((row?.count || 0) > 0) return res.status(409).json({ error: 'Setup already completed' });
        if (!email || !password) return res.status(400).json({ error: 'Missing email/password' });
        if (!isEmail(email)) return res.status(400).json({ error: 'Invalid email' });
        if (String(password).length < 6) return res.status(400).json({ error: 'Password too short' });
        const id = crypto.randomUUID();
        const now = new Date().toISOString();
        const ph = await hashPassword(password);
        await run(
            `INSERT INTO platform_users (id, email, name, role, password_hash, created_at, last_login_at, disabled_at)
             VALUES (?, ?, ?, 'developer', ?, ?, NULL, NULL)`,
            [id, String(email).toLowerCase(), name || 'Developer', ph, now]
        );
        res.json({ success: true });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

app.post('/auth/dev/login', rateLimit(10, 60 * 1000), async (req, res) => {
    if (!DEV_AUTH_ENABLED) return res.status(404).json({ error: 'Not found' });
    const { email, password } = req.body || {};
    const ip = (req.headers['x-forwarded-for'] || req.socket.remoteAddress || '').toString();
    try {
        if (!email || !password) return res.status(400).json({ error: 'Missing email/password' });
        if (!isEmail(email)) return res.status(400).json({ error: 'Invalid email' });
        const u = await get("SELECT * FROM platform_users WHERE email = ?", [String(email).toLowerCase()]);
        if (!u || u.disabled_at) {
            await run("INSERT INTO login_attempts (id, at, ip, email, success, reason) VALUES (?, ?, ?, ?, 0, ?)", [crypto.randomUUID(), new Date().toISOString(), ip, String(email).toLowerCase(), 'USER_NOT_FOUND']);
            return res.status(401).json({ error: 'Invalid credentials' });
        }
        const ok = await verifyPassword(password, u.password_hash);
        await run("INSERT INTO login_attempts (id, at, ip, email, success, reason) VALUES (?, ?, ?, ?, ?, ?)", [crypto.randomUUID(), new Date().toISOString(), ip, String(email).toLowerCase(), ok ? 1 : 0, ok ? 'OK' : 'BAD_PASSWORD']);
        if (!ok) return res.status(401).json({ error: 'Invalid credentials' });
        const token = await createSession({ actor_type: 'platform', actor_id: u.id, tenant_id: null, role: u.role, ttlSeconds: 60 * 60 * 12 });
        await run("UPDATE platform_users SET last_login_at = ? WHERE id = ?", [new Date().toISOString(), u.id]);
        res.json({ token, user: { email: u.email, role: u.role, name: u.name } });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

app.post('/auth/logout', async (req, res) => {
    try {
        const s = await getSessionFromReq(req);
        if (!s) return res.status(401).json({ error: 'Unauthorized' });
        const now = new Date().toISOString();
        await run("UPDATE sessions SET revoked_at = ? WHERE id = ?", [now, s.id]);
        res.json({ success: true });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

app.post('/auth/register', rateLimit(10, 60 * 1000), async (req, res) => {
    const { email, password, name, phone, address } = req.body;

    try {
        if (!email || !password) return res.status(400).json({ error: 'Missing email/password' });
        if (!isEmail(email)) return res.status(400).json({ error: 'Invalid email' });
        if (String(password).length < 6) return res.status(400).json({ error: 'Password too short' });
        const existing = await get("SELECT id FROM tenants WHERE contact_email = ?", [email]);
        if (existing) return res.status(400).json({ error: 'Email already registered' });

        const id = crypto.randomUUID();
        const endAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString();
        const ph = await hashPassword(password);

        await run(`INSERT INTO tenants (id, name, status, subscription_plan, plan_type, subscription_end_at, address, contact_email, contact_phone, password_hash) 
                   VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
            [id, name || 'New Tenant', 'PENDING_APPROVAL', 'FREE', 'TRIAL', endAt, address || '', String(email).toLowerCase(), phone || '', ph]);

        res.json({ success: true, message: 'Registration successful. Waiting for approval.' });
    } catch (e) {
        console.error(e);
        res.status(500).json({ error: e.message });
    }
});

app.post('/auth/signup', rateLimit(10, 60 * 1000), async (req, res) => {
    const { tenant_name, email, password } = req.body || {};
    try {
        const tn = String(tenant_name || '').trim();
        const em = String(email || '').trim().toLowerCase();
        const pw = String(password || '');

        if (!tn || !em || !pw) return res.status(400).json({ error: 'Missing tenant_name/email/password' });
        if (!isEmail(em)) return res.status(400).json({ error: 'Invalid email' });
        if (pw.length < 6) return res.status(400).json({ error: 'Password too short' });

        const existing = await get("SELECT id FROM tenants WHERE contact_email = ?", [em]);
        if (existing) return res.status(409).json({ error: 'Email already registered' });

        const id = crypto.randomUUID();
        const now = new Date();
        const endAt = new Date(now.getTime() + 14 * 24 * 60 * 60 * 1000).toISOString();
        const ph = await hashPassword(pw);

        await run(
            `INSERT INTO tenants (id, name, status, subscription_plan, plan_type, subscription_end_at, address, contact_email, contact_phone, password_hash)
             VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
            [id, tn, 'ACTIVE', 'TRIAL', 'TRIAL', endAt, '', em, '', ph]
        );

        const planRow = await get("SELECT code FROM subscription_plans WHERE code = ?", ['TRIAL']).catch(() => null);
        if (planRow) {
            await run(
                `INSERT INTO tenant_subscriptions (id, tenant_id, plan_code, status, current_period_start, current_period_end, cancel_at_period_end, canceled_at, grace_end_at, created_at, updated_at)
                 VALUES (?, ?, ?, ?, ?, ?, 0, NULL, NULL, ?, ?)`,
                [crypto.randomUUID(), id, 'TRIAL', 'TRIALING', now.toISOString(), endAt, now.toISOString(), now.toISOString()]
            ).catch(() => { });
        }

        const roleKey = normalizeRoleKey('kepala_sppg', 'tenant');
        const token = await createSession({ actor_type: 'tenant', actor_id: id, tenant_id: id, role: roleKey, ttlSeconds: 60 * 60 * 24 });
        const sub = await getActiveSubscription(id);
        res.json({
            token,
            tenant_id: id,
            user: { email: em, role: roleKey, role_key: roleKey, role_scope: MBG_ROLE_CANONICAL[roleKey]?.scope || 'operational_lead' },
            subscription: sub.subscription,
            plan: sub.plan,
            subscription_state: sub.state
        });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

app.post('/auth/login', rateLimit(15, 60 * 1000), async (req, res) => {
    const { email, password } = req.body;

    try {
        if (!email || !password) return res.status(400).json({ error: 'Missing email/password' });
        if (!isEmail(email)) return res.status(400).json({ error: 'Invalid email' });
        const t = await get("SELECT * FROM tenants WHERE contact_email = ?", [String(email).toLowerCase()]);
        if (!t) {
            return res.status(404).json({ error: 'Account not found' });
        }

        const ok = await verifyPassword(password, t.password_hash);
        if (!ok) {
            return res.status(401).json({ error: 'Invalid password' });
        }
        if (t.password_hash && !isScryptHash(t.password_hash)) {
            const upgraded = await hashPassword(password);
            await run("UPDATE tenants SET password_hash = ? WHERE id = ?", [upgraded, t.id]);
        }

        if (t.status === 'PENDING_APPROVAL') {
            return res.status(403).json({ error: 'Account is pending approval from administrator.' });
        }

        const sub = await getActiveSubscription(t.id);
        const roleKey = normalizeRoleKey('kepala_sppg', 'tenant');
        const token = await createSession({ actor_type: 'tenant', actor_id: t.id, tenant_id: t.id, role: roleKey, ttlSeconds: 60 * 60 * 24 });
        res.json({
            token,
            tenant_id: t.id,
            user: { email, role: roleKey, role_key: roleKey, role_scope: MBG_ROLE_CANONICAL[roleKey]?.scope || 'operational_lead' },
            subscription: sub.subscription,
            plan: sub.plan,
            subscription_state: sub.state
        });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

app.post('/auth/forgot-password', rateLimit(10, 60 * 1000), async (req, res) => {
    const { email, tenant_id } = req.body || {};
    try {
        const em = String(email || '').trim().toLowerCase();
        const tid = String(tenant_id || '').trim();
        if (!em) return res.status(400).json({ error: 'Missing email' });
        if (!isEmail(em)) return res.status(400).json({ error: 'Invalid email' });

        let actor = null;
        if (tid) {
            actor = await get("SELECT id FROM users WHERE tenant_id = ? AND email = ? LIMIT 1", [tid, em])
                .then(r => r ? ({ actor_type: 'user', actor_id: r.id }) : null)
                .catch(() => null);
        }
        if (!actor) {
            const t = await get("SELECT id FROM tenants WHERE contact_email = ? LIMIT 1", [em]).catch(() => null);
            actor = t ? { actor_type: 'tenant', actor_id: t.id } : null;
        }

        const now = new Date();
        const expiresAt = new Date(now.getTime() + 60 * 60 * 1000).toISOString();
        const token = base64url(crypto.randomBytes(32));
        const tokenHash = sha256Hex(token);

        if (actor) {
            await run(
                `INSERT INTO password_resets (id, actor_type, actor_id, token_hash, expires_at, used_at, created_at)
                 VALUES (?, ?, ?, ?, ?, NULL, ?)`,
                [crypto.randomUUID(), actor.actor_type, actor.actor_id, tokenHash, expiresAt, now.toISOString()]
            );
        }

        const debug = (String(process.env.SHOW_RESET_TOKEN || '').trim().toLowerCase() === 'true') || String(req.headers.host || '').includes('localhost');
        if (debug && actor) {
            return res.json({ success: true, reset_token: token });
        }
        res.json({ success: true });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

app.post('/auth/reset-password', rateLimit(10, 60 * 1000), async (req, res) => {
    const { token, password } = req.body || {};
    try {
        const tk = String(token || '').trim();
        const pw = String(password || '');
        if (!tk || !pw) return res.status(400).json({ error: 'Missing token/password' });
        if (pw.length < 6) return res.status(400).json({ error: 'Password too short' });

        const tokenHash = sha256Hex(tk);
        const nowIso = new Date().toISOString();
        const row = await get(
            `SELECT * FROM password_resets WHERE token_hash = ? AND used_at IS NULL AND expires_at > ? LIMIT 1`,
            [tokenHash, nowIso]
        );
        if (!row) return res.status(400).json({ error: 'Token invalid/expired' });

        const ph = await hashPassword(pw);
        if (row.actor_type === 'tenant') {
            await run("UPDATE tenants SET password_hash = ? WHERE id = ?", [ph, row.actor_id]);
        } else if (row.actor_type === 'user') {
            await run("UPDATE users SET password_hash = ? WHERE id = ?", [ph, row.actor_id]);
        }
        await run("UPDATE password_resets SET used_at = ? WHERE id = ?", [nowIso, row.id]);
        res.json({ success: true });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

app.post('/auth/staff/login', rateLimit(20, 60 * 1000), async (req, res) => {
    const { tenant_id, email, password } = req.body;

    try {
        if (!tenant_id || !email || !password) return res.status(400).json({ error: 'Missing tenant/email/password' });
        if (!isEmail(email)) return res.status(400).json({ error: 'Invalid email' });
        // 1. Find Tenant
        let t = await get("SELECT * FROM tenants WHERE id = ? OR name = ?", [tenant_id, tenant_id]);
        if (!t) {
            console.log('[AUTH] Staff login: Tenant not found:', tenant_id);
            return res.status(404).json({ error: 'Kitchen/Tenant not found' });
        }

        // 2. Find Staff in that Tenant
        const user = await get("SELECT * FROM users WHERE tenant_id = ? AND email = ?", [t.id, email]);
        if (!user) {
            return res.status(404).json({ error: 'Staff email not found in this kitchen' });
        }

        // 3. Check Password
        const ok = await verifyPassword(password, user.password_hash);
        if (!ok) {
            return res.status(401).json({ error: 'Invalid password' });
        }
        if (user.password_hash && !isScryptHash(user.password_hash)) {
            const upgraded = await hashPassword(password);
            await run("UPDATE users SET password_hash = ? WHERE id = ?", [upgraded, user.id]);
        }

        const roleKey = normalizeRoleKey(user.role, 'staff');

        // Kebijakan SOP: Koordinator Divisi dan Relawan WAJIB login via Portal Relawan (staff.html)
        // menggunakan Kode Staff + PIN (atau face recognition). Tidak diperbolehkan login ke
        // portal pengelola dengan email+password.
        if (RELAWAN_ONLY_ROLES.has(roleKey)) {
            return res.status(403).json({
                error: 'Akun dengan role Koordinator Divisi / Relawan wajib login melalui Portal Relawan (staff.html) dengan Kode Staff + PIN, bukan via portal pengelola.'
            });
        }

        const sub = await getActiveSubscription(t.id);
        const token = await createSession({ actor_type: 'staff', actor_id: user.id, tenant_id: t.id, role: roleKey, ttlSeconds: 60 * 60 * 24 });
        res.json({
            token,
            tenant_id: t.id,
            user: {
                email: user.email,
                name: user.name,
                role: roleKey,
                role_key: roleKey,
                role_scope: MBG_ROLE_CANONICAL[roleKey]?.scope || 'administration',
                division_id: user.division_id
            },
            subscription: sub.subscription,
            plan: sub.plan,
            subscription_state: sub.state
        });

    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

app.post('/auth/staff/code-login', rateLimit(30, 60 * 1000), async (req, res) => {
    const { tenant_id, staff_code, pin } = req.body || {};
    try {
        const tid = String(tenant_id || '').trim();
        const code = String(staff_code || '').trim();
        const p = String(pin || '').trim();
        if (!tid || !code || !p) return res.status(400).json({ error: 'Missing tenant_id/staff_code/pin' });

        const tidNorm = tid.toLowerCase();
        const tidCompact = tidNorm.replace(/\s+/g, '');
        let t = await get(
            "SELECT * FROM tenants WHERE id = ? OR name = ? OR LOWER(TRIM(COALESCE(name,''))) = ? OR LOWER(REPLACE(COALESCE(name,''), ' ', '')) = ?",
            [tid, tid, tidNorm, tidCompact]
        ).catch(() => null);
        if (!t && tid === 'default') {
            t = { id: 'default', name: 'default', status: 'ACTIVE' };
        }
        if (!t) return res.status(404).json({ error: 'Kitchen/Tenant not found' });
        if (t.status && t.status !== 'ACTIVE' && t.status !== 'PRO') {
            return res.status(403).json({ error: 'Kitchen is not active' });
        }

        // Staff disimpan di SQLite per-tenant (bukan di platform DB). Tanpa konteks tenant, query sebelumnya selalu gagal.
        const staff = await withTenantDatabase(t.id, async () => {
            const schemaKey = `tenant:${t.id}`;
            if (!staffSchemaReadyKeys.has(schemaKey)) {
                await ensureStaffSchemaInCurrentDb();
                staffSchemaReadyKeys.add(schemaKey);
            }
            return await get(
                "SELECT id, tenant_id, name, role, division_id, staff_code, pin_hash FROM staff WHERE tenant_id = ? AND staff_code = ?",
                [t.id, code]
            );
        });
        if (!staff) return res.status(404).json({ error: 'Kode staff tidak ditemukan' });
        if (!staff.pin_hash) return res.status(403).json({ error: 'PIN belum diset. Hubungi admin.' });

        const ok = await verifyPassword(p, staff.pin_hash);
        if (!ok) return res.status(401).json({ error: 'PIN salah' });
        if (staff.pin_hash && !isScryptHash(staff.pin_hash)) {
            const upgraded = await hashPassword(p);
            await withTenantDatabase(t.id, async () => {
                await run("UPDATE staff SET pin_hash = ? WHERE id = ?", [upgraded, staff.id]);
            });
        }

        const roleKey = normalizeRoleKey(staff.role || 'admin', 'staff');
        const token = await createSession({ actor_type: 'staff', actor_id: staff.id, tenant_id: t.id, role: roleKey, ttlSeconds: 60 * 60 * 12 });
        res.json({
            token,
            tenant_id: t.id,
            staff: {
                id: staff.id,
                name: staff.name,
                role: roleKey,
                role_key: roleKey,
                role_scope: MBG_ROLE_CANONICAL[roleKey]?.scope || 'administration',
                division_id: staff.division_id || ''
            }
        });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

