app.post('/api/subscription/subscribe', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = req.auth.actor_type === 'platform' ? (req.headers['x-tenant-id'] || null) : req.auth.tenant_id;
            if (!tenantId) return res.status(400).json({ error: 'Missing tenant scope' });
            // Manual approval flow: only platform/dev/admin can force-activate subscriptions.
            // Tenants must use /api/subscription/request.
            if (req.auth.actor_type !== 'platform') return res.status(403).json({ error: 'Forbidden' });

            const planCode = String(req.body.plan_code || '').toUpperCase().trim();
            if (!planCode) return res.status(400).json({ error: 'Missing plan_code' });
            const plan = await get("SELECT * FROM subscription_plans WHERE code = ? AND is_active = 1", [planCode]);
            if (!plan) return res.status(400).json({ error: 'Invalid plan_code' });
            parseJson(plan, ['features', 'limits']);

            const now = new Date();
            const days = Number(plan?.limits?.days || 30);
            const end = new Date(now.getTime() + (Number.isFinite(days) ? days : 30) * 24 * 60 * 60 * 1000);
            const status = (planCode === 'TRIAL') ? 'TRIALING' : 'ACTIVE';

            await run(
                `INSERT INTO tenant_subscriptions (id, tenant_id, plan_code, status, current_period_start, current_period_end, cancel_at_period_end, canceled_at, grace_end_at, created_at, updated_at)
                 VALUES (?, ?, ?, ?, ?, ?, 0, NULL, NULL, ?, ?)`,
                [crypto.randomUUID(), tenantId, planCode, status, now.toISOString(), end.toISOString(), now.toISOString(), now.toISOString()]
            );

            await run("UPDATE tenants SET plan_type = ?, subscription_end_at = ? WHERE id = ?", [planCode, end.toISOString(), tenantId]);

            const sub = await getActiveSubscription(tenantId);
            res.json({ subscription: sub.subscription, plan: sub.plan, state: sub.state });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

// --- MANUAL SUBSCRIPTION APPROVAL ---
// Tenants create a request, platform/dev/admin approves it.
app.post('/api/subscription/request', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            if (req.auth.actor_type !== 'tenant') return res.status(403).json({ error: 'Forbidden' });

            const tenantId = req.auth.tenant_id;
            if (!tenantId) return res.status(400).json({ error: 'Missing tenant scope' });

            const planCode = String(req.body.plan_code || '').toUpperCase().trim();
            if (!planCode) return res.status(400).json({ error: 'Missing plan_code' });

            const plan = await get("SELECT * FROM subscription_plans WHERE code = ? AND is_active = 1", [planCode]);
            if (!plan) return res.status(400).json({ error: 'Invalid plan_code' });
            parseJson(plan, ['features', 'limits']);

            const existingPending = await get(
                `SELECT * FROM subscription_requests
                 WHERE tenant_id = ? AND status = 'PENDING'
                 ORDER BY requested_at DESC
                 LIMIT 1`,
                [tenantId]
            );
            if (existingPending) {
                return res.json({ request: existingPending });
            }

            const now = new Date().toISOString();
            const id = crypto.randomUUID();
            await run(
                `INSERT INTO subscription_requests
                 (id, tenant_id, plan_code, status, requested_at, decided_at, decided_by, note)
                 VALUES (?, ?, ?, 'PENDING', ?, NULL, NULL, ?)`,
                [id, tenantId, planCode, now, req.body.note ? String(req.body.note) : null]
            );

            const created = await get("SELECT * FROM subscription_requests WHERE id = ?", [id]);
            res.json({ request: created || { id, tenant_id: tenantId, plan_code: planCode, status: 'PENDING', requested_at: now } });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

