app.post('/api/admin/subscription-plans', async (req, res) => {
    await requirePlatform(['developer', 'admin'])(req, res, async () => {
        try {
            const now = new Date().toISOString();
            const code = String(req.body.code || '').toUpperCase().trim();
            const name = String(req.body.name || '').trim();
            if (!code || !name) return res.status(400).json({ error: 'Missing code/name' });
            const existing = await get("SELECT code FROM subscription_plans WHERE code = ?", [code]);
            if (existing) return res.status(409).json({ error: 'Plan code already exists' });
            await run(
                `INSERT INTO subscription_plans (code, name, currency, price_monthly, is_active, features, limits, created_at, updated_at)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                [
                    code,
                    name,
                    String(req.body.currency || 'IDR'),
                    Number.isFinite(req.body.price_monthly) ? req.body.price_monthly : parseInt(req.body.price_monthly || 0, 10),
                    req.body.is_active === 0 ? 0 : 1,
                    JSON.stringify(req.body.features || {}),
                    JSON.stringify(req.body.limits || {}),
                    now,
                    now
                ]
            );
            const plan = await get("SELECT * FROM subscription_plans WHERE code = ?", [code]);
            parseJson(plan, ['features', 'limits']);
            res.json(plan);
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

app.put('/api/admin/subscription-plans/:code', async (req, res) => {
    await requirePlatform(['developer', 'admin'])(req, res, async () => {
        try {
            const code = String(req.params.code || '').toUpperCase().trim();
            const existing = await get("SELECT * FROM subscription_plans WHERE code = ?", [code]);
            if (!existing) return res.status(404).json({ error: 'Not Found' });
            const now = new Date().toISOString();
            const newName = req.body.name !== undefined ? String(req.body.name) : existing.name;
            const newCurrency = req.body.currency !== undefined ? String(req.body.currency) : existing.currency;
            const newPrice = req.body.price_monthly !== undefined ? parseInt(req.body.price_monthly || 0, 10) : existing.price_monthly;
            const newActive = req.body.is_active !== undefined ? (req.body.is_active ? 1 : 0) : existing.is_active;
            const newFeatures = req.body.features !== undefined ? JSON.stringify(req.body.features || {}) : existing.features;
            const newLimits = req.body.limits !== undefined ? JSON.stringify(req.body.limits || {}) : existing.limits;
            await run(
                `UPDATE subscription_plans SET name = ?, currency = ?, price_monthly = ?, is_active = ?, features = ?, limits = ?, updated_at = ? WHERE code = ?`,
                [newName, newCurrency, newPrice, newActive, newFeatures, newLimits, now, code]
            );
            const plan = await get("SELECT * FROM subscription_plans WHERE code = ?", [code]);
            parseJson(plan, ['features', 'limits']);
            res.json(plan);
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

