/**
 * Guard manajemen User Pengelola: HANYA Kepala SPPG (tenant owner yang login via
 * /auth/login, atau sub-user yang role-nya 'kepala_sppg') yang boleh read/write
 * tabel `users`. Akun Kepala SPPG pertama per tenant di-provision oleh dev saat
 * pendaftaran tenant. Role lain (admin sub-user, akuntan, dsb) tidak punya
 * kewenangan membuat/menghapus akun login pengelola.
 *
 * Platform developer tetap diizinkan lewat (actor_type='platform') untuk
 * kebutuhan support & provisioning awal.
 */
const requirePortalUserAdmin = () => requireCanonicalRoles(['kepala_sppg']);

app.get('/api/users', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
      await requirePortalUserAdmin()(req, res, async () => {
        const tId = req.headers['x-tenant-id'];
        try {
            let rows;
            if (tId && tId !== 'null' && tId !== 'undefined') {
                rows = await all(
                    "SELECT id, email, name, role, tenant_id, division_id FROM users WHERE tenant_id = ? ORDER BY name, email",
                    [tId]
                );
            } else {
                rows = await all("SELECT id, email, name, role, tenant_id, division_id FROM users ORDER BY name, email");
            }
            res.json(rows);
        } catch (e) {
            console.error(e);
            res.status(500).json({ error: e.message });
        }
      });
    });
});

app.post('/api/users', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
      await requirePortalUserAdmin()(req, res, async () => {
        const tId = req.headers['x-tenant-id'];
        const newUser = { id: crypto.randomUUID(), ...req.body };

        if (!newUser.tenant_id && tId && tId !== 'null') {
            newUser.tenant_id = tId;
        }

        try {
            const emailRaw = String(newUser.email || '').trim().toLowerCase();
            const nameRaw = String(newUser.name || '').trim();
            const roleRaw = String(newUser.role || '').trim();
            if (!emailRaw || !isEmail(emailRaw)) {
                return res.status(400).json({ error: 'Email tidak valid' });
            }
            if (!nameRaw) {
                return res.status(400).json({ error: 'Nama wajib diisi' });
            }
            const roleKey = normalizeRoleKey(roleRaw, 'staff');
            if (RELAWAN_ONLY_ROLES.has(roleKey)) {
                return res.status(400).json({
                    error: 'Role Koordinator Divisi / Relawan tidak boleh didaftarkan di User Pengelola. Gunakan menu Staff (Portal Relawan).'
                });
            }
            if (!MBG_ROLE_CANONICAL[roleKey]) {
                return res.status(400).json({ error: `Role tidak dikenal: ${roleRaw}` });
            }

            const duplicate = await get(
                "SELECT id FROM users WHERE LOWER(TRIM(email)) = ? AND (tenant_id = ? OR (tenant_id IS NULL AND ? IS NULL))",
                [emailRaw, newUser.tenant_id || null, newUser.tenant_id || null]
            );
            if (duplicate) {
                return res.status(409).json({ error: 'Email sudah terdaftar di tenant ini.' });
            }

            const password = newUser.password || '123456';
            const ph = await hashPassword(String(password));
            await run(
                "INSERT INTO users (id, email, name, role, tenant_id, password_hash, division_id) VALUES (?, ?, ?, ?, ?, ?, ?)",
                [newUser.id, emailRaw, nameRaw, roleKey, newUser.tenant_id || null, ph, newUser.division_id || null]
            );
            res.json({ id: newUser.id, email: emailRaw, name: nameRaw, role: roleKey, tenant_id: newUser.tenant_id || null, division_id: newUser.division_id || null });
        } catch (e) { res.status(500).json({ error: e.message }); }
      });
    });
});

app.put('/api/users/:id', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
      await requirePortalUserAdmin()(req, res, async () => {
        try {
            const tId = getTenantIdFromReq(req);
            const userId = req.params.id;
            const { email, name, role, division_id, password } = req.body || {};

            const existing = await get(
                "SELECT id, email, role, tenant_id FROM users WHERE id = ? AND (tenant_id = ? OR ? IS NULL)",
                [userId, tId || null, tId || null]
            );
            if (!existing) return res.status(404).json({ error: 'User tidak ditemukan' });

            const emailRaw = email != null ? String(email).trim().toLowerCase() : existing.email;
            const nameRaw = name != null ? String(name).trim() : null;
            const roleRaw = role != null ? String(role).trim() : existing.role;

            if (!emailRaw || !isEmail(emailRaw)) {
                return res.status(400).json({ error: 'Email tidak valid' });
            }
            const roleKey = normalizeRoleKey(roleRaw, 'staff');
            if (RELAWAN_ONLY_ROLES.has(roleKey)) {
                return res.status(400).json({
                    error: 'Role Koordinator Divisi / Relawan tidak boleh di-assign di User Pengelola.'
                });
            }
            if (!MBG_ROLE_CANONICAL[roleKey]) {
                return res.status(400).json({ error: `Role tidak dikenal: ${roleRaw}` });
            }

            if (emailRaw !== existing.email) {
                const dup = await get(
                    "SELECT id FROM users WHERE LOWER(TRIM(email)) = ? AND id != ? AND (tenant_id = ? OR (tenant_id IS NULL AND ? IS NULL))",
                    [emailRaw, userId, existing.tenant_id || null, existing.tenant_id || null]
                );
                if (dup) return res.status(409).json({ error: 'Email sudah dipakai user lain di tenant ini.' });
            }

            if (password) {
                const ph = await hashPassword(String(password));
                await run(
                    "UPDATE users SET email = ?, name = COALESCE(?, name), role = ?, division_id = ?, password_hash = ? WHERE id = ?",
                    [emailRaw, nameRaw, roleKey, division_id != null ? String(division_id).trim() || null : null, ph, userId]
                );
            } else {
                await run(
                    "UPDATE users SET email = ?, name = COALESCE(?, name), role = ?, division_id = ? WHERE id = ?",
                    [emailRaw, nameRaw, roleKey, division_id != null ? String(division_id).trim() || null : null, userId]
                );
            }
            res.json({ success: true });
        } catch (e) { res.status(500).json({ error: e.message }); }
      });
    });
});

app.delete('/api/users/:id', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
      await requirePortalUserAdmin()(req, res, async () => {
        try {
            const tId = getTenantIdFromReq(req);
            const userId = req.params.id;
            const existing = await get(
                "SELECT id, role, email, tenant_id FROM users WHERE id = ? AND (tenant_id = ? OR ? IS NULL)",
                [userId, tId || null, tId || null]
            );
            if (!existing) return res.status(404).json({ error: 'User tidak ditemukan' });

            // Safety: larang menghapus diri sendiri agar tenant tidak kehilangan akses login
            // Kepala SPPG. Kalau self-delete diperlukan, harus via tenant flow (misal arsip).
            if (req.auth && req.auth.actor_type === 'staff' && req.auth.actor_id === userId) {
                return res.status(400).json({ error: 'Tidak bisa menghapus akun Anda sendiri.' });
            }

            // Safety: jangan hapus kepala_sppg terakhir di tenant (selain tenant owner yang ada di
            // tabel tenants). Jika user ini kepala_sppg dan merupakan satu-satunya sub-user kepala_sppg,
            // biarkan tenant owner tetap akses, tapi kita hindari kondisi aneh.
            if (normalizeRoleKey(existing.role, 'staff') === 'kepala_sppg') {
                const othersCount = await get(
                    "SELECT COUNT(*) as c FROM users WHERE tenant_id = ? AND id != ? AND LOWER(COALESCE(role,'')) = 'kepala_sppg'",
                    [existing.tenant_id || null, userId]
                );
                if (Number(othersCount?.c || 0) === 0) {
                    console.warn(`[USER DELETE] Menghapus Kepala SPPG terakhir (sub-user) di tenant ${existing.tenant_id}. Tenant owner (tenants table) tetap punya akses.`);
                }
            }

            await run("DELETE FROM users WHERE id = ?", [userId]);
            res.json({ success: true });
        } catch (e) { res.status(500).json({ error: e.message }); }
      });
    });
});

