app.get('/api/dashboard/stats', async (req, res) => {
    try {
        const now = new Date().toISOString().split('T')[0]; // YYYY-MM-DD

        // Active Batches (simplification: total batches in plans that are not archived/completed?)
        // For now, let's count batches where end_time > now
        const activeBatches = await get("SELECT COUNT(*) as count FROM batches WHERE end_time > ?", [new Date().toISOString()]);

        // Low Stock (hardcoded threshold < 50 for demo)
        const lowStock = await get("SELECT COUNT(*) as count FROM inventory WHERE quantity < 50");

        // Today's Production
        const todayProd = await get("SELECT SUM(batch_size) as total FROM batches WHERE start_time LIKE ?", [`${now}%`]);

        // Monthly Expenses
        const currentMonth = now.substring(0, 7); // YYYY-MM
        const expenses = await get("SELECT SUM(amount) as total FROM transactions WHERE date LIKE ?", [`${currentMonth}%`]);

        res.json({
            active_batches: activeBatches.count,
            low_stock_items: lowStock.count,
            today_production: todayProd.total || 0,
            month_expenses: expenses.total || 0
        });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

