app.put('/api/tenants/:id', async (req, res) => {
    await requirePlatform(['developer', 'admin'])(req, res, async () => {
        try {
            const { name, status, plan_type, subscription_end_at, address, contact_email, contact_phone, password } = req.body;

            // 1. Get existing to prevent overwriting with null
            const existing = await get("SELECT * FROM tenants WHERE id = ?", [req.params.id]);
            if (!existing) return res.status(404).json({ error: 'Tenant not found' });

            const newName = name !== undefined ? name : existing.name;
            const newStatus = status !== undefined ? status : existing.status;
            const newPlan = plan_type !== undefined ? plan_type : existing.plan_type;
            const newEnd = subscription_end_at !== undefined ? subscription_end_at : existing.subscription_end_at;
            const newAddr = address !== undefined ? address : existing.address;
            let newEmail = contact_email !== undefined ? String(contact_email).toLowerCase() : existing.contact_email;
            const newPhone = contact_phone !== undefined ? contact_phone : existing.contact_phone;

            if (contact_email !== undefined) {
                if (!isEmail(newEmail)) return res.status(400).json({ error: 'Invalid email' });
                const dup = await get("SELECT id FROM tenants WHERE contact_email = ? AND id != ?", [newEmail, req.params.id]);
                if (dup) return res.status(409).json({ error: 'Email already registered' });
            }

            let newPasswordHash = existing.password_hash;
            if (password !== undefined && String(password).trim() !== '') {
                const pw = String(password || '');
                if (pw.length < 6) return res.status(400).json({ error: 'Password too short' });
                newPasswordHash = await hashPassword(pw);
            }

            await run(
                `UPDATE tenants
             SET name=?, status=?, plan_type=?, subscription_end_at=?, address=?, contact_email=?, contact_phone=?, password_hash=?
             WHERE id=?`,
                [newName, newStatus, newPlan, newEnd, newAddr, newEmail, newPhone, newPasswordHash, req.params.id]
            );

            const t = await get("SELECT * FROM tenants WHERE id = ?", [req.params.id]);
            res.json(t);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

