// --- ACTIVATION ---
app.post('/api/tenants/activate', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const key = req.body.key;
        const tId = req.headers['x-tenant-id'];
        const hwid = req.body.hwid;

        if (!hwid || !tId) return res.status(400).json({ error: 'Missing params' });

        try {
            const hwidHash = sha256Hex(hwid);
            const revoked = await get("SELECT id FROM device_activations WHERE tenant_id = ? AND hwid_hash = ? AND revoked_at IS NOT NULL", [tId, hwidHash]);
            if (revoked) return res.status(403).json({ error: 'Device revoked' });
            const k = await get("SELECT * FROM licenses WHERE key_code = ?", [key]);
            if (!k) return res.status(400).json({ error: 'Invalid key' });

            if (k.status === 'USED' && k.used_by !== tId) {
                return res.status(403).json({ error: 'Key used by another tenant' });
            }

            const t = await get("SELECT * FROM tenants WHERE id = ?", [tId]);
            if (!t) return res.status(404).json({ error: 'Tenant not found' });

            let bound_devices = [];
            try { bound_devices = JSON.parse(k.bound_devices || '[]'); } catch (e) { }

            const isBound = bound_devices.includes(hwid);
            let newly_bound = false;
            let days_added = 0;

            if (!isBound) {
                if (bound_devices.length >= 5) {
                    return res.status(403).json({ error: 'Device limit reached (Max 5)' });
                }
                bound_devices.push(hwid);
                newly_bound = true;

                if (k.status === 'UNUSED') {
                    const now = new Date();
                    const currentEnd = new Date(t.subscription_end_at).getTime() > now.getTime() ?
                        new Date(t.subscription_end_at).getTime() : now.getTime();
                    const newEnd = new Date(currentEnd + (k.days * 24 * 60 * 60 * 1000)).toISOString();

                    await run("UPDATE tenants SET subscription_end_at = ?, plan_type = 'PRO' WHERE id = ?", [newEnd, tId]);
                    await run(
                        `INSERT INTO tenant_subscriptions (id, tenant_id, plan_code, status, current_period_start, current_period_end, cancel_at_period_end, canceled_at, grace_end_at, created_at, updated_at)
                     VALUES (?, ?, 'PRO', 'ACTIVE', ?, ?, 0, NULL, NULL, ?, ?)`,
                        [crypto.randomUUID(), tId, now.toISOString(), newEnd, now.toISOString(), now.toISOString()]
                    );
                    await run("UPDATE licenses SET status = 'USED', used_by = ?, activated_at = ? WHERE key_code = ?", [tId, now.toISOString(), key]);

                    t.subscription_end_at = newEnd;
                    t.plan_type = 'PRO';
                    days_added = k.days;
                }
                // Always update devices
                await run("UPDATE licenses SET bound_devices = ? WHERE key_code = ?", [JSON.stringify(bound_devices), key]);
                await upsertDeviceActivation({ tenantId: tId, hwid, licenseKey: key });
            }

            res.json({
                success: true,
                added_days: days_added,
                newly_bound: newly_bound,
                device_bound: true,
                devices_used: bound_devices.length,
                devices_max: 5,
                plan_type: t.plan_type,
                expires: t.subscription_end_at
            });
        } catch (e) {
            console.error(e);
            res.status(500).json({ error: e.message });
        }
    });
});

