app.post('/api/admin/activation-requests/:id/approve', async (req, res) => {
    await requirePlatform(['developer', 'admin'])(req, res, async () => {
        try {
            const r = await get("SELECT * FROM activation_requests WHERE id = ?", [req.params.id]);
            if (!r) return res.status(404).json({ error: 'Request not found' });
            if (r.status !== 'PENDING') return res.status(400).json({ error: 'Request not pending' });

            const key = `MBG-${crypto.randomBytes(2).toString('hex').toUpperCase()}-${crypto.randomBytes(2).toString('hex').toUpperCase()}`;
            const now = new Date().toISOString();

            // Create License
            await run(`INSERT INTO licenses (key_code, days, status, generated_at, used_by, bound_devices, activated_at)
                   VALUES (?, ?, 'USED', ?, ?, ?, ?)`,
                [key, r.plan_duration, now, r.tenant_id, JSON.stringify([r.hwid]), now]);

            // Update Request
            await run("UPDATE activation_requests SET status = 'APPROVED', license_key = ?, approved_at = ? WHERE id = ?", [key, now, r.id]);

            // Update Tenant
            const t = await get("SELECT * FROM tenants WHERE id = ?", [r.tenant_id]);
            const currentEnd = new Date(t.subscription_end_at).getTime() > Date.now() ?
                new Date(t.subscription_end_at).getTime() : Date.now();
            const newEnd = new Date(currentEnd + (r.plan_duration * 24 * 60 * 60 * 1000)).toISOString();

            await run("UPDATE tenants SET subscription_end_at = ?, plan_type = 'PRO' WHERE id = ?", [newEnd, r.tenant_id]);
            await run(
                `INSERT INTO tenant_subscriptions (id, tenant_id, plan_code, status, current_period_start, current_period_end, cancel_at_period_end, canceled_at, grace_end_at, created_at, updated_at)
             VALUES (?, ?, 'PRO', 'ACTIVE', ?, ?, 0, NULL, NULL, ?, ?)`,
                [crypto.randomUUID(), r.tenant_id, now, newEnd, now, now]
            );
            await upsertDeviceActivation({ tenantId: r.tenant_id, hwid: r.hwid, licenseKey: key });

            res.json({ success: true, key });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

