// --- KITCHEN CONFIG (Protected Updates) ---

/** Logo SPPG: hanya data URL gambar aman; batas ukuran agar SQLite tidak membengkak. */
function sanitizeKitchenLogoDataUrl(raw) {
    const s = String(raw == null ? '' : raw).trim();
    if (!s) return '';
    if (!/^data:image\/(png|jpeg|jpg|gif|webp);base64,/i.test(s)) return '';
    if (s.length > 1800000) return '';
    return s;
}

function parseKitchenConfigRow(row) {
    if (!row || !row.config) return {};
    try {
        return typeof row.config === 'object' ? row.config : JSON.parse(row.config);
    } catch (e) {
        return {};
    }
}

app.put('/api/kitchen/config', async (req, res) => {
    try {
        let existing = {};
        try {
            const row = await get("SELECT config FROM kitchen_config WHERE id = '1'");
            existing = parseKitchenConfigRow(row);
        } catch (e) {
            existing = {};
        }

        const body = req.body && typeof req.body === 'object' ? req.body : {};
        const divisions = Array.isArray(body.divisions)
            ? body.divisions.map(d => {
                if (!d || !d.id) return null;
                return {
                    id: String(d.id),
                    name: String(d.name || d.id),
                    capabilities: Array.isArray(d.capabilities) ? d.capabilities.map(String) : [],
                    max_parallel_batches: Number.isFinite(Number(d.max_parallel_batches)) ? Math.max(1, Number(d.max_parallel_batches)) : 1,
                    notes: typeof d.notes === 'string' ? d.notes : ''
                };
            }).filter(Boolean)
            : (Array.isArray(existing.divisions) ? existing.divisions : []);
        const custom_capabilities = Array.isArray(body.custom_capabilities)
            ? body.custom_capabilities
                .map(c => (c && c.id) ? { id: String(c.id).trim(), label: String(c.label || c.id).trim(), description: String(c.description || '') } : null)
                .filter(Boolean)
            : (Array.isArray(existing.custom_capabilities) ? existing.custom_capabilities : []);

        const merged = { ...existing, ...body, divisions, custom_capabilities };
        if (Object.prototype.hasOwnProperty.call(merged, 'logo_data_url')) {
            merged.logo_data_url = sanitizeKitchenLogoDataUrl(merged.logo_data_url);
        }
        await run("UPDATE kitchen_config SET config = ? WHERE id = '1'", [JSON.stringify(merged)]);
        res.json(normalizeKitchenConfigDivisions(merged));
    } catch (e) { res.status(500).json({ error: e.message }); }
});

