app.post('/api/ingredients', async (req, res) => {
    const item = { id: crypto.randomUUID(), ...req.body };
    try {
        const initialQty = Number(item.initial_qty || 0);
        if (!Number.isFinite(initialQty)) return res.status(400).json({ error: 'Invalid initial quantity' });
        if (initialQty < 0) return res.status(400).json({ error: 'Quantity must be non-negative' });
        const normalizedUnit = (String(item.unit || '').toLowerCase() === 'gram' || String(item.unit || '').toLowerCase() === 'pcs')
            ? String(item.unit).toLowerCase()
            : normalizeUnitAndQty(item.unit, 1).unit;
        item.unit = normalizedUnit;
        await run(
            "INSERT INTO ingredients (id, name, unit, estimated_price, nutr_code, nutrition_info) VALUES (?, ?, ?, ?, ?, ?)",
            [item.id, item.name, item.unit, item.estimated_price ?? null, item.nutr_code ?? null, item.nutrition_info ? JSON.stringify(item.nutrition_info) : null]
        );
        if (initialQty > 0) {
            await run("INSERT OR REPLACE INTO inventory (id, ingredient_id, quantity) VALUES (?, ?, ?)", [crypto.randomUUID(), item.id, initialQty]);
            await run(
                `INSERT INTO inventory_movements (id, at, ingredient_id, movement_type, qty_before, qty_after, delta, note, actor_email)
                 VALUES (?, ?, ?, 'INIT', 0, ?, ?, 'Initial stock', NULL)`,
                [crypto.randomUUID(), new Date().toISOString(), item.id, initialQty, initialQty]
            );
        }
        res.json(item);
    } catch (e) { res.status(500).json({ error: e.message }); }
});

// --- NUTRISURVEY ---
function normalizeNutrLabel(s) {
    return String(s || '')
        .toLowerCase()
        .replace(/\(.*?\)/g, '')
        .replace(/[^a-z0-9]+/g, ' ')
        .trim()
        .replace(/\s+/g, ' ');
}

function parseNutritionInfo(val) {
    if (!val) return {};
    if (typeof val === 'object') return val;
    try { return JSON.parse(String(val)); } catch (e) { return {}; }
}

async function resolveActorEmail(auth) {
    if (!auth) return null;
    try {
        if (auth.actor_type === 'platform') {
            const u = await get("SELECT email FROM platform_users WHERE id = ?", [auth.actor_id]);
            return u ? u.email : null;
        }
        if (auth.actor_type === 'tenant') {
            const t = await get("SELECT contact_email as email FROM tenants WHERE id = ?", [auth.actor_id]);
            return t ? t.email : null;
        }
        if (auth.actor_type === 'staff') {
            const s = await get("SELECT email FROM users WHERE id = ?", [auth.actor_id]);
            return s ? s.email : null;
        }
        return null;
    } catch (e) {
        return null;
    }
}

async function getNutrientList() {
    return await all("SELECT * FROM nutr_nutrients ORDER BY idx ASC");
}

async function getNutrientIndexMap() {
    const list = await getNutrientList();
    const map = new Map();
    for (const n of list) map.set(String(n.code), Number(n.idx));
    return { list, map };
}

function readFloatFromBlob(buf, idx) {
    if (!buf || !Buffer.isBuffer(buf)) return Number.NaN;
    if (typeof idx !== 'number' || !Number.isFinite(idx)) return Number.NaN;
    const off = idx * 4;
    if (off + 4 > buf.length) return Number.NaN;
    return buf.readFloatLE(off);
}

function getTenantKeyFromReq(req) {
    return String(req.headers['x-tenant-id'] || '').trim() || '';
}

function isIsoDateOnly(s) {
    return /^\d{4}-\d{2}-\d{2}$/.test(String(s || '').trim());
}

async function calcMenuTotals(menu_id, wantCodes, idxMap) {
    const menu = await get("SELECT m.*, r.ingredients FROM menu m LEFT JOIN recipes r ON m.recipe_id = r.id WHERE m.id = ?", [menu_id]);
    if (!menu) {
        const err = new Error('Menu not found');
        err.status = 404;
        throw err;
    }
    parseJson(menu, ['ingredients']);
    const items = Array.isArray(menu.ingredients) ? menu.ingredients : [];

    const ingIds = items.map(x => x.ingredient_id).filter(Boolean);
    const ingRows = ingIds.length ? await all(`SELECT * FROM ingredients WHERE id IN (${ingIds.map(() => '?').join(',')})`, ingIds) : [];
    const ingById = new Map(ingRows.map(r => [r.id, r]));
    const nutrCodes = Array.from(new Set(ingRows.map(r => r.nutr_code).filter(Boolean)));
    const foodsRows = nutrCodes.length ? await all(`SELECT code, nutr_values FROM nutr_foods WHERE code IN (${nutrCodes.map(() => '?').join(',')})`, nutrCodes) : [];
    const foodByCode = new Map(foodsRows.map(r => [r.code, r.nutr_values]));

    const totals = {};
    wantCodes.forEach(c => totals[c] = 0);
    let missing_count = 0;

    for (const it of items) {
        const ing = ingById.get(it.ingredient_id);
        const qty = Math.max(0, Number(it.quantity || 0));
        const info = ing ? parseNutritionInfo(ing.nutrition_info) : {};
        const manual = (info && typeof info.manual_nutrients === 'object' && info.manual_nutrients) ? info.manual_nutrients : null;
        let used = false;
        if (ing && ing.nutr_code) {
            const buf = foodByCode.get(ing.nutr_code) || null;
            for (const code of wantCodes) {
                const idx = idxMap.get(code);
                const per100 = readFloatFromBlob(buf, idx);
                const val = Number.isFinite(per100) ? (per100 * (qty / 100)) : null;
                if (val !== null) { totals[code] += val; used = true; }
            }
        }
        if (!used && manual) {
            for (const code of wantCodes) {
                const per100 = Number(manual[code]);
                const val = Number.isFinite(per100) ? (per100 * (qty / 100)) : null;
                if (val !== null) { totals[code] += val; used = true; }
            }
        }
        if (!used) missing_count += 1;
    }

    return { menu_id, menu_name: menu.name, totals, missing_count };
}

async function buildTargets(target_set, wantCodes, nutrients, totalsDerived) {
    if (!target_set) return null;
    const targetRows = await all("SELECT target_set, label, min, max FROM nutr_targets WHERE target_set = ?", [target_set]);
    const byNorm = new Map();
    targetRows.forEach(t => byNorm.set(normalizeNutrLabel(t.label), t));
    const targets = {};
    for (const code of wantCodes) {
        const n = (nutrients || []).find(x => x.code === code);
        if (!n) continue;
        const key = normalizeNutrLabel(n.label || n.name);
        const t = byNorm.get(key) || null;
        targets[code] = t ? { min: t.min, max: t.max, label: t.label } : null;
    }
    if (totalsDerived && totalsDerived.energy_kcal !== undefined) {
        const t = byNorm.get('energy');
        targets.energy_kcal = t ? { min: t.min, max: t.max, label: t.label } : null;
    }
    return targets;
}

