app.get('/api/nutri/foods', async (req, res) => {
    const q = String(req.query.query || '').trim();
    const limit = Math.max(1, Math.min(50, Number(req.query.limit || 20)));
    try {
        if (!q) {
            const rows = await all("SELECT code, name FROM nutr_foods ORDER BY code ASC LIMIT ?", [limit]);
            return res.json(rows);
        }
        const rows = await all(
            "SELECT code, name FROM nutr_foods WHERE code LIKE ? OR name LIKE ? ORDER BY name ASC LIMIT ?",
            [`%${q}%`, `%${q}%`, limit]
        );
        res.json(rows);
    } catch (e) { res.status(500).json({ error: e.message }); }
});

app.get('/api/nutri/food/:code', async (req, res) => {
    const code = String(req.params.code || '').trim();
    const codesRaw = String(req.query.codes || '').trim();
    try {
        const row = await get("SELECT code, name, nutr_values FROM nutr_foods WHERE code = ?", [code]);
        if (!row) return res.status(404).json({ error: 'Not found' });
        const { list, map } = await getNutrientIndexMap();
        const wantCodes = codesRaw ? codesRaw.split(',').map(s => s.trim()).filter(Boolean) : null;
        if (!wantCodes) {
            return res.json({ code: row.code, name: row.name, values: null, nutrients: list });
        }
        const out = {};
        for (const c of wantCodes) {
            const idx = map.get(c);
            out[c] = (idx === undefined) ? null : readFloatFromBlob(row.nutr_values, idx);
        }
        res.json({ code: row.code, name: row.name, values: out });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

