app.post('/api/nutri/link-ingredient', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const ingredient_id = String(req.body.ingredient_id || '').trim();
        const nutr_code = String(req.body.nutr_code || '').trim();
        if (!ingredient_id || !nutr_code) return res.status(400).json({ error: 'Missing ingredient_id/nutr_code' });
        try {
            const ing = await get("SELECT * FROM ingredients WHERE id = ?", [ingredient_id]);
            if (!ing) return res.status(404).json({ error: 'Ingredient not found' });
            const food = await get("SELECT code, name FROM nutr_foods WHERE code = ?", [nutr_code]);
            if (!food) return res.status(404).json({ error: 'Food code not found' });
            const info = parseNutritionInfo(ing.nutrition_info);
            info.nutr_code = nutr_code;
            info.nutr_name = food.name;
            await run("UPDATE ingredients SET nutr_code = ?, nutrition_info = ? WHERE id = ?", [
                nutr_code,
                JSON.stringify(info),
                ingredient_id
            ]);
            res.json({ success: true, ingredient_id, nutr_code, nutr_name: food.name });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.post('/api/nutri/unlink-ingredient', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const ingredient_id = String(req.body.ingredient_id || '').trim();
        const clear_manual = !!req.body.clear_manual;
        if (!ingredient_id) return res.status(400).json({ error: 'Missing ingredient_id' });
        try {
            const ing = await get("SELECT * FROM ingredients WHERE id = ?", [ingredient_id]);
            if (!ing) return res.status(404).json({ error: 'Ingredient not found' });
            const info = parseNutritionInfo(ing.nutrition_info);
            delete info.nutr_code;
            delete info.nutr_name;
            if (clear_manual) delete info.manual_nutrients;
            await run("UPDATE ingredients SET nutr_code = NULL, nutrition_info = ? WHERE id = ?", [
                JSON.stringify(info),
                ingredient_id
            ]);
            res.json({ success: true, ingredient_id });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.post('/api/nutri/ingredient/manual-values', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const ingredient_id = String(req.body.ingredient_id || '').trim();
        const per100 = (req.body && typeof req.body.per100 === 'object' && req.body.per100) ? req.body.per100 : null;
        if (!ingredient_id) return res.status(400).json({ error: 'Missing ingredient_id' });
        if (!per100) return res.status(400).json({ error: 'Missing per100' });
        try {
            const ing = await get("SELECT * FROM ingredients WHERE id = ?", [ingredient_id]);
            if (!ing) return res.status(404).json({ error: 'Ingredient not found' });
            const info = parseNutritionInfo(ing.nutrition_info);
            info.manual_nutrients = per100;
            await run("UPDATE ingredients SET nutrition_info = ? WHERE id = ?", [JSON.stringify(info), ingredient_id]);
            res.json({ success: true, ingredient_id });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.post('/api/nutri/menu/update-ingredients', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const menu_id = String(req.body.menu_id || '').trim();
        const items = Array.isArray(req.body.items) ? req.body.items : null;
        if (!menu_id) return res.status(400).json({ error: 'Missing menu_id' });
        if (!items) return res.status(400).json({ error: 'Missing items' });
        try {
            const m = await get("SELECT id, recipe_id FROM menu WHERE id = ?", [menu_id]);
            if (!m) return res.status(404).json({ error: 'Menu not found' });
            const payload = items
                .map(x => ({ ingredient_id: String(x.ingredient_id || '').trim(), quantity: Math.max(0, Number(x.qty_g || 0)) }))
                .filter(x => x.ingredient_id && x.quantity > 0);
            await run("UPDATE recipes SET ingredients = ? WHERE id = ?", [JSON.stringify(payload), m.recipe_id]);
            res.json({ success: true, menu_id, count: payload.length });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.post('/api/nutri/calc/menu', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const menu_id = String(req.body.menu_id || '').trim();
        const codesRaw = Array.isArray(req.body.nutrient_codes) ? req.body.nutrient_codes : null;
        const target_set = req.body.target_set ? String(req.body.target_set) : null;
        const itemsOverrideRaw = Array.isArray(req.body.items_override) ? req.body.items_override : null;
        if (!menu_id) return res.status(400).json({ error: 'Missing menu_id' });
        try {
            const menu = await get("SELECT m.*, r.ingredients FROM menu m LEFT JOIN recipes r ON m.recipe_id = r.id WHERE m.id = ?", [menu_id]);
            if (!menu) return res.status(404).json({ error: 'Menu not found' });
            parseJson(menu, ['ingredients']);
            const items = itemsOverrideRaw
                ? itemsOverrideRaw
                    .map(x => ({
                        ingredient_id: String(x?.ingredient_id || '').trim(),
                        quantity: Math.max(0, Number(x?.qty_g ?? x?.quantity ?? 0))
                    }))
                    .filter(x => x.ingredient_id)
                : (Array.isArray(menu.ingredients) ? menu.ingredients : []);

            const { list: nutrients, map: idxMap } = await getNutrientIndexMap();
            const defaultCodes = ['GJ', 'ZE', 'ZF', 'ZK'];
            const wantCodes = (codesRaw && codesRaw.length)
                ? codesRaw.map(c => String(c)).filter(c => idxMap.has(c))
                : defaultCodes.filter(c => idxMap.has(c));

            const ingIds = items.map(x => x.ingredient_id).filter(Boolean);
            const ingRows = ingIds.length ? await all(`SELECT * FROM ingredients WHERE id IN (${ingIds.map(() => '?').join(',')})`, ingIds) : [];
            const ingById = new Map(ingRows.map(r => [r.id, r]));
            const nutrCodes = Array.from(new Set(ingRows.map(r => r.nutr_code).filter(Boolean)));
            const foodsRows = nutrCodes.length ? await all(`SELECT code, nutr_values FROM nutr_foods WHERE code IN (${nutrCodes.map(() => '?').join(',')})`, nutrCodes) : [];
            const foodByCode = new Map(foodsRows.map(r => [r.code, r.nutr_values]));

            const detail = [];
            const totals = {};
            wantCodes.forEach(c => totals[c] = 0);
            let missing_count = 0;

            for (const it of items) {
                const ing = ingById.get(it.ingredient_id);
                const qty = Math.max(0, Number(it.quantity || 0));
                const info = ing ? parseNutritionInfo(ing.nutrition_info) : {};
                const manual = (info && typeof info.manual_nutrients === 'object' && info.manual_nutrients) ? info.manual_nutrients : null;
                const row = {
                    ingredient_id: it.ingredient_id,
                    ingredient_name: ing ? ing.name : '-',
                    qty_g: qty,
                    nutr_code: ing ? ing.nutr_code : null,
                    values: {},
                    source: 'unlinked'
                };
                let used = false;
                if (ing && ing.nutr_code) {
                    const buf = foodByCode.get(ing.nutr_code) || null;
                    for (const code of wantCodes) {
                        const idx = idxMap.get(code);
                        const per100 = readFloatFromBlob(buf, idx);
                        const val = Number.isFinite(per100) ? (per100 * (qty / 100)) : null;
                        row.values[code] = val;
                        if (val !== null) { totals[code] += val; used = true; }
                    }
                    if (used) row.source = 'nutrisurvey';
                }
                if (!used && manual) {
                    row.source = 'manual';
                    for (const code of wantCodes) {
                        const per100 = Number(manual[code]);
                        const val = Number.isFinite(per100) ? (per100 * (qty / 100)) : null;
                        row.values[code] = val;
                        if (val !== null) totals[code] += val;
                    }
                    used = true;
                }
                if (!used) {
                    for (const code of wantCodes) row.values[code] = null;
                    missing_count += 1;
                }
                detail.push(row);
            }

            const totalsDerived = {};
            if (totals.GJ !== undefined && Number.isFinite(totals.GJ)) totalsDerived.energy_kcal = totals.GJ / 4.184;

            const targets = await buildTargets(target_set, wantCodes, nutrients, totalsDerived);

            res.json({
                menu_id,
                menu_name: menu.name,
                nutrient_codes: wantCodes,
                nutrients: nutrients.filter(n => wantCodes.includes(n.code)),
                detail,
                totals,
                totals_derived: totalsDerived,
                target_set,
                targets,
                missing_count
            });

            try {
                const actor_email = await resolveActorEmail(req.auth);
                await run(
                    `INSERT INTO nutr_calc_runs (id, at, actor_email, menu_id, menu_name, target_set, nutrient_codes, totals, detail, missing_count, energy_kcal)
                     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                    [
                        crypto.randomUUID(),
                        new Date().toISOString(),
                        actor_email,
                        menu_id,
                        menu.name,
                        target_set,
                        wantCodes.join(','),
                        JSON.stringify(totals),
                        JSON.stringify({
                            menu_id,
                            menu_name: menu.name,
                            nutrient_codes: wantCodes,
                            nutrients: nutrients.filter(n => wantCodes.includes(n.code)),
                            detail,
                            totals,
                            totals_derived: totalsDerived,
                            target_set,
                            targets,
                            missing_count
                        }),
                        missing_count,
                        totalsDerived.energy_kcal ?? null
                    ]
                );
            } catch (e) { }
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

