app.post('/api/nutri/diary/day', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const day_date = String(req.body.date || '').trim();
        const title = (req.body.title === undefined) ? null : String(req.body.title || '').trim();
        const target_set = (req.body.target_set === undefined || req.body.target_set === null) ? null : String(req.body.target_set || '').trim();
        if (!day_date) return res.status(400).json({ error: 'Missing date' });
        if (!isIsoDateOnly(day_date)) return res.status(400).json({ error: 'Invalid date format (YYYY-MM-DD)' });
        const tenant_id = getTenantKeyFromReq(req);
        const now = new Date().toISOString();
        try {
            const existing = await get(
                "SELECT * FROM nutr_diary_days WHERE tenant_id = ? AND day_date = ?",
                [tenant_id, day_date]
            );
            if (existing) {
                const nextTitle = title === null ? (existing.title || null) : title;
                const nextTarget = target_set === null ? (existing.target_set || null) : target_set;
                await run(
                    "UPDATE nutr_diary_days SET title = ?, target_set = ?, updated_at = ? WHERE id = ? AND tenant_id = ?",
                    [nextTitle, nextTarget, now, existing.id, tenant_id]
                );
                const day = await get("SELECT * FROM nutr_diary_days WHERE id = ? AND tenant_id = ?", [existing.id, tenant_id]);
                return res.json({ day });
            }
            const id = crypto.randomUUID();
            await run(
                "INSERT INTO nutr_diary_days (id, tenant_id, day_date, title, target_set, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?)",
                [id, tenant_id, day_date, title, target_set, now, now]
            );
            const day = await get("SELECT * FROM nutr_diary_days WHERE id = ? AND tenant_id = ?", [id, tenant_id]);
            res.json({ day });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

