app.put('/api/nutri/diary/day/:id', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const id = String(req.params.id || '').trim();
        if (!id) return res.status(400).json({ error: 'Missing id' });
        const tenant_id = getTenantKeyFromReq(req);
        const title = (req.body.title === undefined) ? null : String(req.body.title || '').trim();
        const target_set = (req.body.target_set === undefined || req.body.target_set === null) ? null : String(req.body.target_set || '').trim();
        const entries = Array.isArray(req.body.entries) ? req.body.entries : null;
        if (!entries) return res.status(400).json({ error: 'Missing entries' });
        const now = new Date().toISOString();
        try {
            const day = await get("SELECT * FROM nutr_diary_days WHERE id = ? AND tenant_id = ?", [id, tenant_id]);
            if (!day) return res.status(404).json({ error: 'Not found' });
            const nextTitle = title === null ? (day.title || null) : title;
            const nextTarget = target_set === null ? (day.target_set || null) : target_set;
            await run("BEGIN");
            await run(
                "UPDATE nutr_diary_days SET title = ?, target_set = ?, updated_at = ? WHERE id = ? AND tenant_id = ?",
                [nextTitle, nextTarget, now, id, tenant_id]
            );
            await run("DELETE FROM nutr_diary_entries WHERE tenant_id = ? AND day_id = ?", [tenant_id, id]);
            for (let i = 0; i < entries.length; i++) {
                const e = entries[i] || {};
                const entry_type = String(e.entry_type || '').trim();
                if (entry_type !== 'menu' && entry_type !== 'food') continue;
                const ref_id = String(e.ref_id || '').trim();
                if (!ref_id) continue;
                const name = (e.name === undefined || e.name === null) ? null : String(e.name || '').trim();
                const portions = Math.max(0, Number(e.portions || 0) || 0);
                const qty_g = (entry_type === 'food') ? Math.max(0, Number(e.qty_g || 0) || 0) : null;
                const rowId = String(e.id || '').trim() || crypto.randomUUID();
                await run(
                    `INSERT INTO nutr_diary_entries (id, tenant_id, day_id, entry_type, ref_id, name, qty_g, portions, sort_order, created_at, updated_at)
                     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                    [rowId, tenant_id, id, entry_type, ref_id, name, qty_g, portions || 1, i, now, now]
                );
            }
            await run("COMMIT");
            const outDay = await get("SELECT * FROM nutr_diary_days WHERE id = ? AND tenant_id = ?", [id, tenant_id]);
            const outEntries = await all(
                "SELECT * FROM nutr_diary_entries WHERE tenant_id = ? AND day_id = ? ORDER BY sort_order ASC, created_at ASC",
                [tenant_id, id]
            );
            res.json({ day: outDay, entries: outEntries });
        } catch (e) {
            try { await run("ROLLBACK"); } catch (_) { }
            res.status(500).json({ error: e.message });
        }
    });
});

app.post('/api/nutri/diary/day/:id/calc', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const id = String(req.params.id || '').trim();
        if (!id) return res.status(400).json({ error: 'Missing id' });
        const tenant_id = getTenantKeyFromReq(req);
        const codesRaw = Array.isArray(req.body.nutrient_codes) ? req.body.nutrient_codes : null;
        const target_set = (req.body.target_set === undefined || req.body.target_set === null) ? null : String(req.body.target_set || '').trim();
        try {
            const day = await get("SELECT * FROM nutr_diary_days WHERE id = ? AND tenant_id = ?", [id, tenant_id]);
            if (!day) return res.status(404).json({ error: 'Not found' });
            const entries = await all(
                "SELECT * FROM nutr_diary_entries WHERE tenant_id = ? AND day_id = ? ORDER BY sort_order ASC, created_at ASC",
                [tenant_id, id]
            );

            const { list: nutrients, map: idxMap } = await getNutrientIndexMap();
            const defaultCodes = ['GJ', 'ZE', 'ZF', 'ZK'];
            const wantCodes = (codesRaw && codesRaw.length)
                ? codesRaw.map(c => String(c)).filter(c => idxMap.has(c))
                : defaultCodes.filter(c => idxMap.has(c));

            const totals = {};
            wantCodes.forEach(c => totals[c] = 0);
            const detail = [];
            let missing_count = 0;

            for (const row of entries) {
                const entry_type = String(row.entry_type || '').trim();
                const portions = Math.max(0, Number(row.portions || 0) || 0) || 1;
                if (entry_type === 'menu') {
                    const m = await calcMenuTotals(String(row.ref_id || '').trim(), wantCodes, idxMap);
                    const values = {};
                    for (const c of wantCodes) {
                        const v = (m.totals && m.totals[c] !== undefined) ? Number(m.totals[c]) : 0;
                        const scaled = v * portions;
                        values[c] = scaled;
                        totals[c] += scaled;
                    }
                    missing_count += Number(m.missing_count || 0);
                    detail.push({
                        entry_type: 'menu',
                        ref_id: m.menu_id,
                        name: row.name || m.menu_name,
                        portions,
                        qty_g: null,
                        values,
                        missing_count: Number(m.missing_count || 0)
                    });
                    continue;
                }
                if (entry_type === 'food') {
                    const code = String(row.ref_id || '').trim();
                    if (!code) continue;
                    const qty_g_each = Math.max(0, Number(row.qty_g || 0) || 0);
                    const total_g = qty_g_each * portions;
                    const food = await get("SELECT code, name, nutr_values FROM nutr_foods WHERE code = ?", [code]);
                    const values = {};
                    let used = false;
                    for (const c of wantCodes) {
                        const idx = idxMap.get(c);
                        const per100 = readFloatFromBlob(food ? food.nutr_values : null, idx);
                        const val = Number.isFinite(per100) ? (per100 * (total_g / 100)) : null;
                        values[c] = val;
                        if (val !== null) { totals[c] += val; used = true; }
                    }
                    if (!used) missing_count += 1;
                    detail.push({
                        entry_type: 'food',
                        ref_id: code,
                        name: row.name || (food ? food.name : code),
                        portions,
                        qty_g: qty_g_each,
                        values,
                        missing_count: used ? 0 : 1
                    });
                    continue;
                }
            }

            const totalsDerived = {};
            if (totals.GJ !== undefined && Number.isFinite(totals.GJ)) totalsDerived.energy_kcal = totals.GJ / 4.184;

            const useTarget = target_set || (day.target_set || null);
            const targets = await buildTargets(useTarget, wantCodes, nutrients, totalsDerived);

            res.json({
                day_id: id,
                day_date: day.day_date,
                title: day.title || null,
                nutrient_codes: wantCodes,
                nutrients: nutrients.filter(n => wantCodes.includes(n.code)),
                detail,
                totals,
                totals_derived: totalsDerived,
                target_set: useTarget,
                targets,
                missing_count
            });
        } catch (e) {
            const status = e && e.status ? Number(e.status) : 500;
            res.status(status).json({ error: e.message });
        }
    });
});

// --- HELPERS ---
function generateId(prefix) {
    const now = new Date();
    const y = now.getFullYear().toString().substr(-2);
    const m = (now.getMonth() + 1).toString().padStart(2, '0');
    const d = now.getDate().toString().padStart(2, '0');
    const h = now.getHours().toString().padStart(2, '0');
    const min = now.getMinutes().toString().padStart(2, '0');
    const s = now.getSeconds().toString().padStart(2, '0');
    const ms = now.getMilliseconds().toString().padStart(3, '0');
    return `${prefix}-${y}${m}${d}-${h}${min}${s}${ms}`;
}

function readableCode(prefix, id) {
    const raw = String(id || '').replace(/-/g, '');
    const part = raw ? raw.slice(0, 8).toUpperCase() : 'UNKNOWN';
    return `${prefix}-${part}`;
}

async function getKitchenConfigSafe() {
    const row = await get("SELECT config FROM kitchen_config WHERE id = 1");
    if (!row || !row.config) return normalizeKitchenConfigDivisions({ divisions: [] });
    try {
        return normalizeKitchenConfigDivisions(JSON.parse(row.config));
    } catch (e) {
        return normalizeKitchenConfigDivisions({ divisions: [] });
    }
}

