/**
 * Selaras /api/facerec/register: satu kombinasi nama+divisi per tenant; staff_code unik per tenant jika diisi.
 * excludeStaffId: untuk PUT — abaikan baris yang sedang diubah.
 */
async function assertStaffUniqueInTenant(tenantId, { name, division_id, staff_code }, excludeStaffId = null) {
    const tid = String(tenantId || '').trim();
    if (!tid) return;
    const n = String(name || '').trim();
    const div = String(division_id || '').trim();
    const code = String(staff_code || '').trim();

    if (n) {
        let sql =
            "SELECT id FROM staff WHERE tenant_id = ? AND LOWER(TRIM(name)) = LOWER(TRIM(?)) AND LOWER(TRIM(COALESCE(division_id,''))) = LOWER(TRIM(?))";
        const params = [tid, n, div];
        if (excludeStaffId) {
            sql += " AND id != ?";
            params.push(String(excludeStaffId));
        }
        const row = await get(sql, params).catch(() => null);
        if (row) {
            const err = new Error(
                `Staf dengan nama **${n}** pada divisi **${div || "(kosong)"}** sudah ada di dapur ini.`
            );
            err.status = 409;
            throw err;
        }
    }
    if (code) {
        let sql = "SELECT id FROM staff WHERE tenant_id = ? AND LOWER(TRIM(staff_code)) = LOWER(TRIM(?))";
        const params = [tid, code];
        if (excludeStaffId) {
            sql += " AND id != ?";
            params.push(String(excludeStaffId));
        }
        const row = await get(sql, params).catch(() => null);
        if (row) {
            const err = new Error(`Kode staf **${code}** sudah dipakai di dapur ini.`);
            err.status = 409;
            throw err;
        }
    }
}

