app.delete('/api/staff/:id', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const staffId = req.params.id;
            
            // 1. Delete from main DB
            await run("DELETE FROM staff WHERE id = ? AND tenant_id = ?", [staffId, tenantId]);
            
            // 2. Notify Face API to cleanup (Async, don't block response but log errors)
            const _faceDel = getFaceApiConnect();
            const pyReq = http.request({
                hostname: _faceDel.hostname,
                port: _faceDel.port,
                path: '/delete',
                method: 'POST',
                headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
            }, pyRes => {
                let body = '';
                pyRes.on('data', d => body += d);
                pyRes.on('end', () => {
                    if (pyRes.statusCode >= 400) {
                        console.error(`[WARN] Face API /delete failed for ${staffId}: ${body}`);
                    } else {
                        console.log(`[INFO] Face API /delete success for ${staffId}`);
                    }
                });
            });
            pyReq.on('error', e => console.error(`[WARN] Face API /delete connection error for ${staffId}: ${e.message}`));
            pyReq.write(`staff_id=${staffId}&tenant_id=${tenantId}`);
            pyReq.end();

            res.json({ success: true });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

