function jakartaYmdFromIso(iso) {
    const d = new Date(iso);
    if (isNaN(d.getTime())) return '';
    const fmt = new Intl.DateTimeFormat('en-CA', { timeZone: 'Asia/Jakarta', year: 'numeric', month: '2-digit', day: '2-digit' });
    return fmt.format(d);
}

/** Akhir hari kalender di Asia/Jakarta, sebagai instant UTC (untuk sesi masuk tanpa keluar). */
function endOfJakartaDayUtc(ymd) {
    const parts = String(ymd || '').trim().split('-');
    if (parts.length !== 3) return new Date();
    const y = parseInt(parts[0], 10);
    const m = parseInt(parts[1], 10);
    const d = parseInt(parts[2], 10);
    if (!Number.isFinite(y) || !Number.isFinite(m) || !Number.isFinite(d)) return new Date();
    return new Date(Date.UTC(y, m - 1, d, 16, 59, 59, 999));
}

/**
 * Menit kerja dari event CLOCK_IN / BREAK / CLOCK_OUT.
 * Jika hanya CLOCK_IN tanpa CLOCK_OUT (sesi masih buka), hitung sampai sekarang (hari ini) atau
 * sampai akhir hari kalender Jakarta (hari lampau), agar Absensi Harian tidak nol hanya karena belum absen pulang.
 */
function calcWorkedMinutesFromEvents(events) {
    let currentIn = null;
    let currentInWorkDate = '';
    let breakStart = null;
    let breakMinutes = 0;
    let workedMinutes = 0;
    for (const e of events) {
        const ty = String(e.event_type || '').trim().toUpperCase();
        const at = new Date(e.occurred_at);
        if (isNaN(at.getTime())) continue;
        if (ty === 'CLOCK_IN') {
            if (!currentIn) {
                currentIn = at;
                currentInWorkDate = jakartaYmdFromIso(e.occurred_at);
            }
        } else if (ty === 'BREAK_START') {
            if (currentIn && !breakStart) breakStart = at;
        } else if (ty === 'BREAK_END') {
            if (breakStart) {
                breakMinutes += Math.floor((at.getTime() - breakStart.getTime()) / 60000);
                breakStart = null;
            }
        } else if (ty === 'CLOCK_OUT') {
            if (currentIn) {
                const total = Math.floor((at.getTime() - currentIn.getTime()) / 60000) - breakMinutes;
                if (total > 0) workedMinutes += total;
                currentIn = null;
                currentInWorkDate = '';
                breakStart = null;
                breakMinutes = 0;
            }
        }
    }
    if (currentIn && currentInWorkDate) {
        const todayJakarta = jakartaYmdFromIso(new Date().toISOString());
        const endAt =
            currentInWorkDate === todayJakarta ? new Date() : endOfJakartaDayUtc(currentInWorkDate);
        if (endAt.getTime() > currentIn.getTime()) {
            const total = Math.floor((endAt.getTime() - currentIn.getTime()) / 60000) - breakMinutes;
            if (total > 0) workedMinutes += total;
        }
    }
    return workedMinutes;
}

function haversineDistanceMeters(lat1, lon1, lat2, lon2) {
    const R = 6371000; // earth radius (meters)
    const toRad = (d) => (Number(d) * Math.PI) / 180;
    const dLat = toRad(lat2) - toRad(lat1);
    const dLon = toRad(lon2) - toRad(lon1);
    const a = Math.sin(dLat / 2) ** 2 + Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon / 2) ** 2;
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
}

function safeJsonParse(val, fallback = {}) {
    if (val == null) return fallback;
    if (typeof val === 'object') return val;
    try { return JSON.parse(String(val)); } catch (e) { return fallback; }
}

const ATTENDANCE_POLICY_DEFAULT = {
    work_hours_per_day: 8,
    overtime_after_hours: 8,
    late_grace_minutes: 10,
    max_geo_radius_m: 50,
    biweekly_days: 14,
};

function normalizeAttendancePolicy(raw) {
    const src = raw && typeof raw === 'object' ? raw : {};
    const clampNum = (v, fallback, min, max) => {
        const n = Number(v);
        if (!Number.isFinite(n)) return fallback;
        if (n < min) return min;
        if (n > max) return max;
        return n;
    };
    return {
        work_hours_per_day: clampNum(src.work_hours_per_day, ATTENDANCE_POLICY_DEFAULT.work_hours_per_day, 1, 24),
        overtime_after_hours: clampNum(src.overtime_after_hours, ATTENDANCE_POLICY_DEFAULT.overtime_after_hours, 1, 24),
        late_grace_minutes: clampNum(src.late_grace_minutes, ATTENDANCE_POLICY_DEFAULT.late_grace_minutes, 0, 180),
        max_geo_radius_m: clampNum(src.max_geo_radius_m, ATTENDANCE_POLICY_DEFAULT.max_geo_radius_m, 10, 2000),
        biweekly_days: Math.round(clampNum(src.biweekly_days, ATTENDANCE_POLICY_DEFAULT.biweekly_days, 7, 31)),
    };
}

async function getAttendancePolicySafe() {
    const cfg = await getKitchenConfigSafe().catch(() => ({}));
    const policy = cfg?.attendance_policy || {};
    return normalizeAttendancePolicy(policy);
}

async function findShiftForAttendance(tenantId, staffId, divisionId, workDate) {
    const stid = sanitizeTenantId(tenantId);
    let shift = await get(`
        SELECT s.id, s.name, s.start_time, s.end_time
        FROM staff_shift_assignments ssa
        JOIN shifts s ON s.id = ssa.shift_id
        WHERE (ssa.tenant_id = ? OR ssa.tenant_id = ?)
          AND ssa.staff_id = ?
          AND ssa.work_date = ?
        LIMIT 1
    `, [tenantId, stid, staffId, workDate]);
    if (shift) return shift;
    shift = await get(`
        SELECT id, name, start_time, end_time
        FROM shifts
        WHERE (tenant_id = ? OR tenant_id = ?)
          AND (division_id = ? OR division_id = 'all')
        ORDER BY (CASE WHEN division_id = 'all' THEN 1 ELSE 0 END) ASC, created_at ASC
        LIMIT 1
    `, [tenantId, stid, String(divisionId || 'UNKNOWN')]);
    return shift || null;
}

function computeLateMinutes(occurredAtIso, shiftStart, lateGraceMinutes) {
    if (!occurredAtIso || !shiftStart || !/^\d{2}:\d{2}/.test(String(shiftStart))) return 0;
    const d = new Date(occurredAtIso);
    if (!Number.isFinite(d.getTime())) return 0;
    const occTotal = d.getHours() * 60 + d.getMinutes();
    const [h, m] = String(shiftStart).split(':').map(x => parseInt(x, 10));
    const shiftTotal = (Number.isFinite(h) ? h : 0) * 60 + (Number.isFinite(m) ? m : 0);
    return Math.max(0, occTotal - shiftTotal - Math.max(0, Number(lateGraceMinutes || 0)));
}

async function upsertAttendanceDailyFromEvents({
    tenantId,
    staffId,
    workDate,
    staffDivisionId,
    events,
    nowIso,
    forceStatus = null,
    note = ''
}) {
    const safeEvents = Array.isArray(events) ? events : [];
    const minutesWorked = Math.max(0, calcWorkedMinutesFromEvents(safeEvents) || 0);
    const policy = await getAttendancePolicySafe();
    const overtimeMinutes = Math.max(0, minutesWorked - Math.round(policy.overtime_after_hours * 60));
    const shift = await findShiftForAttendance(tenantId, staffId, staffDivisionId || '', workDate);
    const shiftId = shift?.id || null;
    const clockInEvent = safeEvents.find(e => String(e?.event_type || '').toUpperCase() === 'CLOCK_IN');
    const lateMinutes = clockInEvent ? computeLateMinutes(clockInEvent.occurred_at, shift?.start_time, policy.late_grace_minutes) : 0;
    const status = String(forceStatus || (minutesWorked > 0 ? 'PRESENT' : 'ABSENT')).toUpperCase();
    await run(
        `INSERT INTO attendance_daily (tenant_id, staff_id, work_date, shift_id, minutes_worked, late_minutes, overtime_minutes, status, note, updated_at)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
         ON CONFLICT(tenant_id, staff_id, work_date)
         DO UPDATE SET
            shift_id = excluded.shift_id,
            minutes_worked = excluded.minutes_worked,
            late_minutes = excluded.late_minutes,
            overtime_minutes = excluded.overtime_minutes,
            status = excluded.status,
            note = excluded.note,
            updated_at = excluded.updated_at`,
        [tenantId, staffId, workDate, shiftId, minutesWorked, lateMinutes, overtimeMinutes, status, String(note || ''), nowIso]
    );
    return {
        minutes_worked: minutesWorked,
        overtime_minutes: overtimeMinutes,
        late_minutes: lateMinutes,
        status,
        shift_id: shiftId,
        policy,
    };
}

const FACE_RECOGNITION_CACHE = new Map();
const FACE_RECOGNITION_CACHE_TTL_MS = 5 * 60 * 1000;
const FACE_RECOGNITION_CACHE_MAX = 3000;

function pruneFaceRecognitionCache() {
    const now = Date.now();
    for (const [k, v] of FACE_RECOGNITION_CACHE.entries()) {
        if (!v || !v.ts || (now - v.ts) > FACE_RECOGNITION_CACHE_TTL_MS) FACE_RECOGNITION_CACHE.delete(k);
    }
    if (FACE_RECOGNITION_CACHE.size <= FACE_RECOGNITION_CACHE_MAX) return;
    const all = Array.from(FACE_RECOGNITION_CACHE.entries()).sort((a, b) => Number(a[1]?.ts || 0) - Number(b[1]?.ts || 0));
    const overflow = FACE_RECOGNITION_CACHE.size - FACE_RECOGNITION_CACHE_MAX;
    for (let i = 0; i < overflow; i += 1) FACE_RECOGNITION_CACHE.delete(all[i][0]);
}

function buildFaceCacheKey(tenantId, imageData) {
    const raw = String(imageData || '');
    const len = raw.length;
    // Reduce collision risk: hash full payload for smaller input, or prefix+suffix+length for very large input.
    const sigInput = len <= 65536 ? raw : `${raw.slice(0, 65536)}::${raw.slice(-16384)}::len=${len}`;
    const sig = crypto.createHash('sha1').update(sigInput).digest('hex');
    return `${tenantId}::len=${len}::${sig}`;
}

/** GET /health ke Face API — jika false, /recognize akan gagal instan (~beberapa ms, bukan inferensi ML). */
function checkFaceApiHealth(hostname, port, timeoutMs = 3000) {
    const h = String(hostname || '').trim() || '127.0.0.1';
    const p = Math.max(1, parseInt(port, 10) || 5000);
    return new Promise((resolve) => {
        let settled = false;
        const finish = (ok) => {
            if (settled) return;
            settled = true;
            resolve(!!ok);
        };
        const req = http.request(
            { hostname: h, port: p, path: '/health', method: 'GET' },
            (pyRes) => {
                const ok = pyRes.statusCode >= 200 && pyRes.statusCode < 300;
                try {
                    pyRes.resume();
                } catch (_) {}
                pyRes.on('end', () => finish(ok));
            }
        );
        req.on('error', () => finish(false));
        req.on('timeout', () => {
            try {
                req.destroy();
            } catch (_) {}
            finish(false);
        });
        req.setTimeout(timeoutMs);
        req.end();
    });
}

function isFaceApiTransportError(errText) {
    const s = String(errText || '').toLowerCase();
    return (
        s.includes('econnrefused')
        || s.includes('enotfound')
        || s.includes('econnreset')
        || s.includes('etimedout')
        || s.includes('socket hang up')
        || s.includes('connect refused')
    );
}

function workDateIsoRange(workDate) {
    const day = String(workDate || '').trim();
    if (!day) return { fromIso: '', toIso: '' };
    const next = addDaysYmd(day, 1);
    return {
        fromIso: `${day}T00:00:00.000Z`,
        toIso: `${next}T00:00:00.000Z`,
    };
}

async function loadAttendanceEventsForWorkDate(tenantId, staffId, workDate) {
    const tid = String(tenantId || '').trim();
    const sid = String(staffId || '').trim();
    const wd = String(workDate || '').trim();
    if (!tid || !sid || !wd) return [];
    const { fromIso, toIso } = workDateIsoRange(wd);
    if (!fromIso || !toIso) return [];
    return await all(
        `SELECT staff_id, event_type, occurred_at
         FROM attendance_events
         WHERE tenant_id = ?
           AND staff_id = ?
           AND datetime(occurred_at) >= datetime(?)
           AND datetime(occurred_at) < datetime(?)
         ORDER BY occurred_at`,
        [tid, sid, fromIso, toIso]
    );
}

function normalizeClientEventId(raw) {
    const val = String(raw || '').trim();
    if (!val) return '';
    return val.slice(0, 120);
}

async function findAttendanceEventByClientEventId(tenantId, clientEventId) {
    const tid = String(tenantId || '').trim();
    const ceid = normalizeClientEventId(clientEventId);
    if (!tid || !ceid) return null;
    return await get(
        `SELECT id, tenant_id, staff_id, event_type, occurred_at, source, note, client_event_id, meta_json, created_at
         FROM attendance_events
         WHERE tenant_id = ? AND client_event_id = ?
         LIMIT 1`,
        [tid, ceid]
    );
}

