/**
 * Shift assignment efektif per tanggal:
 *  - Untuk tiap staff tenant, resolve shift yang berlaku di `work_date`.
 *  - Prioritas: override manual (staff_shift_assignments) → default shift divisi staff
 *    (shifts dengan division_id = staff.division_id, lalu 'all' sebagai fallback).
 *  - Tidak membuat record di DB — hanya view terhitung.
 */
app.get('/api/attendance/assignments/effective', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const tid = sanitizeTenantId(tenantId);
            const work_date = String(req.query.work_date || '').trim();
            const staff_id = String(req.query.staff_id || '').trim();
            if (!work_date) return res.status(400).json({ error: 'work_date wajib diisi' });

            const staffRows = await all(
                staff_id
                    ? "SELECT id, name, staff_code, division_id FROM staff WHERE tenant_id = ? AND id = ? ORDER BY name"
                    : "SELECT id, name, staff_code, division_id FROM staff WHERE tenant_id = ? ORDER BY name",
                staff_id ? [tenantId, staff_id] : [tenantId]
            );

            const assignments = await all(
                `SELECT a.id, a.staff_id, a.shift_id, sh.name AS shift_name, sh.start_time, sh.end_time
                 FROM staff_shift_assignments a
                 JOIN shifts sh ON sh.id = a.shift_id
                 WHERE a.tenant_id = ? AND a.work_date = ?`,
                [tenantId, work_date]
            );
            const assignmentByStaff = new Map(assignments.map(r => [String(r.staff_id), r]));

            const shifts = await all(
                `SELECT id, name, start_time, end_time, division_id
                 FROM shifts
                 WHERE (tenant_id = ? OR tenant_id = ?)
                 ORDER BY created_at ASC`,
                [tenantId, tid]
            );
            const shiftsByDiv = new Map();
            for (const s of shifts) {
                const key = String(s.division_id || 'all').toLowerCase();
                if (!shiftsByDiv.has(key)) shiftsByDiv.set(key, []);
                shiftsByDiv.get(key).push(s);
            }

            const resolveDefaultShift = (divisionId) => {
                const key = String(divisionId || '').toLowerCase();
                const own = key ? shiftsByDiv.get(key) : null;
                if (own && own.length) return own[0];
                const anyDiv = shiftsByDiv.get('all');
                return anyDiv && anyDiv.length ? anyDiv[0] : null;
            };

            const rows = staffRows.map(staff => {
                const override = assignmentByStaff.get(String(staff.id));
                if (override) {
                    return {
                        id: override.id,
                        staff_id: staff.id,
                        staff_name: staff.name,
                        staff_code: staff.staff_code,
                        division_id: staff.division_id || null,
                        shift_id: override.shift_id,
                        shift_name: override.shift_name,
                        start_time: override.start_time,
                        end_time: override.end_time,
                        source: 'override',
                        work_date,
                    };
                }
                const fallback = resolveDefaultShift(staff.division_id);
                return {
                    id: null,
                    staff_id: staff.id,
                    staff_name: staff.name,
                    staff_code: staff.staff_code,
                    division_id: staff.division_id || null,
                    shift_id: fallback ? fallback.id : null,
                    shift_name: fallback ? fallback.name : null,
                    start_time: fallback ? fallback.start_time : null,
                    end_time: fallback ? fallback.end_time : null,
                    source: fallback ? 'auto' : 'none',
                    work_date,
                };
            });

            res.json({
                work_date,
                rows,
                summary: {
                    total: rows.length,
                    override: rows.filter(r => r.source === 'override').length,
                    auto: rows.filter(r => r.source === 'auto').length,
                    missing_shift: rows.filter(r => r.source === 'none').length,
                },
            });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

app.get('/api/attendance/events', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const staff_id = String(req.query.staff_id || '').trim();
            const from = String(req.query.from || '').trim();
            const to = String(req.query.to || '').trim();
            let sql = `
                SELECT e.*, s.name AS staff_name
                FROM attendance_events e
                LEFT JOIN staff s ON s.id = e.staff_id
                WHERE e.tenant_id = ?
            `;
            const params = [tenantId];
            if (staff_id) { sql += " AND e.staff_id = ?"; params.push(staff_id); }
            if (from) { sql += " AND datetime(e.occurred_at) >= datetime(?)"; params.push(from); }
            if (to) { sql += " AND datetime(e.occurred_at) <= datetime(?)"; params.push(to); }
            sql += " ORDER BY datetime(e.occurred_at) DESC LIMIT 5000";
            const rows = await all(sql, params);
            rows.forEach(r => { try { r.meta_json = JSON.parse(r.meta_json || '{}'); } catch (e) { r.meta_json = {}; } });
            res.json(rows);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.delete('/api/attendance/events/:id', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const id = String(req.params.id || '').trim();
            if (!id) return res.status(400).json({ error: 'Missing event id' });

            const ev = await get(
                "SELECT staff_id, occurred_at FROM attendance_events WHERE tenant_id = ? AND id = ?",
                [tenantId, id]
            );
            if (!ev) return res.status(404).json({ error: 'Event not found' });

            const staff_id = ev.staff_id ? String(ev.staff_id).trim() : '';
            const occurred_at = ev.occurred_at;
            const work_date = jakartaYmdFromIso(occurred_at);

            await run(
                "DELETE FROM attendance_events WHERE tenant_id = ? AND id = ?",
                [tenantId, id]
            );

            // Keep attendance_daily consistent: remove row for that staff/day, then re-insert only if
            // there are still events that day (otherwise daily stays deleted — true "hapus absensi harian").
            if (staff_id && work_date) {
                await run(
                    "DELETE FROM attendance_daily WHERE tenant_id = ? AND staff_id = ? AND work_date = ?",
                    [tenantId, staff_id, work_date]
                );

                const evsForDay = await loadAttendanceEventsForWorkDate(tenantId, staff_id, work_date);
                if (evsForDay.length > 0) {
                    const nowIso = new Date().toISOString();
                    const staffRow = await get("SELECT division_id FROM staff WHERE tenant_id = ? AND id = ?", [tenantId, staff_id]).catch(() => null);
                    await upsertAttendanceDailyFromEvents({
                        tenantId,
                        staffId: staff_id,
                        workDate: work_date,
                        staffDivisionId: staffRow?.division_id || '',
                        events: evsForDay,
                        nowIso,
                        note: 'AUTO_RECOMPUTE'
                    });
                }
            }

            res.json({ ok: true, deleted_event_id: id, updated_daily: !!staff_id && !!work_date });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.post('/api/attendance/events/:id/correct-face', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            // Restrict correction to tenant admins only (as requested).
            if (req.auth?.actor_type !== 'tenant') {
                return res.status(403).json({ error: 'Hanya admin tenant yang dapat melakukan koreksi.' });
            }

            const tenantId = getTenantIdFromReq(req);
            const eventId = String(req.params.id || '').trim();
            const staff_id = String(req.body?.staff_id || '').trim();
            const division_id = String(req.body?.division_id || '').trim();
            const add_as_training = req.body?.add_as_training !== false;
            const apply_now = req.body?.apply_now !== false;
            if (!eventId || !staff_id || !division_id) {
                return res.status(400).json({ error: 'Missing required fields (event_id, staff_id, division_id)' });
            }

            const ev = await get(
                "SELECT id, occurred_at, note, staff_id, meta_json FROM attendance_events WHERE tenant_id = ? AND id = ?",
                [tenantId, eventId]
            );
            if (!ev) return res.status(404).json({ error: 'Event not found' });

            const meta = safeJsonParse(ev.meta_json, {});
            const image_data = String(meta?.attendance_photo || '').trim();
            if (!image_data || !image_data.startsWith('data:image/')) {
                return res.status(400).json({ error: 'Foto event tidak tersedia untuk training.' });
            }

            const staff = await get(
                "SELECT id, name, division_id FROM staff WHERE tenant_id = ? AND id = ?",
                [tenantId, staff_id]
            );
            if (!staff) return res.status(404).json({ error: 'Staff tidak ditemukan pada tenant ini.' });
            if (String(staff.division_id || '').trim() !== division_id) {
                return res.status(400).json({ error: 'Divisi staff tidak sesuai dengan pilihan koreksi.' });
            }

            let training_result = null;
            if (add_as_training) {
                training_result = await (async () => {
                    const _face = getFaceApiConnect();
                    return new Promise((resolve) => {
                        const pyReq = http.request(
                            {
                                hostname: _face.hostname,
                                port: _face.port,
                                path: '/add-sample',
                                method: 'POST',
                                headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
                            },
                            pyRes => {
                                let body = '';
                                pyRes.on('data', d => body += d);
                                pyRes.on('end', () => {
                                    try {
                                        const data = body ? JSON.parse(body) : {};
                                        if (pyRes.statusCode >= 400) {
                                            return resolve({ ok: false, error: data?.detail || body || 'Face API add-sample failed' });
                                        }
                                        resolve({ ok: true, ...data });
                                    } catch (e) {
                                        resolve({ ok: pyRes.statusCode < 400, error: e.message });
                                    }
                                });
                            }
                        );
                        pyReq.on('error', e => resolve({ ok: false, error: e.message }));
                        pyReq.write(
                            `staff_id=${encodeURIComponent(staff_id)}&tenant_id=${encodeURIComponent(tenantId)}&image_data=${encodeURIComponent(image_data)}`
                        );
                        pyReq.end();
                    });
                })();
            }

            const correction = {
                at: new Date().toISOString(),
                by_actor: req.auth?.actor_type || 'tenant',
                staff_id,
                staff_name: String(staff.name || ''),
                division_id,
                add_as_training: !!add_as_training,
                apply_now: !!apply_now,
                training_result: training_result || null,
            };
            meta.manual_correction = correction;

            if (apply_now) {
                const correctedNote = 'Dikoreksi manual (admin tenant)';
                await run(
                    "UPDATE attendance_events SET staff_id = ?, note = ?, meta_json = ? WHERE tenant_id = ? AND id = ?",
                    [staff_id, correctedNote, JSON.stringify(meta), tenantId, eventId]
                );

                const work_date = jakartaYmdFromIso(ev.occurred_at);
                if (work_date) {
                    await run(
                        "DELETE FROM attendance_daily WHERE tenant_id = ? AND staff_id = ? AND work_date = ?",
                        [tenantId, staff_id, work_date]
                    );
                    const evsForDay = await loadAttendanceEventsForWorkDate(tenantId, staff_id, work_date);
                    if (evsForDay.length > 0) {
                        const nowIso = new Date().toISOString();
                        await upsertAttendanceDailyFromEvents({
                            tenantId,
                            staffId: staff_id,
                            workDate: work_date,
                            staffDivisionId: staff.division_id || division_id || '',
                            events: evsForDay,
                            nowIso,
                            note: 'AUTO_CORRECTION'
                        });
                    }
                }
            } else {
                await run(
                    "UPDATE attendance_events SET meta_json = ? WHERE tenant_id = ? AND id = ?",
                    [JSON.stringify(meta), tenantId, eventId]
                );
            }

            res.json({
                ok: true,
                event_id: eventId,
                staff_id,
                division_id,
                apply_now,
                training_added: !!(training_result && training_result.ok),
                training_result,
            });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.post('/api/attendance/events/direct', async (req, res) => {
    try {
        const {
            tenant_id,
            staff_code,
            event_type,
            occurred_at,
            source,
            note,
            photo_data_url,
            latitude,
            longitude,
            geo_accuracy,
            geo_captured_at,
            client_event_id,
            client_metrics
        } = req.body || {};
        if (!tenant_id || !staff_code) return res.status(400).json({ error: 'Tenant and Staff Code required' });

        const tid = String(tenant_id || '').trim();
        const scode = String(staff_code || '').trim();
        const tdb = await ensureTenantDb(tid);
        await ensureStaffSchemaForTenantId(tid);
        const attendancePolicy = await getAttendancePolicySafe();
        const maxGeoRadiusM = Math.max(10, Number(attendancePolicy.max_geo_radius_m || 50));
        const kcfg = await getKitchenConfigSafe();
        const kGps =
            kcfg?.kitchen_gps ||
            kcfg?.kitchenGps ||
            kcfg?.kitchen?.gps ||
            kcfg?.kitchen?.gps_point ||
            null;
        const kLat = kGps ? Number(kGps.latitude) : NaN;
        const kLng = kGps ? Number(kGps.longitude) : NaN;
        const gpsPointValid = Number.isFinite(kLat) && Number.isFinite(kLng);
        const latN0 = Number(latitude);
        const lngN0 = Number(longitude);
        const hasEventGps = Number.isFinite(latN0) && Number.isFinite(lngN0) && Math.abs(latN0) <= 90 && Math.abs(lngN0) <= 180;
        if (!gpsPointValid) {
            return res.status(400).json({ error: 'Titik GPS dapur belum diset admin — absensi tidak dapat divalidasi jarak.' });
        }
        if (!hasEventGps) {
            return res.status(400).json({ error: 'Lokasi GPS wajib untuk absensi — izinkan lokasi atau coba lagi di area sinyal lebih baik.' });
        }
        const dist0 = haversineDistanceMeters(latN0, lngN0, kLat, kLng);
        if (dist0 > maxGeoRadiusM) {
            return res.status(400).json({
                error: `Lokasi di luar radius kebijakan (${Math.round(maxGeoRadiusM)}m). Jarak terukur ~${Math.round(dist0)}m.`,
                distance_m: Math.round(dist0),
                max_geo_radius_m: Math.round(maxGeoRadiusM),
            });
        }
        const active = await getActiveSubscription(tid);
        const planCode = String(active?.plan?.code || '').toUpperCase();
        const rawMb = active?.plan?.limits?.max_db_mb;
        let maxMb = Number(rawMb);
        if (!Number.isFinite(maxMb) || maxMb <= 0) {
            const fallback = { FREE: 50, TRIAL: 200, PRO: 1024, ENTERPRISE: 5000 };
            maxMb = fallback[planCode] || 1024;
        }
        const maxDbBytes = Math.floor(maxMb * 1024 * 1024);
        const tenantDbPathValue = tenantDbPath(tid);

        await dbContext.run(
            { db: tdb, tenantId: tid, maxDbBytes, tenantDbPath: tenantDbPathValue },
            async () => {
            const ingestStartedAt = Date.now();
            const clientEventId = normalizeClientEventId(client_event_id);
            if (clientEventId) {
                const existing = await findAttendanceEventByClientEventId(tid, clientEventId);
                if (existing) {
                    console.log(`[FACE ATTENDANCE] direct tenant=${tid} duplicate=yes client_event_id=${clientEventId}`);
                    return res.json({
                        id: existing.id,
                        staff_id: existing.staff_id || null,
                        event_type: existing.event_type,
                        occurred_at: existing.occurred_at,
                        staff_name: null,
                        note: existing.note || '',
                        duplicate: true,
                        client_event_id: clientEventId,
                    });
                }
            }
            const staff = await get(
                'SELECT id, name, division_id, staff_code FROM staff WHERE tenant_id = ? COLLATE NOCASE AND staff_code = ? COLLATE NOCASE',
                [tid, scode]
            );
            if (!staff) return res.status(404).json({ error: 'Staff not found' });

            const now = new Date();
            const nowIso = now.toISOString();
            const occ = occurred_at || nowIso;
            const workDate = jakartaYmdFromIso(occ);
            const lateGraceMinutes = Math.max(0, Number(attendancePolicy.late_grace_minutes || 10));

            const todayEvs = await loadAttendanceEventsForWorkDate(tid, staff.id, workDate);
            if (event_type === 'CLOCK_IN' && todayEvs.some(e => e.event_type === 'CLOCK_IN')) {
                return res.status(400).json({ error: 'Anda sudah melakukan Absen Masuk (Clock In) hari ini.' });
            }
            if (event_type === 'CLOCK_OUT' && todayEvs.some(e => e.event_type === 'CLOCK_OUT')) {
                return res.status(400).json({ error: 'Anda sudah melakukan Absen Pulang (Clock Out) hari ini.' });
            }

            let finalNote = note || '';

            if (event_type === 'CLOCK_IN' || event_type === 'CLOCK_OUT') {
                try {
                    // Robust shift lookup: check assignments first, then division fallback, then "all" fallback.
                    // We check for both req-passed tenant id and its sanitized version (incase of mismatch in DB).
                    const stid = sanitizeTenantId(tid);

                    let shift = await get(`
                        SELECT s.start_time, s.end_time 
                        FROM staff_shift_assignments ssa
                        JOIN shifts s ON s.id = ssa.shift_id
                        WHERE (ssa.tenant_id = ? OR ssa.tenant_id = ?) AND ssa.staff_id = ? AND ssa.work_date = ?
                    `, [tid, stid, staff.id, workDate]);

                    if (!shift) {
                        // Fallback order: Specific Division -> "all"
                        shift = await get(`
                            SELECT start_time, end_time 
                            FROM shifts 
                            WHERE (tenant_id = ? OR tenant_id = ?) AND (division_id = ? OR division_id = 'all')
                            ORDER BY (CASE WHEN division_id = 'all' THEN 1 ELSE 0 END) ASC, created_at ASC LIMIT 1
                        `, [tid, stid, staff.division_id || 'UNKNOWN']);
                    }

                    if (shift) {
                        const occDate = new Date(occ);
                        const occTotalMinutes = (occDate.getHours() * 60) + occDate.getMinutes();

                        if (event_type === 'CLOCK_IN' && shift.start_time) {
                            const [sHour, sMin] = shift.start_time.split(':').map(Number);
                            const shiftTotalMinutes = (sHour * 60) + sMin;
                            if (occTotalMinutes > shiftTotalMinutes + lateGraceMinutes) {
                                finalNote = (finalNote ? finalNote + ' ' : '') + 'Terlambat';
                            } else {
                                finalNote = (finalNote ? finalNote + ' ' : '') + 'Tepat Waktu';
                            }
                        } else if (event_type === 'CLOCK_OUT' && shift.end_time) {
                            const [eHour, eMin] = shift.end_time.split(':').map(Number);
                            const shiftEndTotal = (eHour * 60) + eMin;
                            if (occTotalMinutes < shiftEndTotal - lateGraceMinutes) {
                                finalNote = (finalNote ? finalNote + ' ' : '') + 'Pulang Awal';
                            } else {
                                finalNote = (finalNote ? finalNote + ' ' : '') + 'Sesuai Jadwal';
                            }
                        }
                        finalNote = finalNote.trim();
                    }
                } catch (err) {
                    console.error('[SHIFT CHECK ERROR]', err);
                }
            }

            const meta = {
                name: staff.name,
                division_id: staff.division_id,
                biometric: true,
                face_portal_snapshot: true,
                photo_required: false,
                client_metrics: safeJsonParse(client_metrics, {})
            };
            const p = String(photo_data_url || '').trim();
            if (p.startsWith('data:image/')) {
                meta.attendance_photo = p.length > 400000 ? p.slice(0, 400000) : p;
                meta.photo_required = true;
            }
            const latN = latN0;
            const lngN = lngN0;
            meta.location = {
                latitude: latN,
                longitude: lngN,
                accuracy: geo_accuracy != null && Number.isFinite(Number(geo_accuracy)) ? Number(geo_accuracy) : null,
                captured_at: String(geo_captured_at || occ || nowIso).slice(0, 40)
            };
            meta.policy_max_geo_radius_m = Math.round(maxGeoRadiusM);
            meta.policy_distance_m = Math.round(dist0);
            const meta_json = JSON.stringify(meta);

            const id = crypto.randomUUID();
            await run(
                "INSERT INTO attendance_events (id, tenant_id, staff_id, event_type, occurred_at, source, note, client_event_id, meta_json, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                [id, tid, staff.id, event_type, occ, source || 'face_portal', finalNote, clientEventId || null, meta_json, nowIso]
            );

            try {
                const evs = await loadAttendanceEventsForWorkDate(tid, staff.id, workDate);
                await upsertAttendanceDailyFromEvents({
                    tenantId: tid,
                    staffId: staff.id,
                    workDate,
                    staffDivisionId: staff.division_id || '',
                    events: evs,
                    nowIso,
                    note: 'AUTO_FACE_PORTAL'
                });
            } catch (reErr) { console.error('Auto-recompute error:', reErr); }

            const ingestMs = Date.now() - ingestStartedAt;
            const clientPhotoBytes = Number(safeJsonParse(client_metrics, {})?.photo_bytes || 0);
            console.log(
                `[FACE ATTENDANCE] direct tenant=${tid} staff=${staff.id} type=${event_type} duplicate=no ingest_ms=${ingestMs} photo_bytes=${clientPhotoBytes || 0}`
            );
            res.json({
                id,
                staff_id: staff.id,
                event_type,
                occurred_at: occ,
                staff_name: staff.name,
                note: finalNote,
                duplicate: false,
                client_event_id: clientEventId || '',
                ingest_ms: ingestMs,
                photo_bytes: clientPhotoBytes > 0 ? clientPhotoBytes : undefined,
            });
        });
    } catch (e) {
        console.error('[FACE ATTENDANCE ERROR]', e);
        res.status(500).json({ error: e.message });
    }
});

/**
 * Relawan capture absensi: simpan foto + lokasi + waktu ke attendance_events tanpa staff_code/staff_id.
 * Staff_id dan analisis (face match + validasi lokasi + ketepatan waktu) dilakukan belakangan oleh portal staff/HR.
 */
app.post('/api/attendance/events/relawan-capture', async (req, res) => {
    try {
        const {
            tenant_id,
            event_type,
            occurred_at,
            source,
            note,
            photo_data_url,
            latitude,
            longitude,
            geo_accuracy,
            geo_captured_at,
            client_event_id,
            client_metrics,
        } = req.body || {};

        if (!tenant_id || !event_type) {
            return res.status(400).json({ error: 'tenant_id dan event_type wajib diisi' });
        }

        const tid = String(tenant_id || '').trim();
        if (!tid) return res.status(400).json({ error: 'tenant_id wajib diisi' });
        const tdb = await ensureTenantDb(tid);
        await ensureStaffSchemaForTenantId(tid);
        const attendancePolicy = await getAttendancePolicySafe();
        const maxGeoRadiusM = Math.max(10, Number(attendancePolicy.max_geo_radius_m || 50));
        const kcfg = await getKitchenConfigSafe();
        const kGps =
            kcfg?.kitchen_gps ||
            kcfg?.kitchenGps ||
            kcfg?.kitchen?.gps ||
            kcfg?.kitchen?.gps_point ||
            null;
        const kLat = kGps ? Number(kGps.latitude) : NaN;
        const kLng = kGps ? Number(kGps.longitude) : NaN;
        const gpsPointValid = Number.isFinite(kLat) && Number.isFinite(kLng);
        const latN0 = Number(latitude);
        const lngN0 = Number(longitude);
        const hasEventGps = Number.isFinite(latN0) && Number.isFinite(lngN0) && Math.abs(latN0) <= 90 && Math.abs(lngN0) <= 180;
        if (!gpsPointValid) {
            return res.status(400).json({ error: 'Titik GPS dapur belum diset admin — absensi tidak dapat divalidasi jarak.' });
        }
        if (!hasEventGps) {
            return res.status(400).json({ error: 'Lokasi GPS wajib untuk absensi — izinkan lokasi atau coba lagi di area sinyal lebih baik.' });
        }
        const dist0 = haversineDistanceMeters(latN0, lngN0, kLat, kLng);
        if (dist0 > maxGeoRadiusM) {
            return res.status(400).json({
                error: `Lokasi di luar radius kebijakan (${Math.round(maxGeoRadiusM)}m). Jarak terukur ~${Math.round(dist0)}m.`,
                distance_m: Math.round(dist0),
                max_geo_radius_m: Math.round(maxGeoRadiusM),
            });
        }

        const active = await getActiveSubscription(tid);
        const planCode = String(active?.plan?.code || '').toUpperCase();
        const rawMb = active?.plan?.limits?.max_db_mb;
        let maxMb = Number(rawMb);
        if (!Number.isFinite(maxMb) || maxMb <= 0) {
            const fallback = { FREE: 50, TRIAL: 200, PRO: 1024, ENTERPRISE: 5000 };
            maxMb = fallback[planCode] || 1024;
        }
        const maxDbBytes = Math.floor(maxMb * 1024 * 1024);
        const tenantDbPathValue = tenantDbPath(tid);

        await dbContext.run(
            { db: tdb, tenantId: tid, maxDbBytes, tenantDbPath: tenantDbPathValue },
            async () => {
                const ingestStartedAt = Date.now();
                const clientEventId = normalizeClientEventId(client_event_id);
                if (clientEventId) {
                    const existing = await findAttendanceEventByClientEventId(tid, clientEventId);
                    if (existing) {
                        console.log(`[FACE ATTENDANCE] relawan tenant=${tid} duplicate=yes client_event_id=${clientEventId}`);
                        return res.json({
                            id: existing.id,
                            tenant_id: tid,
                            event_type: existing.event_type,
                            occurred_at: existing.occurred_at,
                            status: 'CAPTURED',
                            duplicate: true,
                            client_event_id: clientEventId,
                        });
                    }
                }
                const now = new Date();
                const nowIso = now.toISOString();
                const occ = occurred_at || nowIso;

                const finalNote = String(note || '').trim();

                // Meta untuk kebutuhan analisis belakangan (HR/portal staff).
                const meta = {
                    biometric: true,
                    face_portal_snapshot: true,
                    analysis_done: false,
                    photo_required: false,
                    client_metrics: safeJsonParse(client_metrics, {}),
                };

                const p = String(photo_data_url || '').trim();
                if (p.startsWith('data:image/')) {
                    meta.attendance_photo = p.length > 400000 ? p.slice(0, 400000) : p;
                    meta.photo_required = true;
                }

                const latN = latN0;
                const lngN = lngN0;
                meta.location = {
                    latitude: latN,
                    longitude: lngN,
                    accuracy:
                        geo_accuracy != null && Number.isFinite(Number(geo_accuracy))
                            ? Number(geo_accuracy)
                            : null,
                    captured_at: String(geo_captured_at || occ || nowIso).slice(0, 40),
                };
                meta.policy_max_geo_radius_m = Math.round(maxGeoRadiusM);
                meta.policy_distance_m = Math.round(dist0);

                const id = crypto.randomUUID();
                await run(
                    "INSERT INTO attendance_events (id, tenant_id, staff_id, event_type, occurred_at, source, note, client_event_id, meta_json, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                    [
                        id,
                        tid,
                        null,
                        event_type,
                        occ,
                        source || 'face_portal',
                        finalNote,
                        clientEventId || null,
                        JSON.stringify(meta),
                        nowIso,
                    ]
                );

                const ingestMs = Date.now() - ingestStartedAt;
                const clientPhotoBytes = Number(safeJsonParse(client_metrics, {})?.photo_bytes || 0);
                console.log(
                    `[FACE ATTENDANCE] relawan tenant=${tid} type=${event_type} duplicate=no ingest_ms=${ingestMs} photo_bytes=${clientPhotoBytes || 0}`
                );
                res.json({
                    id,
                    tenant_id: tid,
                    event_type,
                    occurred_at: occ,
                    status: 'CAPTURED',
                    duplicate: false,
                    client_event_id: clientEventId || '',
                    ingest_ms: ingestMs,
                    photo_bytes: clientPhotoBytes > 0 ? clientPhotoBytes : undefined,
                });
            }
        );
    } catch (e) {
        console.error('[RELawan CAPTURE ERROR]', e);
        res.status(500).json({ error: e.message });
    }
});

// Optional async GPS update for relawan portal: lets submit complete quickly without waiting long geolocation.
app.post('/api/attendance/events/:id/location', async (req, res) => {
    try {
        const eventId = String(req.params.id || '').trim();
        const tenantFromBody = String(req.body?.tenant_id || '').trim();
        const tenantFromHeader = (() => {
            try { return String(getTenantIdFromReq(req) || '').trim(); } catch (e) { return ''; }
        })();
        const tid = tenantFromBody || tenantFromHeader;
        if (!eventId || !tid) return res.status(400).json({ error: 'event_id and tenant_id wajib diisi' });

        const lat = Number(req.body?.latitude);
        const lng = Number(req.body?.longitude);
        if (!Number.isFinite(lat) || !Number.isFinite(lng) || Math.abs(lat) > 90 || Math.abs(lng) > 180) {
            return res.status(400).json({ error: 'Koordinat tidak valid' });
        }
        const acc = req.body?.geo_accuracy != null && Number.isFinite(Number(req.body.geo_accuracy))
            ? Number(req.body.geo_accuracy)
            : null;
        const capAt = String(req.body?.geo_captured_at || new Date().toISOString()).slice(0, 40);

        const attendancePolicy = await getAttendancePolicySafe();
        const maxGeoRadiusM = Math.max(10, Number(attendancePolicy.max_geo_radius_m || 50));
        const kcfg = await getKitchenConfigSafe();
        const kGps =
            kcfg?.kitchen_gps ||
            kcfg?.kitchenGps ||
            kcfg?.kitchen?.gps ||
            kcfg?.kitchen?.gps_point ||
            null;
        const kLat = kGps ? Number(kGps.latitude) : NaN;
        const kLng = kGps ? Number(kGps.longitude) : NaN;
        const gpsPointValid = Number.isFinite(kLat) && Number.isFinite(kLng);
        if (!gpsPointValid) {
            return res.status(400).json({ error: 'Titik GPS dapur belum diset admin — lokasi tidak dapat divalidasi jarak.' });
        }
        const distPatch = haversineDistanceMeters(lat, lng, kLat, kLng);
        if (distPatch > maxGeoRadiusM) {
            return res.status(400).json({
                error: `Lokasi di luar radius kebijakan (${Math.round(maxGeoRadiusM)}m). Jarak terukur ~${Math.round(distPatch)}m.`,
                distance_m: Math.round(distPatch),
                max_geo_radius_m: Math.round(maxGeoRadiusM),
            });
        }

        const tdb = await ensureTenantDb(tid);
        await ensureStaffSchemaForTenantId(tid);
        const active = await getActiveSubscription(tid);
        const planCode = String(active?.plan?.code || '').toUpperCase();
        const rawMb = active?.plan?.limits?.max_db_mb;
        let maxMb = Number(rawMb);
        if (!Number.isFinite(maxMb) || maxMb <= 0) {
            const fallback = { FREE: 50, TRIAL: 200, PRO: 1024, ENTERPRISE: 5000 };
            maxMb = fallback[planCode] || 1024;
        }
        const maxDbBytes = Math.floor(maxMb * 1024 * 1024);

        await dbContext.run(
            { db: tdb, tenantId: tid, maxDbBytes, tenantDbPath: tenantDbPath(tid) },
            async () => {
                const row = await get(
                    "SELECT id, meta_json FROM attendance_events WHERE tenant_id = ? AND id = ? LIMIT 1",
                    [tid, eventId]
                );
                if (!row) return res.status(404).json({ error: 'Event tidak ditemukan' });
                const meta = safeJsonParse(row.meta_json, {});
                meta.location = {
                    latitude: lat,
                    longitude: lng,
                    accuracy: acc,
                    captured_at: capAt,
                };
                meta.policy_max_geo_radius_m = Math.round(maxGeoRadiusM);
                meta.policy_distance_m = Math.round(distPatch);
                await run(
                    "UPDATE attendance_events SET meta_json = ? WHERE tenant_id = ? AND id = ?",
                    [JSON.stringify(meta), tid, eventId]
                );
                res.json({ ok: true, id: eventId, tenant_id: tid, location_updated: true });
            }
        );
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

/**
 * Analisis bulk absensi relawan:
 * - face match dari snapshot di meta_json.attendance_photo
 * - cek lokasi vs titik GPS dapur radius 50m
 * - hitung catatan ketepatan waktu (logika existing shift)
 * - update staff_id + note + meta_json.analysis_done
 *
 * (Overwrite ulang seluruh event dalam rentang yang dipilih).
 * Body opsional: only_wajah_tidak_cocok: true → hanya event dengan catatan "Wajah tidak cocok" (deteksi ulang).
 */
app.post('/api/attendance/events/relawan/analyze-bulk', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const { from, to } = req.body || {};
            const body = req.body || {};
            const onlyWajahTidakCocok =
                body.only_wajah_tidak_cocok === true ||
                String(body.only_wajah_tidak_cocok || '').toLowerCase() === 'true';
            const forceReanalyze =
                body.force_reanalyze === true ||
                String(body.force_reanalyze || '').toLowerCase() === 'true';
            const batchLimit = Math.max(10, Math.min(500, parseInt(body.batch_limit || 120, 10) || 120));
            const tid = getTenantIdFromReq(req);

            const fromIso = from ? String(from).trim() : null;
            const toIso = to ? String(to).trim() : null;

            const now = new Date();
            const nowIso = now.toISOString();
            const occFrom = fromIso && !isNaN(new Date(fromIso).getTime()) ? fromIso : new Date(now.setHours(0, 0, 0, 0)).toISOString();
            // "to" end-of-day if missing
            const occTo = toIso && !isNaN(new Date(toIso).getTime()) ? toIso : new Date(nowIso).toISOString();

            const tdb = await ensureTenantDb(tid);
            await ensureStaffSchemaForTenantId(tid);

            // Load kitchen GPS config for location validation.
            const kcfg = await getKitchenConfigSafe();
            const kGps =
                kcfg?.kitchen_gps ||
                kcfg?.kitchenGps ||
                kcfg?.kitchen?.gps ||
                kcfg?.kitchen?.gps_point ||
                null;
            const kLat = kGps ? Number(kGps.latitude) : NaN;
            const kLng = kGps ? Number(kGps.longitude) : NaN;
            const gpsPointValid = Number.isFinite(kLat) && Number.isFinite(kLng);
            const attendancePolicy = await getAttendancePolicySafe();
            const maxGeoRadiusM = Math.max(10, Number(attendancePolicy.max_geo_radius_m || 50));

            const active = await getActiveSubscription(tid);
            const planCode = String(active?.plan?.code || '').toUpperCase();
            const rawMb = active?.plan?.limits?.max_db_mb;
            let maxMb = Number(rawMb);
            if (!Number.isFinite(maxMb) || maxMb <= 0) {
                const fallback = { FREE: 50, TRIAL: 200, PRO: 1024, ENTERPRISE: 5000 };
                maxMb = fallback[planCode] || 1024;
            }
            const maxDbBytes = Math.floor(maxMb * 1024 * 1024);
            const tenantDbPathValue = tenantDbPath(tid);

            const results = {
                processed: 0,
                updated: 0,
                skipped_no_photo: 0,
                failed_face: 0,
                failed: 0,
                recognize_calls: 0,
                recognize_cache_hits: 0,
                recognize_ms_total: 0,
                recognize_upstream_errors: 0,
            };

            if (forceReanalyze || onlyWajahTidakCocok) {
                FACE_RECOGNITION_CACHE.clear();
            }

            const _faceConnPre = getFaceApiConnect();
            const faceApiOk = await checkFaceApiHealth(_faceConnPre.hostname, _faceConnPre.port);
            if (!faceApiOk) {
                return res.json({
                    ok: false,
                    face_api_unreachable: true,
                    face_api_target: `http://${_faceConnPre.hostname}:${_faceConnPre.port}`,
                    message:
                        'Face API (Python) tidak dijalankan atau tidak terjangkau di alamat ini. Jalankan layanan wajah (biasanya port 5000), lalu ulangi analisis. Rata-rata ~5 ms per recognize biasanya berarti koneksi ditolak, bukan inferensi model.',
                    tenant_id: tid,
                    from: occFrom,
                    to: occTo,
                    only_wajah_tidak_cocok: onlyWajahTidakCocok,
                    force_reanalyze: forceReanalyze,
                    batch_limit: batchLimit,
                    eligible_in_range: 0,
                    recognize_avg_ms: 0,
                    ...results,
                });
            }

            await dbContext.run(
                { db: tdb, tenantId: tid, maxDbBytes, tenantDbPath: tenantDbPathValue },
                async () => {
                    // Fetch candidates and overwrite analysis results.
                    let sql = `
                        SELECT id, event_type, occurred_at, source, note, staff_id, meta_json
                        FROM attendance_events
                        WHERE tenant_id = ? AND occurred_at BETWEEN ? AND ?`;
                    const qparams = [tid, occFrom, occTo];
                    if (onlyWajahTidakCocok) {
                        sql += ` AND LOWER(TRIM(IFNULL(note, ''))) = 'wajah tidak cocok'`;
                    }
                    if (!forceReanalyze) {
                        sql += ` AND (
                            meta_json IS NULL OR TRIM(meta_json) = '' OR
                            LOWER(meta_json) NOT LIKE '%"analysis_done":true%' OR
                            LOWER(meta_json) LIKE '%"analysis_error":"face_not_match"%' OR
                            LOWER(meta_json) LIKE '%"analysis_error":"staff_not_found_in_db"%'
                        )`;
                    }
                    sql += ` ORDER BY datetime(occurred_at) ASC LIMIT ?`;
                    qparams.push(batchLimit);
                    const rows = await all(sql, qparams);

                    for (const r of rows || []) {
                        const meta = safeJsonParse(r.meta_json, {});
                        if (!meta?.face_portal_snapshot || !meta?.attendance_photo) {
                            results.skipped_no_photo += 1;
                            // Mark as done to avoid repeated attempts.
                            meta.analysis_done = true;
                            meta.analysis_error = 'NO_PHOTO';
                            await run(
                                "UPDATE attendance_events SET meta_json = ? WHERE id = ? AND tenant_id = ?",
                                [JSON.stringify(meta), r.id, tid]
                            );
                            continue;
                        }

                        results.processed += 1;

                        const image_data = String(meta.attendance_photo || '').trim();

                        // 1) Face recognize -> staffId
                        pruneFaceRecognitionCache();
                        const faceCacheKey = buildFaceCacheKey(tid, image_data);
                        let rec = FACE_RECOGNITION_CACHE.get(faceCacheKey)?.result || null;
                        if (!rec) {
                            const recognizeStartedAt = Date.now();
                            results.recognize_calls += 1;
                            rec = await (async () => {
                                const _faceRec = getFaceApiConnect();
                                return new Promise((resolve) => {
                                    const pyReq = http.request(
                                        {
                                            hostname: _faceRec.hostname,
                                            port: _faceRec.port,
                                            path: '/recognize',
                                            method: 'POST',
                                            headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
                                        },
                                        pyRes => {
                                            let body = '';
                                            pyRes.on('data', d => body += d);
                                            pyRes.on('end', () => {
                                                try {
                                                    if (pyRes.statusCode >= 400) {
                                                        return resolve({ verified: false, staff_id: '', error: body });
                                                    }
                                                    const data = body ? JSON.parse(body) : {};
                                                    resolve(data);
                                                } catch (e) {
                                                    resolve({ verified: false, staff_id: '', error: e.message });
                                                }
                                            });
                                        }
                                    );
                                    pyReq.on('error', e => resolve({ verified: false, staff_id: '', error: e.message }));
                                    pyReq.write(`image_data=${encodeURIComponent(image_data)}&tenant_id=${encodeURIComponent(tid)}`);
                                    pyReq.end();
                                });
                            })();
                            results.recognize_ms_total += (Date.now() - recognizeStartedAt);
                            FACE_RECOGNITION_CACHE.set(faceCacheKey, { ts: Date.now(), result: rec });
                        } else {
                            results.recognize_cache_hits += 1;
                        }

                        const verified = !!rec?.verified;
                        const staffId = normalizeFacerecStaffId(rec?.staff_id || '');
                        const upstreamErr = String(rec?.error || '').trim();
                        meta.analysis_rec_last = {
                            verified: !!verified,
                            staff_id: String(rec?.staff_id || '').slice(0, 80),
                            distance: rec?.distance != null && Number.isFinite(Number(rec.distance)) ? Number(rec.distance) : null,
                            message: String(rec?.message || '').slice(0, 240),
                            error: upstreamErr.slice(0, 240)
                        };
                        if (!verified || !staffId) {
                            results.failed_face += 1;
                            meta.analysis_done = true;
                            const transportFail = upstreamErr && isFaceApiTransportError(upstreamErr);
                            if (transportFail) {
                                results.recognize_upstream_errors += 1;
                                meta.analysis_error = 'FACE_API_UNREACHABLE';
                            } else {
                                meta.analysis_error = 'FACE_NOT_MATCH';
                            }
                            const failNote = transportFail
                                ? `Face API tidak terhubung (${upstreamErr.slice(0, 120)})`
                                : 'Wajah tidak cocok';
                            await run(
                                "UPDATE attendance_events SET note = ?, staff_id = ?, meta_json = ? WHERE id = ? AND tenant_id = ?",
                                [failNote, null, JSON.stringify(meta), r.id, tid]
                            );
                            continue;
                        }

                        const staff = await get(
                            'SELECT id, name, division_id FROM staff WHERE tenant_id = ? COLLATE NOCASE AND id = ? COLLATE NOCASE',
                            [tid, staffId]
                        );
                        if (!staff) {
                            results.failed_face += 1;
                            meta.analysis_done = true;
                            meta.analysis_error = 'STAFF_NOT_FOUND_IN_DB';
                            await run(
                                "UPDATE attendance_events SET note = ?, staff_id = ?, meta_json = ? WHERE id = ? AND tenant_id = ?",
                                [
                                    'Foto dikenali tapi ID tidak ada di daftar staff — sinkronkan staff atau daftar ulang wajah.',
                                    null,
                                    JSON.stringify(meta),
                                    r.id,
                                    tid
                                ]
                            );
                            continue;
                        }

                        // 2) Location validate vs kitchen gps
                        let locOk = false;
                        let locReason = '';
                        const loc = meta?.location || {};
                        const lat = Number(loc.latitude);
                        const lng = Number(loc.longitude);
                        if (!gpsPointValid) {
                            locOk = false;
                            locReason = 'KITCHEN_GPS_NOT_SET';
                        } else if (!Number.isFinite(lat) || !Number.isFinite(lng)) {
                            locOk = false;
                            locReason = 'EVENT_GPS_NOT_AVAILABLE';
                        } else {
                            const dist = haversineDistanceMeters(lat, lng, kLat, kLng);
                            locOk = dist <= maxGeoRadiusM;
                            locReason = locOk ? '' : `DIST_${Math.round(dist)}_M`;
                        }

                        // 3) Existing shift time note
                        const occ = r.occurred_at;
                        const occDate = new Date(occ);
                        const occTotalMinutes = (occDate.getHours() * 60) + occDate.getMinutes();
                        const workDate = jakartaYmdFromIso(occ);

                        let timeNote = '';
                        try {
                            const stid = sanitizeTenantId(tid);
                            let shift = await get(`
                                SELECT s.start_time, s.end_time
                                FROM staff_shift_assignments ssa
                                JOIN shifts s ON s.id = ssa.shift_id
                                WHERE (ssa.tenant_id = ? OR ssa.tenant_id = ?) AND ssa.staff_id = ? AND ssa.work_date = ?
                            `, [tid, stid, staff.id, workDate]);

                            if (!shift) {
                                shift = await get(`
                                    SELECT start_time, end_time
                                    FROM shifts
                                    WHERE (tenant_id = ? OR tenant_id = ?) AND (division_id = ? OR division_id = 'all')
                                    ORDER BY (CASE WHEN division_id = 'all' THEN 1 ELSE 0 END) ASC, created_at ASC LIMIT 1
                                `, [tid, stid, staff.division_id || 'UNKNOWN']);
                            }

                            if (shift) {
                                if (r.event_type === 'CLOCK_IN' && shift.start_time) {
                                    const [sHour, sMin] = shift.start_time.split(':').map(Number);
                                    const shiftTotalMinutes = (sHour * 60) + sMin;
                                    const lateGraceMinutes = Math.max(0, Number(attendancePolicy.late_grace_minutes || 10));
                                    timeNote = occTotalMinutes > shiftTotalMinutes + lateGraceMinutes ? 'Terlambat' : 'Tepat Waktu';
                                } else if (r.event_type === 'CLOCK_OUT' && shift.end_time) {
                                    const [eHour, eMin] = shift.end_time.split(':').map(Number);
                                    const shiftEndTotal = (eHour * 60) + eMin;
                                    const lateGraceMinutes = Math.max(0, Number(attendancePolicy.late_grace_minutes || 10));
                                    timeNote = occTotalMinutes < shiftEndTotal - lateGraceMinutes ? 'Pulang Awal' : 'Sesuai Jadwal';
                                }
                            }
                        } catch (e) {
                            console.error('[RELawan ANALYZE SHIFT ERROR]', e);
                        }

                        const locNote = locOk ? '' : `Lokasi tidak sesuai (>${Math.round(maxGeoRadiusM)}m)`;
                        const finalNote = locNote && timeNote ? `${locNote} - ${timeNote}` : (locNote || timeNote || '');

                        // 4) Update event -> staff_id + note + mark done.
                        meta.analysis_done = true;
                        meta.analysis_error = '';
                        meta.analysis_face_verified = true;
                        meta.analysis_location_ok = locOk;
                        if (locReason && locReason.startsWith('DIST_')) {
                            const m = Number(locReason.replace('DIST_', '').replace('_M', ''));
                            if (Number.isFinite(m)) meta.analysis_distance_m = m;
                        }
                        meta.analysis_final_note = finalNote;
                        meta.analysis_work_date = workDate;

                        await run(
                            "UPDATE attendance_events SET staff_id = ?, note = ?, meta_json = ? WHERE id = ? AND tenant_id = ?",
                            [locOk ? staff.id : null, finalNote, JSON.stringify(meta), r.id, tid]
                        );

                        // Jika lokasi tidak sesuai: staff_id tetap NULL dan attendance_daily tidak dibuat/diperbarui.
                        if (!locOk) {
                            results.updated += 1;
                            continue;
                        }

                        // 5) Recompute attendance_daily for this staff+workDate
                        const evs = await loadAttendanceEventsForWorkDate(tid, staff.id, workDate);
                        await upsertAttendanceDailyFromEvents({
                            tenantId: tid,
                            staffId: staff.id,
                            workDate,
                            staffDivisionId: staff.division_id || '',
                            events: evs,
                            nowIso,
                            note: 'AUTO_BULK_ANALYZE'
                        });

                        results.updated += 1;
                    }

                    res.json({
                        ok: true,
                        tenant_id: tid,
                        from: occFrom,
                        to: occTo,
                        only_wajah_tidak_cocok: onlyWajahTidakCocok,
                        force_reanalyze: forceReanalyze,
                        batch_limit: batchLimit,
                        eligible_in_range: (rows || []).length,
                        max_geo_radius_m: maxGeoRadiusM,
                        policy: attendancePolicy,
                        recognize_avg_ms: results.recognize_calls > 0
                            ? Math.round(results.recognize_ms_total / results.recognize_calls)
                            : 0,
                        face_api_target: `http://${_faceConnPre.hostname}:${_faceConnPre.port}`,
                        ...results,
                    });
                }
            );
        } catch (e) {
            console.error('[RELawan ANALYZE-BULK ERROR]', e);
            res.status(500).json({ error: e.message });
        }
    });
});

app.get('/api/attendance/events/raw', async (req, res) => {
    try {
        const { tenant_id, staff_code, from, to } = req.query;
        if (!tenant_id || !staff_code) return res.status(400).json({ error: 'Tenant and Staff Code required' });

        const tid = String(tenant_id || '').trim();
        const scode = String(staff_code || '').trim();
        const tdb = await ensureTenantDb(tid);
        await ensureStaffSchemaForTenantId(tid);
        const active = await getActiveSubscription(tid);
        const planCode = String(active?.plan?.code || '').toUpperCase();
        const rawMb = active?.plan?.limits?.max_db_mb;
        let maxMb = Number(rawMb);
        if (!Number.isFinite(maxMb) || maxMb <= 0) {
            const fallback = { FREE: 50, TRIAL: 200, PRO: 1024, ENTERPRISE: 5000 };
            maxMb = fallback[planCode] || 1024;
        }
        const maxDbBytes = Math.floor(maxMb * 1024 * 1024);

        await dbContext.run(
            { db: tdb, tenantId: tid, maxDbBytes, tenantDbPath: tenantDbPath(tid) },
            async () => {
                const staff = await get(
                    'SELECT id FROM staff WHERE tenant_id = ? COLLATE NOCASE AND staff_code = ? COLLATE NOCASE',
                    [tid, scode]
                );
                if (!staff) return res.status(404).json({ error: 'Staff not found' });
                const rows = await all(
                    'SELECT * FROM attendance_events WHERE tenant_id = ? AND staff_id = ? AND occurred_at BETWEEN ? AND ? ORDER BY occurred_at DESC',
                    [tid, staff.id, from, to]
                );
                const parsed = rows.map(r => ({
                    ...r,
                    meta_json: typeof r.meta_json === 'string' ? JSON.parse(r.meta_json) : (r.meta_json || {})
                }));
                res.json(parsed);
            });
    } catch (e) {
        console.error('[HISTORY ERROR]', e);
        res.status(500).json({ error: e.message });
    }
});

app.post('/api/attendance/events', async (req, res) => {
    try {
        const tenantId = getTenantIdFromReq(req);
            const { staff_id, event_type, occurred_at, source, note, meta_json, client_event_id } = req.body;
            
            if (!staff_id || !event_type || !occurred_at) {
                return res.status(400).json({ error: 'Missing required fields' });
            }

            const clientEventId = normalizeClientEventId(client_event_id);
            const eventId = crypto.randomUUID();
            const now = new Date().toISOString();
            const attendancePolicy = await getAttendancePolicySafe();
            const lateGraceMinutes = Math.max(0, Number(attendancePolicy.late_grace_minutes || 10));
            
            let finalNote = note || '';
            const workDate = jakartaYmdFromIso(occurred_at);
            let duplicateResponse = null;
            
            await withTenantDatabase(tenantId, async () => {
                if (clientEventId) {
                    const existing = await findAttendanceEventByClientEventId(tenantId, clientEventId);
                    if (existing) {
                        duplicateResponse = { success: true, id: existing.id, note: existing.note || '', duplicate: true, client_event_id: clientEventId };
                        return;
                    }
                }
                const staff = await get("SELECT division_id FROM staff WHERE id = ?", [staff_id]);
                if (!staff) throw new Error('Staff not found');

                const todayEvs = await loadAttendanceEventsForWorkDate(tenantId, staff_id, workDate);
                if (event_type === 'CLOCK_IN' && todayEvs.some(e => e.event_type === 'CLOCK_IN')) {
                    throw new Error('Anda sudah melakukan Absen Masuk (Clock In) hari ini.');
                }
                if (event_type === 'CLOCK_OUT' && todayEvs.some(e => e.event_type === 'CLOCK_OUT')) {
                    throw new Error('Anda sudah melakukan Absen Pulang (Clock Out) hari ini.');
                }
                
                if (event_type === 'CLOCK_IN' || event_type === 'CLOCK_OUT') {
                    try {
                        // Same robust matching logic for manual events
                        const stid = sanitizeTenantId(tenantId);
                        let shift = await get(`
                            SELECT s.start_time, s.end_time 
                            FROM staff_shift_assignments ssa
                            JOIN shifts s ON s.id = ssa.shift_id
                            WHERE (ssa.tenant_id = ? OR ssa.tenant_id = ?) AND ssa.staff_id = ? AND ssa.work_date = ?
                        `, [tenantId, stid, staff_id, workDate]);

                        if (!shift) {
                            // Fallback order: Specific Division -> "all"
                            shift = await get(`
                                SELECT start_time, end_time 
                                FROM shifts 
                                WHERE (tenant_id = ? OR tenant_id = ?) AND (division_id = ? OR division_id = 'all')
                                ORDER BY (CASE WHEN division_id = 'all' THEN 1 ELSE 0 END) ASC, created_at ASC LIMIT 1
                            `, [tenantId, stid, staff.division_id || 'UNKNOWN']);
                        }

                        if (shift) {
                            const occDate = new Date(occurred_at);
                            const occTotalMinutes = (occDate.getHours() * 60) + occDate.getMinutes();

                            if (event_type === 'CLOCK_IN' && shift.start_time) {
                                const [sHour, sMin] = shift.start_time.split(':').map(Number);
                                const shiftTotalMinutes = (sHour * 60) + sMin;
                                if (occTotalMinutes > shiftTotalMinutes + lateGraceMinutes) {
                                    finalNote = (finalNote ? finalNote + ' ' : '') + 'Terlambat';
                                } else {
                                    finalNote = (finalNote ? finalNote + ' ' : '') + 'Tepat Waktu';
                                }
                            } else if (event_type === 'CLOCK_OUT' && shift.end_time) {
                                const [eHour, eMin] = shift.end_time.split(':').map(Number);
                                const shiftEndTotal = (eHour * 60) + eMin;
                                if (occTotalMinutes < shiftEndTotal - lateGraceMinutes) {
                                    finalNote = (finalNote ? finalNote + ' ' : '') + 'Pulang Awal';
                                } else {
                                    finalNote = (finalNote ? finalNote + ' ' : '') + 'Sesuai Jadwal';
                                }
                            }
                            finalNote = finalNote.trim();
                        }
                    } catch (err) {
                        console.error('[SHIFT CHECK ERROR]', err);
                    }
                }

                await run(
                    "INSERT INTO attendance_events (id, tenant_id, staff_id, event_type, occurred_at, source, note, client_event_id, meta_json, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                    [eventId, tenantId, staff_id, event_type, occurred_at, source || 'staff_portal', finalNote, clientEventId || null, JSON.stringify(meta_json || {}), now]
                );

                try {
                    const evs = await loadAttendanceEventsForWorkDate(tenantId, staff_id, workDate);
                    await upsertAttendanceDailyFromEvents({
                        tenantId,
                        staffId: staff_id,
                        workDate,
                        staffDivisionId: staff.division_id || '',
                        events: evs,
                        nowIso: now,
                        note: 'AUTO_MANUAL_EVENT'
                    });
                } catch (reErr) { console.error('Auto-recompute error:', reErr); }
            });
            if (duplicateResponse) return res.json(duplicateResponse);
            res.json({ success: true, id: eventId, note: finalNote, duplicate: false, client_event_id: clientEventId || '' });
        } catch (e) {
            console.error('Error creating manual attendance event:', e);
            res.status(500).json({ error: e.message });
        }
});

app.get('/api/attendance/daily', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const work_date = String(req.query.work_date || '').trim();
            const staff_id = String(req.query.staff_id || '').trim();
            const from_date = String(req.query.from_date || '').trim();
            const to_date = String(req.query.to_date || '').trim();
            let sql = `
                SELECT d.staff_id, s.name AS staff_name, d.work_date, d.shift_id, sh.name AS shift_name,
                       d.minutes_worked, d.late_minutes, d.overtime_minutes, d.status, d.note
                FROM attendance_daily d
                JOIN staff s ON s.id = d.staff_id
                LEFT JOIN shifts sh ON sh.id = d.shift_id
                WHERE d.tenant_id = ?
            `;
            const params = [tenantId];
            if (work_date) { sql += " AND d.work_date = ?"; params.push(work_date); }
            if (staff_id) { sql += " AND d.staff_id = ?"; params.push(staff_id); }
            if (from_date) { sql += " AND d.work_date >= ?"; params.push(from_date); }
            if (to_date) { sql += " AND d.work_date <= ?"; params.push(to_date); }
            sql += " ORDER BY d.work_date DESC, s.name LIMIT 5000";
            const rows = await all(sql, params);

            // Hydrate clock_in_at / clock_out_at dari attendance_events.
            // Agregasi dilakukan di Node (bukan SQL) karena:
            //  1) SQLite datetime() tidak selalu kompatibel dengan ISO millisecond/Z
            //     sehingga konversi zona waktu paling robust lewat jakartaYmdFromIso.
            //  2) Pemilihan clock_in/out harus konsisten dengan cara minutes_worked
            //     dihitung di calcWorkedMinutesFromEvents (berbasis pasangan sesi).
            //     Tanpa ini, staff yang double-tap CLOCK_OUT atau ada event yatim
            //     bisa menampilkan span "02:00–10:46" tapi durasi "4j 51m" — membingungkan.
            if (rows.length > 0) {
                const staffIds = Array.from(new Set(rows.map(r => r.staff_id).filter(Boolean)));
                const workDates = rows.map(r => r.work_date).filter(Boolean).sort();
                const minWorkDate = workDates[0];
                const maxWorkDate = workDates[workDates.length - 1];
                // Buffer 1 hari ke luar untuk event yang occurred_at UTC tapi jatuh di Jakarta day dalam range.
                const evFrom = addDaysYmd(minWorkDate, -1);
                const evTo = addDaysYmd(maxWorkDate, 1);
                if (staffIds.length > 0 && evFrom && evTo) {
                    const placeholders = staffIds.map(() => '?').join(',');
                    const evRows = await all(
                        `SELECT staff_id, event_type, occurred_at
                           FROM attendance_events
                          WHERE tenant_id = ?
                            AND staff_id IN (${placeholders})
                            AND date(occurred_at) BETWEEN ? AND ?
                          ORDER BY occurred_at ASC`,
                        [tenantId, ...staffIds, evFrom, evTo]
                    );
                    // Group events per (staff, jakartaDay) dalam urutan waktu.
                    const groups = new Map();
                    for (const ev of evRows) {
                        if (!ev || !ev.occurred_at) continue;
                        const et = String(ev.event_type || '').trim().toUpperCase();
                        if (et !== 'CLOCK_IN' && et !== 'CLOCK_OUT' &&
                            et !== 'BREAK_START' && et !== 'BREAK_END') continue;
                        const jakDay = jakartaYmdFromIso(ev.occurred_at);
                        if (!jakDay) continue;
                        const key = `${ev.staff_id}__${jakDay}`;
                        if (!groups.has(key)) groups.set(key, []);
                        groups.get(key).push({ type: et, at: ev.occurred_at });
                    }
                    // Untuk tiap group, tentukan clock_in_at (CLOCK_IN pertama yang membuka sesi)
                    // dan clock_out_at (CLOCK_OUT yang menutup sesi TERAKHIR yang berhasil dipasangkan).
                    const resolved = new Map();
                    for (const [key, evs] of groups.entries()) {
                        let firstIn = null;
                        let openIn = null;
                        let lastClosingOut = null;
                        for (const e of evs) {
                            if (e.type === 'CLOCK_IN') {
                                if (!firstIn) firstIn = e.at;
                                if (!openIn) openIn = e.at;
                            } else if (e.type === 'CLOCK_OUT') {
                                if (openIn) {
                                    lastClosingOut = e.at;
                                    openIn = null;
                                }
                            }
                        }
                        resolved.set(key, {
                            clock_in_at: firstIn,
                            // Kalau sesi terakhir belum ditutup (openIn != null), biarkan null
                            // supaya UI menampilkan "-" pada clock out (konsisten: durasi dihitung
                            // sampai sekarang/akhir hari, tapi event out-nya memang tidak ada).
                            clock_out_at: openIn ? null : lastClosingOut,
                        });
                    }
                    for (const r of rows) {
                        const b = resolved.get(`${r.staff_id}__${r.work_date}`);
                        r.clock_in_at = b ? b.clock_in_at : null;
                        r.clock_out_at = b ? b.clock_out_at : null;
                    }
                } else {
                    for (const r of rows) { r.clock_in_at = null; r.clock_out_at = null; }
                }
            }

            res.json(rows);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.post('/api/attendance/daily', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const staff_id = String(req.body.staff_id || '').trim();
            const work_date = String(req.body.work_date || '').trim();
            const shift_id = req.body.shift_id ? String(req.body.shift_id).trim() : null;
            const minutes_worked = Number(req.body.minutes_worked || 0);
            const late_minutes = Number(req.body.late_minutes || 0);
            const policy = await getAttendancePolicySafe();
            const hasCustomOvertime = Object.prototype.hasOwnProperty.call(req.body || {}, 'overtime_minutes');
            const overtime_minutes = hasCustomOvertime
                ? Number(req.body.overtime_minutes || 0)
                : Math.max(0, Math.round(minutes_worked - (Number(policy.overtime_after_hours || 8) * 60)));
            const status = String(req.body.status || 'PRESENT').trim() || 'PRESENT';
            const note = String(req.body.note || '').trim();
            if (!staff_id || !work_date) return res.status(400).json({ error: 'Missing required fields' });
            const now = new Date().toISOString();
            await run(
                `INSERT INTO attendance_daily (tenant_id, staff_id, work_date, shift_id, minutes_worked, late_minutes, overtime_minutes, status, note, updated_at)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                 ON CONFLICT(tenant_id, staff_id, work_date)
                 DO UPDATE SET
                    shift_id = excluded.shift_id,
                    minutes_worked = excluded.minutes_worked,
                    late_minutes = excluded.late_minutes,
                    overtime_minutes = excluded.overtime_minutes,
                    status = excluded.status,
                    note = excluded.note,
                    updated_at = excluded.updated_at`,
                [tenantId, staff_id, work_date, shift_id, minutes_worked, late_minutes, overtime_minutes, status, note, now]
            );
            res.json({ success: true });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.post('/api/attendance/recompute', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const staff_id = req.body.staff_id ? String(req.body.staff_id).trim() : '';
            let from_date = String(req.body.from_date || '').trim();
            let to_date = String(req.body.to_date || '').trim();
            const todayJakarta = jakartaYmdFromIso(new Date().toISOString());
            if (req.body.today_jakarta === true || String(req.body.today_jakarta || '').toLowerCase() === 'true') {
                from_date = todayJakarta;
                to_date = todayJakarta;
            }
            if (!from_date || !to_date) return res.status(400).json({ error: 'Missing required fields' });
            if (from_date > to_date) return res.status(400).json({ error: 'Invalid date range' });
            // Hanya event yang sudah punya staff (terdeteksi / terpasang); abaikan relawan mentah (staff_id NULL).
            let sql = `SELECT staff_id, event_type, occurred_at FROM attendance_events
                WHERE tenant_id = ? AND occurred_at IS NOT NULL
                AND staff_id IS NOT NULL AND TRIM(staff_id) != ''`;
            const params = [tenantId];
            if (staff_id) { sql += " AND staff_id = ?"; params.push(staff_id); }
            sql += " ORDER BY staff_id, occurred_at";
            const rows = await all(sql, params);
            const grouped = new Map();
            for (const r of rows) {
                const d = jakartaYmdFromIso(r.occurred_at);
                if (!d) continue;
                if (d < from_date || d > to_date) continue;
                const sid = String(r.staff_id || '').trim();
                if (!sid) continue;
                const k = `${sid}::${d}`;
                if (!grouped.has(k)) grouped.set(k, []);
                grouped.get(k).push(r);
            }
            // True sync mode: clear daily rows in selected scope first,
            // then rebuild only from attendance_events that currently exist.
            let cleared_days = 0;
            if (staff_id) {
                const before = await get(
                    `SELECT COUNT(*) AS c FROM attendance_daily WHERE tenant_id = ? AND staff_id = ? AND work_date BETWEEN ? AND ?`,
                    [tenantId, staff_id, from_date, to_date]
                );
                cleared_days = Number(before?.c || 0);
                await run(
                    `DELETE FROM attendance_daily WHERE tenant_id = ? AND staff_id = ? AND work_date BETWEEN ? AND ?`,
                    [tenantId, staff_id, from_date, to_date]
                );
            } else {
                const before = await get(
                    `SELECT COUNT(*) AS c FROM attendance_daily WHERE tenant_id = ? AND work_date BETWEEN ? AND ?`,
                    [tenantId, from_date, to_date]
                );
                cleared_days = Number(before?.c || 0);
                await run(
                    `DELETE FROM attendance_daily WHERE tenant_id = ? AND work_date BETWEEN ? AND ?`,
                    [tenantId, from_date, to_date]
                );
            }

            const now = new Date().toISOString();
            let updated_days = 0;
            let skipped_days = 0;
            const staffIds = Array.from(new Set(Array.from(grouped.keys()).map(k => String(k).split('::')[0]).filter(Boolean)));
            const staffDivisionRows = staffIds.length
                ? await all(
                    `SELECT id, division_id FROM staff WHERE tenant_id = ? AND id IN (${staffIds.map(() => '?').join(',')})`,
                    [tenantId, ...staffIds]
                )
                : [];
            const staffDivisionMap = new Map((staffDivisionRows || []).map(r => [String(r.id), String(r.division_id || '')]));
            const sep = '::';
            for (const [k, evs] of grouped.entries()) {
                const li = k.lastIndexOf(sep);
                const d = li >= 0 ? k.slice(li + sep.length) : '';
                const sid = li >= 0 ? k.slice(0, li) : '';
                if (!sid || !d) continue;
                await upsertAttendanceDailyFromEvents({
                    tenantId,
                    staffId: sid,
                    workDate: d,
                    staffDivisionId: staffDivisionMap.get(sid) || '',
                    events: evs,
                    nowIso: now,
                    note: 'AUTO_RECOMPUTE'
                });
                updated_days += 1;
            }
            const policy = await getAttendancePolicySafe();
            res.json({
                updated_days,
                skipped_days,
                cleared_days,
                from_date,
                to_date,
                today_jakarta: todayJakarta,
                policy,
            });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

function addDaysYmd(ymd, deltaDays) {
    const d = new Date(`${ymd}T00:00:00Z`);
    if (!Number.isFinite(d.getTime())) return ymd;
    d.setUTCDate(d.getUTCDate() + Number(deltaDays || 0));
    return d.toISOString().slice(0, 10);
}

app.get('/api/attendance/recap', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const policy = await getAttendancePolicySafe();
            const cycle = String(req.query.cycle || 'daily').trim().toLowerCase();
            const staffId = String(req.query.staff_id || '').trim();
            const includePhotos = String(req.query.include_photos || '1').trim() !== '0';
            const toDateInput = String(req.query.to_date || '').trim() || jakartaYmdFromIso(new Date().toISOString());
            const biweeklySpan = Math.max(7, Number(policy.biweekly_days || 14));
            const defaultFrom = cycle === 'biweekly' ? addDaysYmd(toDateInput, -(biweeklySpan - 1)) : toDateInput;
            const fromDate = String(req.query.from_date || '').trim() || defaultFrom;
            const toDate = toDateInput;
            if (!fromDate || !toDate || fromDate > toDate) {
                return res.status(400).json({ error: 'Invalid date range' });
            }

            let sql = `
                SELECT
                    d.staff_id,
                    s.name AS staff_name,
                    s.division_id,
                    COUNT(*) AS total_days,
                    SUM(CASE WHEN UPPER(COALESCE(d.status,'')) = 'PRESENT' THEN 1 ELSE 0 END) AS present_days,
                    SUM(COALESCE(d.minutes_worked, 0)) AS worked_minutes,
                    SUM(COALESCE(d.overtime_minutes, 0)) AS overtime_minutes,
                    SUM(COALESCE(d.late_minutes, 0)) AS late_minutes
                FROM attendance_daily d
                JOIN staff s ON s.id = d.staff_id
                WHERE d.tenant_id = ?
                  AND d.work_date >= ?
                  AND d.work_date <= ?
            `;
            const params = [tenantId, fromDate, toDate];
            if (staffId) {
                sql += " AND d.staff_id = ?";
                params.push(staffId);
            }
            sql += " GROUP BY d.staff_id, s.name, s.division_id ORDER BY s.name";
            const rows = await all(sql, params);
            const normalized = (rows || []).map((r) => {
                const workedMinutes = Number(r.worked_minutes || 0);
                const overtimeMinutes = Number(r.overtime_minutes || 0);
                const lateMinutes = Number(r.late_minutes || 0);
                const totalDays = Number(r.total_days || 0);
                const presentDays = Number(r.present_days || 0);
                return {
                    staff_id: r.staff_id,
                    staff_name: r.staff_name || '-',
                    division_id: r.division_id || '',
                    from_date: fromDate,
                    to_date: toDate,
                    total_days: totalDays,
                    present_days: presentDays,
                    absent_days: Math.max(0, totalDays - presentDays),
                    worked_minutes: workedMinutes,
                    worked_hours: Number((workedMinutes / 60).toFixed(2)),
                    overtime_minutes: overtimeMinutes,
                    overtime_hours: Number((overtimeMinutes / 60).toFixed(2)),
                    late_minutes: lateMinutes,
                    avg_worked_hours_per_day: totalDays > 0 ? Number(((workedMinutes / 60) / totalDays).toFixed(2)) : 0,
                    overtime_threshold_hours: Number(policy.overtime_after_hours || 8),
                    regular_hours_per_day: Number(policy.work_hours_per_day || 8),
                };
            });

            if (includePhotos && normalized.length > 0) {
                const staffIds = normalized.map(r => String(r.staff_id || '')).filter(Boolean);
                const placeholders = staffIds.map(() => '?').join(',');
                const eventRows = await all(
                    `SELECT staff_id, event_type, occurred_at, meta_json
                     FROM attendance_events
                     WHERE tenant_id = ?
                       AND staff_id IN (${placeholders})
                       AND occurred_at >= ?
                       AND occurred_at <= ?
                       AND meta_json IS NOT NULL
                     ORDER BY datetime(occurred_at) DESC
                     LIMIT ?`,
                    [tenantId, ...staffIds, `${fromDate}T00:00:00`, `${toDate}T23:59:59.999`, Math.min(8000, Math.max(500, staffIds.length * 80))]
                );
                const photoMap = new Map();
                for (const ev of (eventRows || [])) {
                    const sid = String(ev.staff_id || '');
                    if (!sid) continue;
                    const meta = safeJsonParse(ev.meta_json, {});
                    const photo = String(meta?.attendance_photo || '').trim();
                    if (!photo.startsWith('data:image/')) continue;
                    const item = photoMap.get(sid) || {
                        photo_count: 0,
                        latest_photo: '',
                        latest_photo_at: '',
                        latest_clock_in_photo: '',
                        latest_clock_in_at: '',
                        latest_clock_out_photo: '',
                        latest_clock_out_at: '',
                        photo_samples: [],
                    };
                    const occ = String(ev.occurred_at || '');
                    const et = String(ev.event_type || '').toUpperCase();
                    item.photo_count += 1;
                    if (!item.latest_photo) {
                        item.latest_photo = photo;
                        item.latest_photo_at = occ;
                    }
                    if (et === 'CLOCK_IN' && !item.latest_clock_in_photo) {
                        item.latest_clock_in_photo = photo;
                        item.latest_clock_in_at = occ;
                    }
                    if (et === 'CLOCK_OUT' && !item.latest_clock_out_photo) {
                        item.latest_clock_out_photo = photo;
                        item.latest_clock_out_at = occ;
                    }
                    if (item.photo_samples.length < 3) {
                        item.photo_samples.push({
                            event_type: et,
                            occurred_at: occ,
                            photo_data_url: photo,
                        });
                    }
                    photoMap.set(sid, item);
                }

                normalized.forEach((r) => {
                    const p = photoMap.get(String(r.staff_id || ''));
                    r.photo_count = Number(p?.photo_count || 0);
                    r.latest_photo = p?.latest_photo || '';
                    r.latest_photo_at = p?.latest_photo_at || '';
                    r.latest_clock_in_photo = p?.latest_clock_in_photo || '';
                    r.latest_clock_in_at = p?.latest_clock_in_at || '';
                    r.latest_clock_out_photo = p?.latest_clock_out_photo || '';
                    r.latest_clock_out_at = p?.latest_clock_out_at || '';
                    r.photo_samples = Array.isArray(p?.photo_samples) ? p.photo_samples : [];
                });
            }
            res.json({
                cycle,
                from_date: fromDate,
                to_date: toDate,
                policy,
                include_photos: includePhotos,
                rows: normalized,
            });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

