app.post('/api/payroll/periods/:id/calculate', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const periodId = req.params.id;
            const period = await get("SELECT * FROM payroll_periods WHERE id = ? AND tenant_id = ?", [periodId, tenantId]);
            if (!period) return res.status(404).json({ error: 'Not found' });
            if (String(period.status || '').toUpperCase() !== 'DRAFT') return res.status(409).json({ error: 'Not draft' });
            const workingDays = countWorkingDays(period.start_date, period.end_date);
            const stats = await all(
                `SELECT staff_id,
                        COALESCE(SUM(minutes_worked), 0) AS minutes_worked,
                        COALESCE(SUM(CASE WHEN status = 'ABSENT' THEN 0 ELSE 1 END), 0) AS days_present
                 FROM attendance_daily
                 WHERE tenant_id = ? AND work_date BETWEEN ? AND ?
                 GROUP BY staff_id`,
                [tenantId, period.start_date, period.end_date]
            );
            let updated_items = 0;
            let skipped_no_rate = 0;
            const now = new Date().toISOString();
            for (const s of stats) {
                const rateRow = await get(
                    "SELECT pay_type, rate, currency FROM staff_compensation WHERE tenant_id = ? AND staff_id = ? AND effective_from <= ? ORDER BY effective_from DESC LIMIT 1",
                    [tenantId, s.staff_id, period.end_date]
                );
                if (!rateRow || !rateRow.pay_type || !rateRow.rate) { skipped_no_rate += 1; continue; }
                const payType = String(rateRow.pay_type || '').toUpperCase();
                const rate = Number(rateRow.rate || 0);
                const currency = String(rateRow.currency || 'IDR');
                const minutes = Number(s.minutes_worked || 0);
                const daysPresent = Number(s.days_present || 0);
                let gross = 0;
                if (payType === 'HOURLY') gross = rate * minutes / 60.0;
                else if (payType === 'DAILY') gross = rate * daysPresent;
                else if (payType === 'MONTHLY') gross = workingDays > 0 ? rate * daysPresent / workingDays : 0;
                else { skipped_no_rate += 1; continue; }
                const deductions = 0;
                const net = gross;
                const breakdown = JSON.stringify({ minutes_worked: minutes, days_present: daysPresent, working_days: workingDays, calc: payType });
                const id = crypto.randomUUID();
                await run(
                    `INSERT INTO payroll_items (id, tenant_id, period_id, staff_id, pay_type, rate, minutes_worked, gross, deductions, net, currency, breakdown_json, created_at, updated_at)
                     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                     ON CONFLICT(tenant_id, period_id, staff_id)
                     DO UPDATE SET
                        pay_type = excluded.pay_type,
                        rate = excluded.rate,
                        minutes_worked = excluded.minutes_worked,
                        gross = excluded.gross,
                        deductions = excluded.deductions,
                        net = excluded.net,
                        currency = excluded.currency,
                        breakdown_json = excluded.breakdown_json,
                        updated_at = excluded.updated_at`,
                    [id, tenantId, periodId, s.staff_id, payType, rate, minutes, gross, deductions, net, currency, breakdown, now, now]
                );
                updated_items += 1;
            }
            res.json({ updated_items, skipped_no_rate });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

