function divisionLabelFromKitchenConfig(divisionId, kcfg) {
    const id = String(divisionId || 'UNASSIGNED');
    if (id === 'UNASSIGNED') return 'Tanpa divisi';
    const divs = (kcfg && kcfg.divisions) || [];
    const d = divs.find((x) => String(x && x.id) === id);
    if (d && d.name) return String(d.name);
    return id;
}

/**
 * KPI per divisi: kehadiran & penilaian manual; + metrik operasional BGN per agregat divisi.
 * Didaftarkan ganda: `/api/performance/divisions` dan `/api/reports/divisions/bgn-kpi` (alias di bawah prefix reports, sama seperti batch performance).
 */
async function handleGetPerformanceDivisions(req, res) {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            await ensureStaffSchemaInCurrentDb();
            try { await ensurePenerimaManfaatSchemaInCurrentDb(); } catch (e) { }
            try { await ensureReportWorkflowSchema(); } catch (e) { }
            try { await ensureProgramReadySchema(); } catch (e) { }
            const tenantId = getTenantIdFromReq(req);
            const periodDaysRaw = Number(req.query?.period_days || 30);
            const periodDays = Number.isFinite(periodDaysRaw) ? Math.min(90, Math.max(7, Math.round(periodDaysRaw))) : 30;
            const since = new Date(Date.now() - periodDays * 86400000);
            const sinceYmd = since.toISOString().slice(0, 10);
            const todayYmd = new Date().toISOString().slice(0, 10);

            const kcfg = await getKitchenConfigSafe().catch(() => ({ divisions: [] }));
            const divIdsFromConfig = (kcfg.divisions || []).map((d) => String(d.id || '').trim()).filter(Boolean);

            const byDivision = await all(
                `SELECT COALESCE(NULLIF(TRIM(s.division_id), ''), 'UNASSIGNED') AS division_id,
                        COALESCE(SUM(CASE
                            WHEN d.work_date IS NOT NULL AND UPPER(COALESCE(d.status, 'PRESENT')) != 'ABSENT' THEN 1
                            ELSE 0
                        END), 0) AS present_days,
                        COALESCE(SUM(CASE
                            WHEN d.work_date IS NOT NULL
                                 AND COALESCE(d.late_minutes, 0) = 0
                                 AND UPPER(COALESCE(d.status, 'PRESENT')) != 'ABSENT' THEN 1
                            ELSE 0
                        END), 0) AS ontime_present_days
                 FROM staff s
                 LEFT JOIN attendance_daily d
                   ON d.tenant_id = s.tenant_id
                  AND d.staff_id = s.id
                  AND d.work_date >= ?
                 WHERE s.tenant_id = ?
                 GROUP BY COALESCE(NULLIF(TRIM(s.division_id), ''), 'UNASSIGNED')`,
                [sinceYmd, tenantId]
            );
            const attMap = new Map((byDivision || []).map((r) => [String(r.division_id || 'UNASSIGNED'), r]));

            const manualRows = await all(
                'SELECT division_id, kedisiplinan, five_r, improvement, note, updated_at FROM division_kpi_manual WHERE tenant_id = ?',
                [tenantId]
            );
            const manualMap = new Map((manualRows || []).map((r) => [String(r.division_id), r]));

            const taskStatsByDivision = await all(
                `SELECT COALESCE(NULLIF(TRIM(division_id), ''), 'UNASSIGNED') AS division_id,
                        COUNT(*) AS total_tasks,
                        SUM(CASE WHEN UPPER(COALESCE(status,'')) IN ('DONE','COMPLETED') THEN 1 ELSE 0 END) AS done_tasks,
                        AVG(CASE WHEN UPPER(COALESCE(status,'')) IN ('DONE','COMPLETED') THEN COALESCE(duration_minutes,0) END) AS avg_minutes
                 FROM tasks
                 WHERE tenant_id = ?
                   AND (
                        COALESCE(end_time, start_time, due_date, created_at) IS NULL
                        OR date(COALESCE(end_time, start_time, due_date, created_at)) >= date(?)
                   )
                 GROUP BY COALESCE(NULLIF(TRIM(division_id), ''), 'UNASSIGNED')`,
                [tenantId, sinceYmd]
            );
            const batchStatsByDivision = await all(
                `SELECT COALESCE(NULLIF(TRIM(b.division_id), ''), 'UNASSIGNED') AS division_id,
                        COUNT(*) AS total_batches,
                        SUM(CASE WHEN UPPER(COALESCE(b.status, '')) IN ('DONE', 'COMPLETED', 'ON_TIME') THEN 1 ELSE 0 END) AS on_time_batches
                 FROM batches b
                 INNER JOIN plans p ON p.id = b.plan_id
                 WHERE p.tenant_id = ?
                   AND (
                        COALESCE(b.end_time, b.start_time) IS NULL
                        OR date(COALESCE(b.end_time, b.start_time)) >= date(?)
                   )
                 GROUP BY COALESCE(NULLIF(TRIM(b.division_id), ''), 'UNASSIGNED')`,
                [tenantId, sinceYmd]
            );
            const foodSafetyByDivision = await all(
                `SELECT COALESCE(NULLIF(TRIM(division_id), ''), 'UNASSIGNED') AS division_id,
                        COUNT(*) AS checked_reports,
                        SUM(
                            CASE
                                WHEN quality_warnings IS NULL
                                     OR TRIM(quality_warnings) = ''
                                     OR TRIM(quality_warnings) = '[]'
                                THEN 1 ELSE 0
                            END
                        ) AS safe_reports
                 FROM daily_reports
                 WHERE tenant_id = ?
                   AND period_type = 'daily'
                   AND period_start >= ?
                 GROUP BY COALESCE(NULLIF(TRIM(division_id), ''), 'UNASSIGNED')`,
                [tenantId, sinceYmd]
            );
            let distAgg = null;
            try {
                distAgg = await get(
                    `SELECT
                        COALESCE(SUM(target_portions), 0) AS target_portions,
                        COALESCE(SUM(served_portions), 0) AS served_portions
                     FROM pm_distribution_events
                     WHERE tenant_id = ?
                       AND service_date >= ?
                       AND service_date <= ?`,
                    [tenantId, sinceYmd, todayYmd]
                );
            } catch (e) { distAgg = { target_portions: 0, served_portions: 0 }; }
            const statsMap = new Map((taskStatsByDivision || []).map((r) => [
                String(r.division_id || 'UNASSIGNED'),
                {
                    totalTasks: Number(r.total_tasks || 0),
                    doneTasks: Number(r.done_tasks || 0),
                    avgMinutes: Number(r.avg_minutes || 0)
                }
            ]));
            const batchMap = new Map((batchStatsByDivision || []).map((r) => [
                String(r.division_id || 'UNASSIGNED'),
                {
                    totalBatches: Number(r.total_batches || 0),
                    onTimeBatches: Number(r.on_time_batches || 0)
                }
            ]));
            const foodSafetyMap = new Map((foodSafetyByDivision || []).map((r) => [
                String(r.division_id || 'UNASSIGNED'),
                {
                    checkedReports: Number(r.checked_reports || 0),
                    safeReports: Number(r.safe_reports || 0)
                }
            ]));
            const targetPortions = Number(distAgg?.target_portions || 0);
            const servedPortions = Number(distAgg?.served_portions || 0);
            const beneficiaryCoverageRate = targetPortions > 0 ? (servedPortions / targetPortions) : 0;

            const allKeys = new Set([...divIdsFromConfig, ...attMap.keys(), ...manualMap.keys()]);
            (taskStatsByDivision || []).forEach((r) => { allKeys.add(String(r.division_id || 'UNASSIGNED')); });
            (batchStatsByDivision || []).forEach((r) => { allKeys.add(String(r.division_id || 'UNASSIGNED')); });
            (foodSafetyByDivision || []).forEach((r) => { allKeys.add(String(r.division_id || 'UNASSIGNED')); });
            if (allKeys.size === 0) {
                for (const d of (kcfg.divisions || [])) {
                    if (d && d.id) allKeys.add(String(d.id));
                }
            }

            // ============ 4 KPI tambahan (program-ready) ============
            let yieldByDivMap = new Map();
            let tenantAkgFulfillment = null;
            let tenantCostPerMeal = null;
            let tenantStockAccuracy = null;
            try {
                await ensureProgramReadySchema();

                // Yield per divisi dari batches.input_kg & output_kg
                try {
                    const yieldRows = await all(
                        `SELECT COALESCE(NULLIF(TRIM(b.division_id), ''), 'UNASSIGNED') AS division_id,
                                COALESCE(SUM(b.input_kg), 0) AS total_input,
                                COALESCE(SUM(b.output_kg), 0) AS total_output,
                                COUNT(CASE WHEN b.input_kg IS NOT NULL THEN 1 END) AS samples
                         FROM batches b
                         INNER JOIN plans p ON p.id = b.plan_id
                         WHERE p.tenant_id = ?
                           AND (COALESCE(b.end_time, b.start_time) IS NULL OR date(COALESCE(b.end_time, b.start_time)) >= date(?))
                         GROUP BY COALESCE(NULLIF(TRIM(b.division_id), ''), 'UNASSIGNED')`,
                        [tenantId, sinceYmd]
                    );
                    for (const r of yieldRows || []) {
                        const input = Number(r.total_input || 0);
                        const output = Number(r.total_output || 0);
                        const samples = Number(r.samples || 0);
                        yieldByDivMap.set(String(r.division_id), {
                            yield_rate: input > 0 ? (output / input) : null,
                            waste_rate: input > 0 ? Math.max(0, (input - output) / input) : null,
                            samples
                        });
                    }
                } catch (e) { }

                // AKG fulfillment: menu dengan total_kalori >= 0.9 * target kategori
                try {
                    const akgMap = await getAkgTargetsMap(tenantId);
                    if (akgMap.size > 0) {
                        const menuRows = await all(
                            `SELECT m.id AS menu_id,
                                    m.kategori_pm AS kategori_pm,
                                    COALESCE(m.status_approval, 'DRAFT') AS status_approval,
                                    SUM(COALESCE(json_extract(i.nutrition_info, '$.calories'), 0) * COALESCE(fmi.qty, 0) / 100.0) AS kalori_total,
                                    SUM(COALESCE(json_extract(i.nutrition_info, '$.protein'), 0) * COALESCE(fmi.qty, 0) / 100.0) AS protein_total
                             FROM menu m
                             LEFT JOIN food_menu_ingredients fmi ON fmi.menu_id = m.id
                             LEFT JOIN ingredients i ON i.id = fmi.ingredient_id
                             GROUP BY m.id, m.kategori_pm, m.status_approval`,
                            []
                        );
                        let approvedCount = 0, okCount = 0;
                        for (const mm of menuRows || []) {
                            const kat = String(mm.kategori_pm || '').toUpperCase();
                            if (!kat) continue;
                            if (String(mm.status_approval || '').toUpperCase() !== 'APPROVED') continue;
                            const target = akgMap.get(kat);
                            if (!target) continue;
                            approvedCount++;
                            const kaloriOk = Number(mm.kalori_total || 0) >= 0.9 * Number(target.target_kalori || 0);
                            const proteinOk = Number(mm.protein_total || 0) >= 0.9 * Number(target.target_protein || 0);
                            if (kaloriOk && proteinOk) okCount++;
                        }
                        tenantAkgFulfillment = approvedCount > 0 ? (okCount / approvedCount) : null;
                    }
                } catch (e) { }

                // Cost per meal: (ingredient_cost estimate + operational_cost) / served_portions
                try {
                    const opCost = await get(
                        `SELECT COALESCE(SUM(total_cost), 0) AS c FROM operational_consumption_events WHERE tenant_id = ? AND service_date >= ? AND service_date <= ?`,
                        [tenantId, sinceYmd, todayYmd]
                    );
                    const served = Number(distAgg?.served_portions || 0);
                    let ingredientCost = 0;
                    try {
                        const ingAgg = await get(
                            `SELECT COALESCE(SUM(COALESCE(sm.qty, 0) * COALESCE(sm.unit_cost, 0)), 0) AS c
                             FROM stock_movements sm
                             WHERE sm.tenant_id = ? AND sm.direction IN ('OUT','CONSUME','ISSUE') AND date(sm.created_at) >= date(?)`,
                            [tenantId, sinceYmd]
                        );
                        ingredientCost = Number(ingAgg?.c || 0);
                    } catch (e) {
                        try {
                            const ingAlt = await get(
                                `SELECT COALESCE(SUM(COALESCE(qty, 0) * COALESCE(estimated_price, 0)), 0) AS c
                                 FROM batch_ingredient_usage WHERE tenant_id = ? AND date(created_at) >= date(?)`,
                                [tenantId, sinceYmd]
                            );
                            ingredientCost = Number(ingAlt?.c || 0);
                        } catch (e2) { }
                    }
                    tenantCostPerMeal = served > 0 ? ((Number(opCost?.c || 0) + ingredientCost) / served) : null;
                } catch (e) { }

                // Stock accuracy dari opname terakhir
                try {
                    const latestRun = await get(
                        `SELECT id FROM stock_opname_runs WHERE tenant_id = ? AND status = 'FINAL' ORDER BY opname_date DESC LIMIT 1`,
                        [tenantId]
                    );
                    if (latestRun && latestRun.id) {
                        const acc = await get(
                            `SELECT COALESCE(SUM(ABS(variance_qty)), 0) AS v, COALESCE(SUM(system_qty), 0) AS s
                             FROM stock_opname_entries WHERE run_id = ? AND tenant_id = ?`,
                            [latestRun.id, tenantId]
                        );
                        const s = Number(acc?.s || 0);
                        const v = Number(acc?.v || 0);
                        tenantStockAccuracy = s > 0 ? Math.max(0, 1 - (v / s)) : null;
                    }
                } catch (e) { }
            } catch (e) { }

            const rows = Array.from(allKeys).sort((a, b) => a.localeCompare(b, 'id', { numeric: true })).map((divId) => {
                const a = attMap.get(divId) || { present_days: 0, ontime_present_days: 0 };
                const present = Number(a.present_days || 0);
                const ontime = Number(a.ontime_present_days || 0);
                const kehadiran_pct = present > 0 ? (ontime / present) * 100 : null;
                const m = manualMap.get(divId);
                const divisionKey = String(divId);
                const divTaskStats = statsMap.get(divisionKey) || { totalTasks: 0, doneTasks: 0, avgMinutes: 0 };
                const divBatchStats = batchMap.get(divisionKey) || { totalBatches: 0, onTimeBatches: 0 };
                const divFoodStats = foodSafetyMap.get(divisionKey) || { checkedReports: 0, safeReports: 0 };
                const divYield = yieldByDivMap.get(divisionKey) || { yield_rate: null, waste_rate: null, samples: 0 };
                const sopRate = divTaskStats.totalTasks > 0 ? (divTaskStats.doneTasks / divTaskStats.totalTasks) : 0;
                const onTimeDistRate = divBatchStats.totalBatches > 0 ? (divBatchStats.onTimeBatches / divBatchStats.totalBatches) : 0;
                const foodSafetyRate = divFoodStats.checkedReports > 0 ? (divFoodStats.safeReports / divFoodStats.checkedReports) : 0;
                const weightedScore = (
                    (sopRate * 0.35) +
                    (onTimeDistRate * 0.30) +
                    (beneficiaryCoverageRate * 0.20) +
                    (foodSafetyRate * 0.15)
                ) * 100;
                return {
                    division_id: divId,
                    division_name: divisionLabelFromKitchenConfig(divId, kcfg),
                    kehadiran_pct: kehadiran_pct == null ? null : Number(kehadiran_pct.toFixed(1)),
                    kedisiplinan: m && m.kedisiplinan != null ? Number(m.kedisiplinan) : null,
                    five_r: m && m.five_r != null ? Number(m.five_r) : null,
                    improvement: m && m.improvement != null ? Number(m.improvement) : null,
                    note: m && m.note != null ? String(m.note) : '',
                    kpi_sppg_sop_compliance_rate: sopRate,
                    kpi_on_time_distribution_rate: onTimeDistRate,
                    kpi_beneficiary_coverage_rate: beneficiaryCoverageRate,
                    kpi_food_safety_compliance_rate: foodSafetyRate,
                    kpi_menu_akg_fulfillment_rate: tenantAkgFulfillment,
                    kpi_yield_rate: divYield.yield_rate,
                    kpi_waste_rate: divYield.waste_rate,
                    kpi_cost_per_meal: tenantCostPerMeal,
                    kpi_stock_accuracy: tenantStockAccuracy,
                    kpi_score: Number(weightedScore.toFixed(1)),
                    kpi_window_days: periodDays,
                    kpi_window_from: sinceYmd,
                    kpi_window_to: todayYmd,
                    kpi_model: 'division_v3_program_ready',
                    kpi_formula_version: MBG_CANONICAL_SPEC_VERSION
                };
            });
            res.json(rows);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
}

