/** KPI per staff (agregat divisi + operasional) — tampilan Manajemen Staff. */
app.get('/api/performance/staff', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            await ensureStaffSchemaInCurrentDb();
            const tenantId = getTenantIdFromReq(req);
            const periodDaysRaw = Number(req.query?.period_days || 30);
            const periodDays = Number.isFinite(periodDaysRaw) ? Math.min(90, Math.max(7, Math.round(periodDaysRaw))) : 30;
            const since = new Date(Date.now() - periodDays * 86400000);
            const sinceYmd = since.toISOString().slice(0, 10);
            const todayYmd = new Date().toISOString().slice(0, 10);

            const staffRows = await all(
                `SELECT s.id AS staff_id,
                        s.name AS staff_name,
                        s.division_id AS division_id,
                        COALESCE(SUM(CASE WHEN d.work_date IS NOT NULL AND UPPER(COALESCE(d.status,'PRESENT')) != 'ABSENT' THEN 1 ELSE 0 END), 0) AS present_days,
                        COALESCE(SUM(CASE WHEN d.work_date IS NOT NULL AND COALESCE(d.late_minutes,0) = 0 AND UPPER(COALESCE(d.status,'PRESENT')) != 'ABSENT' THEN 1 ELSE 0 END), 0) AS ontime_present_days
                 FROM staff s
                 LEFT JOIN attendance_daily d
                   ON d.tenant_id = s.tenant_id
                  AND d.staff_id = s.id
                  AND d.work_date >= ?
                 WHERE s.tenant_id = ?
                 GROUP BY s.id, s.name, s.division_id
                 ORDER BY s.name`,
                [sinceYmd, tenantId]
            );
            const taskStatsByDivision = await all(
                `SELECT COALESCE(NULLIF(TRIM(division_id), ''), 'UNASSIGNED') AS division_id,
                        COUNT(*) AS total_tasks,
                        SUM(CASE WHEN UPPER(COALESCE(status,'')) IN ('DONE','COMPLETED') THEN 1 ELSE 0 END) AS done_tasks,
                        AVG(CASE WHEN UPPER(COALESCE(status,'')) IN ('DONE','COMPLETED') THEN COALESCE(duration_minutes,0) END) AS avg_minutes
                 FROM tasks
                 WHERE tenant_id = ?
                   AND (
                        COALESCE(end_time, start_time, due_date, created_at) IS NULL
                        OR date(COALESCE(end_time, start_time, due_date, created_at)) >= date(?)
                   )
                 GROUP BY COALESCE(NULLIF(TRIM(division_id), ''), 'UNASSIGNED')`,
                [tenantId, sinceYmd]
            );
            const batchStatsByDivision = await all(
                `SELECT COALESCE(NULLIF(TRIM(b.division_id), ''), 'UNASSIGNED') AS division_id,
                        COUNT(*) AS total_batches,
                        SUM(CASE WHEN UPPER(COALESCE(b.status, '')) IN ('DONE', 'COMPLETED', 'ON_TIME') THEN 1 ELSE 0 END) AS on_time_batches
                 FROM batches b
                 INNER JOIN plans p ON p.id = b.plan_id
                 WHERE p.tenant_id = ?
                   AND (
                        COALESCE(b.end_time, b.start_time) IS NULL
                        OR date(COALESCE(b.end_time, b.start_time)) >= date(?)
                   )
                 GROUP BY COALESCE(NULLIF(TRIM(b.division_id), ''), 'UNASSIGNED')`,
                [tenantId, sinceYmd]
            );
            const foodSafetyByDivision = await all(
                `SELECT COALESCE(NULLIF(TRIM(division_id), ''), 'UNASSIGNED') AS division_id,
                        COUNT(*) AS checked_reports,
                        SUM(
                            CASE
                                WHEN quality_warnings IS NULL
                                     OR TRIM(quality_warnings) = ''
                                     OR TRIM(quality_warnings) = '[]'
                                THEN 1 ELSE 0
                            END
                        ) AS safe_reports
                 FROM daily_reports
                 WHERE tenant_id = ?
                   AND period_type = 'daily'
                   AND period_start >= ?
                 GROUP BY COALESCE(NULLIF(TRIM(division_id), ''), 'UNASSIGNED')`,
                [tenantId, sinceYmd]
            );
            const distAgg = await get(
                `SELECT
                    COALESCE(SUM(target_portions), 0) AS target_portions,
                    COALESCE(SUM(served_portions), 0) AS served_portions
                 FROM pm_distribution_events
                 WHERE tenant_id = ?
                   AND service_date >= ?
                   AND service_date <= ?`,
                [tenantId, sinceYmd, todayYmd]
            );
            const statsMap = new Map((taskStatsByDivision || []).map((r) => [
                String(r.division_id || 'UNASSIGNED'),
                {
                    totalTasks: Number(r.total_tasks || 0),
                    doneTasks: Number(r.done_tasks || 0),
                    avgMinutes: Number(r.avg_minutes || 0)
                }
            ]));
            const batchMap = new Map((batchStatsByDivision || []).map((r) => [
                String(r.division_id || 'UNASSIGNED'),
                {
                    totalBatches: Number(r.total_batches || 0),
                    onTimeBatches: Number(r.on_time_batches || 0)
                }
            ]));
            const foodSafetyMap = new Map((foodSafetyByDivision || []).map((r) => [
                String(r.division_id || 'UNASSIGNED'),
                {
                    checkedReports: Number(r.checked_reports || 0),
                    safeReports: Number(r.safe_reports || 0)
                }
            ]));
            const staffPerDivision = new Map();
            (staffRows || []).forEach((r) => {
                const k = String(r.division_id || 'UNASSIGNED');
                staffPerDivision.set(k, (staffPerDivision.get(k) || 0) + 1);
            });
            const targetPortions = Number(distAgg?.target_portions || 0);
            const servedPortions = Number(distAgg?.served_portions || 0);
            const beneficiaryCoverageRate = targetPortions > 0 ? (servedPortions / targetPortions) : 0;

            const kpiManualRows = await all(
                'SELECT staff_id, kedisiplinan, five_r, improvement, note FROM staff_kpi_manual WHERE tenant_id = ?',
                [tenantId]
            );
            const kpiManualByStaff = new Map((kpiManualRows || []).map((m) => [String(m.staff_id), m]));

            const out = (staffRows || []).map((r) => {
                const presentDays = Number(r.present_days || 0);
                const ontimePresentDays = Number(r.ontime_present_days || 0);
                const divisionKey = String(r.division_id || 'UNASSIGNED');
                const divTaskStats = statsMap.get(divisionKey) || { totalTasks: 0, doneTasks: 0, avgMinutes: 0 };
                const divBatchStats = batchMap.get(divisionKey) || { totalBatches: 0, onTimeBatches: 0 };
                const divFoodStats = foodSafetyMap.get(divisionKey) || { checkedReports: 0, safeReports: 0 };
                const staffCount = Number(staffPerDivision.get(divisionKey) || 1);
                const tasksCompleted = Math.round(divTaskStats.doneTasks / Math.max(staffCount, 1));
                const sopRate = divTaskStats.totalTasks > 0 ? (divTaskStats.doneTasks / divTaskStats.totalTasks) : 0;
                const onTimeDistRate = divBatchStats.totalBatches > 0 ? (divBatchStats.onTimeBatches / divBatchStats.totalBatches) : 0;
                const foodSafetyRate = divFoodStats.checkedReports > 0 ? (divFoodStats.safeReports / divFoodStats.checkedReports) : 0;
                const attendanceRatePct = presentDays > 0 ? (ontimePresentDays / presentDays) * 100.0 : 0;
                const weightedScore = (
                    (sopRate * 0.35) +
                    (onTimeDistRate * 0.30) +
                    (beneficiaryCoverageRate * 0.20) +
                    (foodSafetyRate * 0.15)
                ) * 100;
                const km = kpiManualByStaff.get(String(r.staff_id));
                return {
                    staff_id: r.staff_id,
                    staff_name: r.staff_name,
                    division_id: r.division_id || 'UNASSIGNED',
                    tasks_completed: tasksCompleted,
                    avg_completion_time_minutes: Number(divTaskStats.avgMinutes || 0),
                    ontime_rate: attendanceRatePct,
                    attendance_ontime_rate: presentDays > 0 ? (ontimePresentDays / presentDays) : 0,
                    kehadiran_pct: presentDays > 0 ? Number(((ontimePresentDays / presentDays) * 100).toFixed(1)) : null,
                    kedisiplinan: km && km.kedisiplinan != null ? Number(km.kedisiplinan) : null,
                    five_r: km && km.five_r != null ? Number(km.five_r) : null,
                    improvement: km && km.improvement != null ? Number(km.improvement) : null,
                    kpi_note: km && km.note != null ? String(km.note) : '',
                    kpi_sppg_sop_compliance_rate: sopRate,
                    kpi_on_time_distribution_rate: onTimeDistRate,
                    kpi_beneficiary_coverage_rate: beneficiaryCoverageRate,
                    kpi_food_safety_compliance_rate: foodSafetyRate,
                    kpi_score: Number(weightedScore.toFixed(1)),
                    kpi_formula_version: MBG_CANONICAL_SPEC_VERSION,
                    kpi_window_from: sinceYmd,
                    kpi_window_to: todayYmd
                };
            });
            res.json(out);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.post('/api/performance/staff-kpi', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            await ensureStaffSchemaInCurrentDb();
            const tenantId = getTenantIdFromReq(req);
            const staff_id = String(req.body?.staff_id || '').trim();
            if (!staff_id) return res.status(400).json({ error: 'staff_id wajib' });

            // Self-assessment guard:
            // - Staff actor (login via /auth/staff/code-login di relawan portal) tidak
            //   boleh menilai KPI dirinya sendiri. Hanya penilai lain (koordinator
            //   lain, atau atasan di Portal Pengelola) yang boleh.
            // - Tenant/platform actor (pengelola portal / developer) boleh menilai
            //   siapa pun termasuk ke staff_id yang kebetulan sama, karena mereka
            //   bukan staff yang sedang dinilai (actor_id mereka bukan staff_id).
            if (req.auth?.actor_type === 'staff') {
                const actorStaffId = String(req.auth.actor_id || '').trim();
                if (actorStaffId && actorStaffId === staff_id) {
                    return res.status(403).json({
                        error: 'Koordinator tidak boleh menilai KPI dirinya sendiri. Penilaian Anda dilakukan oleh atasan di Portal Pengelola.'
                    });
                }
            }

            const clamp01_100 = (v) => {
                if (v == null || v === '') return null;
                const n = Number(v);
                if (!Number.isFinite(n)) return null;
                return Math.max(0, Math.min(100, Math.round(n * 10) / 10));
            };
            const kedisiplinan = clamp01_100(req.body?.kedisiplinan);
            const five_r = clamp01_100(req.body?.five_r);
            const improvement = clamp01_100(req.body?.improvement);
            const note = req.body?.note != null ? String(req.body.note).trim().slice(0, 2000) : null;
            const now = new Date().toISOString();
            await run(
                `INSERT INTO staff_kpi_manual (tenant_id, staff_id, kedisiplinan, five_r, improvement, note, updated_at)
                 VALUES (?, ?, ?, ?, ?, ?, ?)
                 ON CONFLICT(tenant_id, staff_id) DO UPDATE SET
                   kedisiplinan = excluded.kedisiplinan,
                   five_r = excluded.five_r,
                   improvement = excluded.improvement,
                   note = excluded.note,
                   updated_at = excluded.updated_at`,
                [tenantId, staff_id, kedisiplinan, five_r, improvement, note, now]
            );
            res.json({ ok: true, staff_id });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

