app.post('/api/drafts', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
            const plan_date = String(req.body.plan_date || '').trim();
            const status = String(req.body.status || 'DRAFT').trim() || 'DRAFT';
            const data = req.body.data ?? req.body.data_json ?? null;
            if (!plan_date || !data) return res.status(400).json({ error: 'Missing required fields' });
            const id = crypto.randomUUID();
            const now = new Date().toISOString();
            await run(
                "INSERT INTO production_drafts (id, tenant_id, plan_date, data_json, status, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?)",
                [id, tenantId, plan_date, JSON.stringify(data), status, now, now]
            );
            res.json({ id, tenant_id: tenantId, plan_date, status });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

