app.post('/api/kitchen/config/:divKey', async (req, res) => {
    try {
        const id = 'config_' + req.params.divKey;
        const cfg = JSON.stringify(req.body);
        const exists = await get("SELECT id FROM kitchen_config WHERE id = ?", [id]);
        if (exists) await run("UPDATE kitchen_config SET config = ? WHERE id = ?", [cfg, id]);
        else await run("INSERT INTO kitchen_config (id, config) VALUES (?, ?)", [id, cfg]);
        res.json({ success: true });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

app.get('/api/production/master_snapshot', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
            const foodId = String(req.query.food_id || '').trim();

            const foods = await all(
                "SELECT id, tenant_id, name, created_at, date_served, packaging_type FROM foods WHERE tenant_id = ? ORDER BY COALESCE(date_served, created_at) DESC",
                [tenantId]
            );

            const menus = foodId
                ? await all("SELECT * FROM food_menus WHERE tenant_id = ? AND food_id = ? ORDER BY created_at DESC", [tenantId, foodId])
                : await all("SELECT * FROM food_menus WHERE tenant_id = ? ORDER BY created_at DESC", [tenantId]);

            const menuIds = (menus || []).map(m => m.id);
            let menuIngredients = [];
            if (menuIds.length) {
                const placeholders = menuIds.map(() => '?').join(',');
                menuIngredients = await all(
                    `SELECT fmi.*, i.name as ingredient_name, i.unit as ingredient_unit
                     FROM food_menu_ingredients fmi
                     LEFT JOIN ingredients i ON i.id = fmi.ingredient_id
                     WHERE fmi.tenant_id = ? AND fmi.food_menu_id IN (${placeholders})`,
                    [tenantId, ...menuIds]
                );
            }

            const equipment = await all("SELECT * FROM kitchen_equipment WHERE tenant_id = ? ORDER BY name", [tenantId]);
            const configRows = await all("SELECT * FROM kitchen_config WHERE id LIKE 'config_%'");
            const division_config = {};
            configRows.forEach(r => {
                try { division_config[r.id.replace('config_', '')] = JSON.parse(r.config); } catch (e) { }
            });

            res.json({
                generated_at: new Date().toISOString(),
                tenant_id: tenantId,
                foods,
                menus,
                menu_ingredients: menuIngredients,
                equipment,
                division_config
            });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

// --- SCHEDULER V3 (AI) ---
app.post('/api/tasks/v2/generate', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const { food_id, deliveries, mode, start_time } = req.body;
            // deliveries: [{ time: ISOString, portions: number }]
            if (!food_id || !deliveries || !deliveries.length) return res.status(400).json({ error: 'Missing params' });

            // 1. Get Food & Menus
            const food = await get("SELECT * FROM foods WHERE id = ?", [food_id]);
            if (!food) return res.status(404).json({ error: 'Food not found' });

            const menus = await all("SELECT * FROM food_menus WHERE food_id = ?", [food_id]);
            if (!menus.length) return res.status(400).json({ error: 'Food has no menus' });

            // 2. Get Equipment
            const equipment = await all("SELECT * FROM kitchen_equipment WHERE status = 'active'");

            // 3. Get Division Configs
            const divConfigs = {};
            const configRows = await all("SELECT * FROM kitchen_config WHERE id LIKE 'config_%'");
            configRows.forEach(r => {
                try { divConfigs[r.id.replace('config_', '')] = JSON.parse(r.config); } catch (e) { }
            });

            // 3. Calculate Schedule
            const rates = {
                prep_per_hour: divConfigs.prep?.cutting_speed_kg_per_hour * 10 || 100, // Estimate 10 portions per kg
                pack_per_hour: (3600 / (divConfigs.packing?.seconds_per_portion || 15)) * (divConfigs.packing?.packer_count || 1)
            };
            const primaryMenu = menus[0];

            let result;
            if (mode === 'forward') {
                const st = start_time ? new Date(start_time) : new Date();
                result = calculateForwardSchedule(st, deliveries, primaryMenu, equipment, rates);
            } else {
                result = calculateScheduleV2(deliveries, primaryMenu, equipment, rates);
            }

            // 4. Save Plan (Basic & Details)
            const planId = crypto.randomUUID();
            const now = new Date().toISOString();
            const tenantId = req.headers['x-tenant-id'];

            await run("INSERT INTO plans (id, code, tenant_id, status, created_at) VALUES (?, ?, ?, 'DRAFT', ?)",
                [planId, readableCode('PLAN', planId), tenantId, now]);

            let minStart = null;
            let maxEnd = null;

            for (const [idx, d] of deliveries.entries()) {
                const deliveryId = crypto.randomUUID();
                // Use result.schedule time if available, otherwise original
                const sch = result.schedule.find(s => s.portions === d.portions && (s.target_time === d.time || s.delivery_time.toISOString() === d.time));
                const finalTime = sch ? sch.delivery_time.toISOString() : d.time;

                await run("INSERT INTO order_deliveries (id, order_id, delivery_time, portion_count, status) VALUES (?, ?, ?, ?, 'PENDING')",
                    [deliveryId, planId, finalTime, d.portions]);

                if (sch) {
                    const t = sch.timeline;

                    // Helper to insert task
                    const addTask = async (title, divId, start, end) => {
                        const s = start.toISOString();
                        const e = end.toISOString();
                        const dur = Math.round((end.getTime() - start.getTime()) / 60000);
                        await run(`INSERT INTO tasks (id, tenant_id, title, division_id, status, plan_id, start_time, end_time, duration_minutes, created_at) 
                            VALUES (?, ?, ?, ?, 'PENDING', ?, ?, ?, ?, ?)`,
                            [crypto.randomUUID(), tenantId, `${title} (Batch ${idx + 1})`, divId, planId, s, e, dur, now]);

                        if (!minStart || start < minStart) minStart = start;
                        if (!maxEnd || end > maxEnd) maxEnd = end;
                    };

                    // 1. Receiving
                    if (t.receiving) await addTask('Penerimaan Bahan', 'receiving', t.receiving.start, t.receiving.end);

                    // 2. Prep
                    if (t.prep) await addTask('Persiapan Bahan', 'prep', t.prep.start, t.prep.end);

                    // 3. Cooking (Batches + Task)
                    if (t.cooking && t.cooking.batches && t.cooking.batches.length) {
                        const batchStart = new Date(Math.min(...t.cooking.batches.map(b => b.start)));
                        const batchEnd = new Date(Math.max(...t.cooking.batches.map(b => b.end)));
                        await addTask('Pengolahan / Memasak', 'cooking', batchStart, batchEnd);

                        for (const [bIdx, b] of t.cooking.batches.entries()) {
                            await run(`INSERT INTO batches (id, code, plan_id, menu_item_id, batch_number, batch_size, start_time, end_time, status, division_id)
                                VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'PENDING', 'cooking')`,
                                [crypto.randomUUID(), readableCode('BATCH', crypto.randomUUID()), planId, primaryMenu.id, bIdx + 1, b.size, b.start.toISOString(), b.end.toISOString()]);
                        }
                    }

                    // 4. Packing
                    if (t.packing) await addTask('Pemorsian & Packing', 'packing', t.packing.start, t.packing.end);

                    // 5. Driver
                    if (t.driver) await addTask('Pengiriman', 'driver', t.driver.start, t.driver.end);
                }
            }

            // 6. Support Divisions (Cleaning, Security, Ompreng)
            const planStart = minStart || new Date();
            const planEnd = maxEnd || new Date(planStart.getTime() + 8 * 3600 * 1000);

            // Cleaning: After production
            await run(`INSERT INTO tasks (id, tenant_id, title, division_id, status, plan_id, start_time, end_time, duration_minutes, created_at) 
                VALUES (?, ?, ?, 'cleaning', 'PENDING', ?, ?, ?, 60, ?)`,
                [crypto.randomUUID(), tenantId, 'Kebersihan Area Produksi', planId, planEnd.toISOString(), new Date(planEnd.getTime() + 3600000).toISOString(), now]);

            // Security: During production
            await run(`INSERT INTO tasks (id, tenant_id, title, division_id, status, plan_id, start_time, end_time, duration_minutes, created_at) 
                VALUES (?, ?, ?, 'security', 'PENDING', ?, ?, ?, ?, ?)`,
                [crypto.randomUUID(), tenantId, 'Pengamanan Area', planId, planStart.toISOString(), planEnd.toISOString(), Math.round((planEnd - planStart) / 60000), now]);

            // Ompreng: After delivery (Assuming 2 hours after last delivery)
            const omprengStart = new Date(planEnd.getTime() + 2 * 3600000);
            await run(`INSERT INTO tasks (id, tenant_id, title, division_id, status, plan_id, start_time, end_time, duration_minutes, created_at) 
                VALUES (?, ?, ?, 'ompreng', 'PENDING', ?, ?, ?, 120, ?)`,
                [crypto.randomUUID(), tenantId, 'Pencucian Ompreng', planId, omprengStart.toISOString(), new Date(omprengStart.getTime() + 7200000).toISOString(), now]);

            res.json({
                plan: { code: readableCode('PLAN', planId), id: planId },
                schedule: result.schedule,
                feasibility: result.feasibility
            });

        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});


function parseDataUrlImage(dataUrl) {
    const m = String(dataUrl || '').match(/^data:(image\/png|image\/jpeg);base64,(.+)$/i);
    if (!m) return null;
    try { return Buffer.from(m[2], 'base64'); } catch (e) { return null; }
}

function ensureDir(p) {
    try { fs.mkdirSync(p, { recursive: true }); } catch (e) { }
}

function safeFileName(s) {
    return String(s || '').replace(/[^a-zA-Z0-9_-]/g, '').slice(0, 64) || 'x';
}

async function saveAttendancePhoto({ tenantId, staffId, dataUrl }) {
    const buf = parseDataUrlImage(dataUrl);
    if (!buf) return null;
    const base = path.join(__dirname, 'uploads', 'attendance', safeFileName(tenantId), safeFileName(staffId));
    ensureDir(base);
    const file = `${crypto.randomUUID()}.jpg`;
    const abs = path.join(base, file);
    await fs.promises.writeFile(abs, buf);
    return `/uploads/attendance/${encodeURIComponent(safeFileName(tenantId))}/${encodeURIComponent(safeFileName(staffId))}/${encodeURIComponent(file)}`;
}

function normalizeUnit(u) {
    const s = String(u || '').trim().toLowerCase();
    if (!s) return '';
    if (s === 'gram' || s === 'gr') return 'g';
    if (s === 'kilogram') return 'kg';
    if (s === 'liter' || s === 'ltr') return 'l';
    return s;
}

function gramsToUnit(grams, unit) {
    const u = normalizeUnit(unit);
    const g = Number(grams || 0);
    if (!Number.isFinite(g)) return { qty: 0, unit: u || 'g' };
    if (u === 'kg') return { qty: g / 1000, unit: 'kg' };
    if (u === 'g' || !u) return { qty: g, unit: 'g' };
    return { qty: g, unit: u };
}

function safeNumber(n) {
    const x = Number(n);
    return Number.isFinite(x) ? x : 0;
}

function getTenantIdFromReq(req) {
    const headerTid = String(req.headers['x-tenant-id'] || '').trim();
    if (req.auth && req.auth.actor_type === 'platform') return headerTid || null;
    const tid = req.auth && req.auth.tenant_id ? String(req.auth.tenant_id).trim() : '';
    return tid || headerTid || null;
}

/** Samakan baris pivot food_menu_items dengan kolom menu.food_id (kalkulator material & daftar menu food memakai pivot + food_id). */
async function mbgSyncFoodMenuItemsPivotForMenu(req, menuId, foodIdOrNull) {
    const mid = String(menuId || '').trim();
    if (!mid) return;
    await ensureProductionLibrarySchemaInCurrentDb();
    await run('DELETE FROM food_menu_items WHERE menu_id = ?', [mid]).catch(() => {});
    const fid = foodIdOrNull ? String(foodIdOrNull).trim() : '';
    if (!fid) return;
    const tenantId = getTenantIdFromReq(req);
    if (!tenantId) return;
    const now = new Date().toISOString();
    await run(
        'INSERT INTO food_menu_items (id, tenant_id, food_id, menu_id, created_at) VALUES (?, ?, ?, ?, ?)',
        [crypto.randomUUID(), tenantId, fid, mid, now]
    ).catch(() => {});
}

function toIso(d) {
    const dt = d instanceof Date ? d : new Date(d);
    if (!Number.isFinite(dt.getTime())) return null;
    return dt.toISOString();
}

async function getProductionSettings() {
    const cfg = await getKitchenConfigSafe();
    const p = cfg && cfg.production ? cfg.production : {};
    return {
        prep_parallel_limit: Math.max(1, Number(p.prep_parallel_limit || 2)),
        cook_parallel_limit: Math.max(1, Number(p.cook_parallel_limit || 2)),
        portion_parallel_limit: Math.max(1, Number(p.portion_parallel_limit || 2)),
        driver_minutes: Math.max(0, Number(p.driver_minutes || 30)),
        poll_interval_ms: Math.max(500, Number(p.poll_interval_ms || 1500))
    };
}

async function logProductionEvent(orderId, type, message, payload) {
    try {
        await run(
            "INSERT INTO production_events (id, order_id, at, type, message, payload) VALUES (?, ?, ?, ?, ?, ?)",
            [crypto.randomUUID(), orderId, new Date().toISOString(), String(type || ''), String(message || ''), payload ? JSON.stringify(payload) : null]
        );
    } catch (e) { }
}

function calcRatePerMinute(outputQty, minutes) {
    const out = safeNumber(outputQty);
    const min = safeNumber(minutes);
    if (out <= 0 || min <= 0) return 0;
    return out / min;
}

function minutesBetweenIso(a, b) {
    const ta = a ? new Date(a).getTime() : NaN;
    const tb = b ? new Date(b).getTime() : NaN;
    if (!Number.isFinite(ta) || !Number.isFinite(tb)) return 0;
    return Math.max(0, (tb - ta) / 60000);
}

async function productionTick() {
    const nowIso = new Date().toISOString();
    const settings = await getProductionSettings();

    const runningPreps = await all("SELECT * FROM prep_jobs WHERE status = 'RUNNING'");
    for (const j of runningPreps) {
        const last = j.last_calc_at || j.started_at || nowIso;
        const mins = minutesBetweenIso(last, nowIso);
        if (mins <= 0) continue;
        const rate = calcRatePerMinute(j.prep_output_qty, j.prep_minutes);
        const producedBefore = safeNumber(j.produced_qty);
        const producedAfter = producedBefore + mins * rate;
        const cap = safeNumber(j.required_qty);
        const finalProduced = cap > 0 ? Math.min(cap, producedAfter) : producedAfter;
        const done = cap > 0 && finalProduced >= cap - 1e-9;
        await run(
            "UPDATE prep_jobs SET produced_qty = ?, last_calc_at = ?, status = ?, finished_at = COALESCE(finished_at, ?) WHERE id = ?",
            [finalProduced, nowIso, done ? 'DONE' : 'RUNNING', done ? nowIso : null, j.id]
        );
        if (done) await logProductionEvent(j.order_id, 'PREP_DONE', 'Bahan selesai dipersiapkan', { ingredient_id: j.ingredient_id });
    }

    const prepared = await all("SELECT order_id, ingredient_id, SUM(COALESCE(produced_qty,0)) as qty FROM prep_jobs GROUP BY order_id, ingredient_id");
    const preparedMap = new Map();
    for (const r of prepared) preparedMap.set(`${r.order_id}|${r.ingredient_id}`, safeNumber(r.qty));

    const consumedRows = await all(`
        SELECT b.order_id as order_id, r.ingredient_id as ingredient_id, SUM(COALESCE(r.required_qty,0)) as qty
        FROM cook_batch_requirements r
        JOIN cook_batches_v2 b ON b.id = r.cook_batch_id
        WHERE r.needs_prep = 1 AND b.status IN ('COOKING','DONE')
        GROUP BY b.order_id, r.ingredient_id
    `);
    const consumedMap = new Map();
    for (const r of consumedRows) consumedMap.set(`${r.order_id}|${r.ingredient_id}`, safeNumber(r.qty));

    const cooking = await all("SELECT id, order_id FROM cook_batches_v2 WHERE status = 'COOKING'");
    const cookingCountByOrder = new Map();
    for (const b of cooking) cookingCountByOrder.set(b.order_id, (cookingCountByOrder.get(b.order_id) || 0) + 1);

    const queuedCook = await all(`
        SELECT b.*
        FROM cook_batches_v2 b
        JOIN production_orders o ON o.id = b.order_id
        WHERE b.status = 'QUEUED' AND COALESCE(o.status,'') <> 'STOPPED'
        ORDER BY b.queued_at ASC
    `);
    for (const b of queuedCook) {
        const running = cookingCountByOrder.get(b.order_id) || 0;
        if (running >= settings.cook_parallel_limit) continue;
        const reqs = await all("SELECT * FROM cook_batch_requirements WHERE cook_batch_id = ?", [b.id]);
        let ok = true;
        for (const r of reqs) {
            if (Number(r.needs_prep || 0) !== 1) continue;
            const key = `${b.order_id}|${r.ingredient_id}`;
            const preparedQty = preparedMap.get(key) || 0;
            const consumedQty = consumedMap.get(key) || 0;
            const have = preparedQty - consumedQty;
            if (have + 1e-9 < safeNumber(r.required_qty)) { ok = false; break; }
        }
        if (!ok) continue;
        const menu = await get("SELECT cook_minutes FROM food_menus WHERE id = ?", [b.food_menu_id]);
        const cookMin = Math.max(1, Number(menu?.cook_minutes || 30));
        const expectedEnd = new Date(Date.now() + cookMin * 60000).toISOString();
        await run(
            "UPDATE cook_batches_v2 SET status = 'COOKING', started_at = ?, expected_end_at = ? WHERE id = ?",
            [nowIso, expectedEnd, b.id]
        );
        for (const r of reqs) {
            if (Number(r.needs_prep || 0) !== 1) continue;
            const key = `${b.order_id}|${r.ingredient_id}`;
            consumedMap.set(key, (consumedMap.get(key) || 0) + safeNumber(r.required_qty));
        }
        cookingCountByOrder.set(b.order_id, running + 1);
        await logProductionEvent(b.order_id, 'COOK_START', 'Batch memasak dimulai', { cook_batch_id: b.id, food_menu_id: b.food_menu_id });
    }

    const cookingNow = await all("SELECT * FROM cook_batches_v2 WHERE status = 'COOKING'");
    for (const b of cookingNow) {
        const end = b.expected_end_at ? new Date(b.expected_end_at).getTime() : 0;
        if (end && end <= Date.now()) {
            await run(
                "UPDATE cook_batches_v2 SET status = 'DONE', finished_at = ?, cooked_portions = ? WHERE id = ?",
                [nowIso, b.batch_size, b.id]
            );
            await logProductionEvent(b.order_id, 'COOK_DONE', 'Batch memasak selesai', { cook_batch_id: b.id, cooked_portions: b.batch_size });
        }
    }

    const doneCook = await all("SELECT * FROM cook_batches_v2 WHERE status = 'DONE'");
    for (const b of doneCook) {
        const exists = await get("SELECT id FROM portion_batches WHERE cook_batch_id = ?", [b.id]);
        if (exists) continue;
        const menu = await get("SELECT portion_minutes, portion_capacity FROM food_menus WHERE id = ?", [b.food_menu_id]);
        const portionMin = Math.max(1, Number(menu?.portion_minutes || 10));
        const portionCap = Math.max(1, Number(menu?.portion_capacity || 10));
        await run(
            `INSERT INTO portion_batches (id, order_id, cook_batch_id, food_menu_id, target_portions, status, started_at, expected_end_at, finished_at, portions_done, last_calc_at, portion_minutes, portion_capacity)
             VALUES (?, ?, ?, ?, ?, 'QUEUED', NULL, NULL, NULL, 0, NULL, ?, ?)`,
            [crypto.randomUUID(), b.order_id, b.id, b.food_menu_id, b.cooked_portions || b.batch_size, portionMin, portionCap]
        );
    }

    const portionRunning = await all("SELECT * FROM portion_batches WHERE status = 'RUNNING'");
    const portionCountByOrder = new Map();
    for (const p of portionRunning) portionCountByOrder.set(p.order_id, (portionCountByOrder.get(p.order_id) || 0) + 1);

    const queuedPortion = await all(`
        SELECT p.*
        FROM portion_batches p
        JOIN production_orders o ON o.id = p.order_id
        WHERE p.status = 'QUEUED' AND COALESCE(o.status,'') <> 'STOPPED'
        ORDER BY p.id ASC
    `);
    for (const p of queuedPortion) {
        const running = portionCountByOrder.get(p.order_id) || 0;
        if (running >= settings.portion_parallel_limit) continue;
        const rate = calcRatePerMinute(p.portion_capacity, p.portion_minutes);
        const target = Math.max(0, Number(p.target_portions || 0));
        const durationMin = rate > 0 ? Math.ceil(target / rate) : 0;
        const expectedEnd = durationMin > 0 ? new Date(Date.now() + durationMin * 60000).toISOString() : nowIso;
        await run(
            "UPDATE portion_batches SET status = 'RUNNING', started_at = ?, expected_end_at = ?, last_calc_at = ? WHERE id = ?",
            [nowIso, expectedEnd, nowIso, p.id]
        );
        portionCountByOrder.set(p.order_id, running + 1);
        await logProductionEvent(p.order_id, 'PORTION_START', 'Pemorsian dimulai', { portion_batch_id: p.id, cook_batch_id: p.cook_batch_id });
    }

    const portionRun2 = await all("SELECT * FROM portion_batches WHERE status = 'RUNNING'");
    for (const p of portionRun2) {
        const last = p.last_calc_at || p.started_at || nowIso;
        const mins = minutesBetweenIso(last, nowIso);
        const rate = calcRatePerMinute(p.portion_capacity, p.portion_minutes);
        const doneBefore = safeNumber(p.portions_done);
        const doneAfter = doneBefore + mins * rate;
        const target = safeNumber(p.target_portions);
        const finalDone = target > 0 ? Math.min(target, Math.floor(doneAfter + 1e-9)) : Math.floor(doneAfter + 1e-9);
        const finished = target > 0 && finalDone >= target;
        await run(
            "UPDATE portion_batches SET portions_done = ?, last_calc_at = ?, status = ?, finished_at = COALESCE(finished_at, ?) WHERE id = ?",
            [finalDone, nowIso, finished ? 'DONE' : 'RUNNING', finished ? nowIso : null, p.id]
        );
        if (finished) await logProductionEvent(p.order_id, 'PORTION_DONE', 'Pemorsian selesai', { portion_batch_id: p.id, target_portions: target });
    }

    const orders = await all("SELECT id FROM production_orders WHERE status IN ('PLANNED','IN_PROGRESS')");
    for (const o of orders) {
        const anyStarted = await get("SELECT id FROM cook_batches_v2 WHERE order_id = ? AND started_at IS NOT NULL LIMIT 1", [o.id]);
        if (anyStarted) await run("UPDATE production_orders SET status = 'IN_PROGRESS' WHERE id = ? AND status = 'PLANNED'", [o.id]);
        const remaining = await get("SELECT COUNT(*) as c FROM portion_batches WHERE order_id = ? AND status <> 'DONE'", [o.id]);
        if (Number(remaining?.c || 0) === 0) await run("UPDATE production_orders SET status = 'DONE' WHERE id = ?", [o.id]);
    }
}

async function validatePlanDocs(planId) {
    const errors = [];

    const plan = await get("SELECT * FROM plans WHERE id = ? OR code = ? LIMIT 1", [planId, planId]);
    if (!plan) {
        errors.push({ code: 'PLAN_NOT_FOUND', message: `Plan tidak ditemukan` });
        return { ok: false, errors };
    }

    const kitchen = await getKitchenConfigSafe();
    const kitchenName = String(kitchen.kitchen_name || kitchen.name || '').trim();
    const kitchenAddress = String(kitchen.address || '').trim();
    const kitchenContact = String(kitchen.contact_phone || kitchen.contact || '').trim();

    if (!kitchenName || !kitchenAddress || !kitchenContact) {
        errors.push({
            code: 'KITCHEN_CONFIG_MISSING',
            message: 'Kop SPPG belum lengkap (nama kitchen, alamat, kontak). Silakan lengkapi di Kitchen Config.'
        });
    }

    if (plan.source_order_id) {
        const data = await buildProductionOrderDocData(plan.source_order_id, plan.tenant_id);
        if (!data.ok) return { ok: false, errors: data.errors || [], plan, kitchen };
        if (errors.length) return { ok: false, errors, plan, kitchen };
        return { ok: true, errors: [], plan, kitchen };
    }

    const batches = await all("SELECT * FROM batches WHERE plan_id = ?", [planId]);
    if (!batches.length) {
        errors.push({ code: 'BATCH_EMPTY', message: `Plan tidak memiliki batch` });
    }

    const tasks = await all("SELECT * FROM tasks WHERE plan_id = ?", [planId]);
    const divisions = Array.isArray(kitchen.divisions) ? kitchen.divisions : [];
    for (const d of divisions) {
        const id = String(d.id || '').trim();
        if (!id) continue;
        const has = tasks.some(t => String(t.division_id || '') === id);
        if (!has) {
            errors.push({ code: 'DIVISION_TIMELINE_MISSING', message: `Timeline divisi ${d.name || id} belum diatur` });
        }
    }

    const menuIds = Array.from(new Set(batches.map(b => b.menu_item_id).filter(Boolean)));
    for (const menuId of menuIds) {
        const menu = await get("SELECT * FROM menu WHERE id = ?", [menuId]);
        if (!menu) {
            errors.push({ code: 'MENU_NOT_FOUND', message: `Menu tidak ditemukan: ${menuId}` });
            continue;
        }
        const recipe = await get("SELECT * FROM recipes WHERE id = ?", [menu.recipe_id]);
        if (!recipe) {
            errors.push({ code: 'RECIPE_MISSING', message: `Menu ${menu.name} belum memiliki resep lengkap` });
            continue;
        }
        let ings = [];
        try { ings = JSON.parse(recipe.ingredients || '[]'); } catch (e) { ings = []; }
        if (!Array.isArray(ings) || ings.length === 0) {
            errors.push({ code: 'RECIPE_EMPTY', message: `Menu ${menu.name} belum memiliki resep lengkap` });
            continue;
        }
        for (const it of ings) {
            const ingId = String(it.ingredient_id || '').trim();
            if (!ingId) continue;
            const ing = await get("SELECT * FROM ingredients WHERE id = ?", [ingId]);
            if (!ing) {
                errors.push({ code: 'INGREDIENT_NOT_FOUND', message: `Ingredient ${ingId} tidak ditemukan (menu ${menu.name})` });
                continue;
            }
            if (ing.estimated_price === null || ing.estimated_price === undefined || !Number.isFinite(Number(ing.estimated_price))) {
                errors.push({ code: 'PRICE_MISSING', message: `Data harga untuk bahan ${ing.name} masih kosong` });
            }
            const unit = String(ing.unit || '').trim();
            if (!unit) {
                errors.push({ code: 'UNIT_MISSING', message: `Satuan untuk bahan ${ing.name} masih kosong` });
            }
        }
    }

    return { ok: errors.length === 0, errors, plan, kitchen };
}

async function buildPlanDocData(planId) {
    const v = await validatePlanDocs(planId);
    if (!v.ok) return { ok: false, errors: v.errors };

    const plan = v.plan;
    const kitchen = v.kitchen;

    if (plan && plan.source_order_id) {
        const od = await buildProductionOrderDocData(plan.source_order_id, plan.tenant_id);
        if (!od.ok) return { ok: false, errors: od.errors || [] };
        const divisions = Array.isArray(od.kitchen.divisions) ? od.kitchen.divisions : [];
        const norm = (s) => String(s || '').toLowerCase();
        const divisionNameById = new Map(divisions.map(d => {
            const id = String(d.id || '');
            const name = String(d.name || d.id || '');
            const disp = (id === 'kitchen' || norm(name).includes('kitchen')) ? 'Cooking' : name;
            return [id, disp];
        }));
        const tasks = await all("SELECT * FROM tasks WHERE plan_id = ? ORDER BY start_time ASC", [planId]);
        const generalTimeline = tasks.map(t => ({
            id: t.id,
            title: t.title,
            division_id: t.division_id,
            division_name: divisionNameById.get(String(t.division_id || '')) || String(t.division_id || ''),
            start_time: t.start_time,
            end_time: t.end_time,
            status: t.status
        }));
        const byDivision = {};
        for (const t of generalTimeline) {
            const k = String(t.division_id || 'unknown');
            if (!byDivision[k]) byDivision[k] = [];
            byDivision[k].push(t);
        }
        const summary = { ...(od.summary || {}) };
        summary.plan_id = plan.id;
        summary.plan_code = plan.code || summary.order_code || readableCode('PL', plan.id);
        return { ok: true, plan, kitchen: od.kitchen, menus: od.menus, invoice: od.invoice, timeline: { general: generalTimeline, by_division: byDivision }, summary };
    }
    const divisions = Array.isArray(kitchen.divisions) ? kitchen.divisions : [];
    const norm = (s) => String(s || '').toLowerCase();
    const divisionNameById = new Map(divisions.map(d => {
        const id = String(d.id || '');
        const name = String(d.name || d.id || '');
        const disp = (id === 'kitchen' || norm(name).includes('kitchen')) ? 'Cooking' : name;
        return [id, disp];
    }));


    const batches = await all("SELECT * FROM batches WHERE plan_id = ?", [planId]);
    const portionsByMenu = new Map();
    for (const b of batches) {
        const menuId = b.menu_item_id;
        if (!menuId) continue;
        portionsByMenu.set(menuId, safeNumber(portionsByMenu.get(menuId)) + safeNumber(b.batch_size));
    }

    const menus = [];
    const invoiceMap = new Map();

    for (const [menuId, portions] of portionsByMenu.entries()) {
        const menu = await get("SELECT * FROM menu WHERE id = ?", [menuId]);
        const recipe = await get("SELECT * FROM recipes WHERE id = ?", [menu.recipe_id]);
        let recipeIngredients = [];
        try { recipeIngredients = JSON.parse(recipe.ingredients || '[]'); } catch (e) { recipeIngredients = []; }

        const items = [];
        for (const ri of recipeIngredients) {
            const ingId = String(ri.ingredient_id || '').trim();
            const perPortionG = safeNumber(ri.quantity);
            if (!ingId || perPortionG <= 0) continue;
            const ing = await get("SELECT * FROM ingredients WHERE id = ?", [ingId]);
            const totalG = perPortionG * safeNumber(portions);
            const unit = String(ing.unit || '').trim();
            const unitQty = gramsToUnit(totalG, unit);
            const pricePerUnit = safeNumber(ing.estimated_price);
            const cost = unitQty.qty * pricePerUnit;

            items.push({
                ingredient_id: ingId,
                ingredient_name: ing.name,
                unit,
                qty_g: totalG,
                qty: unitQty.qty,
                qty_unit: unitQty.unit,
                price_per_unit: pricePerUnit,
                cost
            });

            const prev = invoiceMap.get(ingId) || {
                ingredient_id: ingId,
                ingredient_name: ing.name,
                unit,
                qty_g: 0,
                qty: 0,
                qty_unit: unitQty.unit,
                price_per_unit: pricePerUnit,
                cost: 0
            };
            prev.qty_g += totalG;
            const newUnitQty = gramsToUnit(prev.qty_g, unit);
            prev.qty = newUnitQty.qty;
            prev.qty_unit = newUnitQty.unit;
            prev.price_per_unit = pricePerUnit;
            prev.cost = prev.qty * pricePerUnit;
            invoiceMap.set(ingId, prev);
        }

        menus.push({
            menu_id: menuId,
            menu_name: menu.name,
            recipe_id: menu.recipe_id,
            portions: safeNumber(portions),
            recipe_instructions: recipe.instructions || '',
            ingredients: items
        });
    }

    const invoice = Array.from(invoiceMap.values()).sort((a, b) => String(a.ingredient_name).localeCompare(String(b.ingredient_name)));

    const tasks = await all("SELECT * FROM tasks WHERE plan_id = ? ORDER BY start_time ASC", [planId]);
    const generalTimeline = tasks.map(t => ({
        id: t.id,
        title: t.title,
        division_id: t.division_id,
        division_name: divisionNameById.get(String(t.division_id || '')) || String(t.division_id || ''),
        start_time: t.start_time,
        end_time: t.end_time,
        status: t.status
    }));
    const byDivision = {};
    for (const t of generalTimeline) {
        const k = String(t.division_id || 'unknown');
        if (!byDivision[k]) byDivision[k] = [];
        byDivision[k].push(t);
    }

    const summary = {
        plan_id: plan.id,
        plan_code: plan.code || readableCode('PL', plan.id),
        target_portions: safeNumber(plan.target_portions),
        target_delivery_time: plan.target_delivery_time,
        menu_count: menus.length,
        ingredient_count: invoice.length,
        total_cost: invoice.reduce((a, r) => a + safeNumber(r.cost), 0)
    };

    return { ok: true, plan, kitchen, menus, invoice, timeline: { general: generalTimeline, by_division: byDivision }, summary };
}

function pdfHeader(doc, kitchen, title) {
    const w = doc.page.width - doc.page.margins.left - doc.page.margins.right;
    const left = doc.page.margins.left;
    const top = doc.page.margins.top;
    const name = String(kitchen.kitchen_name || kitchen.name || '').trim();
    const addr = String(kitchen.address || '').trim();
    const contact = String(kitchen.contact_phone || kitchen.contact || '').trim();
    const email = String(kitchen.contact_email || '').trim();
    const logoBuf = kitchen.logo_data_url ? parseDataUrlImage(kitchen.logo_data_url) : null;

    doc.save();
    if (logoBuf) {
        try { doc.image(logoBuf, left, top - 8, { width: 48, height: 48 }); } catch (e) { }
    }
    const textLeft = logoBuf ? left + 56 : left;
    doc.fontSize(14).font('Helvetica-Bold').text(name || 'SPPG', textLeft, top - 4, { width: w - (textLeft - left) });
    doc.fontSize(9).font('Helvetica').fillColor('#333').text(addr, textLeft, top + 14, { width: w - (textLeft - left) });
    doc.fontSize(9).text([contact, email].filter(Boolean).join(' • '), textLeft, top + 26, { width: w - (textLeft - left) });
    doc.moveTo(left, top + 46).lineTo(left + w, top + 46).strokeColor('#999').stroke();
    doc.fillColor('#000');
    doc.fontSize(12).font('Helvetica-Bold').text(title, left, top + 56, { width: w });
    doc.moveDown();
    doc.restore();
    doc.y = top + 78;
}

function pdfMetaBlock(doc, meta) {
    const left = doc.page.margins.left;
    const w = doc.page.width - doc.page.margins.left - doc.page.margins.right;
    const pad = 8;
    const y = doc.y;
    const h = 48;
    doc.save();
    doc.roundedRect(left, y, w, h, 6).fillAndStroke('#F5F7FA', '#D0D5DD');
    doc.fillColor('#111827');
    doc.font('Helvetica-Bold').fontSize(9).text('Ringkasan', left + pad, y + 8);
    doc.font('Helvetica').fontSize(9).fillColor('#344054');
    const a = [
        `Plan: ${meta.plan_code || '-'}`,
        `Target: ${Number(meta.target_portions || 0).toLocaleString('id-ID')} porsi`,
        `Delivery: ${meta.target_delivery_time ? new Date(meta.target_delivery_time).toLocaleString('id-ID') : '-'}`,
        `Generated: ${meta.generated_at ? new Date(meta.generated_at).toLocaleString('id-ID') : '-'}`,
        `By: ${meta.generated_by || '-'}`,
    ].filter(Boolean);
    doc.text(a.slice(0, 3).join(' • '), left + pad, y + 22, { width: w - pad * 2 });
    doc.text(a.slice(3).join(' • '), left + pad, y + 34, { width: w - pad * 2 });
    doc.restore();
    doc.moveDown(0.8);
}

function pdfEnsureSpace(doc, height) {
    const bottom = doc.page.height - doc.page.margins.bottom;
    if (doc.y + height > bottom) doc.addPage();
}

function pdfTable(doc, columns, rows, opts) {
    const options = opts || {};
    const left = options.x ?? doc.page.margins.left;
    const tableWidth = columns.reduce((a, c) => a + c.width, 0);
    const padX = options.padX ?? 6;
    const padY = options.padY ?? 4;
    const headerFill = options.headerFill ?? '#EEF2F6';
    const border = options.border ?? '#D0D5DD';
    const text = options.text ?? '#111827';
    const headerText = options.headerText ?? '#111827';
    const fontSize = options.fontSize ?? 9;
    const rowGap = options.rowGap ?? 0;

    function drawHeader() {
        const y = doc.y;
        const h = options.headerHeight ?? 18;
        doc.save();
        doc.fillColor(headerFill).rect(left, y, tableWidth, h).fill();
        doc.strokeColor(border).rect(left, y, tableWidth, h).stroke();
        doc.font('Helvetica-Bold').fontSize(fontSize).fillColor(headerText);
        let x = left;
        for (const col of columns) {
            doc.text(String(col.header || ''), x + padX, y + padY, { width: col.width - padX * 2, align: col.align || 'left' });
            doc.strokeColor(border).moveTo(x, y).lineTo(x, y + h).stroke();
            x += col.width;
        }
        doc.strokeColor(border).moveTo(left + tableWidth, y).lineTo(left + tableWidth, y + h).stroke();
        doc.restore();
        doc.y = y + h + rowGap;
    }

    function rowHeightFor(row) {
        doc.font('Helvetica').fontSize(fontSize);
        let h = 0;
        for (const col of columns) {
            const v = row[col.key];
            const s = (v === null || v === undefined) ? '' : String(v);
            const hh = doc.heightOfString(s, { width: col.width - padX * 2, align: col.align || 'left' });
            h = Math.max(h, hh);
        }
        return Math.max(options.minRowHeight ?? 16, h + padY * 2);
    }

    drawHeader();

    for (const row of rows) {
        const rh = rowHeightFor(row);
        pdfEnsureSpace(doc, rh + 2);
        if (doc.y + rh > doc.page.height - doc.page.margins.bottom) {
            doc.addPage();
            drawHeader();
        }

        const y = doc.y;
        doc.save();
        doc.strokeColor(border).rect(left, y, tableWidth, rh).stroke();
        doc.font('Helvetica').fontSize(fontSize).fillColor(text);
        let x = left;
        for (const col of columns) {
            const v = row[col.key];
            const s = (v === null || v === undefined) ? '' : String(v);
            doc.text(s, x + padX, y + padY, { width: col.width - padX * 2, align: col.align || 'left' });
            doc.strokeColor(border).moveTo(x, y).lineTo(x, y + rh).stroke();
            x += col.width;
        }
        doc.strokeColor(border).moveTo(left + tableWidth, y).lineTo(left + tableWidth, y + rh).stroke();
        doc.restore();
        doc.y = y + rh + rowGap;
    }
}

function pdfFooter(doc, meta) {
    const left = doc.page.margins.left;
    const w = doc.page.width - doc.page.margins.left - doc.page.margins.right;
    const y = doc.page.height - doc.page.margins.bottom - 16;
    const pageNo = meta.page_no || 1;
    const docNo = meta.doc_no || '';
    const curY = doc.y;
    doc.save();
    doc.strokeColor('#D0D5DD').moveTo(left, y - 6).lineTo(left + w, y - 6).stroke();
    doc.font('Helvetica').fontSize(8).fillColor('#667085').text(docNo, left, y, { width: w * 0.7, align: 'left' });
    doc.font('Helvetica').fontSize(8).fillColor('#667085').text(`Halaman ${pageNo}`, left, y, { width: w, align: 'right' });
    doc.restore();
    doc.y = curY;
}

function pdfSignatureTable(doc, title, roles) {
    const left = doc.page.margins.left;
    const w = doc.page.width - doc.page.margins.left - doc.page.margins.right;
    const cols = roles.length;
    const colW = Math.floor(w / cols);
    const rowH = 70;
    const border = '#D0D5DD';
    pdfEnsureSpace(doc, rowH + 40);

    doc.font('Helvetica-Bold').fontSize(10).fillColor('#111827').text(title, left, doc.y);
    doc.moveDown(0.4);
    const top = doc.y;

    doc.save();
    doc.strokeColor(border).rect(left, top, colW * cols, rowH).stroke();
    for (let i = 1; i < cols; i++) {
        doc.strokeColor(border).moveTo(left + colW * i, top).lineTo(left + colW * i, top + rowH).stroke();
    }
    doc.restore();

    for (let i = 0; i < cols; i++) {
        const x = left + colW * i + 8;
        const r = roles[i];
        doc.font('Helvetica-Bold').fontSize(9).fillColor('#111827').text(String(r || ''), x, top + 8, { width: colW - 16 });
        doc.font('Helvetica').fontSize(9).fillColor('#344054').text('Nama:', x, top + 26, { width: colW - 16 });
        doc.text('Tanda tangan:', x, top + 42, { width: colW - 16 });
    }

    doc.y = top + rowH + 10;
}

function sendPdf(res, filename) {
    res.setHeader('Content-Type', 'application/pdf');
    res.setHeader('Content-Disposition', `attachment; filename="${filename}"`);
}

function sendXlsx(res, filename) {
    res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
    res.setHeader('Content-Disposition', `attachment; filename="${filename}"`);
}

