app.put('/api/menu/:id', async (req, res) => {
    const { name, ingredients, cooking_time, batch_capacity, portion_size, extra_packing_json, packaging_type, tools, steps, food_id, workflow_recipe_id, recipe_id, workflow_id, packaging_stack_json } = req.body;
    try {
        await ensureProductionLibrarySchemaInCurrentDb();
        const menu = await get("SELECT * FROM menu WHERE id = ?", [req.params.id]);
        if (!menu) return res.status(404).json({ error: 'Menu not found' });
        if (name) {
            const dupe = await get("SELECT id FROM menu WHERE lower(name) = lower(?) AND id <> ? LIMIT 1", [String(name).trim(), req.params.id]);
            if (dupe?.id) return res.status(409).json({ error: 'Nama menu sudah ada. Gunakan nama lain.' });
        }

        // New-model fields (recipe_id, workflow_id, packaging_stack_json)
        let nextRecipeId = menu.recipe_id || null;
        if (recipe_id !== undefined) {
            const rid = String(recipe_id || '').trim();
            if (rid) {
                const ex = await get("SELECT id FROM recipes WHERE id = ?", [rid]);
                if (!ex?.id) return res.status(400).json({ error: 'recipe_id tidak ditemukan di library resep' });
                nextRecipeId = rid;
            }
        }
        let nextWorkflowIdLib = menu.workflow_id || null;
        if (workflow_id !== undefined) {
            const wid = String(workflow_id || '').trim();
            if (wid) {
                const ex = await get("SELECT id FROM workflows WHERE id = ?", [wid]);
                if (!ex?.id) return res.status(400).json({ error: 'workflow_id tidak ditemukan di library workflow' });
                nextWorkflowIdLib = wid;
            } else {
                nextWorkflowIdLib = null;
            }
        }
        let nextPackagingStack = menu.packaging_stack_json;
        if (packaging_stack_json !== undefined) nextPackagingStack = JSON.stringify(packaging_stack_json || null);

        const baseRecipeId = String(menu.recipe_id || '').trim();
        let nextWorkflowId = menu.workflow_recipe_id;
        if (workflow_recipe_id !== undefined) {
            const w = String(workflow_recipe_id || '').trim();
            nextWorkflowId = w && w !== baseRecipeId ? w : null;
        }
        if (nextWorkflowId) {
            const ex = await get("SELECT id FROM recipes WHERE id = ?", [nextWorkflowId]);
            if (!ex?.id) return res.status(400).json({ error: 'workflow_recipe_id tidak ditemukan di master resep' });
        }
        const stepTargetRecipeId = nextWorkflowId || baseRecipeId;

        // Update Recipe: jangan timpa ingredients/resep bila body tidak kirim ingredients (form Menu baru hanya kirim name/recipe_id/food_id).
        const curRecipe = menu.recipe_id
            ? await get(
                'SELECT ingredients, cooking_time, batch_capacity, portion_size, extra_packing_json, packaging_type FROM recipes WHERE id = ?',
                [menu.recipe_id]
            ).catch(() => null)
            : null;
        let recipeIngsStr;
        if (ingredients !== undefined) {
            recipeIngsStr = JSON.stringify(ingredients || []);
        } else {
            const raw = curRecipe && curRecipe.ingredients;
            recipeIngsStr = typeof raw === 'string' ? raw : JSON.stringify(raw != null && raw !== '' ? raw : []);
        }
        const nextCook = cooking_time !== undefined ? Number(cooking_time || 0) : Number(curRecipe?.cooking_time ?? 60);
        const nextBatch = batch_capacity !== undefined ? Number(batch_capacity || 0) : Number(curRecipe?.batch_capacity ?? 50);
        const nextPortion = portion_size !== undefined ? Number(portion_size || 0) : Number(curRecipe?.portion_size ?? 1);
        let nextExtra = curRecipe?.extra_packing_json;
        if (extra_packing_json !== undefined) nextExtra = JSON.stringify(extra_packing_json || null);
        else if (nextExtra != null && typeof nextExtra !== 'string') nextExtra = JSON.stringify(nextExtra);
        const nextPackType = packaging_type !== undefined ? (packaging_type || null) : (curRecipe?.packaging_type ?? null);
        await run(
            'UPDATE recipes SET ingredients = ?, cooking_time = ?, batch_capacity = ?, portion_size = ?, extra_packing_json = ?, packaging_type = ? WHERE id = ?',
            [recipeIngsStr, nextCook || 60, nextBatch || 50, nextPortion || 1, nextExtra, nextPackType, menu.recipe_id]
        );

        if (Array.isArray(steps)) {
            await run("DELETE FROM recipe_steps WHERE recipe_id = ?", [stepTargetRecipeId]);
            for (let i = 0; i < steps.length; i++) {
                const s = steps[i] || {};
                await run(
                    "INSERT INTO recipe_steps (id, tenant_id, recipe_id, step_order, title, division_id, duration_minutes, required_resource_type, batch_capacity) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
                    [crypto.randomUUID(), null, stepTargetRecipeId, i + 1, String(s.title || ''), String(s.division_id || 'prep'), Number(s.duration_minutes || 0), String(s.required_resource_type || ''), Number(s.batch_capacity || 0)]
                );
            }
        }

        if (Array.isArray(tools)) {
            await run("DELETE FROM recipe_tools WHERE recipe_id = ?", [menu.recipe_id]);
            for (const t of tools) {
                if (!t || !t.tool_id) continue;
                await run(
                    "INSERT INTO recipe_tools (id, tenant_id, recipe_id, tool_id, batch_capacity, batch_duration_minutes) VALUES (?, ?, ?, ?, ?, ?)",
                    [crypto.randomUUID(), null, menu.recipe_id, String(t.tool_id), Number(t.batch_capacity || 0), Number(t.batch_duration_minutes || 0)]
                );
            }
        }

        // Update Menu (name only; timing/capacity are sourced from recipe)
        const nextFoodId = food_id === undefined ? (menu.food_id || null) : (food_id || null);
        await run(
            "UPDATE menu SET name = ?, food_id = ?, workflow_recipe_id = ?, recipe_id = ?, workflow_id = ?, packaging_stack_json = ? WHERE id = ?",
            [name || menu.name, nextFoodId, nextWorkflowId, nextRecipeId, nextWorkflowIdLib, nextPackagingStack, req.params.id]
        );

        await mbgSyncFoodMenuItemsPivotForMenu(req, req.params.id, nextFoodId);

        res.json({ success: true });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

app.post('/api/menu', async (req, res) => {
    const { name, ingredients, cooking_time, batch_capacity, portion_size, extra_packing_json, packaging_type, tools, steps, food_id, workflow_recipe_id, recipe_id: recipeRefId, workflow_id, packaging_stack_json } = req.body;
    const menuId = generateId('MN');

    try {
        await ensureProductionLibrarySchemaInCurrentDb();
        const dupe = await get("SELECT id FROM menu WHERE lower(name) = lower(?) LIMIT 1", [String(name || '').trim()]);
        if (dupe?.id) return res.status(409).json({ error: 'Nama menu sudah ada. Gunakan nama lain.' });

        // NEW-MODEL path: if recipeRefId passed explicitly, reuse existing recipe from library.
        // Legacy path: create implicit recipe from inline ingredients.
        let recipeId;
        if (recipeRefId) {
            const ex = await get("SELECT id FROM recipes WHERE id = ?", [String(recipeRefId)]);
            if (!ex?.id) return res.status(400).json({ error: 'recipe_id tidak ditemukan di library resep' });
            recipeId = String(recipeRefId);
        } else {
            recipeId = generateId('RC');
            await run("INSERT INTO recipes (id, name, instructions, ingredients, cooking_time, batch_capacity, portion_size, extra_packing_json, packaging_type) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
                [recipeId, name + ' Recipe', 'Auto-generated', JSON.stringify(ingredients || []), cooking_time || 60, batch_capacity || 50, portion_size || 1, JSON.stringify(extra_packing_json || null), packaging_type || null]);
        }

        // Workflow library ref (new model)
        let workflowIdLib = null;
        if (workflow_id) {
            const ex = await get("SELECT id FROM workflows WHERE id = ?", [String(workflow_id)]);
            if (!ex?.id) return res.status(400).json({ error: 'workflow_id tidak ditemukan di library workflow' });
            workflowIdLib = String(workflow_id);
        }

        // Legacy workflow_recipe_id (master resep as workflow source)
        const w = String(workflow_recipe_id || '').trim();
        let nextWorkflowId = w && w !== recipeId ? w : null;
        if (nextWorkflowId) {
            const ex = await get("SELECT id FROM recipes WHERE id = ?", [nextWorkflowId]);
            if (!ex?.id) return res.status(400).json({ error: 'workflow_recipe_id tidak ditemukan di master resep' });
        }
        const stepTargetRecipeId = nextWorkflowId || recipeId;

        // 2. Create Menu Item linked to Recipe + workflow + packaging_stack
        await run(
            "INSERT INTO menu (id, name, recipe_id, food_id, workflow_recipe_id, workflow_id, packaging_stack_json) VALUES (?, ?, ?, ?, ?, ?, ?)",
            [menuId, name, recipeId, food_id || null, nextWorkflowId, workflowIdLib, JSON.stringify(packaging_stack_json || null)]
        );

        await mbgSyncFoodMenuItemsPivotForMenu(req, menuId, food_id || null);

        if (Array.isArray(steps)) {
            for (let i = 0; i < steps.length; i++) {
                const s = steps[i] || {};
                await run(
                    "INSERT INTO recipe_steps (id, tenant_id, recipe_id, step_order, title, division_id, duration_minutes, required_resource_type, batch_capacity) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
                    [crypto.randomUUID(), null, stepTargetRecipeId, i + 1, String(s.title || ''), String(s.division_id || 'prep'), Number(s.duration_minutes || 0), String(s.required_resource_type || ''), Number(s.batch_capacity || 0)]
                );
            }
        }

        if (Array.isArray(tools)) {
            for (const t of tools) {
                if (!t || !t.tool_id) continue;
                await run(
                    "INSERT INTO recipe_tools (id, tenant_id, recipe_id, tool_id, batch_capacity, batch_duration_minutes) VALUES (?, ?, ?, ?, ?, ?)",
                    [crypto.randomUUID(), null, recipeId, String(t.tool_id), Number(t.batch_capacity || 0), Number(t.batch_duration_minutes || 0)]
                );
            }
        }

        res.json({
            id: menuId, name,
            recipe_id: recipeId,
            workflow_id: workflowIdLib,
            workflow_recipe_id: nextWorkflowId,
            packaging_stack_json: packaging_stack_json || null,
            ingredients, cooking_time, batch_capacity,
            portion_size: portion_size || 1,
            extra_packing_json: extra_packing_json || null,
            packaging_type: packaging_type || null
        });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

