app.post('/api/recipes', async (req, res) => {
    try {
        await ensureProductionLibrarySchemaInCurrentDb();
        const b = req.body || {};
        const id = generateId('RC');
        const name = String(b.name || '').trim();
        if (!name) return res.status(400).json({ error: 'name wajib' });
        const ingredients = Array.isArray(b.ingredients) ? b.ingredients : [];
        for (const ing of ingredients) {
            if (ing && ing.unit && !['gram', 'pcs'].includes(String(ing.unit).toLowerCase())) {
                const norm = normalizeUnitAndQty(ing.unit, ing.qty_per_portion || 0);
                ing.unit = norm.unit;
                ing.qty_per_portion = norm.qty;
            }
        }
        await run(
            "INSERT INTO recipes (id, name, instructions, ingredients, cooking_time, batch_capacity, portion_size) VALUES (?, ?, ?, ?, ?, ?, ?)",
            [id, name, String(b.instructions || ''), JSON.stringify(ingredients), Number(b.cooking_time || 60), Number(b.batch_capacity || 50), Number(b.portion_size || 1)]
        );
        if (Array.isArray(b.tools)) {
            for (const t of b.tools) {
                if (!t || !t.tool_id) continue;
                await run(
                    "INSERT INTO recipe_tools (id, tenant_id, recipe_id, tool_id, batch_capacity, batch_duration_minutes) VALUES (?, ?, ?, ?, ?, ?)",
                    [crypto.randomUUID(), null, id, String(t.tool_id), Number(t.batch_capacity || 0), Number(t.batch_duration_minutes || 0)]
                );
            }
        }
        res.json({ id, name, ingredients, cooking_time: Number(b.cooking_time || 60), batch_capacity: Number(b.batch_capacity || 50), portion_size: Number(b.portion_size || 1) });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

