const VALID_ACTIVITY_TYPES_BUILTIN = ['receive', 'sortir', 'prep', 'cook', 'plate', 'qc', 'dist', 'cleaning'];

async function getValidActivityTypes() {
    try {
        const row = await get("SELECT config FROM kitchen_config WHERE id = '1'").catch(() => null);
        const cfg = row && row.config ? JSON.parse(row.config) : {};
        const customs = Array.isArray(cfg.custom_capabilities) ? cfg.custom_capabilities.map(c => c.id) : [];
        return [...VALID_ACTIVITY_TYPES_BUILTIN, ...customs];
    } catch (e) {
        return VALID_ACTIVITY_TYPES_BUILTIN.slice();
    }
}

