app.delete('/api/workflows/:id', async (req, res) => {
    try {
        await ensureProductionLibrarySchemaInCurrentDb();
        const id = String(req.params.id || '').trim();
        const detach = String(req.query.detach || '').trim() === '1';
        if (detach) {
            await run("UPDATE menu SET workflow_id = NULL WHERE workflow_id = ?", [id]);
        }
        const refMenu = await get("SELECT id FROM menu WHERE workflow_id = ? LIMIT 1", [id]).catch(() => null);
        if (refMenu?.id) {
            return res.status(409).json({
                error: 'Workflow masih dipakai oleh menu',
                code: 'WORKFLOW_IN_USE',
                hint: 'Ubah workflow di Food & Menu (Edit menu), atau ulangi hapus dengan query ?detach=1 untuk melepaskan penautan workflow dari semua menu lalu menghapus (tindakan admin).'
            });
        }
        await run("DELETE FROM workflow_steps WHERE workflow_id = ?", [id]);
        await run("DELETE FROM workflows WHERE id = ?", [id]);
        res.sendStatus(204);
    } catch (e) { res.status(500).json({ error: e.message }); }
});

