app.put('/api/workflows/:id/steps', async (req, res) => {
    try {
        await ensureProductionLibrarySchemaInCurrentDb();
        const workflowId = req.params.id;
        const wf = await get("SELECT id FROM workflows WHERE id = ?", [workflowId]);
        if (!wf) return res.status(404).json({ error: 'Workflow not found' });
        const steps = Array.isArray(req.body?.steps) ? req.body.steps : [];
        const validTypes = await getValidActivityTypes();
        for (const s of steps) {
            const at = String(s.activity_type || '').toLowerCase();
            if (at === 'pack') return res.status(400).json({ error: "activity_type='pack' tidak boleh di-input manual - di-generate otomatis dari menu.packaging_stack" });
            if (at && !validTypes.includes(at)) {
                // allow custom (free-text) - tapi tetap log warning (not blocking)
            }
            if (!s.title) return res.status(400).json({ error: 'Setiap step wajib title' });
        }
        await run("DELETE FROM workflow_steps WHERE workflow_id = ?", [workflowId]);
        for (let i = 0; i < steps.length; i++) {
            const s = steps[i] || {};
            const sid = s.id && String(s.id).startsWith('WS_') ? String(s.id) : generateId('WS');
            const depArr = Array.isArray(s.depends_on_step_ids) ? s.depends_on_step_ids.map(String) : [];
            const ingArr = Array.isArray(s.ingredient_refs) ? s.ingredient_refs.map(String) : [];
            await run(
                `INSERT INTO workflow_steps (id, tenant_id, workflow_id, step_order, title, description, activity_type,
                    duration_minutes_per_batch, batch_capacity, required_resource_type, required_skill_level,
                    depends_on_step_ids, parallelizable, qc_required, temperature_celsius, hygiene_level,
                    ingredient_refs, ingredient_group, notes)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                [
                    sid, null, workflowId, i + 1, String(s.title || ''), String(s.description || ''),
                    String(s.activity_type || 'prep'),
                    Number(s.duration_minutes_per_batch || 0), Number(s.batch_capacity || 0),
                    String(s.required_resource_type || ''), String(s.required_skill_level || 'junior'),
                    JSON.stringify(depArr),
                    s.parallelizable ? 1 : 0, s.qc_required ? 1 : 0,
                    s.temperature_celsius != null ? Number(s.temperature_celsius) : null,
                    String(s.hygiene_level || 'medium'),
                    JSON.stringify(ingArr),
                    String(s.ingredient_group || ''),
                    String(s.notes || '')
                ]
            );
        }
        await run("UPDATE workflows SET updated_at = ? WHERE id = ?", [new Date().toISOString(), workflowId]);
        res.json({ success: true, step_count: steps.length });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

