// Durasi layer untuk satu batch berisi `batchPortions` unit (final pack / virtual pack).
// Prioritas: units_per_hour > 0 → menit = (batchPortions / units_per_hour) * 60
// Fallback legacy: duration_minutes = total menit untuk satu batch (tanpa skala porsi).
function packagingLayerMinutesForBatch(layer, batchPortions) {
    const portions = Math.max(1, Number(batchPortions) || 1);
    const uph = Number(layer && layer.units_per_hour);
    if (Number.isFinite(uph) && uph > 0) {
        return (portions / uph) * 60;
    }
    const dm = Number(layer && layer.duration_minutes);
    if (Number.isFinite(dm) && dm > 0) return dm;
    return 0.5;
}

// Helper: validasi & normalisasi packaging_stack (array layer)
// Input: array | string | null
// Output: array [{ material, material_type, quantity, unit, units_per_hour? } | { ..., duration_minutes? legacy }]
function normalizeFoodPackagingStack(raw) {
    if (raw == null) return [];
    let arr = raw;
    if (typeof arr === 'string') {
        try { arr = JSON.parse(arr); } catch (e) { return []; }
    }
    if (!Array.isArray(arr)) return [];
    return arr
        .map((layer, idx) => {
            const l = layer || {};
            const uphRaw = Number(l.units_per_hour);
            const hasUph = Number.isFinite(uphRaw) && uphRaw > 0;
            const base = {
                material: String(l.material || '').trim(),
                material_type: String(l.material_type || l.material || '').trim(),
                quantity: Number(l.quantity || 1) || 1,
                unit: String(l.unit || 'pcs').trim(),
                order: Number.isFinite(Number(l.order)) ? Number(l.order) : idx
            };
            if (hasUph) {
                const units_per_hour = Math.min(1e12, Math.max(1e-12, uphRaw));
                return { ...base, units_per_hour };
            }
            const dm = Number(l.duration_minutes);
            return {
                ...base,
                duration_minutes: Math.max(0.1, Number.isFinite(dm) && dm > 0 ? dm : 0.5)
            };
        })
        .filter(l => l.material.length > 0)
        .sort((a, b) => (a.order || 0) - (b.order || 0));
}

app.get('/api/foods', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const tenantId = getTenantIdFromReq(req);
        if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
        try {
            await ensureProductionLibrarySchemaInCurrentDb();
            const foods = await all(
                "SELECT id, tenant_id, name, created_at, date_served, packaging_type, packaging_stack_json FROM foods WHERE tenant_id = ? ORDER BY COALESCE(date_served, created_at) DESC",
                [tenantId]
            );
            foods.forEach(f => {
                try { f.packaging_stack = f.packaging_stack_json ? JSON.parse(f.packaging_stack_json) : []; }
                catch (e) { f.packaging_stack = []; }
                // Backward-compat: kalau stack kosong tapi ada packaging_type, bikin 1 layer default
                if (!Array.isArray(f.packaging_stack) || !f.packaging_stack.length) {
                    if (f.packaging_type) {
                        f.packaging_stack = [{
                            material: f.packaging_type,
                            material_type: f.packaging_type,
                            quantity: 1, unit: 'pcs', units_per_hour: 400, order: 0
                        }];
                    } else {
                        f.packaging_stack = [];
                    }
                }
            });
            res.json(foods);
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

app.get('/api/foods/:id', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const tenantId = getTenantIdFromReq(req);
        const id = String(req.params.id || '').trim();
        if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
        if (!id) return res.status(400).json({ error: 'Missing id' });
        try {
            await ensureProductionLibrarySchemaInCurrentDb();
            const f = await get(
                "SELECT id, tenant_id, name, created_at, date_served, packaging_type, packaging_stack_json FROM foods WHERE id = ? AND tenant_id = ?",
                [id, tenantId]
            );
            if (!f) return res.status(404).json({ error: 'Not found' });
            try { f.packaging_stack = f.packaging_stack_json ? JSON.parse(f.packaging_stack_json) : []; }
            catch (e) { f.packaging_stack = []; }
            if (!Array.isArray(f.packaging_stack) || !f.packaging_stack.length) {
                if (f.packaging_type) {
                    f.packaging_stack = [{
                        material: f.packaging_type,
                        material_type: f.packaging_type,
                        quantity: 1, unit: 'pcs', units_per_hour: 400, order: 0
                    }];
                } else {
                    f.packaging_stack = [];
                }
            }
            // Sertakan menus: pivot + menu yang hanya punya menu.food_id (data lama / sebelum sinkron pivot).
            try {
                const pivotMenus = await all(
                    `SELECT m.id, m.name, m.recipe_id, m.workflow_id, m.portion_size
                     FROM food_menu_items fmi JOIN menu m ON m.id = fmi.menu_id
                     WHERE fmi.food_id = ?
                       AND (fmi.tenant_id IS NULL OR TRIM(COALESCE(fmi.tenant_id,'')) = '' OR fmi.tenant_id = ?)`,
                    [id, tenantId]
                ).catch(() => []);
                const byMenu = new Map((pivotMenus || []).map(m => [String(m.id), m]));
                const directMenus = await all(
                    'SELECT m.id, m.name, m.recipe_id, m.workflow_id, m.portion_size FROM menu m WHERE m.food_id = ?',
                    [id]
                ).catch(() => []);
                for (const m of directMenus || []) {
                    const k = String(m.id);
                    if (!byMenu.has(k)) byMenu.set(k, m);
                }
                f.menus = [...byMenu.values()];
            } catch (e) { f.menus = []; }
            res.json(f);
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

app.post('/api/foods', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const tenantId = getTenantIdFromReq(req);
        if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
        const name = String(req.body.name || '').trim();
        if (!name) return res.status(400).json({ error: 'Name required' });
        const date_served = req.body.date_served ? String(req.body.date_served) : null;
        const packaging_type = req.body.packaging_type ? String(req.body.packaging_type) : null;
        // Terima stack baru; fallback: build single-layer dari packaging_type
        let stack = normalizeFoodPackagingStack(req.body.packaging_stack);
        if (!stack.length && packaging_type) {
            stack = [{
                material: packaging_type, material_type: packaging_type,
                quantity: 1, unit: 'pcs', units_per_hour: 400, order: 0
            }];
        }
        if (!stack.length) {
            return res.status(400).json({
                error: 'packaging_stack kosong atau tidak valid. Isi minimal satu layer Final Packaging (material + kecepatan / durasi).',
                code: 'PACKAGING_STACK_REQUIRED'
            });
        }
        try {
            await ensureProductionLibrarySchemaInCurrentDb();
            const id = crypto.randomUUID();
            const now = new Date().toISOString();
            await run(
                "INSERT INTO foods (id, tenant_id, name, created_at, date_served, packaging_type, packaging_stack_json) VALUES (?, ?, ?, ?, ?, ?, ?)",
                [id, tenantId, name, now, date_served, packaging_type, JSON.stringify(stack)]
            );
            const menuItemIds = Array.isArray(req.body.menu_item_ids) ? req.body.menu_item_ids : [];
            for (const mid of menuItemIds) {
                const menuId = String(mid || '').trim();
                if (!menuId) continue;
                try {
                    await run(
                        "INSERT INTO food_menu_items (id, tenant_id, food_id, menu_id, created_at) VALUES (?, ?, ?, ?, ?)",
                        [crypto.randomUUID(), tenantId, id, menuId, now]
                    );
                } catch (e) { }
            }
            res.json({ id, tenant_id: tenantId, name, created_at: now, date_served, packaging_type, packaging_stack: stack });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

