app.get('/api/foods/:id/menus', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const tenantId = getTenantIdFromReq(req);
        const foodId = String(req.params.id || '').trim();
        if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
        if (!foodId) return res.status(400).json({ error: 'Missing id' });
        try {
            await ensureProductionLibrarySchemaInCurrentDb();
            const rows = await all(
                `SELECT m.*, r.ingredients, r.cooking_time, r.batch_capacity, r.portion_size, r.extra_packing_json, r.packaging_type
                 FROM food_menu_items fmi
                 JOIN menu m ON m.id = fmi.menu_id
                 LEFT JOIN recipes r ON r.id = m.recipe_id
                 WHERE fmi.food_id = ?
                   AND (fmi.tenant_id IS NULL OR TRIM(COALESCE(fmi.tenant_id,'')) = '' OR fmi.tenant_id = ?)
                 ORDER BY fmi.created_at DESC`,
                [foodId, tenantId]
            );
            const byId = new Map((rows || []).map(r => [String(r.id), r]));
            const directRows = await all(
                `SELECT m.*, r.ingredients, r.cooking_time, r.batch_capacity, r.portion_size, r.extra_packing_json, r.packaging_type
                 FROM menu m
                 LEFT JOIN recipes r ON r.id = m.recipe_id
                 WHERE m.food_id = ?`,
                [foodId]
            ).catch(() => []);
            for (const r of directRows || []) {
                const k = String(r.id);
                if (!byId.has(k)) byId.set(k, r);
            }
            const merged = [...byId.values()];
            merged.forEach(r => parseJson(r, ['ingredients']));
            merged.forEach(r => parseJson(r, ['extra_packing_json']));
            res.json(merged);
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

app.put('/api/foods/:id', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const tenantId = getTenantIdFromReq(req);
        const id = String(req.params.id || '').trim();
        if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
        if (!id) return res.status(400).json({ error: 'Missing id' });
        try {
            await ensureProductionLibrarySchemaInCurrentDb();
            const cur = await get("SELECT * FROM foods WHERE id = ? AND tenant_id = ?", [id, tenantId]);
            if (!cur) return res.status(404).json({ error: 'Not found' });
            const name = String(req.body.name ?? cur.name).trim();
            const date_served = req.body.date_served === undefined ? cur.date_served : (req.body.date_served ? String(req.body.date_served) : null);
            const packaging_type = req.body.packaging_type === undefined ? cur.packaging_type : (req.body.packaging_type ? String(req.body.packaging_type) : null);
            if (!name) return res.status(400).json({ error: 'Name required' });
            // packaging_stack update (opsional). Jika undefined → pakai nilai lama.
            let stackJson = cur.packaging_stack_json;
            if (req.body.packaging_stack !== undefined) {
                const stack = normalizeFoodPackagingStack(req.body.packaging_stack);
                stackJson = JSON.stringify(stack);
            }
            await run(
                "UPDATE foods SET name = ?, date_served = ?, packaging_type = ?, packaging_stack_json = ? WHERE id = ? AND tenant_id = ?",
                [name, date_served, packaging_type, stackJson, id, tenantId]
            );
            res.json({ success: true });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

