app.delete('/api/production/orders/:id/plan', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const tenantId = getTenantIdFromReq(req);
        const q = String(req.params.id || '').trim();
        if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
        try {
            const order = await get("SELECT * FROM production_orders WHERE (id = ? OR code = ?) AND tenant_id = ? LIMIT 1", [q, q, tenantId]);
            if (!order) return res.status(404).json({ error: 'Order not found' });

            // Helper to delete plan and related data
            const deletePlanData = async (planId) => {
                if (!planId) return;
                try { await run("DELETE FROM plan_backups WHERE plan_id = ? AND tenant_id = ?", [planId, tenantId]); } catch (e) { }
                await run("DELETE FROM plan_doc_generations WHERE plan_id = ?", [planId]);
                await run("DELETE FROM tasks WHERE batch_id IN (SELECT id FROM batches WHERE plan_id = ?)", [planId]);
                await run("DELETE FROM tasks WHERE plan_id = ?", [planId]);
                await run("DELETE FROM batches WHERE plan_id = ?", [planId]);
                await run("DELETE FROM plans WHERE id = ?", [planId]);
            };

            const candidates = new Map();
            const ref = order.plan_id ? String(order.plan_id).trim() : '';
            if (ref) {
                const p = await get("SELECT id, code, tenant_id FROM plans WHERE id = ? OR code = ? LIMIT 1", [ref, ref]);
                if (p?.id) candidates.set(String(p.id), p);
            }
            const byOrder = await all(
                "SELECT id, code, tenant_id FROM plans WHERE source_order_id = ? AND (tenant_id = ? OR tenant_id IS NULL) ORDER BY created_at DESC",
                [order.id, tenantId]
            );
            for (const p of (byOrder || [])) candidates.set(String(p.id), p);

            for (const p of candidates.values()) {
                const planId = String(p.id);
                const planCode = String(p.code || '').trim();
                // Update references in orders first
                if (planCode) {
                    try { await run("UPDATE production_orders SET plan_id = NULL WHERE tenant_id = ? AND (plan_id = ? OR plan_id = ?)", [tenantId, planId, planCode]); } catch (e) { }
                } else {
                    try { await run("UPDATE production_orders SET plan_id = NULL WHERE plan_id = ? AND tenant_id = ?", [planId, tenantId]); } catch (e) { }
                }
                await deletePlanData(planId);
            }

            await run("UPDATE production_orders SET plan_id = NULL WHERE id = ? AND tenant_id = ?", [order.id, tenantId]);

            res.sendStatus(204);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.delete('/api/production/orders/:id', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const tenantId = getTenantIdFromReq(req);
        const q = String(req.params.id || '').trim();
        if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
        try {
            const order = await get("SELECT * FROM production_orders WHERE (id = ? OR code = ?) AND tenant_id = ? LIMIT 1", [q, q, tenantId]);
            if (!order) return res.status(404).json({ error: 'Order not found' });

            // 1. Delete associated Plan if exists
            const candidates = new Map();
            const ref = order.plan_id ? String(order.plan_id).trim() : '';
            if (ref) {
                const p = await get("SELECT id FROM plans WHERE id = ? OR code = ? LIMIT 1", [ref, ref]);
                if (p?.id) candidates.set(String(p.id), String(p.id));
            }
            const byOrder = await all("SELECT id FROM plans WHERE source_order_id = ? AND (tenant_id = ? OR tenant_id IS NULL)", [order.id, tenantId]);
            for (const p of (byOrder || [])) candidates.set(String(p.id), String(p.id));

            for (const planId of candidates.values()) {
                await run("DELETE FROM plan_backups WHERE plan_id = ? AND tenant_id = ?", [planId, tenantId]);
                await run("DELETE FROM plan_doc_generations WHERE plan_id = ?", [planId]);
                await run("DELETE FROM tasks WHERE batch_id IN (SELECT id FROM batches WHERE plan_id = ?)", [planId]);
                await run("DELETE FROM tasks WHERE plan_id = ?", [planId]);
                await run("DELETE FROM batches WHERE plan_id = ?", [planId]);
                await run("DELETE FROM plans WHERE id = ?", [planId]);
            }

            // 2. Delete Order Data
            await run("DELETE FROM prep_jobs WHERE order_id = ?", [order.id]);
            await run("DELETE FROM cook_batches_v2 WHERE order_id = ?", [order.id]); // Cascade delete requirements usually, but let's be safe
            // Assuming cook_batch_requirements has FK cascade or we delete manually? 
            // SQLite FKs are enabled in reset_db but maybe not consistently.
            // Let's rely on FKs or simple cleanup.

            await run("DELETE FROM production_order_items WHERE order_id = ?", [order.id]);
            await run("DELETE FROM order_deliveries WHERE order_id = ?", [order.id]);
            await run("DELETE FROM production_orders WHERE id = ? AND tenant_id = ?", [order.id, tenantId]);

            res.sendStatus(204);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

