async function buildProductionOrderDocData(orderId, tenantId) {
    const order = await get("SELECT * FROM production_orders WHERE id = ? AND tenant_id = ?", [orderId, tenantId]);
    if (!order) return { ok: false, errors: [{ code: 'ORDER_NOT_FOUND', message: 'Order tidak ditemukan' }] };

    const kitchen = await getKitchenConfigSafe();
    const kitchenName = String(kitchen.kitchen_name || kitchen.name || '').trim();
    const kitchenAddress = String(kitchen.address || '').trim();
    const kitchenContact = String(kitchen.contact_phone || kitchen.contact || '').trim();
    if (!kitchenName || !kitchenAddress || !kitchenContact) {
        return { ok: false, errors: [{ code: 'KITCHEN_CONFIG_MISSING', message: 'Kop SPPG belum lengkap (nama kitchen, alamat, kontak). Silakan lengkapi di Kitchen Config.' }] };
    }

    const items = await all(
        `SELECT oi.*, fm.name as menu_name, fm.instructions, fm.cook_minutes, fm.batch_capacity, fm.portion_minutes, fm.portion_capacity
         FROM production_order_items oi
         JOIN food_menus fm ON fm.id = oi.food_menu_id
         WHERE oi.order_id = ?`,
        [orderId]
    );
    if (!items.length) return { ok: false, errors: [{ code: 'ORDER_EMPTY', message: 'Order tidak memiliki menu' }] };

    const errors = [];
    const menuDocs = [];
    const invoiceMap = new Map();

    for (const it of items) {
        const portions = safeNumber(it.portions);
        const ing = await all(
            `SELECT mi.*, ing.name as ingredient_name, ing.unit as ingredient_unit, ing.estimated_price
             FROM food_menu_ingredients mi
             LEFT JOIN ingredients ing ON ing.id = mi.ingredient_id
             WHERE mi.food_menu_id = ? AND mi.tenant_id = ?`,
            [it.food_menu_id, tenantId]
        );
        if (!ing.length) errors.push({ code: 'MENU_NO_INGREDIENTS', message: `Menu ${it.menu_name} belum memiliki ingredient` });

        const rows = [];
        for (const r of ing) {
            if (!r.ingredient_id) continue;
            const ingredientName = String(r.ingredient_name || r.ingredient_id);
            const unit = String(r.qty_unit || r.ingredient_unit || '-').trim() || '-';
            const price = Number(r.estimated_price);
            const safePrice = Number.isFinite(price) ? price : 0;
            const qty = safeNumber(r.qty_per_portion) * portions;
            const cost = qty * safePrice;
            rows.push({ ingredient_id: r.ingredient_id, ingredient_name: ingredientName, qty, unit, price_per_unit: safePrice, cost });

            const prev = invoiceMap.get(r.ingredient_id) || { ingredient_id: r.ingredient_id, ingredient_name: ingredientName, qty: 0, unit, price_per_unit: safePrice, cost: 0 };
            prev.qty += qty;
            prev.unit = unit || prev.unit;
            prev.price_per_unit = safePrice;
            prev.cost = prev.qty * prev.price_per_unit;
            invoiceMap.set(r.ingredient_id, prev);
        }

        menuDocs.push({
            menu_id: it.food_menu_id,
            menu_name: it.menu_name,
            portions,
            instructions: it.instructions || '',
            ingredients: rows
        });
    }

    if (errors.length) return { ok: false, errors };

    const invoice = Array.from(invoiceMap.values()).sort((a, b) => String(a.ingredient_name).localeCompare(String(b.ingredient_name)));
    const total_cost = invoice.reduce((a, r) => a + safeNumber(r.cost), 0);

    const preps = await all(
        `SELECT p.*, ing.name as ingredient_name
         FROM prep_jobs p
         LEFT JOIN ingredients ing ON ing.id = p.ingredient_id
         WHERE p.order_id = ?
         ORDER BY ingredient_name ASC`,
        [orderId]
    );
    const cooks = await all(
        `SELECT b.*, fm.name as menu_name
         FROM cook_batches_v2 b
         LEFT JOIN food_menus fm ON fm.id = b.food_menu_id
         WHERE b.order_id = ?
         ORDER BY fm.name ASC, b.batch_no ASC`,
        [orderId]
    );
    const portions = await all(
        `SELECT pb.*, fm.name as menu_name
         FROM portion_batches pb
         LEFT JOIN food_menus fm ON fm.id = pb.food_menu_id
         WHERE pb.order_id = ?
         ORDER BY fm.name ASC, pb.started_at ASC`,
        [orderId]
    );

    const summary = {
        order_id: order.id,
        order_code: order.code || readableCode('PO', order.id),
        target_portions: order.target_portions,
        target_delivery_time: order.target_delivery_time,
        menu_count: menuDocs.length,
        ingredient_count: invoice.length,
        total_cost
    };

    return { ok: true, order, kitchen, menus: menuDocs, invoice, timeline: { preps, cooks, portions }, summary };
}

app.get('/api/production/orders/:id/docs/:doc/:format', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const tenantId = getTenantIdFromReq(req);
        const orderId = String(req.params.id || '').trim();
        const docType = String(req.params.doc || '').toLowerCase();
        const fmt = String(req.params.format || '').toLowerCase();
        if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
        try {
            const data = await buildProductionOrderDocData(orderId, tenantId);
            if (!data.ok) return res.status(400).json({ error: 'VALIDATION_FAILED', details: data.errors || [] });
            const code = data.summary.order_code;
            const baseName = `${code}-${docType}`;
            const actorEmail = await resolveActorEmail(req.auth);

            if (fmt === 'pdf') {
                const pdf = new PDFDocument({ size: 'A4', margin: 36 });
                const pt = new PassThrough();
                const chunks = [];
                pt.on('data', c => chunks.push(c));
                pdf.pipe(pt);

                const title = docType === 'menu'
                    ? `Dokumen Menu (${code})`
                    : docType === 'invoice'
                        ? `Invoice Pemesanan Bahan (${code})`
                        : `Timeline Produksi (${code})`;

                const meta = {
                    plan_code: code,
                    target_portions: data.summary.target_portions,
                    target_delivery_time: data.summary.target_delivery_time,
                    generated_at: new Date().toISOString(),
                    generated_by: actorEmail || '-',
                    doc_no: `${code}/${docType.toUpperCase()}/SPPG`,
                    page_no: 1
                };
                let pageNo = 0;
                let inRenderTop = false;
                const renderTop = () => {
                    if (inRenderTop) return;
                    inRenderTop = true;
                    pageNo += 1;
                    meta.page_no = pageNo;
                    pdfHeader(pdf, data.kitchen, title);
                    pdfMetaBlock(pdf, meta);
                    pdfFooter(pdf, meta);
                    inRenderTop = false;
                };
                renderTop();
                pdf.on('pageAdded', renderTop);

                if (docType === 'menu') {
                    for (let i = 0; i < data.menus.length; i++) {
                        const m = data.menus[i];
                        if (i > 0) pdf.addPage();
                        pdf.fontSize(12).font('Helvetica-Bold').text(`${m.menu_name}`);
                        pdf.fontSize(9).font('Helvetica').fillColor('#344054').text(`Porsi: ${Number(m.portions || 0).toLocaleString('id-ID')}`);
                        pdf.fillColor('#000');
                        pdf.moveDown(0.5);
                        pdf.fontSize(10).font('Helvetica-Bold').text('Instruksi');
                        pdf.moveDown(0.2);
                        pdf.fontSize(9).font('Helvetica').text(String(m.instructions || '').trim() || '-', { width: 520 });
                        pdf.moveDown(0.8);
                        pdf.fontSize(10).font('Helvetica-Bold').text('Kebutuhan Bahan (Total untuk Order)');
                        pdf.moveDown(0.4);
                        const rows = (m.ingredients || []).map((it, idx) => ({
                            no: idx + 1,
                            bahan: it.ingredient_name,
                            qty: Number(it.qty || 0).toFixed(2),
                            unit: it.unit || '',
                            harga: Number(it.price_per_unit || 0).toLocaleString('id-ID'),
                            biaya: Number(it.cost || 0).toLocaleString('id-ID')
                        }));
                        pdfTable(
                            pdf,
                            [
                                { key: 'no', header: 'No', width: 32, align: 'right' },
                                { key: 'bahan', header: 'Bahan', width: 230, align: 'left' },
                                { key: 'qty', header: 'Qty', width: 60, align: 'right' },
                                { key: 'unit', header: 'Unit', width: 46, align: 'left' },
                                { key: 'harga', header: 'Harga/Unit', width: 76, align: 'right' },
                                { key: 'biaya', header: 'Biaya', width: 76, align: 'right' }
                            ],
                            rows,
                            { fontSize: 9 }
                        );
                        const subtotal = (m.ingredients || []).reduce((a, r) => a + safeNumber(r.cost), 0);
                        pdf.moveDown(0.4);
                        pdf.fontSize(10).font('Helvetica-Bold').text(`Subtotal Menu: Rp ${Number(subtotal || 0).toLocaleString('id-ID')}`, { align: 'right' });
                    }
                    pdf.moveDown(0.8);
                    pdfSignatureTable(pdf, 'Pengesahan', ['Chef', 'Ahli Gizi', 'Kepala SPPG']);
                } else if (docType === 'invoice') {
                    pdf.fontSize(10).font('Helvetica-Bold').text('Daftar Pemesanan Bahan');
                    pdf.moveDown(0.4);
                    const rows = (data.invoice || []).map((r, idx) => ({
                        no: idx + 1,
                        bahan: r.ingredient_name,
                        qty: Number(r.qty || 0).toFixed(2),
                        unit: r.unit || '',
                        harga: Number(r.price_per_unit || 0).toLocaleString('id-ID'),
                        biaya: Number(r.cost || 0).toLocaleString('id-ID')
                    }));
                    pdfTable(
                        pdf,
                        [
                            { key: 'no', header: 'No', width: 32, align: 'right' },
                            { key: 'bahan', header: 'Bahan', width: 230, align: 'left' },
                            { key: 'qty', header: 'Qty', width: 60, align: 'right' },
                            { key: 'unit', header: 'Unit', width: 46, align: 'left' },
                            { key: 'harga', header: 'Harga/Unit', width: 76, align: 'right' },
                            { key: 'biaya', header: 'Biaya', width: 76, align: 'right' }
                        ],
                        rows,
                        { fontSize: 9 }
                    );
                    pdf.moveDown(0.6);
                    pdf.fontSize(11).font('Helvetica-Bold').text(`Total Estimasi: Rp ${Number(data.summary.total_cost || 0).toLocaleString('id-ID')}`, { align: 'right' });
                    pdf.moveDown(0.8);
                    pdfSignatureTable(pdf, 'Pengesahan', ['Gudang/Purchasing', 'Ahli Gizi', 'Kepala SPPG']);
                } else if (docType === 'timeline') {
                    pdf.fontSize(10).font('Helvetica-Bold').text('Persiapan Bahan');
                    pdf.moveDown(0.4);
                    const prepRows = (data.timeline.preps || []).map((p, idx) => ({
                        no: idx + 1,
                        bahan: p.ingredient_name || p.ingredient_id,
                        req: `${Number(p.required_qty || 0).toFixed(2)} ${p.unit || ''}`,
                        status: p.status || '',
                        checklist: ''
                    }));
                    pdfTable(
                        pdf,
                        [
                            { key: 'no', header: 'No', width: 28, align: 'right' },
                            { key: 'bahan', header: 'Bahan', width: 250, align: 'left' },
                            { key: 'req', header: 'Kebutuhan', width: 110, align: 'left' },
                            { key: 'status', header: 'Sistem', width: 70, align: 'left' },
                            { key: 'checklist', header: 'Checklist', width: 62, align: 'left' }
                        ],
                        prepRows,
                        { fontSize: 8 }
                    );
                    pdf.addPage();
                    pdf.fontSize(10).font('Helvetica-Bold').text('Batch Memasak');
                    pdf.moveDown(0.4);
                    const cookRows = (data.timeline.cooks || []).map((b, idx) => ({
                        no: idx + 1,
                        menu: b.menu_name || '',
                        batch: `#${b.batch_no || '-'}`,
                        size: String(b.batch_size || 0),
                        status: b.status || '',
                        checklist: ''
                    }));
                    pdfTable(
                        pdf,
                        [
                            { key: 'no', header: 'No', width: 28, align: 'right' },
                            { key: 'menu', header: 'Menu', width: 210, align: 'left' },
                            { key: 'batch', header: 'Batch', width: 50, align: 'left' },
                            { key: 'size', header: 'Porsi', width: 50, align: 'right' },
                            { key: 'status', header: 'Sistem', width: 70, align: 'left' },
                            { key: 'checklist', header: 'Checklist', width: 88, align: 'left' }
                        ],
                        cookRows,
                        { fontSize: 8 }
                    );
                    pdf.addPage();
                    pdf.fontSize(10).font('Helvetica-Bold').text('Pemorsian');
                    pdf.moveDown(0.4);
                    const portionRows = (data.timeline.portions || []).map((p, idx) => ({
                        no: idx + 1,
                        menu: p.menu_name || '',
                        target: String(p.target_portions || 0),
                        done: String(p.portions_done || 0),
                        checklist: ''
                    }));
                    pdfTable(
                        pdf,
                        [
                            { key: 'no', header: 'No', width: 28, align: 'right' },
                            { key: 'menu', header: 'Menu', width: 260, align: 'left' },
                            { key: 'target', header: 'Target', width: 70, align: 'right' },
                            { key: 'done', header: 'Done', width: 60, align: 'right' },
                            { key: 'checklist', header: 'Checklist', width: 74, align: 'left' }
                        ],
                        portionRows,
                        { fontSize: 8 }
                    );
                    pdf.moveDown(0.8);
                    pdfSignatureTable(pdf, 'Pengesahan', ['Koordinator Produksi', 'Kepala SPPG']);
                } else {
                    pdf.text('Dokumen tidak dikenal');
                }

                const done = new Promise((resolve, reject) => {
                    pt.on('end', resolve);
                    pt.on('error', reject);
                    pdf.on('error', reject);
                });
                pdf.end();
                await done;
                const buf = Buffer.concat(chunks);
                sendPdf(res, `${baseName}.pdf`);
                res.end(buf);
                return;
            }

            if (fmt === 'xlsx') {
                const wb = new ExcelJS.Workbook();
                wb.creator = 'MBG Kitchen';
                wb.created = new Date();
                const header = {
                    name: String(data.kitchen.kitchen_name || data.kitchen.name || ''),
                    address: String(data.kitchen.address || ''),
                    contact: String(data.kitchen.contact_phone || data.kitchen.contact || ''),
                    code
                };

                if (docType === 'menu') {
                    for (const m of data.menus) {
                        const ws = wb.addWorksheet(String(m.menu_name || 'Menu').slice(0, 28));
                        ws.addRow([header.name]).font = { bold: true, size: 14 };
                        ws.addRow([header.address]);
                        ws.addRow([header.contact]);
                        ws.addRow([`Order: ${header.code}`]).font = { bold: true };
                        ws.addRow([]);
                        ws.addRow(['Menu', m.menu_name]).font = { bold: true };
                        ws.addRow(['Porsi', m.portions]).font = { bold: true };
                        ws.addRow([]);
                        const hr = ws.addRow(['Bahan', 'Qty', 'Unit', 'Harga/Unit', 'Biaya']);
                        hr.font = { bold: true };
                        hr.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFEEF2F6' } };
                        for (const it of m.ingredients) ws.addRow([it.ingredient_name, it.qty, it.unit, it.price_per_unit, it.cost]);
                        ws.getColumn(2).numFmt = '0.00';
                        ws.getColumn(4).numFmt = '#,##0';
                        ws.getColumn(5).numFmt = '#,##0';
                    }
                } else if (docType === 'invoice') {
                    const ws = wb.addWorksheet('Invoice');
                    ws.addRow([header.name]).font = { bold: true, size: 14 };
                    ws.addRow([header.address]);
                    ws.addRow([header.contact]);
                    ws.addRow([`Order: ${header.code}`]).font = { bold: true };
                    ws.addRow([]);
                    const hr = ws.addRow(['Bahan', 'Qty', 'Unit', 'Harga/Unit', 'Biaya']);
                    hr.font = { bold: true };
                    hr.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFEEF2F6' } };
                    for (const r of data.invoice) ws.addRow([r.ingredient_name, r.qty, r.unit, r.price_per_unit, r.cost]);
                    ws.addRow([]);
                    const tr = ws.addRow(['Total', '', '', '', data.summary.total_cost]);
                    tr.font = { bold: true };
                    ws.getColumn(2).numFmt = '0.00';
                    ws.getColumn(4).numFmt = '#,##0';
                    ws.getColumn(5).numFmt = '#,##0';
                } else if (docType === 'timeline') {
                    const ws = wb.addWorksheet('Prep');
                    ws.addRow([header.name]).font = { bold: true, size: 14 };
                    ws.addRow([header.address]);
                    ws.addRow([header.contact]);
                    ws.addRow([`Order: ${header.code}`]).font = { bold: true };
                    ws.addRow([]);
                    ws.addRow(['Bahan', 'Kebutuhan', 'Status', 'Checklist']).font = { bold: true };
                    for (const p of data.timeline.preps || []) ws.addRow([p.ingredient_name || p.ingredient_id, `${p.required_qty} ${p.unit || ''}`, p.status || '', '']);
                    const wsc = wb.addWorksheet('Cooking');
                    wsc.addRow([header.name]).font = { bold: true, size: 14 };
                    wsc.addRow([header.address]);
                    wsc.addRow([header.contact]);
                    wsc.addRow([`Order: ${header.code}`]).font = { bold: true };
                    wsc.addRow([]);
                    wsc.addRow(['Menu', 'Batch', 'Porsi', 'Status', 'Checklist']).font = { bold: true };
                    for (const b of data.timeline.cooks || []) wsc.addRow([b.menu_name || '', b.batch_no || '', b.batch_size || 0, b.status || '', '']);
                    const wsp = wb.addWorksheet('Portion');
                    wsp.addRow([header.name]).font = { bold: true, size: 14 };
                    wsp.addRow([header.address]);
                    wsp.addRow([header.contact]);
                    wsp.addRow([`Order: ${header.code}`]).font = { bold: true };
                    wsp.addRow([]);
                    wsp.addRow(['Menu', 'Target', 'Done', 'Checklist']).font = { bold: true };
                    for (const p of data.timeline.portions || []) wsp.addRow([p.menu_name || '', p.target_portions || 0, p.portions_done || 0, '']);
                } else {
                    const ws = wb.addWorksheet('Doc');
                    ws.addRow(['Dokumen tidak dikenal']);
                }

                const buf = await wb.xlsx.writeBuffer();
                sendXlsx(res, `${baseName}.xlsx`);
                res.end(Buffer.from(buf));
                return;
            }

            res.status(400).json({ error: 'FORMAT_NOT_SUPPORTED' });
        } catch (e) {
            if (res.headersSent) { try { res.end(); } catch (_) { } return; }
            res.status(500).json({ error: e.message });
        }
    });
});


