app.post('/api/purchases', async (req, res) => {
    const { ingredient_id, quantity, total_price, purchase_date, notes } = req.body;

    if (!ingredient_id || !quantity || !total_price) return res.status(400).json({ error: 'Missing fields' });

    try {
        await run(`CREATE TABLE IF NOT EXISTS purchases (
            id TEXT PRIMARY KEY,
            ingredient_id TEXT,
            quantity REAL,
            total_price REAL,
            unit_price REAL,
            purchase_date TEXT,
            notes TEXT,
            created_at TEXT
        )`);

        const id = crypto.randomUUID();
        const unitPrice = total_price / quantity;
        const now = new Date().toISOString();
        let purchaseDate = now;
        if (purchase_date) {
            const d = new Date(purchase_date);
            if (!Number.isNaN(d.getTime())) purchaseDate = d.toISOString();
        }

        await run(`INSERT INTO purchases (id, ingredient_id, quantity, total_price, unit_price, purchase_date, notes, created_at)
                   VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
            [id, ingredient_id, quantity, total_price, unitPrice, purchaseDate, notes || '', now]);

        // Update Ingredient Price (Weighted Average or Last Price?)
        // Strategy: Update 'estimated_price' to Last Purchase Price for accuracy
        await run("UPDATE ingredients SET estimated_price = ? WHERE id = ?", [unitPrice, ingredient_id]);

        // Also update stock? (Optional, assume 'yes' for simple inventory)
        // await run("UPDATE ingredients SET stock = stock + ? WHERE id = ?", [quantity, ingredient_id]);

        res.json({ success: true, id, unit_price: unitPrice });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

