async function ensureMarketPricesTable() {
    await run(`CREATE TABLE IF NOT EXISTS market_prices (
        id TEXT PRIMARY KEY,
        commodity_name TEXT,
        price REAL,
        unit TEXT,
        region TEXT,
        date TEXT,
        source TEXT,
        fetched_at TEXT,
        source_url TEXT,
        commodity_id TEXT,
        price_date TEXT
    )`);
    try { await run("ALTER TABLE market_prices ADD COLUMN fetched_at TEXT"); } catch (e) { }
    try { await run("ALTER TABLE market_prices ADD COLUMN source_url TEXT"); } catch (e) { }
    try { await run("ALTER TABLE market_prices ADD COLUMN commodity_id TEXT"); } catch (e) { }
    try { await run("ALTER TABLE market_prices ADD COLUMN price_date TEXT"); } catch (e) { }
    try { await run("CREATE UNIQUE INDEX IF NOT EXISTS idx_market_prices_unique ON market_prices(commodity_name, unit, region, date)"); } catch (e) { }
}

function httpGetText(url, timeoutMs = 15000) {
    return new Promise((resolve, reject) => {
        let u;
        try { u = new URL(url); } catch (e) { reject(new Error('Invalid URL')); return; }
        const req = https.request({
            protocol: u.protocol,
            hostname: u.hostname,
            port: u.port || 443,
            path: u.pathname + u.search,
            method: 'GET',
            headers: {
                'User-Agent': 'MBG-CloudKitchen/1.0',
                'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
                'Accept-Encoding': 'gzip, deflate, br, identity'
            }
        }, (res) => {
            const status = Number(res.statusCode || 0);
            if (status < 200 || status >= 300) {
                res.resume();
                reject(new Error(`HTTP ${status}`));
                return;
            }
            const chunks = [];
            res.on('data', chunk => chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk)));
            res.on('end', () => {
                const buf = Buffer.concat(chunks);
                const enc = String(res.headers['content-encoding'] || '').toLowerCase().trim();

                const finish = (outBuf) => {
                    try { resolve(outBuf.toString('utf8')); } catch (e) { reject(e); }
                };

                if (!enc || enc === 'identity') return finish(buf);
                if (enc.includes('gzip')) return zlib.gunzip(buf, (e, out) => e ? reject(e) : finish(out));
                if (enc.includes('deflate')) return zlib.inflate(buf, (e, out) => e ? reject(e) : finish(out));
                if (enc.includes('br')) return zlib.brotliDecompress(buf, (e, out) => e ? reject(e) : finish(out));
                finish(buf);
            });
        });
        req.on('error', reject);
        req.setTimeout(timeoutMs, () => {
            try { req.destroy(new Error('Timeout')); } catch (e) { }
        });
        req.end();
    });
}

function httpPostForm(url, form, timeoutMs = 15000) {
    return new Promise((resolve, reject) => {
        let u;
        try { u = new URL(url); } catch (e) { reject(new Error('Invalid URL')); return; }
        const body = new URLSearchParams(form).toString();
        const req = https.request({
            protocol: u.protocol,
            hostname: u.hostname,
            port: u.port || 443,
            path: u.pathname + u.search,
            method: 'POST',
            headers: {
                'User-Agent': 'MBG-CloudKitchen/1.0',
                'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
                'Accept-Encoding': 'gzip, deflate, br, identity',
                'Content-Type': 'application/x-www-form-urlencoded',
                'Content-Length': Buffer.byteLength(body)
            }
        }, (res) => {
            const status = Number(res.statusCode || 0);
            if (status < 200 || status >= 300) {
                res.resume();
                reject(new Error(`HTTP ${status}`));
                return;
            }
            const chunks = [];
            res.on('data', chunk => chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk)));
            res.on('end', () => {
                const buf = Buffer.concat(chunks);
                const enc = String(res.headers['content-encoding'] || '').toLowerCase().trim();

                const finish = (outBuf) => {
                    try { resolve(outBuf.toString('utf8')); } catch (e) { reject(e); }
                };

                if (!enc || enc === 'identity') return finish(buf);
                if (enc.includes('gzip')) return zlib.gunzip(buf, (e, out) => e ? reject(e) : finish(out));
                if (enc.includes('deflate')) return zlib.inflate(buf, (e, out) => e ? reject(e) : finish(out));
                if (enc.includes('br')) return zlib.brotliDecompress(buf, (e, out) => e ? reject(e) : finish(out));
                finish(buf);
            });
        });
        req.on('error', reject);
        req.setTimeout(timeoutMs, () => {
            try { req.destroy(new Error('Timeout')); } catch (e) { }
        });
        req.write(body);
        req.end();
    });
}

function parseSiskaperbapoDisplayShow(html) {
    const text = String(html || '')
        .replace(/<script[\s\S]*?<\/script>/gi, '\n')
        .replace(/<style[\s\S]*?<\/style>/gi, '\n')
        .replace(/<[^>]+>/g, '\n')
        .replace(/&nbsp;/g, ' ')
        .replace(/&amp;/g, '&')
        .replace(/&lt;/g, '<')
        .replace(/&gt;/g, '>')
        .replace(/&quot;/g, '"')
        .replace(/&#39;/g, "'");

    const lines = text.split('\n').map(s => String(s || '').trim()).filter(Boolean);
    const items = [];
    for (let i = 0; i < lines.length - 1; i++) {
        const name = lines[i];
        const next = lines[i + 1];
        if (!name || !next) continue;
        if (!/^Rp/i.test(next)) continue;
        const raw = next.replace(/^Rp/i, '').trim();
        const digits = raw.replace(/[^\d]/g, '');
        if (!digits) continue;
        const price = Number(digits);
        if (!Number.isFinite(price) || price <= 0) continue;

        let commodity_name = name;
        let unit = '';
        const parts = name.split(' / ').map(s => s.trim()).filter(Boolean);
        if (parts.length >= 2) {
            commodity_name = parts[0];
            unit = parts.slice(1).join(' / ');
        }
        items.push({ commodity_name, unit, price });
        i++;
    }
    return items;
}

function decodeHtml(s) {
    return String(s || '')
        .replace(/&nbsp;/g, ' ')
        .replace(/&amp;/g, '&')
        .replace(/&lt;/g, '<')
        .replace(/&gt;/g, '>')
        .replace(/&quot;/g, '"')
        .replace(/&#39;/g, "'");
}

function normalizeLabel(s) {
    return String(s || '')
        .toLowerCase()
        .replace(/\s+/g, ' ')
        .replace(/[^a-z0-9 ]+/g, '')
        .trim();
}

function parseSelectOptions(html) {
    const out = [];
    const re = /<option[^>]*value=["']?([^"'>]*)["']?[^>]*>([\s\S]*?)<\/option>/gi;
    let m;
    while ((m = re.exec(String(html || '')))) {
        const value = decodeHtml(m[1] || '').trim();
        const label = decodeHtml(m[2] || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
        if (!value || !label) continue;
        out.push({ value, label });
    }
    return out;
}

const SISKAPERBAPO_KABKOTA_CACHE = {
    fetchedAt: 0,
    byNormLabel: new Map()
};

function htmlTableToRows(html) {
    const rows = [];
    const trRe = /<tr[^>]*>([\s\S]*?)<\/tr>/gi;
    let m;
    while ((m = trRe.exec(String(html || '')))) {
        const tr = m[1] || '';
        const cells = [];
        const tdRe = /<(td|th)[^>]*>([\s\S]*?)<\/\1>/gi;
        let c;
        while ((c = tdRe.exec(tr))) {
            const cellHtml = c[2] || '';
            const text = decodeHtml(cellHtml.replace(/<[^>]+>/g, ' ')).replace(/\s+/g, ' ').trim();
            cells.push(text);
        }
        if (cells.length) rows.push(cells);
    }
    return rows;
}

function kabkotaSlugFromRegionLabel(regionLabel) {
    const raw = String(regionLabel || '').trim();
    const m = raw.match(/^(kabupaten|kota)\s+(.+)$/i);
    if (!m) return '';
    const kind = m[1].toLowerCase() === 'kabupaten' ? 'kab' : 'kota';
    const name = String(m[2] || '').toLowerCase().replace(/[^a-z0-9]+/g, '');
    if (!name) return '';
    return name + kind;
}

async function getSiskaperbapoKabkotaSlug(regionLabel) {
    const ttlMs = 6 * 60 * 60 * 1000;
    const now = Date.now();
    const norm = normalizeLabel(regionLabel);
    if (!norm) return '';

    if (!SISKAPERBAPO_KABKOTA_CACHE.fetchedAt || (now - SISKAPERBAPO_KABKOTA_CACHE.fetchedAt) >= ttlMs) {
        try {
            const html = await httpGetText('https://siskaperbapo.jatimprov.go.id/harga/tabel');
            const opts = parseSelectOptions(html);
            const map = new Map();
            opts.forEach(o => {
                const v = String(o.value || '').trim();
                const l = String(o.label || '').trim();
                if (!v || !l) return;
                if (!/^(?:[a-z0-9]+(?:kab|kota)|provinsi)$/i.test(v)) return;
                const k = normalizeLabel(l);
                if (!k) return;
                if (!map.has(k)) map.set(k, v);
            });
            if (map.size) {
                SISKAPERBAPO_KABKOTA_CACHE.byNormLabel = map;
                SISKAPERBAPO_KABKOTA_CACHE.fetchedAt = now;
            }
        } catch (e) { }
    }

    const hit = SISKAPERBAPO_KABKOTA_CACHE.byNormLabel.get(norm);
    if (hit) return hit;
    return kabkotaSlugFromRegionLabel(regionLabel);
}

function stripHtmlToLines(html) {
    const text = String(html || '')
        .replace(/<script[\s\S]*?<\/script>/gi, '\n')
        .replace(/<style[\s\S]*?<\/style>/gi, '\n')
        .replace(/<[^>]+>/g, '\n');
    return decodeHtml(text)
        .split('\n')
        .map(s => String(s || '').trim())
        .filter(Boolean);
}

function parseSiskaperbapoHargaTabel(html) {
    const rows = htmlTableToRows(html);
    if (rows.length) {
        const headerIdx = rows.findIndex(r => r.some(v => String(v || '').toUpperCase().includes('NAMA BAHAN POKOK')) && r.some(v => String(v || '').toUpperCase().includes('HARGA SEKARANG')));
        const start = headerIdx >= 0 ? headerIdx + 1 : 0;
        const items = [];
        const dashRe = /^\s*[\-\u2013\u2014\u2212]\s*/;
        const allowedCategory = new Set([
            'beras',
            'gula',
            'minyak goreng',
            'daging',
            'telur ayam',
            'susu',
            'jagung pipilan kering',
            'garam beryodium',
            'tepung terigu',
            'kacang kedelai',
            'mie instant',
            'cabe',
            'bawang',
            'sayur mayur',
            'ikan segar',
            'ikan asin',
            'kacang hijau',
            'kacang tanah',
            'ketela pohon',
            'buah buahan'
        ]);
        const isAllowedCategory = (cat) => {
            const c = String(cat || '').trim();
            if (!c) return true;
            if (allowedCategory.has(c)) return true;
            if (c.includes('bumbu')) return true;
            if (c.includes('rempah')) return true;
            if (c.includes('ikan')) return true;
            if (c.includes('buah')) return true;
            if (c.includes('sayur')) return true;
            return false;
        };
        let currentCategory = '';
        for (let i = start; i < rows.length; i++) {
            const r = rows[i];
            if (!r || r.length < 5) continue;
            const nameRaw = String(r[1] || '').trim();
            const isItem = dashRe.test(nameRaw);
            if (!isItem) {
                const no = String(r[0] || '').trim();
                const cat = normalizeLabel(nameRaw);
                if (/^\d+$/.test(no) && cat) currentCategory = cat;
                continue;
            }
            if (currentCategory && !isAllowedCategory(currentCategory)) continue;
            const commodity_name = nameRaw.replace(dashRe, '').trim();
            const unit = String(r[2] || '').trim();
            const priceRaw = String(r[4] || '').trim();
            const digits = priceRaw.replace(/[^\d]/g, '');
            const price = digits ? Number(digits) : null;
            const safePrice = (Number.isFinite(price) && price > 0) ? price : null;
            items.push({ commodity_name, unit, price: safePrice, price_date: null });
        }
        if (items.length) return items;
    }

    const lines = stripHtmlToLines(html);
    const items = [];
    const dashRe = /^\s*[\-\u2013\u2014\u2212]\s*/;
    const stopAfter = new Set(['semen', 'besi beton sni murni', 'paku', 'gas elpigi 3 kg', 'pupuk']);
    let stop = false;
    for (let i = 0; i < lines.length - 3; i++) {
        const nameRaw = lines[i];
        const norm = normalizeLabel(nameRaw);
        if (stopAfter.has(norm)) stop = true;
        if (stop) break;
        if (!dashRe.test(nameRaw)) continue;
        const commodity_name = nameRaw.replace(dashRe, '').trim();
        const unit = lines[i + 1] || '';
        const priceYesterday = lines[i + 2] || '';
        const priceNow = lines[i + 3] || '';
        const digits = String(priceNow).replace(/[^\d]/g, '');
        const price = digits ? Number(digits) : null;
        const safePrice = (Number.isFinite(price) && price > 0) ? price : null;
        items.push({ commodity_name, unit, price: safePrice, price_date: null });
        i += 3;
    }
    return items;
}

function toISODateUTC(d) {
    const yyyy = d.getUTCFullYear();
    const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
    const dd = String(d.getUTCDate()).padStart(2, '0');
    return `${yyyy}-${mm}-${dd}`;
}

function isValidSiskaperbapoCommodityName(name) {
    const raw = String(name || '').trim();
    if (!raw) return false;
    if (raw.startsWith('>')) return false;
    if (raw.startsWith('->')) return false;
    const n = normalizeLabel(raw);
    if (!n) return false;
    const bannedContains = [
        'grafik',
        'informasi',
        'tren',
        'display',
        'login',
        'provinsi',
        'kabupaten',
        'kota'
    ];
    if (bannedContains.some(x => n.includes(x))) return false;
    return /[a-z]/i.test(raw);
}

function addDaysISO(dateStr, deltaDays) {
    const m = String(dateStr || '').match(/^(\d{4})-(\d{2})-(\d{2})$/);
    if (!m) return '';
    const y = Number(m[1]), mo = Number(m[2]), d = Number(m[3]);
    const dt = new Date(Date.UTC(y, mo - 1, d));
    if (Number.isNaN(dt.getTime())) return '';
    dt.setUTCDate(dt.getUTCDate() + Number(deltaDays || 0));
    return toISODateUTC(dt);
}

async function fetchHargaTabelKabkota(kabkota, isoDate) {
    const endpoint = 'https://siskaperbapo.jatimprov.go.id/harga/tabel.nodesign/';
    const form = {
        tanggal: isoDate,
        kabkota: kabkota,
        pasar: ''
    };
    let html;
    let usedUrl = endpoint;
    try {
        html = await httpPostForm(endpoint, form);
    } catch (e) {
        console.warn(`[SYNC] POST to .nodesign failed, fallback to GET. Error: ${e.message}`);
        usedUrl = `https://siskaperbapo.jatimprov.go.id/harga/tabel/?kabkota=${encodeURIComponent(kabkota)}&tanggal=${encodeURIComponent(isoDate)}`;
        html = await httpGetText(usedUrl);
    }
    const list = parseSiskaperbapoHargaTabel(html);
    list.forEach(it => { it.source_url = usedUrl; });
    return { url: usedUrl, list, html };
}

function keyCommodity(it) {
    return `${String(it.commodity_name || '').toLowerCase()}|${String(it.unit || '').toLowerCase()}`;
}

async function fillMissingWithLastAvailable(kabkota, safeDate, list) {
    const items = Array.isArray(list) ? list : [];
    const byKey = new Map();
    items.forEach(it => {
        const k = keyCommodity(it);
        byKey.set(k, { ...it, price_date: it.price ? safeDate : null });
    });

    let missingKeys = new Set();
    for (const [k, it] of byKey.entries()) {
        if (!it.price) missingKeys.add(k);
    }
    if (!missingKeys.size) return Array.from(byKey.values());

    const lookbackDays = 30;
    for (let back = 1; back <= lookbackDays && missingKeys.size; back++) {
        const prevDate = addDaysISO(safeDate, -back);
        if (!prevDate) break;
        let prev;
        try {
            prev = await fetchHargaTabelKabkota(kabkota, prevDate);
        } catch (e) {
            continue;
        }
        const prevMap = new Map();
        (prev.list || []).forEach(p => {
            if (!p.price) return;
            prevMap.set(keyCommodity(p), p);
        });
        for (const k of Array.from(missingKeys)) {
            const found = prevMap.get(k);
            if (!found) continue;
            const cur = byKey.get(k);
            byKey.set(k, {
                ...cur,
                price: found.price,
                price_date: prevDate,
                source_url: found.source_url || prev.url || cur.source_url
            });
            missingKeys.delete(k);
        }
    }
    return Array.from(byKey.values());
}

app.get('/api/pricing/market-prices', async (req, res) => {
    const date = String(req.query.date || '').trim();
    const region = String(req.query.region || '').trim();
    try {
        await ensureMarketPricesTable();
        if (!date) return res.status(400).json({ error: 'date required' });
        if (!region) return res.status(400).json({ error: 'region required' });
        const rows = await all(
            `SELECT commodity_name, unit, price, region, date, source, fetched_at, source_url, price_date
             FROM market_prices
             WHERE date = ? AND region = ?
               AND commodity_name NOT LIKE '%Grafik%'
               AND commodity_name NOT LIKE '%Informasi%'
               AND commodity_name NOT LIKE '%Tren%'
               AND commodity_name NOT LIKE 'Provinsi %'
               AND commodity_name NOT LIKE 'Kabupaten %'
               AND commodity_name NOT LIKE 'Kota %'
             ORDER BY commodity_name ASC`,
            [date, region]
        );
        res.json(rows);
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

app.post('/api/pricing/sync-siskaperbapo', async (req, res) => {
    const { date, region } = req.body;
    console.log(`[SYNC] Request received for ${region} on ${date}`);
    try {
        await ensureMarketPricesTable();
        const safeDate = String(date || '').trim();
        const safeRegion = String(region || '').trim();
        if (!safeDate) return res.status(400).json({ error: 'date required' });
        if (!safeRegion) return res.status(400).json({ error: 'region required' });
        if (!/^\d{4}-\d{2}-\d{2}$/.test(safeDate)) return res.status(400).json({ error: 'Invalid date format (YYYY-MM-DD)' });

        const kabkota = await getSiskaperbapoKabkotaSlug(safeRegion);
        if (!kabkota) return res.status(400).json({ error: 'Invalid region label' });

        const fetched = await fetchHargaTabelKabkota(kabkota, safeDate);
        const sourceUrl = fetched.url;
        const marketDataRaw = fetched.list;
        if (!Array.isArray(marketDataRaw) || marketDataRaw.length === 0) {
            const sample = String(fetched.html || '').slice(0, 300);
            return res.status(502).json({ error: `Siskaperbapo response parsed empty (kabkota=${kabkota})`, source_url: sourceUrl, sample });
        }

        const marketData = await fillMissingWithLastAvailable(kabkota, safeDate, marketDataRaw);
        console.log(`[SYNC] Parsed ${marketData.length} items from ${sourceUrl}`);
        const cleanData = marketData.filter(it => isValidSiskaperbapoCommodityName(it.commodity_name));
        if (!cleanData.length) {
            const sample = String(fetched.html || '').slice(0, 300);
            return res.status(502).json({ error: `Siskaperbapo parsed only junk rows (kabkota=${kabkota})`, source_url: sourceUrl, sample });
        }
        try {
            await run("DELETE FROM market_prices WHERE region = ? AND date = ? AND source = 'siskaperbapo'", [safeRegion, safeDate]);
        } catch (e) { }
        const results = [];
        const now = new Date().toISOString();
        for (const item of cleanData) {
            const id = crypto.randomUUID();
            try {
                await run(
                    `INSERT INTO market_prices (id, commodity_name, price, unit, region, date, source, fetched_at, source_url, commodity_id, price_date)
                     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, NULL, ?)
                     ON CONFLICT(commodity_name, unit, region, date)
                     DO UPDATE SET price = excluded.price, source = excluded.source, fetched_at = excluded.fetched_at, source_url = excluded.source_url, price_date = excluded.price_date`,
                    [id, item.commodity_name, item.price ?? null, item.unit || '', safeRegion, safeDate, 'siskaperbapo', now, String(item.source_url || sourceUrl), item.price_date || null]
                );
                results.push({ commodity_name: item.commodity_name, unit: item.unit || '', price: item.price, price_date: item.price_date || null });
            } catch (insErr) {
                console.error("[SYNC] Insert error:", insErr.message);
                throw insErr;
            }
        }

        console.log(`[SYNC] Success. Processed ${results.length} items.`);
        res.json({ success: true, count: results.length, data: results });
    } catch (e) {
        console.error("[SYNC] FATAL ERROR:", e);
        res.status(500).json({ error: e.message });
    }
});

app.post('/api/pricing/import-to-db', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const { items, region, date } = req.body;
        if (!Array.isArray(items) || !items.length) return res.status(400).json({ error: 'No items to import' });

        let updatedCount = 0;
        let insertedCount = 0;
        const tenantId = getTenantIdFromReq(req);

        try {
            for (const item of items) {
                const name = String(item.commodity_name || '').trim();
                const unit = String(item.unit || '').trim();
                const price = Number(item.price);
                if (!name || !Number.isFinite(price)) continue;

                // 1. Check Ingredients
                let existingIng = null;
                try {
                    existingIng = tenantId
                        ? await get("SELECT id, estimated_price FROM ingredients WHERE name = ? AND tenant_id = ?", [name, tenantId])
                        : await get("SELECT id, estimated_price FROM ingredients WHERE name = ?", [name]);
                } catch (e) {
                    if (e.message.includes('no such column: tenant_id')) {
                        // Fallback for old schema
                        existingIng = await get("SELECT id, estimated_price FROM ingredients WHERE name = ?", [name]);
                    } else throw e;
                }

                let ingredientId;

                if (existingIng) {
                    ingredientId = existingIng.id;
                    try {
                        if (tenantId) {
                            await run("UPDATE ingredients SET estimated_price = ? WHERE id = ? AND tenant_id = ?", [price, ingredientId, tenantId]);
                        } else {
                            await run("UPDATE ingredients SET estimated_price = ? WHERE id = ?", [price, ingredientId]);
                        }
                    } catch (e) {
                        if (e.message.includes('no such column: tenant_id')) {
                            await run("UPDATE ingredients SET estimated_price = ? WHERE id = ?", [price, ingredientId]);
                        } else throw e;
                    }
                    updatedCount++;
                } else {
                    ingredientId = crypto.randomUUID();
                    const now = new Date().toISOString();
                    try {
                        if (tenantId) {
                            await run(
                                "INSERT INTO ingredients (id, name, unit, estimated_price, tenant_id, created_at) VALUES (?, ?, ?, ?, ?, ?)",
                                [ingredientId, name, unit, price, tenantId, now]
                            );
                        } else {
                            await run(
                                "INSERT INTO ingredients (id, name, unit, estimated_price, created_at) VALUES (?, ?, ?, ?, ?)",
                                [ingredientId, name, unit, price, now]
                            );
                        }
                        insertedCount++;
                    } catch (e) {
                        if (e.message.includes('no such column: tenant_id')) {
                            await run(
                                "INSERT INTO ingredients (id, name, unit, estimated_price, created_at) VALUES (?, ?, ?, ?, ?)",
                                [ingredientId, name, unit, price, now]
                            );
                            insertedCount++;
                        } else throw e;
                    }
                }

                if (ingredientId) {
                    const inv = await get("SELECT * FROM inventory WHERE ingredient_id = ?", [ingredientId]);
                    if (!inv) {
                        await run("INSERT INTO inventory (id, ingredient_id, quantity) VALUES (?, ?, 0)", [crypto.randomUUID(), ingredientId]);
                    }
                }
            }

            res.json({ success: true, updated: updatedCount, inserted: insertedCount });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

app.post('/api/pricing/simulate', async (req, res) => {
    // items: [{ menu_id, portions }, ...]
    const { items } = req.body;

    // Backward compatibility for single item
    let menuItems = [];
    if (req.body.menu_id && req.body.portions) {
        menuItems.push({ menu_id: req.body.menu_id, portions: req.body.portions });
    } else if (Array.isArray(items)) {
        menuItems = items;
    }

    if (menuItems.length === 0) return res.status(400).json({ error: 'Invalid input: No menus selected' });

    try {
        let totalEstimatedCost = 0;
        let menuBreakdowns = [];
        let aggregatedIngredients = {}; // To sum up same ingredients across menus

        for (const item of menuItems) {
            const { menu_id, portions } = item;
            if (!menu_id || !portions || portions <= 0) continue;

            const menu = await get("SELECT m.name, m.recipe_id, r.ingredients FROM menu m JOIN recipes r ON m.recipe_id = r.id WHERE m.id = ?", [menu_id]);
            if (!menu) continue;

            const ingredients = JSON.parse(menu.ingredients || '[]');
            let menuTotalCost = 0;
            const ingredientDetails = [];

            for (const ing of ingredients) {
                const ingData = await get("SELECT name, unit, estimated_price FROM ingredients WHERE id = ?", [ing.ingredient_id]);
                if (ingData) {
                    const qtyNeeded = ing.quantity_per_portion * portions;
                    const cost = qtyNeeded * (ingData.estimated_price || 0);
                    menuTotalCost += cost;

                    // Add to detailed breakdown for this menu
                    ingredientDetails.push({
                        name: ingData.name,
                        unit: ingData.unit,
                        qty_per_portion: ing.quantity_per_portion,
                        total_qty: qtyNeeded,
                        unit_price: ingData.estimated_price,
                        total_cost: cost
                    });

                    // Add to aggregated list
                    if (!aggregatedIngredients[ingData.name]) {
                        aggregatedIngredients[ingData.name] = {
                            name: ingData.name,
                            unit: ingData.unit,
                            total_qty: 0,
                            unit_price: ingData.estimated_price,
                            total_cost: 0
                        };
                    }
                    aggregatedIngredients[ingData.name].total_qty += qtyNeeded;
                    aggregatedIngredients[ingData.name].total_cost += cost;
                }
            }

            totalEstimatedCost += menuTotalCost;
            menuBreakdowns.push({
                menu_name: menu.name,
                portions: portions,
                subtotal: menuTotalCost,
                cost_per_portion: menuTotalCost / portions,
                ingredients: ingredientDetails
            });
        }

        // Convert aggregated map to array
        const aggregatedBreakdown = Object.values(aggregatedIngredients).sort((a, b) => b.total_cost - a.total_cost);

        res.json({
            grand_total: totalEstimatedCost,
            menu_breakdowns: menuBreakdowns,
            aggregated_breakdown: aggregatedBreakdown
        });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

