app.put('/api/inventory/:id', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const { quantity, note } = req.body || {};
        const ingredientId = String(req.params.id || '').trim();
        if (!ingredientId) return res.status(400).json({ error: 'Missing ingredient_id' });
        try {
            const cur = await get("SELECT quantity FROM inventory WHERE ingredient_id = ?", [ingredientId]);
            const before = Number(cur?.quantity || 0);
            const after = Number(quantity || 0);
            await run("UPDATE inventory SET quantity = ? WHERE ingredient_id = ?", [after, ingredientId]);
            const actor_email = await resolveActorEmail(req.auth);
            await run(
                `INSERT INTO inventory_movements (id, at, ingredient_id, movement_type, qty_before, qty_after, delta, note, actor_email)
                 VALUES (?, ?, ?, 'set', ?, ?, ?, ?, ?)`,
                [crypto.randomUUID(), new Date().toISOString(), ingredientId, before, after, (after - before), String(note || ''), actor_email]
            );
            res.json({ success: true });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.post('/api/inventory/adjust', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const ingredient_id = String(req.body.ingredient_id || '').trim();
        const mode = String(req.body.mode || 'set').trim();
        const value = Number(req.body.value || 0);
        const note = String(req.body.note || '');
        if (!ingredient_id) return res.status(400).json({ error: 'Missing ingredient_id' });
        if (!Number.isFinite(value)) return res.status(400).json({ error: 'Invalid value' });
        try {
            const cur = await get("SELECT quantity FROM inventory WHERE ingredient_id = ?", [ingredient_id]);
            const before = Number(cur?.quantity || 0);
            const after = mode === 'add' ? (before + value) : mode === 'sub' ? (before - value) : value;
            const finalAfter = Math.max(0, after);
            if (cur) await run("UPDATE inventory SET quantity = ? WHERE ingredient_id = ?", [finalAfter, ingredient_id]);
            else await run("INSERT INTO inventory (id, ingredient_id, quantity) VALUES (?, ?, ?)", [crypto.randomUUID(), ingredient_id, finalAfter]);
            const actor_email = await resolveActorEmail(req.auth);
            const delta = finalAfter - before;
            await run(
                `INSERT INTO inventory_movements (id, at, ingredient_id, movement_type, qty_before, qty_after, delta, note, actor_email)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                [crypto.randomUUID(), new Date().toISOString(), ingredient_id, mode, before, finalAfter, delta, note, actor_email]
            );
            res.json({ success: true, qty_before: before, qty_after: finalAfter, delta });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

