app.get('/api/plans', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
            if (tenantId) {
                try {
                    const orphanIds = await all(
                        `SELECT p.id
                     FROM plans p
                     LEFT JOIN batches b ON b.plan_id = p.id
                     LEFT JOIN tasks t ON t.plan_id = p.id
                     LEFT JOIN production_orders o ON o.plan_id = p.id
                     WHERE (p.tenant_id = ? OR p.tenant_id IS NULL)
                       AND b.id IS NULL
                       AND t.id IS NULL
                       AND o.id IS NULL
                       AND datetime(p.created_at) < datetime('now','-5 seconds')
                       AND UPPER(COALESCE(p.status,'')) NOT IN ('PO_SENT','AWAITING_JOBDESC')
                       AND (COALESCE(TRIM(p.source_procurement_plan_id), '') = '')
                     LIMIT 200`,
                        [tenantId]
                    );
                    for (const r of (orphanIds || [])) {
                        const pid = String(r.id || '').trim();
                        if (!pid) continue;
                        try { await run("DELETE FROM plan_backups WHERE plan_id = ? AND tenant_id = ?", [pid, tenantId]); } catch (e) { }
                        try { await run("DELETE FROM plan_doc_generations WHERE plan_id = ?", [pid]); } catch (e) { }
                        try { await run("DELETE FROM plans WHERE id = ?", [pid]); } catch (e) { }
                    }
                } catch (e) { }
            }
            const rows = await all("SELECT * FROM plans WHERE tenant_id = ? ORDER BY created_at DESC", [tenantId]);
            try { await mbgEnsureLocalProcurementTables(); } catch (e) { /* ignore */ }
            try { await run('ALTER TABLE plans ADD COLUMN war_room_food_id TEXT'); } catch (e) { /* exists */ }
            // Enrich with task counts - SAFE CHECK
            for (let plan of rows) {
                if (!plan.code) {
                    plan.code = readableCode('PL', plan.id);
                    try { await run("UPDATE plans SET code = ? WHERE id = ?", [plan.code, plan.id]); } catch (e) { }
                }
                const batchCount = (await get("SELECT COUNT(*) as c FROM batches WHERE plan_id = ?", [plan.id])).c;
                const totalTaskCount = (await get("SELECT COUNT(*) as c FROM tasks WHERE plan_id = ?", [plan.id])).c;
                plan.stats = { batches: batchCount, tasks: totalTaskCount };
                const o = plan.source_order_id ? await get("SELECT id, code, status FROM production_orders WHERE id = ?", [plan.source_order_id]) : null;
                if (o) plan.runtime = { order_id: o.id, order_code: o.code, status: o.status };
                let procId = String(plan.source_procurement_plan_id || '').trim();
                if (!procId) {
                    const lp = await get(
                        `SELECT id FROM local_procurement_plans
                         WHERE tenant_id = ? AND production_plan_id = ?
                         ORDER BY datetime(created_at) DESC LIMIT 1`,
                        [tenantId, plan.id]
                    ).catch(() => null);
                    if (lp && lp.id) procId = String(lp.id);
                }
                plan.procurement_plan_id = procId || null;
                plan.has_procurement = !!procId;
            }
            res.json(rows);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.delete('/api/plans/purge', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const tenantId = getTenantIdFromReq(req);
        if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
        try {
            const planRows = await all(
                `SELECT id, code FROM plans
                 WHERE tenant_id = ?
                    OR (tenant_id IS NULL AND source_order_id IN (SELECT id FROM production_orders WHERE tenant_id = ?))
                    OR (tenant_id IS NULL AND (id IN (SELECT plan_id FROM production_orders WHERE tenant_id = ?) OR code IN (SELECT plan_id FROM production_orders WHERE tenant_id = ?)))`,
                [tenantId, tenantId, tenantId, tenantId]
            );
            const ids = Array.from(new Set((planRows || []).map(p => String(p.id || '').trim()).filter(Boolean)));

            await run("UPDATE production_orders SET plan_id = NULL WHERE tenant_id = ?", [tenantId]);

            for (const planId of ids) {
                try { await run("DELETE FROM plan_backups WHERE plan_id = ? AND (tenant_id = ? OR tenant_id IS NULL)", [planId, tenantId]); } catch (e) { }
                try { await run("DELETE FROM plan_doc_generations WHERE plan_id = ?", [planId]); } catch (e) { }
                try { await run("DELETE FROM tasks WHERE batch_id IN (SELECT id FROM batches WHERE plan_id = ?)", [planId]); } catch (e) { }
                try { await run("DELETE FROM tasks WHERE plan_id = ?", [planId]); } catch (e) { }
                try { await run("DELETE FROM batches WHERE plan_id = ?", [planId]); } catch (e) { }
                try { await run("DELETE FROM plans WHERE id = ?", [planId]); } catch (e) { }
            }

            res.json({ success: true, deleted: ids.length });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

