app.get('/api/plans/:id/details', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const q = String(req.params.id || '').trim();
            let plan = tenantId
                ? await get("SELECT * FROM plans WHERE (id = ? OR code = ?) AND tenant_id = ? LIMIT 1", [q, q, tenantId])
                : await get("SELECT * FROM plans WHERE id = ? OR code = ? LIMIT 1", [q, q]);
            if (!plan) {
                const order = tenantId
                    ? await get("SELECT id, code, plan_id FROM production_orders WHERE (id = ? OR code = ?) AND tenant_id = ? LIMIT 1", [q, q, tenantId])
                    : await get("SELECT id, code, plan_id FROM production_orders WHERE id = ? OR code = ? LIMIT 1", [q, q]);
                if (order && order.plan_id) {
                    plan = tenantId
                        ? await get("SELECT * FROM plans WHERE id = ? AND tenant_id = ? LIMIT 1", [String(order.plan_id), tenantId])
                        : await get("SELECT * FROM plans WHERE id = ? LIMIT 1", [String(order.plan_id)]);
                }
                if (!plan) {
                    if (order && !order.plan_id) {
                        return res.status(404).json({ error: 'Plan not found', hint: 'Order belum memiliki plan', order_code: order.code || q });
                    }
                    return res.status(404).json({ error: 'Plan not found' });
                }
            }
            if (!plan) return res.status(404).json({ error: 'Plan not found' });
            if (!plan.code) {
                plan.code = readableCode('PL', plan.id);
                try { await run("UPDATE plans SET code = ? WHERE id = ?", [plan.code, plan.id]); } catch (e) { }
            }

            const batches = await all("SELECT * FROM batches WHERE plan_id = ?", [plan.id]);
            const tasks = await all("SELECT * FROM tasks WHERE plan_id = ? ORDER BY start_time ASC", [plan.id]);
            const kitchen = await getKitchenConfigSafe();
            const divs = Array.isArray(kitchen.divisions) ? kitchen.divisions : [];
            const norm = (s) => String(s || '').toLowerCase();
            const displayDivName = (d) => {
                const name = String(d?.name || d?.id || '').trim();
                const id = String(d?.id || '').trim();
                if (id === 'kitchen' || norm(name).includes('kitchen')) return 'Cooking';
                return name || id;
            };
            const divNameById = new Map(divs.map(d => [String(d.id || ''), displayDivName(d)]));

            for (let b of batches) {
                if (!b.code) {
                    const n = String(b.batch_number || '').padStart(2, '0');
                    b.code = b.batch_number ? `${plan.code}-B${n}` : readableCode('BT', b.id);
                    try { await run("UPDATE batches SET code = ? WHERE id = ?", [b.code, b.id]); } catch (e) { }
                }
                const m = await get("SELECT name FROM menu WHERE id = ?", [b.menu_item_id]);
                const fm = m ? null : await get("SELECT name FROM food_menus WHERE id = ?", [b.menu_item_id]);
                b.menu_name = m ? m.name : (fm ? fm.name : (b.menu_item_id || 'Unknown Menu'));
                b.division_name = divNameById.get(String(b.division_id || '')) || (b.division_id || 'Unknown');
            }

            const tasksOut = tasks.map(t => {
                const st = t.start_time ? new Date(t.start_time).getTime() : NaN;
                const en = t.end_time ? new Date(t.end_time).getTime() : NaN;
                const dur = Number.isFinite(st) && Number.isFinite(en) ? Math.max(0, Math.round((en - st) / 60000)) : null;
                return { ...t, division_name: divNameById.get(String(t.division_id || '')) || String(t.division_id || ''), duration_minutes: dur };
            });

            const earliestStart = tasksOut.reduce((min, t) => {
                const st = t.start_time ? new Date(t.start_time).getTime() : NaN;
                if (!Number.isFinite(st)) return min;
                return min === null ? st : Math.min(min, st);
            }, null);
            const latestEnd = tasksOut.reduce((max, t) => {
                const en = t.end_time ? new Date(t.end_time).getTime() : NaN;
                if (!Number.isFinite(en)) return max;
                return max === null ? en : Math.max(max, en);
            }, null);
            const deliveryTs = plan.target_delivery_time ? new Date(plan.target_delivery_time).getTime() : NaN;
            const slackMin = (Number.isFinite(deliveryTs) && latestEnd !== null) ? Math.round((deliveryTs - latestEnd) / 60000) : null;

            res.json({ plan, batches, tasks: tasksOut, stats: { earliest_start_time: earliestStart ? new Date(earliestStart).toISOString() : null, latest_end_time: latestEnd ? new Date(latestEnd).toISOString() : null, slack_minutes: slackMin } });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

// Batalkan plan (status CANCELLED) + jobdesc: task/batch/delivery yang belum terminal → CANCELLED. Task DONE/COMPLETED tidak diubah.
app.post('/api/plans/:id/cancel', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
            const q = String(req.params.id || '').trim();
            if (!q) return res.status(400).json({ error: 'Missing plan id' });

            let planRow = await get(
                "SELECT id, code, status, tenant_id FROM plans WHERE (id = ? OR code = ?) AND tenant_id = ? LIMIT 1",
                [q, q, tenantId]
            );
            if (!planRow?.id) {
                const order = await get(
                    "SELECT plan_id FROM production_orders WHERE (id = ? OR code = ?) AND tenant_id = ? AND plan_id IS NOT NULL LIMIT 1",
                    [q, q, tenantId]
                );
                if (order?.plan_id) {
                    planRow = await get(
                        "SELECT id, code, status, tenant_id FROM plans WHERE id = ? AND tenant_id = ? LIMIT 1",
                        [String(order.plan_id), tenantId]
                    );
                }
            }
            if (!planRow?.id) return res.status(404).json({ error: 'Plan not found' });

            const planId = String(planRow.id);
            if (!planRow.tenant_id) {
                try { await run("UPDATE plans SET tenant_id = ? WHERE id = ? AND tenant_id IS NULL", [tenantId, planId]); } catch (e) { }
            }

            const st = String(planRow.status || '').toUpperCase();
            if (st === 'CANCELLED') {
                return res.json({ success: true, plan_id: planId, plan_code: planRow.code || null, already_cancelled: true });
            }
            if (st === 'COMPLETED') {
                return res.status(409).json({ error: 'Plan sudah selesai, tidak dapat dibatalkan.' });
            }

            const now = new Date().toISOString();
            await run("UPDATE plans SET status = 'CANCELLED' WHERE id = ? AND tenant_id = ?", [planId, tenantId]);
            // Task: cukup filter plan_id (plan sudah diverifikasi tenant); hindari baris legacy tanpa tenant_id terlewat
            await run(
                `UPDATE tasks SET status = 'CANCELLED' WHERE plan_id = ?
                 AND UPPER(COALESCE(status,'')) NOT IN ('COMPLETED','DONE','CANCELLED')`,
                [planId]
            );
            await run(
                `UPDATE batches SET status = 'CANCELLED' WHERE plan_id = ?
                 AND EXISTS (SELECT 1 FROM plans p WHERE p.id = batches.plan_id AND p.tenant_id = ?)
                 AND UPPER(COALESCE(status,'')) NOT IN ('COMPLETED','CANCELLED')`,
                [planId, tenantId]
            );
            try {
                await run(
                    `UPDATE order_deliveries SET status = 'CANCELLED' WHERE plan_id = ? AND tenant_id = ?
                     AND UPPER(COALESCE(status,'')) NOT IN ('CANCELLED','DELIVERED','COMPLETED')`,
                    [planId, tenantId]
                );
            } catch (e) {
                try {
                    await run(
                        `UPDATE order_deliveries SET status = 'CANCELLED' WHERE plan_id = ?
                         AND UPPER(COALESCE(status,'')) NOT IN ('CANCELLED','DELIVERED','COMPLETED')`,
                        [planId]
                    );
                } catch (e2) { }
            }

            try {
                if (typeof logProductionEvent === 'function') {
                    await logProductionEvent(planId, 'PLAN_CANCELLED', 'Plan dibatalkan (monitor / admin)', { plan_code: planRow.code, at: now });
                }
            } catch (e) { }

            res.json({ success: true, plan_id: planId, plan_code: planRow.code || null });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

/** Plan CANCELLED → aktif lagi: status plan PUBLISHED + task/batch/delivery yang status CANCELLED dikembalikan ke PENDING (tanpa draft War Room baru). */
app.post('/api/plans/:id/reactivate', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
            const q = String(req.params.id || '').trim();
            if (!q) return res.status(400).json({ error: 'Missing plan id' });

            let planRow = await get(
                "SELECT id, code, status, tenant_id FROM plans WHERE (id = ? OR code = ?) AND tenant_id = ? LIMIT 1",
                [q, q, tenantId]
            );
            if (!planRow?.id) {
                const order = await get(
                    "SELECT plan_id FROM production_orders WHERE (id = ? OR code = ?) AND tenant_id = ? AND plan_id IS NOT NULL LIMIT 1",
                    [q, q, tenantId]
                );
                if (order?.plan_id) {
                    planRow = await get(
                        "SELECT id, code, status, tenant_id FROM plans WHERE id = ? AND tenant_id = ? LIMIT 1",
                        [String(order.plan_id), tenantId]
                    );
                }
            }
            if (!planRow?.id) return res.status(404).json({ error: 'Plan not found' });

            const planId = String(planRow.id);
            if (!planRow.tenant_id) {
                try { await run("UPDATE plans SET tenant_id = ? WHERE id = ? AND tenant_id IS NULL", [tenantId, planId]); } catch (e) { /* ignore */ }
            }

            const st = String(planRow.status || '').toUpperCase();
            if (st !== 'CANCELLED') {
                return res.status(409).json({ error: 'Hanya plan yang sudah dibatalkan (CANCELLED) yang dapat dimulai ulang lewat aksi ini.' });
            }

            const now = new Date().toISOString();
            await run("UPDATE plans SET status = 'PUBLISHED' WHERE id = ? AND tenant_id = ?", [planId, tenantId]);

            const taskUp = await run(
                `UPDATE tasks SET status = 'PENDING' WHERE plan_id = ?
                 AND UPPER(COALESCE(status,'')) = 'CANCELLED'`,
                [planId]
            );
            const batchUp = await run(
                `UPDATE batches SET status = 'PENDING' WHERE plan_id = ?
                 AND EXISTS (SELECT 1 FROM plans p WHERE p.id = batches.plan_id AND p.tenant_id = ?)
                 AND UPPER(COALESCE(status,'')) = 'CANCELLED'`,
                [planId, tenantId]
            );
            let delUp = { changes: 0 };
            try {
                delUp = await run(
                    `UPDATE order_deliveries SET status = 'PENDING' WHERE plan_id = ? AND tenant_id = ?
                     AND UPPER(COALESCE(status,'')) = 'CANCELLED'`,
                    [planId, tenantId]
                );
            } catch (e) {
                try {
                    delUp = await run(
                        `UPDATE order_deliveries SET status = 'PENDING' WHERE plan_id = ?
                         AND UPPER(COALESCE(status,'')) = 'CANCELLED'`,
                        [planId]
                    );
                } catch (e2) { /* ignore */ }
            }

            try {
                if (typeof logProductionEvent === 'function') {
                    await logProductionEvent(planId, 'PLAN_REACTIVATED', 'Plan diaktifkan kembali: jobdesc + delivery wave dikembalikan ke PENDING', {
                        plan_code: planRow.code,
                        at: now,
                        tasks_reopened: taskUp?.changes || 0,
                        batches_reopened: batchUp?.changes || 0,
                        deliveries_reopened: delUp?.changes || 0
                    });
                }
            } catch (e) { /* ignore */ }

            res.json({
                success: true,
                plan_id: planId,
                plan_code: planRow.code || null,
                tasks_reopened: taskUp?.changes || 0,
                batches_reopened: batchUp?.changes || 0,
                deliveries_reopened: delUp?.changes || 0
            });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

