app.post('/api/plans/:id/docs/generate', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const planId = req.params.id;
            const data = await buildPlanDocData(planId);
            if (!data.ok) return res.status(400).json({ error: 'VALIDATION_FAILED', details: data.errors || [] });

            const actor_email = await resolveActorEmail(req.auth);
            const id = crypto.randomUUID();
            const now = new Date().toISOString();
            await run(
                "INSERT INTO plan_doc_generations (id, plan_id, at, actor_email, status, summary, errors) VALUES (?, ?, ?, ?, 'OK', ?, ?)",
                [id, planId, now, actor_email, JSON.stringify(data.summary || {}), JSON.stringify([])]
            );
            await run(
                "INSERT INTO activity_logs (id, at, actor_email, action, entity_type, entity_id, detail) VALUES (?, ?, ?, 'PLAN_DOC_GENERATE', 'plan', ?, ?)",
                [crypto.randomUUID(), now, actor_email, planId, JSON.stringify({ summary: data.summary || {} })]
            );

            res.json({ success: true, generation_id: id, summary: data.summary });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

