app.post('/api/plans/v2', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const tenantId = getTenantIdFromReq(req);
        if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });
        const food_id = String(req.body.food_id || '').trim();
        const target_portions = Math.max(1, Number(req.body.target_portions || 0));
        const target_delivery_time = toIso(req.body.target_delivery_time || null);
        const plan_start_time = toIso(req.body.plan_start_time || null);
        const items = Array.isArray(req.body.items) ? req.body.items : null;
        if (!food_id) return res.status(400).json({ error: 'food_id required' });
        if (!target_delivery_time) return res.status(400).json({ error: 'target_delivery_time required' });

        try {
            const food = await get("SELECT * FROM foods WHERE id = ? AND tenant_id = ?", [food_id, tenantId]);
            if (!food) return res.status(404).json({ error: 'Food not found' });

            const planId = crypto.randomUUID();
            const planCode = generateId('PL');
            const now = new Date().toISOString();
            await run(
                "INSERT INTO plans (id, code, tenant_id, source_order_id, target_portions, target_delivery_time, status, created_at) VALUES (?, ?, ?, NULL, ?, ?, 'PLANNED', ?)",
                [planId, planCode, tenantId, target_portions, target_delivery_time, now]
            );

            const menus = await all("SELECT * FROM food_menus WHERE food_id = ? AND tenant_id = ?", [food_id, tenantId]);
            if (!menus.length) return res.status(400).json({ error: 'Food belum punya menu' });

            const menuPortions = new Map();
            if (items && items.length) {
                for (const it of items) {
                    const mid = String(it.menu_id || it.food_menu_id || '').trim();
                    const p = Math.max(0, Number(it.portions || 0));
                    if (mid && p > 0) menuPortions.set(mid, p);
                }
            } else {
                for (const m of menus) menuPortions.set(m.id, target_portions);
            }
            if (!menuPortions.size) return res.status(400).json({ error: 'Plan tidak memiliki menu' });

            const orderId = crypto.randomUUID();
            const orderCode = generateId('PO');
            await run(
                "INSERT INTO production_orders (id, code, tenant_id, food_id, plan_id, target_portions, target_delivery_time, status, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, 'PLANNED', ?)",
                [orderId, orderCode, tenantId, food_id, planId, target_portions, target_delivery_time, now]
            );
            await run("UPDATE plans SET source_order_id = ? WHERE id = ?", [orderId, planId]);

            for (const [menuId, portions] of menuPortions.entries()) {
                await run("INSERT INTO production_order_items (id, order_id, food_menu_id, portions) VALUES (?, ?, ?, ?)", [crypto.randomUUID(), orderId, menuId, portions]);
            }

            const ingRows = await all(
                `SELECT mi.* FROM food_menu_ingredients mi
                 WHERE mi.tenant_id = ? AND mi.food_menu_id IN (${Array.from(menuPortions.keys()).map(() => '?').join(',')})`,
                [tenantId, ...Array.from(menuPortions.keys())]
            );

            const requiredByIng = new Map();
            const prepByIng = new Map();
            for (const mi of ingRows) {
                const portions = menuPortions.get(mi.food_menu_id) || 0;
                const reqQty = safeNumber(mi.qty_per_portion) * safeNumber(portions);
                if (reqQty <= 0) continue;
                const unit = String(mi.qty_unit || '').trim() || null;
                const key = mi.ingredient_id;
                const cur = requiredByIng.get(key) || { required_qty: 0, unit };
                cur.required_qty += reqQty;
                cur.unit = unit || cur.unit;
                requiredByIng.set(key, cur);
                const hasPrep = Number(mi.prep_minutes || 0) > 0 && safeNumber(mi.prep_output_qty) > 0;
                if (hasPrep && !prepByIng.has(key)) {
                    prepByIng.set(key, {
                        prep_minutes: Math.max(1, Number(mi.prep_minutes)),
                        prep_output_qty: safeNumber(mi.prep_output_qty),
                        prep_output_unit: String(mi.prep_output_unit || mi.qty_unit || '').trim() || unit || null
                    });
                }
            }

            for (const [ingredientId, req] of requiredByIng.entries()) {
                const prep = prepByIng.get(ingredientId);
                if (!prep) continue;
                await run(
                    `INSERT INTO prep_jobs (id, order_id, ingredient_id, required_qty, unit, prep_minutes, prep_output_qty, prep_output_unit, status, started_at, finished_at, produced_qty, last_calc_at)
                     VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'PLANNED', NULL, NULL, 0, NULL)`,
                    [crypto.randomUUID(), orderId, ingredientId, req.required_qty, req.unit, prep.prep_minutes, prep.prep_output_qty, prep.prep_output_unit]
                );
            }

            for (const [menuId, portions] of menuPortions.entries()) {
                const menu = menus.find(m => m.id === menuId);
                const cap = Math.max(1, Number(menu?.batch_capacity || 50));
                const numBatches = Math.ceil(portions / cap);
                for (let i = 1; i <= numBatches; i++) {
                    const batchSize = i === numBatches ? (portions - cap * (numBatches - 1)) : cap;
                    const batchId = crypto.randomUUID();
                    await run(
                        `INSERT INTO cook_batches_v2 (id, order_id, food_menu_id, batch_no, batch_size, status, queued_at, started_at, expected_end_at, finished_at, cooked_portions, used_ingredients)
                         VALUES (?, ?, ?, ?, ?, 'QUEUED', ?, NULL, NULL, NULL, NULL, NULL)`,
                        [batchId, orderId, menuId, i, batchSize, now]
                    );

                    const mIngs = ingRows.filter(r => r.food_menu_id === menuId);
                    for (const it of mIngs) {
                        const reqQty = safeNumber(it.qty_per_portion) * safeNumber(batchSize);
                        if (reqQty <= 0) continue;
                        const needsPrep = Number(it.prep_minutes || 0) > 0 && safeNumber(it.prep_output_qty) > 0 ? 1 : 0;
                        await run(
                            `INSERT INTO cook_batch_requirements (id, cook_batch_id, ingredient_id, required_qty, unit, needs_prep)
                             VALUES (?, ?, ?, ?, ?, ?)`,
                            [crypto.randomUUID(), batchId, it.ingredient_id, reqQty, String(it.qty_unit || '').trim() || null, needsPrep]
                        );
                    }
                }
            }

            const settings = await getProductionSettings();
            const kitchen = await getKitchenConfigSafe();
            const divisions = Array.isArray(kitchen.divisions) ? kitchen.divisions : [];
            const norm = (s) => String(s || '').toLowerCase();
            const matchDivs = (keywords) => divisions.filter(d => keywords.some(k => norm(d.name || d.id).includes(k)));
            const pickDiv = (keywords, fallbackIdx) => {
                const m = matchDivs(keywords);
                if (m.length) return String(m[0].id || '');
                const f = divisions[fallbackIdx];
                return f ? String(f.id || '') : '';
            };
            const pickDivList = (keywords, n, fallbackStartIdx, exclude) => {
                const ex = exclude instanceof Set ? exclude : new Set();
                const m = matchDivs(keywords).filter(d => !ex.has(String(d.id || '')));
                const ids = m.map(d => String(d.id || '')).filter(Boolean);
                const out = [];
                for (let i = 0; i < n; i++) {
                    const fallback = divisions.slice(fallbackStartIdx).find(d => !ex.has(String(d.id || '')));
                    out.push(ids[i] || (fallback ? String(fallback.id || '') : '') || (ids[0] || ''));
                }
                return out.filter(Boolean).slice(0, n);
            };
            const prepDivId = pickDiv(['prep', 'preparation', 'persiapan', 'bahan'], 0) || 'PREP';
            const cookDivIds = pickDivList(['cooking', 'masak', 'dapur', 'cook', 'kitchen', 'produksi'], settings.cook_parallel_limit, 0);
            const cookEx = new Set(cookDivIds);
            const portionDivIds = pickDivList(['portion', 'porsi', 'packing', 'plating'], settings.portion_parallel_limit, 0, cookEx);
            const driverDivId = pickDiv(['driver', 'delivery', 'pengiriman'], Math.min(2, divisions.length - 1)) || 'DRIVER';

            const prepJobs = await all(
                `SELECT p.*, ing.name as ingredient_name
                 FROM prep_jobs p
                 LEFT JOIN ingredients ing ON ing.id = p.ingredient_id
                 WHERE p.order_id = ?`,
                [orderId]
            );
            const cookBatches = await all(
                `SELECT b.*, fm.name as menu_name, fm.cook_minutes
                 FROM cook_batches_v2 b
                 LEFT JOIN food_menus fm ON fm.id = b.food_menu_id
                 WHERE b.order_id = ?
                 ORDER BY fm.name ASC, b.batch_no ASC`,
                [orderId]
            );
            const cookReqs = await all(
                `SELECT r.*, b.food_menu_id, b.batch_no
                 FROM cook_batch_requirements r
                 JOIN cook_batches_v2 b ON b.id = r.cook_batch_id
                 WHERE b.order_id = ?`,
                [orderId]
            );

            const planStart = plan_start_time || now;

            const prepEndByIng = new Map();
            const prepTasks = [];
            const prepJobsWithDur = prepJobs.map(j => {
                const rate = calcRatePerMinute(j.prep_output_qty, j.prep_minutes);
                const need = safeNumber(j.required_qty);
                const dur = rate > 0 ? Math.max(1, Math.ceil(need / rate)) : 0;
                return { j, need, dur };
            }).filter(x => x.dur > 0);

            prepJobsWithDur.sort((a, b) => b.dur - a.dur);
            const prepLines = Array.from({ length: settings.prep_parallel_limit }, () => new Date(planStart).toISOString());
            for (const it of prepJobsWithDur) {
                let bestIdx = 0;
                let bestStart = prepLines[0];
                for (let i = 1; i < prepLines.length; i++) {
                    if (new Date(prepLines[i]) < new Date(bestStart)) { bestStart = prepLines[i]; bestIdx = i; }
                }
                const start = new Date(bestStart);
                const end = new Date(start.getTime() + it.dur * 60000);
                prepLines[bestIdx] = end.toISOString();
                prepEndByIng.set(it.j.ingredient_id, end.toISOString());
                prepTasks.push({
                    title: `Prep: ${it.j.ingredient_name || it.j.ingredient_id}`,
                    division_id: prepDivId,
                    start_time: start.toISOString(),
                    end_time: end.toISOString(),
                    description: `Kebutuhan: ${it.need.toFixed(2)} ${it.j.unit || ''} • Estimasi: ${it.dur} menit`
                });
            }

            const cookLines = Array.from({ length: settings.cook_parallel_limit }, () => new Date(planStart).toISOString());
            const cookPlanByBatchId = new Map();
            const cookTasks = [];
            const batchesForPlan = [];
            for (const b of cookBatches) {
                const deps = cookReqs.filter(r => r.cook_batch_id === b.id && Number(r.needs_prep || 0) === 1);
                let ready = planStart;
                for (const r of deps) {
                    const t = prepEndByIng.get(r.ingredient_id);
                    if (t && new Date(t) > new Date(ready)) ready = t;
                }
                let bestIdx = 0;
                let bestStart = new Date(Math.max(new Date(ready).getTime(), new Date(cookLines[0]).getTime())).toISOString();
                for (let i = 1; i < cookLines.length; i++) {
                    const s = new Date(Math.max(new Date(ready).getTime(), new Date(cookLines[i]).getTime())).toISOString();
                    if (new Date(s) < new Date(bestStart)) { bestStart = s; bestIdx = i; }
                }
                const durMin = Math.max(1, Number(b.cook_minutes || 30));
                const end = new Date(new Date(bestStart).getTime() + durMin * 60000).toISOString();
                cookLines[bestIdx] = end;
                cookPlanByBatchId.set(b.id, { start: bestStart, end, line: bestIdx + 1 });

                const div = cookDivIds[bestIdx] || cookDivIds[0] || 'COOK';
                cookTasks.push({
                    title: `Cooking: ${b.menu_name || b.food_menu_id} • Batch #${b.batch_no} (${b.batch_size} porsi) • Line ${bestIdx + 1}`,
                    division_id: div,
                    start_time: bestStart,
                    end_time: end,
                    description: `Durasi target: ${durMin} menit`
                });
                batchesForPlan.push({ cook_batch: b, start_time: bestStart, end_time: end, division_id: div });
            }

            const portionRows = [];
            const itemsWithMenu = await all(
                `SELECT oi.*, fm.name as menu_name, fm.portion_minutes, fm.portion_capacity
                 FROM production_order_items oi
                 JOIN food_menus fm ON fm.id = oi.food_menu_id
                 WHERE oi.order_id = ?`,
                [orderId]
            );
            for (const b of cookBatches) {
                const plan = cookPlanByBatchId.get(b.id);
                if (!plan) continue;
                const menu = itemsWithMenu.find(x => x.food_menu_id === b.food_menu_id);
                const portionMin = Math.max(1, Number(menu?.portion_minutes || 10));
                const portionCap = Math.max(1, Number(menu?.portion_capacity || 10));
                const rate = calcRatePerMinute(portionCap, portionMin);
                const dur = rate > 0 ? Math.max(1, Math.ceil(Number(b.batch_size || 0) / rate)) : 0;
                portionRows.push({
                    menu_name: b.menu_name,
                    batch_no: b.batch_no,
                    target_portions: Number(b.batch_size || 0),
                    ready_at: plan.end,
                    duration_min: dur
                });
            }

            const portionLines = Array.from({ length: settings.portion_parallel_limit }, () => new Date(planStart).toISOString());
            portionRows.sort((a, b) => new Date(a.ready_at).getTime() - new Date(b.ready_at).getTime());
            const portionTasks = [];
            for (const p of portionRows) {
                let bestIdx = 0;
                let bestStart = new Date(Math.max(new Date(p.ready_at).getTime(), new Date(portionLines[0]).getTime())).toISOString();
                for (let i = 1; i < portionLines.length; i++) {
                    const s = new Date(Math.max(new Date(p.ready_at).getTime(), new Date(portionLines[i]).getTime())).toISOString();
                    if (new Date(s) < new Date(bestStart)) { bestStart = s; bestIdx = i; }
                }
                const end = p.duration_min > 0 ? new Date(new Date(bestStart).getTime() + p.duration_min * 60000).toISOString() : bestStart;
                portionLines[bestIdx] = end;
                portionTasks.push({
                    title: `Portion: ${p.menu_name || '-'} • Batch #${p.batch_no} (${p.target_portions} porsi) • Line ${bestIdx + 1}`,
                    division_id: portionDivIds[bestIdx] || portionDivIds[0] || 'PORTION',
                    start_time: bestStart,
                    end_time: end,
                    description: `Target: ${p.target_portions} porsi`
                });
            }

            const allTasksForShift = [...prepTasks, ...cookTasks, ...portionTasks];
            const latestEnd = allTasksForShift.reduce((max, t) => {
                const ts = t.end_time ? new Date(t.end_time).getTime() : NaN;
                if (!Number.isFinite(ts)) return max;
                return Math.max(max, ts);
            }, 0);
            const deliveryTs = target_delivery_time ? new Date(target_delivery_time).getTime() : NaN;
            const driverDurationMin = Math.max(0, Number(settings.driver_minutes || 0));
            if (!Number.isFinite(deliveryTs)) return res.status(400).json({ error: 'target_delivery_time required' });

            if (latestEnd > 0 && latestEnd > deliveryTs) {
                const deltaMin = Math.ceil((latestEnd - deliveryTs) / 60000);
                const requiredStartTs = new Date(planStart).getTime() - (latestEnd - deliveryTs);
                const minDeliveryTs = latestEnd;
                const sumDur = (arr) => arr.reduce((a, t) => {
                    const st = t.start_time ? new Date(t.start_time).getTime() : NaN;
                    const en = t.end_time ? new Date(t.end_time).getTime() : NaN;
                    if (!Number.isFinite(st) || !Number.isFinite(en)) return a;
                    return a + Math.max(0, Math.round((en - st) / 60000));
                }, 0);
                const spanDur = (arr) => {
                    const starts = arr.map(t => t.start_time ? new Date(t.start_time).getTime() : NaN).filter(Number.isFinite);
                    const ends = arr.map(t => t.end_time ? new Date(t.end_time).getTime() : NaN).filter(Number.isFinite);
                    if (!starts.length || !ends.length) return 0;
                    return Math.max(0, Math.round((Math.max(...ends) - Math.min(...starts)) / 60000));
                };
                return res.status(400).json({
                    error: 'NOT_FEASIBLE',
                    message: 'Plan tidak feasible dengan target delivery saat ini',
                    details: [
                        { code: 'DELIVERY_TOO_EARLY', message: `Estimasi selesai produksi melewati target delivery (${deltaMin} menit)` },
                        { code: 'DURATION_BREAKDOWN', message: `Durasi: Prep ${sumDur(prepTasks)}m • Cooking ${spanDur(cookTasks)}m • Portion ${spanDur(portionTasks)}m • Driver ${driverDurationMin}m` }
                    ],
                    computed: {
                        plan_start_time: planStart,
                        estimated_finish_time: latestEnd > 0 ? new Date(latestEnd).toISOString() : null,
                        target_delivery_time,
                        required_start_time: Number.isFinite(requiredStartTs) ? new Date(requiredStartTs).toISOString() : null,
                        min_delivery_time: new Date(minDeliveryTs).toISOString(),
                        driver_duration_minutes: driverDurationMin
                    }
                });
            }

            const driverStart = new Date(deliveryTs).toISOString();
            const driverEnd = new Date(deliveryTs + driverDurationMin * 60000).toISOString();
            const driverTask = {
                title: `Delivery: ${planCode}`,
                division_id: driverDivId,
                start_time: driverStart,
                end_time: driverEnd,
                description: `Mulai delivery: ${target_delivery_time}`
            };

            for (let i = 0; i < batchesForPlan.length; i++) {
                const b = batchesForPlan[i];
                const bid = crypto.randomUUID();
                await run(
                    `INSERT INTO batches (id, code, plan_id, menu_item_id, batch_number, batch_size, start_time, end_time, status, division_id)
                     VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'PLANNED', ?)`,
                    [bid, `${planCode}-B${String(i + 1).padStart(2, '0')}`, planId, b.cook_batch.food_menu_id, b.cook_batch.batch_no || (i + 1), b.cook_batch.batch_size, b.start_time, b.end_time, b.division_id]
                );
            }

            const tasksToInsert = [...prepTasks, ...cookTasks, ...portionTasks, driverTask].sort((a, b) => new Date(a.start_time).getTime() - new Date(b.start_time).getTime());
            for (const t of tasksToInsert) {
                await run(
                    `INSERT INTO tasks (id, tenant_id, title, description, division_id, status, due_date, created_at, batch_id, duration_minutes, plan_id, start_time, end_time)
                     VALUES (?, ?, ?, ?, ?, 'PENDING', NULL, ?, NULL, NULL, ?, ?, ?)`,
                    [crypto.randomUUID(), tenantId, t.title, t.description || '', t.division_id, now, planId, t.start_time, t.end_time]
                );
            }

            await logProductionEvent(orderId, 'PLAN_CREATED', 'Production plan dibuat', { plan_id: planId, plan_code: planCode });
            res.json({ success: true, plan_id: planId, plan_code: planCode, order_id: orderId, order_code: orderCode });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

app.post('/api/plans/generate', async (req, res) => {
    // target_portions, menu_item_ids, target_delivery_time
    const { target_portions, menu_item_ids, target_delivery_time } = req.body;
    const items = Array.isArray(req.body.items) ? req.body.items.filter(x => x && x.menu_id && x.portions > 0) : null;
    const tId = req.headers['x-tenant-id'];

    if ((!items && (!target_portions || !menu_item_ids || !menu_item_ids.length)) || !target_delivery_time) {
        return res.status(400).json({ error: 'Missing required fields' });
    }

    try {
        const planId = crypto.randomUUID();
        const planCode = generateId('PL');
        const now = new Date().toISOString();

        // 1. Create Plan
        await run("INSERT INTO plans (id, code, tenant_id, target_portions, target_delivery_time, status, created_at) VALUES (?, ?, ?, ?, ?, ?, ?)",
            [planId, planCode, tId || null, target_portions, target_delivery_time, 'PLANNED', now]);

        // 2. Fetch Menu Details
        let tasks = [];
        let batches = [];
        const targetTime = new Date(target_delivery_time);

        // --- BACKWARD SCHEDULING LOGIC ---
        // Milestones (working backwards from Target Delivery)
        // Dist (Logistics) -> Pack (Packaging) -> Cook (Kitchen) -> Prep (Kitchen) -> Receive (Inventory)

        // 1. Distribution (Delivery) - Assume 60 mins before target
        const distEnd = targetTime;
        const distStart = new Date(distEnd.getTime() - 60 * 60000);

        tasks.push({
            id: crypto.randomUUID(),
            plan_id: planId,
            title: 'Distribution / Delivery',
            description: `Deliver ${target_portions} portions to location`,
            division_id: 'distribution', // or logistics
            start_time: distStart.toISOString(),
            end_time: distEnd.toISOString(),
            duration_minutes: 60,
            status: 'PENDING',
            created_at: now
        });

        // 2. Packing - Ends when Dist Starts
        // Rate: 10 portions per min (example) -> 1000 portions = 100 mins
        const packingDuration = Math.ceil(target_portions / 10);
        const packEnd = distStart;
        const packStart = new Date(packEnd.getTime() - packingDuration * 60000);

        tasks.push({
            id: crypto.randomUUID(),
            plan_id: planId,
            title: 'Packing Phase',
            description: `Pack ${target_portions} portions`,
            division_id: 'packaging',
            start_time: packStart.toISOString(),
            end_time: packEnd.toISOString(),
            duration_minutes: packingDuration,
            status: 'PENDING',
            created_at: now
        });

        // 3. Cooking (Kitchen) - Ends when Packing Starts
        // This depends on Menu Items and Batch Capacity
        // We will create Cooking Batches here
        let currentCookEnd = packStart;

        // Determine portions per menu
        let loopList = [];
        if (items && items.length > 0) {
            loopList = items.map(it => ({ menuId: it.menu_id, portions: it.portions }));
        } else {
            const n = menu_item_ids.length;
            const base = Math.floor(target_portions / n);
            const rem = target_portions % n;
            loopList = menu_item_ids.map((id, idx) => ({ menuId: id, portions: base + (idx === 0 ? rem : 0) }));
        }

        for (const entry of loopList) {
            const menuId = entry.menuId;
            const totalPortions = entry.portions;
            // Fetch menu joined with recipe to get latest cooking_time & batch_capacity
            const menu = await get("SELECT m.*, r.cooking_time AS recipe_cooking_time, r.batch_capacity AS recipe_batch_capacity FROM menu m LEFT JOIN recipes r ON m.recipe_id = r.id WHERE m.id = ?", [menuId]);
            if (!menu) continue;

            // Calc Batches
            const capacity = (menu.recipe_batch_capacity ?? menu.batch_capacity) || 50;
            const cookTime = (menu.recipe_cooking_time ?? menu.cooking_time) || 60;
            const numBatches = Math.ceil(totalPortions / capacity);

            // Create Batches (Sequential for this menu, working backwards)
            for (let i = numBatches; i >= 1; i--) {
                const batchId = crypto.randomUUID();
                const batchSize = (i === numBatches) ? (totalPortions % capacity || capacity) : capacity;

                const batchEnd = currentCookEnd;
                const batchStart = new Date(batchEnd.getTime() - cookTime * 60000);

                // Update cursor for next batch (previous in time)
                currentCookEnd = batchStart;

                // Create Batch Record
                batches.push({
                    id: batchId,
                    code: `${planCode}-B${String(i).padStart(2, '0')}`,
                    plan_id: planId,
                    menu_item_id: menuId,
                    batch_number: i,
                    batch_size: batchSize,
                    start_time: batchStart.toISOString(),
                    end_time: batchEnd.toISOString(),
                    status: 'PENDING',
                    division_id: 'kitchen'
                });

                // Create Cook Task linked to Batch
                tasks.push({
                    id: crypto.randomUUID(),
                    plan_id: planId,
                    batch_id: batchId,
                    title: `Cook Batch #${i}: ${menu.name}`,
                    description: `Cook ${batchSize} portions`,
                    division_id: 'kitchen',
                    start_time: batchStart.toISOString(),
                    end_time: batchEnd.toISOString(),
                    duration_minutes: cookTime,
                    status: 'PENDING',
                    created_at: now
                });
            }
        }

        // 4. Preparation (Kitchen) - Ends when first Cooking starts
        const cookStart = currentCookEnd; // The earliest cooking start time
        const prepDuration = 90; // Fixed 1.5 hours for now
        const prepEnd = cookStart;
        const prepStart = new Date(prepEnd.getTime() - prepDuration * 60000);

        tasks.push({
            id: crypto.randomUUID(),
            plan_id: planId,
            title: 'Ingredient Preparation',
            description: 'Wash, Cut, and Mise en place for all menus',
            division_id: 'kitchen',
            start_time: prepStart.toISOString(),
            end_time: prepEnd.toISOString(),
            duration_minutes: prepDuration,
            status: 'PENDING',
            created_at: now
        });

        // 5. Receiving / Inventory Check - Ends when Prep starts
        const receiveDuration = 30;
        const receiveEnd = prepStart;
        const receiveStart = new Date(receiveEnd.getTime() - receiveDuration * 60000);

        tasks.push({
            id: crypto.randomUUID(),
            plan_id: planId,
            title: 'Material Reception & QC',
            description: 'Check stock availability and quality',
            division_id: 'inventory',
            start_time: receiveStart.toISOString(),
            end_time: receiveEnd.toISOString(),
            duration_minutes: receiveDuration,
            status: 'PENDING',
            created_at: now
        });

        // --- EXECUTE INSERTS IN TRANSACTION ---
        try { await run("BEGIN"); } catch (e) { }
        try {
            // Insert Batches
            for (const b of batches) {
                await run("INSERT INTO batches (id, code, plan_id, menu_item_id, batch_number, batch_size, start_time, end_time, status, division_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                    [b.id, b.code || null, b.plan_id, b.menu_item_id, b.batch_number, b.batch_size, b.start_time, b.end_time, b.status, b.division_id]);
            }
            // Insert Tasks
            for (const t of tasks) {
                await run("INSERT INTO tasks (id, plan_id, batch_id, title, description, division_id, start_time, end_time, duration_minutes, status, created_at, tenant_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                    [t.id, t.plan_id, t.batch_id, t.title, t.description, t.division_id, t.start_time, t.end_time, t.duration_minutes, t.status, t.created_at, tId]);
            }
            try { await run("COMMIT"); } catch (e) { }
        } catch (e) {
            try { await run("ROLLBACK"); } catch (_) { }
            throw e;
        }

        // --- VALIDATION: Ensure all division tasks persisted ---
        const expectedDivisions = ['inventory', 'kitchen', 'packaging', 'distribution'];
        const persisted = await all("SELECT division_id, COUNT(*) as c FROM tasks WHERE plan_id = ? GROUP BY division_id", [planId]);
        const divSet = new Set(persisted.map(p => p.division_id));
        const missingDivs = expectedDivisions.filter(d => !divSet.has(d));
        if (missingDivs.length > 0) {
            const planLevel = tasks.filter(t => !t.batch_id && missingDivs.includes(t.division_id));
            for (const t of planLevel) {
                const exists = await get("SELECT id FROM tasks WHERE id = ?", [t.id]);
                if (!exists) {
                    await run("INSERT INTO tasks (id, plan_id, batch_id, title, description, division_id, start_time, end_time, duration_minutes, status, created_at, tenant_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                        [t.id, t.plan_id, null, t.title, t.description, t.division_id, t.start_time, t.end_time, t.duration_minutes, t.status, t.created_at, tId]);
                }
            }
        }
        const actualTotal = (await get("SELECT COUNT(*) as c FROM tasks WHERE plan_id = ?", [planId])).c;

        res.json({
            success: true,
            plan_id: planId,
            task_count: tasks.length,
            batch_count: batches.length,
            validation: {
                expected_task_count: tasks.length,
                actual_task_count: actualTotal,
                missing_divisions: missingDivs
            },
            schedule_summary: {
                start: receiveStart.toISOString(),
                end: target_delivery_time
            }
        });

    } catch (e) {
        console.error("Plan Gen Error:", e);
        res.status(500).json({ error: e.message });
    }
});


app.post('/api/plans/v4/generate', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            // Accept start_time or plan_start_time
            const { food_id, items, target_delivery_time, plan_start_time, start_time, deliveries } = req.body;

            // 1. Fetch Data
            const food = await get("SELECT * FROM foods WHERE id = ? AND tenant_id = ?", [food_id, tenantId]);
            if (!food) return res.status(404).json({ error: 'Food not found' });

            const customMenus = await all("SELECT * FROM food_menus WHERE food_id = ? AND tenant_id = ?", [food_id, tenantId]);
            const libraryMenus = await all(`
                SELECT m.id, m.name, 
                       COALESCE(r.cooking_time, 60) as cook_minutes,
                       COALESCE(r.batch_capacity, 50) as batch_capacity,
                       COALESCE(r.portion_size, 1) as portion_size,
                       r.ingredients as recipe_ingredients
                FROM food_menu_items fmi
                JOIN menu m ON m.id = fmi.menu_id
                LEFT JOIN recipes r ON r.id = m.recipe_id
                WHERE fmi.food_id = ? AND fmi.tenant_id = ?
            `, [food_id, tenantId]);

            const menus = [...customMenus, ...libraryMenus];
            if (!menus.length) return res.status(400).json({ error: 'Food has no menus' });

            const equipmentList = await all("SELECT * FROM kitchen_equipment WHERE tenant_id = ? AND (status IS NULL OR status = 'active')", [tenantId]);

            // 2. Prepare Config
            const configRows = await all("SELECT * FROM kitchen_config WHERE id LIKE 'config_%'");
            const config = {};

            // Merge Global Config (id=1)
            try {
                const globalConfigRow = await get("SELECT config FROM kitchen_config WHERE id = 1");
                if (globalConfigRow) {
                    const globalCfg = JSON.parse(globalConfigRow.config);
                    Object.assign(config, globalCfg);
                }
            } catch (e) { }

            configRows.forEach(r => {
                try {
                    const key = r.id.replace('config_', '');
                    const val = JSON.parse(r.config);
                    config[key] = val;
                    // Also merge to top level for backward compatibility if needed, 
                    // but nesting is safer.
                    // Object.assign(config, val); 
                } catch (e) { }
            });

            // 3. Prepare Inputs for Engine
            const { SimulationEngine } = require('./scheduler_v4_engine');

            // Format Menus Object with Ingredients
            const menusObj = {};
            // Fetch ingredients for Custom Menus
            const customMenuIds = customMenus.map(m => m.id);
            const ingredientsMap = {};
            const prepMap = {}; // menu_id -> { ingredient_id -> [actions] }

            if (customMenuIds.length > 0) {
                const placeholders = customMenuIds.map(() => '?').join(',');
                const allIngredients = await all(`SELECT * FROM food_menu_ingredients WHERE food_menu_id IN (${placeholders})`, customMenuIds);

                // Fetch Prep Details
                try {
                    const allPrep = await all(`SELECT * FROM menu_ingredient_prep WHERE menu_id IN (${placeholders}) AND is_enabled = 1`, customMenuIds);
                    allPrep.forEach(p => {
                        if (!prepMap[p.menu_id]) prepMap[p.menu_id] = {};
                        if (!prepMap[p.menu_id][p.ingredient_id]) prepMap[p.menu_id][p.ingredient_id] = [];
                        prepMap[p.menu_id][p.ingredient_id].push(p);
                    });
                } catch (e) { console.warn("Prep fetch error", e); }

                allIngredients.forEach(ing => {
                    if (!ingredientsMap[ing.food_menu_id]) ingredientsMap[ing.food_menu_id] = [];
                    // Attach prep actions if any
                    const actions = (prepMap[ing.food_menu_id] && prepMap[ing.food_menu_id][ing.ingredient_id]) || [];
                    ingredientsMap[ing.food_menu_id].push({ ...ing, prep_actions: actions });
                });
            }

            menus.forEach(m => {
                let ingredients = [];
                // If it's a library menu, parse recipe_ingredients
                if (m.recipe_ingredients) {
                    try {
                        ingredients = typeof m.recipe_ingredients === 'string' ? JSON.parse(m.recipe_ingredients) : (m.recipe_ingredients || []);
                    } catch (e) { ingredients = []; }
                } else {
                    // Custom menu, use ingredientsMap
                    ingredients = ingredientsMap[m.id] || [];
                }

                menusObj[m.id] = {
                    ...m,
                    batch_capacity: Number(m.batch_capacity) || 50,
                    cook_minutes: Number(m.cook_minutes) || 60,
                    ingredients
                };
            });

            // Format Orders (Waves)
            let orders = [];
            if (deliveries && Array.isArray(deliveries)) {
                // Group by delivery time (wave)
                const waveMap = new Map();
                deliveries.forEach(d => {
                    // Normalize date
                    let dt;
                    if (d.time instanceof Date) dt = d.time;
                    else if (typeof d.time === 'string') dt = new Date(d.time);
                    else dt = new Date();

                    const timeKey = dt.toISOString();
                    if (!waveMap.has(timeKey)) {
                        waveMap.set(timeKey, { deliveryTime: dt.toISOString(), items: [] });
                    }

                    const p = Number(d.portions || 0);

                    if (d.items && Array.isArray(d.items) && d.items.length > 0) {
                        d.items.forEach(it => {
                            waveMap.get(timeKey).items.push({ menuId: it.menu_id, portions: Number(it.portions || p) });
                        });
                    } else {
                        // Distribute PORTIONS to ALL menus in the food packet
                        // If food is "Packet A" (Rice + Chicken), both get 300 portions.
                        menus.forEach(m => {
                            waveMap.get(timeKey).items.push({ menuId: m.id, portions: p });
                        });
                    }
                });
                orders = Array.from(waveMap.values());
            } else if (items) {
                // Single wave from items
                const time = target_delivery_time || new Date().toISOString();
                orders.push({
                    deliveryTime: time,
                    items: items.map(it => ({ menuId: it.menu_id, portions: Number(it.portions) }))
                });
            } else {
                // Fallback if neither items nor deliveries provided but we have food_id
                // Assume single delivery at target time with total portions?
                // Not standard V4 but good for robustness
                // BUT req.body usually has one of them.
            }

            // Critical Fix: Ensure orders have items
            // If orders is empty but we have food_id and target_delivery_time and maybe 'target_portions' in body?
            // No, the V3/V4 payload standard requires 'deliveries' or 'items'.

            // Check if items are empty
            const totalItems = orders.reduce((sum, o) => sum + o.items.length, 0);
            if (totalItems === 0) {
                // Try to recover from just food_id?
                // If the user provided 'deliveries' with just portions but NO items and NO menus logic failed?
                // The logic above handles menus.forEach.
            }

            if (!orders.length) return res.status(400).json({ error: 'Missing items/deliveries' });

            const startTime = plan_start_time || start_time || new Date().toISOString();

            // 4. Run Simulation
            const engine = new SimulationEngine(config, orders, equipmentList, menusObj, startTime);
            const result = engine.run();

            // 5. Save Results (Optional: Only if requested to save, but usually generate endpoint just returns preview)
            // But V3 generate endpoint SAVES to DB. So we must save.

            const { preview } = req.query;

            if (preview === 'true') {
                res.json({
                    status: 'success',
                    feasibility: result.feasibility,
                    shift_board: result.shiftBoard,
                    timeline: result.timeline,
                    metrics: result.metrics
                });
                return;
            }

            const planId = crypto.randomUUID();
            // plan table schema: id, code, tenant_id, source_order_id, target_portions, target_delivery_time, status, created_at
            // food_id is NOT in plan table based on schema above. But V3 code inserted it?
            // V3: INSERT INTO plans (id, code, tenant_id, target_delivery_time, status, created_at)

            // We need to store food_id somewhere if needed, but schema doesn't show it.
            // Let's stick to existing schema.
            // But wait, the previous code I wrote tried to insert food_id.

            const planCode = `PL-${Date.now().toString().slice(-6)}`;

            await run("INSERT INTO plans (id, code, tenant_id, target_delivery_time, status, created_at) VALUES (?, ?, ?, ?, ?, ?)",
                [planId, planCode, tenantId, target_delivery_time, 'draft', new Date().toISOString()]);

            // Store food_id in title or somewhere? Or maybe just rely on tasks.
            // Actually, `production_orders` has food_id.
            // If we want to link food, maybe update title if column exists, but schema didn't show title column either.
            // Schema: id, code, tenant_id, source_order_id, target_portions, target_delivery_time, status, created_at

            // So I should remove food_id and title from INSERT.
            // production_date also not in schema.


            // Save Tasks
            // Map V4 tasks to DB structure
            for (const t of result.timeline) {
                const taskId = crypto.randomUUID();
                await run(
                    "INSERT INTO tasks (id, tenant_id, plan_id, division_id, title, start_time, end_time, status, resources) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
                    [
                        taskId,
                        tenantId,
                        planId,
                        t.type, // division
                        `${t.type.toUpperCase()} - ${menusObj[t.menuId]?.name || t.menuId} (${t.portions} pax)`,
                        t.startTime.toISOString(),
                        t.endTime.toISOString(),
                        'pending',
                        JSON.stringify({ resourceId: t.resourceId, batch: t.batchNo })
                    ]
                );
            }

            // Return Result with V4 specifics
            res.json({
                plan_id: planId,
                status: 'success',
                feasibility: result.feasibility,
                shift_board: result.shiftBoard,
                timeline: result.timeline,
                metrics: result.metrics
            });

        } catch (e) {
            console.error("Plan Gen V4 Error:", e);
            res.status(500).json({ error: e.message, stack: e.stack });
        }

    });
});

app.post('/api/plans/v3/generate', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const { food_id, items, target_delivery_time, mode, start_time, deliveries, production_date, source_order_id } = req.body;
            const now = new Date().toISOString();

            const food = await get("SELECT * FROM foods WHERE id = ? AND tenant_id = ?", [food_id, tenantId]);
            if (!food) return res.status(404).json({ error: 'Food not found' });
            if (source_order_id) {
                const q = String(source_order_id || '').trim();
                const order = await get("SELECT id, plan_id FROM production_orders WHERE (id = ? OR code = ?) AND tenant_id = ? LIMIT 1", [q, q, tenantId]);
                if (!order) return res.status(404).json({ error: 'Order not found' });
                if (order.plan_id) return res.status(400).json({ error: 'Order sudah memiliki plan' });
            }

            const menus = await all("SELECT * FROM food_menus WHERE food_id = ? AND tenant_id = ?", [food_id, tenantId]);
            if (!menus.length) return res.status(400).json({ error: 'Food has no menus' });
            const menuMap = new Map(menus.map(m => [m.id, m]));

            const configRows = await all("SELECT * FROM kitchen_config WHERE id LIKE 'config_%'");
            const divConfigs = {};
            configRows.forEach(r => {
                try { divConfigs[r.id.replace('config_', '')] = JSON.parse(r.config); } catch (e) { }
            });
            const prepCfg = divConfigs.prep || {};
            const packCfg = divConfigs.packing || {};
            const schedCfg = divConfigs.scheduler || {};

            const prepWorkerCount = Math.max(1, Number(prepCfg.worker_count || prepCfg.prepper_count || 1));
            const packerCount = Math.max(1, Number(packCfg.packer_count || 1));
            const defaultPackSeconds = Math.max(1, Number(packCfg.seconds_per_portion || 15));
            const packagingRates = (packCfg.packaging_rates && typeof packCfg.packaging_rates === 'object') ? packCfg.packaging_rates : {};
            const receivingMinutes = Math.max(1, Number(schedCfg.receiving_minutes || 60));
            const driverMinutes = Math.max(1, Number(schedCfg.driver_minutes || 30));
            const bufferMinutes = Math.max(0, Number(schedCfg.buffer_minutes ?? 10));
            const coolingMinutes = Math.max(0, Number(schedCfg.cooling_minutes ?? 0));
            const minOrderQty = Math.max(0, Number(schedCfg.min_order_qty ?? 0));

            let targetItems = [];
            if (items && items.length > 0) {
                targetItems = items.map(it => ({
                    menuId: it.menu_id,
                    portions: Number(it.portions),
                    deliveryTime: it.delivery_time || target_delivery_time
                }));
            } else if (deliveries && Array.isArray(deliveries)) {
                for (const d of deliveries) {
                    for (const m of menus) {
                        targetItems.push({
                            menuId: m.id,
                            portions: Number(d.portions),
                            deliveryTime: d.time
                        });
                    }
                }
            }
            if (!targetItems.length) return res.status(400).json({ error: 'Missing items/deliveries' });

            const effectiveTargetDelivery = target_delivery_time || (deliveries && deliveries[0] && deliveries[0].time) || null;
            if (!effectiveTargetDelivery) return res.status(400).json({ error: 'Missing target_delivery_time' });

            const totalPortions = targetItems.reduce((a, it) => a + (Number(it.portions) || 0), 0);
            if (minOrderQty > 0 && totalPortions < minOrderQty) {
                return res.status(400).json({ error: `Minimum order quantity ${minOrderQty} porsi` });
            }

            const equipment = await all("SELECT * FROM kitchen_equipment WHERE tenant_id = ? AND (status IS NULL OR status = 'active')", [tenantId]);

            const menuIds = menus.map(m => m.id);
            const placeholders = menuIds.map(() => '?').join(',');
            const ingredientRows = await all(
                `SELECT fmi.*, i.name as ingredient_name, i.unit as ingredient_unit
                 FROM food_menu_ingredients fmi
                 LEFT JOIN ingredients i ON i.id = fmi.ingredient_id
                 WHERE fmi.tenant_id = ? AND fmi.food_menu_id IN (${placeholders})`,
                [tenantId, ...menuIds]
            );
            const ingByMenu = new Map();
            for (const r of (ingredientRows || [])) {
                const mid = String(r.food_menu_id || '').trim();
                if (!ingByMenu.has(mid)) ingByMenu.set(mid, []);
                ingByMenu.get(mid).push(r);
            }

            const missingParams = [];
            for (const m of menus) {
                if (m.recipe_id) {
                    m.steps = await all("SELECT * FROM recipe_steps WHERE recipe_id = ? ORDER BY step_order ASC", [m.recipe_id]);
                    const r = await get("SELECT cooking_time, batch_capacity FROM recipes WHERE id = ?", [m.recipe_id]);
                    if (r) {
                        if (r.cooking_time != null) m.cook_minutes = r.cooking_time;
                        if (r.batch_capacity != null) m.batch_capacity = r.batch_capacity;
                    }
                }
                const cm = Number(m.cook_minutes);
                const bc = Number(m.batch_capacity);
                // Allow flexible validation for auto-seeded data
                if (!Number.isFinite(cm) || cm <= 0) m.cook_minutes = 30; // Default 30 min
                if (!Number.isFinite(bc) || bc <= 0) m.batch_capacity = 50; // Default 50 porsi
            }
            // if (missingParams.length) return res.status(400).json({ error: 'Missing menu parameters', missing: missingParams });

            let fullSchedule = [];
            let sharedUsage = new Map();
            const planId = crypto.randomUUID();
            const planCode = generateId('PL');

            const itemsByMenu = new Map();
            for (const it of targetItems) {
                if (!itemsByMenu.has(it.menuId)) itemsByMenu.set(it.menuId, []);
                itemsByMenu.get(it.menuId).push({ time: it.deliveryTime, portions: it.portions });
            }

            for (const [menuId, its] of itemsByMenu.entries()) {
                const menu = menuMap.get(menuId);
                if (!menu) continue;

                const packType = String(menu.packaging_type || food.packaging_type || '').trim().toLowerCase();
                const packSeconds = packType && packagingRates[packType] && packagingRates[packType].seconds_per_portion
                    ? Math.max(1, Number(packagingRates[packType].seconds_per_portion))
                    : defaultPackSeconds;
                const packPerHour = Math.max(1, Math.floor((3600 / packSeconds) * packerCount));

                const ingRows = ingByMenu.get(String(menuId)) || [];
                let prepMinutesPerPortion = 0;
                for (const r of ingRows) {
                    const qty = Math.max(0, Number(r.qty_per_portion || 0));
                    const basePrep = Math.max(0, Number(r.prep_minutes || 0));
                    if (basePrep > 0) prepMinutesPerPortion += basePrep;

                    const cutOn = Number(r.cutting_enabled || 0) === 1;
                    const washOn = Number(r.washing_enabled || 0) === 1;
                    const peelOn = Number(r.peeling_enabled || 0) === 1;
                    if (cutOn) {
                        const dur = Math.max(0, Number(r.cutting_duration_minutes || 0));
                        const out = Math.max(0, Number(r.cutting_output_per_duration || 0));
                        if (dur > 0 && out > 0) prepMinutesPerPortion += (qty / out) * dur;
                    }
                    if (washOn) {
                        const dur = Math.max(0, Number(r.washing_duration_minutes || 0));
                        const out = Math.max(0, Number(r.washing_output_per_duration || 0));
                        if (dur > 0 && out > 0) prepMinutesPerPortion += (qty / out) * dur;
                    }
                    if (peelOn) {
                        const dur = Math.max(0, Number(r.peeling_duration_minutes || 0));
                        const out = Math.max(0, Number(r.peeling_output_per_duration || 0));
                        if (dur > 0 && out > 0) prepMinutesPerPortion += (qty / out) * dur;
                    }
                }
                const prepPerHourRaw = prepMinutesPerPortion > 0 ? (60 / prepMinutesPerPortion) : Number(prepCfg.prep_per_hour || 50);
                const prepPerHour = Math.max(1, Math.floor(prepPerHourRaw * prepWorkerCount));

                menu.receiving_minutes = receivingMinutes;
                menu.driver_minutes = driverMinutes;
                menu.buffer_minutes = bufferMinutes;
                menu.cooling_minutes = coolingMinutes;

                let result;
                if (mode === 'forward') {
                    result = calculateForwardSchedule(start_time || now, its, menu, equipment, { prep_per_hour: prepPerHour, pack_per_hour: packPerHour }, sharedUsage);
                } else {
                    result = calculateScheduleV2(its, menu, equipment, { prep_per_hour: prepPerHour, pack_per_hour: packPerHour }, sharedUsage);
                }

                sharedUsage = result.equipmentUsage;
                result.schedule.forEach(s => s.menu_id = menuId);
                fullSchedule.push(...result.schedule);
            }

            await run("INSERT INTO plans (id, code, tenant_id, target_delivery_time, status, created_at) VALUES (?, ?, ?, ?, 'PLANNED', ?)",
                [planId, planCode, tenantId, effectiveTargetDelivery, now]);
            if (source_order_id) {
                try {
                    const q = String(source_order_id || '').trim();
                    const order = await get("SELECT id FROM production_orders WHERE (id = ? OR code = ?) AND tenant_id = ? LIMIT 1", [q, q, tenantId]);
                    if (order?.id) {
                        await run("UPDATE plans SET source_order_id = ? WHERE id = ? AND tenant_id = ?", [String(order.id), planId, tenantId]);
                        await run("UPDATE production_orders SET plan_id = ? WHERE id = ? AND tenant_id = ?", [planId, String(order.id), tenantId]);
                    }
                } catch (e) { }
            }

            const divTasks = [];
            for (const sched of fullSchedule) {
                const menu = menuMap.get(sched.menu_id);
                const timeline = sched.timeline;
                for (const [key, val] of Object.entries(timeline)) {
                    if (val.batches) {
                        for (const b of val.batches) {
                            const batchId = crypto.randomUUID();
                            await run("INSERT INTO batches (id, plan_id, menu_item_id, batch_size, start_time, end_time, status, division_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
                                [batchId, planId, sched.menu_id, b.size, new Date(b.start).toISOString(), new Date(b.end).toISOString(), 'PLANNED', 'kitchen']);
                            await run("INSERT INTO tasks (id, plan_id, batch_id, title, division_id, start_time, end_time, status, created_at, tenant_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                                [crypto.randomUUID(), planId, batchId, `Cook: ${b.equipment} (${menu?.name || '-'})`, 'kitchen', new Date(b.start).toISOString(), new Date(b.end).toISOString(), 'PLANNED', now, tenantId]);
                            divTasks.push({ div: 'kitchen', st: new Date(b.start), en: new Date(b.end) });
                        }
                    } else {
                        const k = String(key || '').toLowerCase();
                        const div =
                            k === 'receiving' ? 'inventory' :
                                k === 'prep' ? 'kitchen' :
                                    k === 'packing' ? 'packaging' :
                                        k === 'driver' ? 'distribution' :
                                            'kitchen';
                        const st = new Date(val.start).toISOString();
                        const en = new Date(val.end).toISOString();
                        divTasks.push({ div, st: new Date(val.start), en: new Date(val.end) });
                        await run("INSERT INTO tasks (id, plan_id, title, division_id, start_time, end_time, status, created_at, tenant_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
                            [crypto.randomUUID(), planId, `${key} (${menu?.name || '-'})`, div, st, en, 'PLANNED', now, tenantId]);
                    }
                }
            }

            const earliest = fullSchedule.length
                ? new Date(Math.min(...fullSchedule.map(s => new Date(s.timeline.receiving.start).getTime())))
                : new Date(now);

            const prodStartConstraint = start_time ? new Date(start_time) : null;
            const conflicts = [];
            if (prodStartConstraint && earliest < prodStartConstraint) {
                conflicts.push({ type: 'lead_time', division_id: 'inventory', at: earliest.toISOString(), detail: 'Jadwal mulai lebih awal dari jam mulai produksi' });
            }

            const manpower = {
                inventory: Math.max(1, Number(divConfigs.inventory?.worker_count || 1)),
                kitchen: Math.max(1, Number(divConfigs.kitchen?.worker_count || 1)),
                packaging: Math.max(1, Number(divConfigs.packaging?.worker_count || packerCount || 1)),
                distribution: Math.max(1, Number(divConfigs.distribution?.worker_count || 1))
            };

            const slotMs = 15 * 60 * 1000;
            const buckets = new Map();
            for (const t of divTasks) {
                const s = t.st.getTime();
                const e = t.en.getTime();
                const startSlot = Math.floor(s / slotMs) * slotMs;
                const endSlot = Math.floor((e - 1) / slotMs) * slotMs;
                for (let ts = startSlot; ts <= endSlot; ts += slotMs) {
                    const k = `${t.div}|${ts}`;
                    buckets.set(k, (buckets.get(k) || 0) + 1);
                }
            }
            const peakByDiv = { inventory: 0, kitchen: 0, packaging: 0, distribution: 0 };
            for (const [k, v] of buckets.entries()) {
                const div = k.split('|')[0];
                if (peakByDiv[div] != null) peakByDiv[div] = Math.max(peakByDiv[div], v);
            }
            for (const div of Object.keys(peakByDiv)) {
                const peak = peakByDiv[div];
                const cap = manpower[div];
                if (peak > cap) {
                    conflicts.push({ type: 'manpower', division_id: div, capacity: cap, required: peak, detail: 'Kebutuhan manpower melebihi kapasitas' });
                }
            }

            const feasible = conflicts.length === 0;
            const solutions = [];
            if (!feasible) {
                const mpConf = conflicts.find(c => c.type === 'manpower');
                if (mpConf) solutions.push({ type: 'tambah_manpower', division_id: mpConf.division_id, suggested_worker_count: mpConf.required });
                solutions.push({ type: 'ubah_batch_size', note: 'Kurangi batch_size untuk sebar beban cooking/packing (lebih banyak batch, durasi naik).' });
                const lead = conflicts.find(c => c.type === 'lead_time');
                if (lead && prodStartConstraint) {
                    const diffMin = Math.ceil((prodStartConstraint.getTime() - earliest.getTime()) / 60000);
                    solutions.push({ type: 'adjust_delivery_time', suggested_delay_minutes: diffMin });
                }
            }

            try {
                await run(
                    "INSERT INTO activity_logs (id, at, actor_email, action, entity_type, entity_id, detail) VALUES (?, ?, ?, ?, ?, ?, ?)",
                    [crypto.randomUUID(), now, (req.auth && req.auth.email) ? req.auth.email : (req.headers['x-user-email'] || ''), 'PLAN_GENERATE_V3', 'plan', planId, JSON.stringify({ food_id, production_date: production_date || null, feasible, conflicts })]
                );
            } catch (e) { }
            try {
                const snapshot = JSON.stringify({ plan: { id: planId, code: planCode, food_id, target_delivery_time: effectiveTargetDelivery }, schedule: fullSchedule });
                await run(
                    "INSERT INTO plan_backups (id, tenant_id, plan_id, at, reason, snapshot_json) VALUES (?, ?, ?, ?, ?, ?)",
                    [crypto.randomUUID(), tenantId, planId, now, 'GENERATE', snapshot]
                );
            } catch (e) { }

            res.json({ success: true, plan: { id: planId, code: planCode }, feasible, conflicts, solutions, schedule: fullSchedule });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

app.get('/api/batches', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            if (!tenantId) return res.status(400).json({ error: 'Missing tenant_id' });

            try { await run("DELETE FROM batches WHERE plan_id NOT IN (SELECT id FROM plans)"); } catch (e) { }

            const rows = await all(
                `SELECT b.*, p.code as plan_code
                 FROM batches b
                 JOIN plans p ON p.id = b.plan_id
                 WHERE p.tenant_id = ?
                 ORDER BY datetime(b.start_time) DESC, datetime(b.end_time) DESC`,
                [tenantId]
            );
            rows.forEach(r => parseJson(r, ['checklist']));
            for (const b of rows) {
                if (!b.code) {
                    const planCode = b.plan_code || readableCode('PL', b.plan_id);
                    const n = String(b.batch_number || '').padStart(2, '0');
                    b.code = b.batch_number ? `${planCode}-B${n}` : readableCode('BT', b.id);
                    try { await run("UPDATE batches SET code = ? WHERE id = ?", [b.code, b.id]); } catch (e) { }
                }
            }
            res.json(rows);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.get('/api/batches/plan/:id', async (req, res) => {
    try {
        const rows = await all("SELECT * FROM batches WHERE plan_id = ?", [req.params.id]);
        if (!rows || rows.length === 0) {
            return res.json([]); // Return empty array instead of 404/error to clear loading state
        }
        const plan = await get("SELECT id, code FROM plans WHERE id = ?", [req.params.id]);
        const planCode = plan?.code || readableCode('PL', req.params.id);
        rows.forEach(r => parseJson(r, ['checklist']));
        for (const b of rows) {
            if (!b.code) {
                const n = String(b.batch_number || '').padStart(2, '0');
                b.code = b.batch_number ? `${planCode}-B${n}` : readableCode('BT', b.id);
                try { await run("UPDATE batches SET code = ? WHERE id = ?", [b.code, b.id]); } catch (e) { }
            }
        }
        res.json(rows);
    } catch (e) { res.status(500).json({ error: e.message }); }
});

// --- VALIDATION HELPERS ---
app.get('/api/plans/:id/validate', async (req, res) => {
    try {
        const q = String(req.params.id || '').trim();
        const plan = await get("SELECT * FROM plans WHERE id = ? OR code = ? LIMIT 1", [q, q]);
        if (!plan) return res.status(404).json({ error: 'Plan not found' });
        const expectedDivisions = ['inventory', 'kitchen', 'packaging', 'distribution'];
        const tasks = await all("SELECT * FROM tasks WHERE plan_id = ?", [plan.id]);
        const batches = await all("SELECT * FROM batches WHERE plan_id = ?", [plan.id]);
        const byDiv = {};
        expectedDivisions.forEach(d => byDiv[d] = 0);
        tasks.forEach(t => { if (t.division_id && byDiv.hasOwnProperty(t.division_id)) byDiv[t.division_id]++; });
        const missing = expectedDivisions.filter(d => byDiv[d] === 0);
        res.json({
            plan_id: plan.id,
            total_tasks: tasks.length,
            total_batches: batches.length,
            division_task_counts: byDiv,
            missing_divisions: missing
        });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

// --- FINANCE (LAPKEU FULL) ---
function num(v) {
    const n = Number(v || 0);
    return Number.isFinite(n) ? n : 0;
}

function classifyAccountGroup(accountCode = '', accountName = '') {
    const code = String(accountCode || '').trim();
    const name = String(accountName || '').toLowerCase();
    if (code.startsWith('1')) return 'ASSET';
    if (code.startsWith('2')) return 'LIABILITY';
    if (code.startsWith('3')) return 'EQUITY';
    if (code.startsWith('4') || name.includes('dana bantuan') || name.includes('penerimaan')) return 'INCOME';
    if (code.startsWith('5') || name.includes('biaya') || name.includes('beban')) return 'EXPENSE';
    return 'OTHER';
}

function inferNormalBalance(accountCode = '', accountName = '') {
    const g = classifyAccountGroup(accountCode, accountName);
    if (g === 'ASSET' || g === 'EXPENSE') return 'DEBIT';
    if (g === 'LIABILITY' || g === 'EQUITY' || g === 'INCOME') return 'CREDIT';
    return 'DEBIT';
}

function financeActor(req) {
    return String(req?.auth?.email || req?.auth?.actor_id || 'system');
}

function normalizeDateIso(v) {
    if (!v) return new Date().toISOString();
    try {
        const d = new Date(v);
        if (Number.isFinite(d.getTime())) return d.toISOString();
    } catch (e) { }
    return new Date().toISOString();
}

/** Map display name (kolom 7 dropdown) to account code. */
const FINANCE_AKUN_COL7_MAP = {
    'Petty Cash/Cash in Hand': '1101',
    'Kas di Bank': '1102',
    'Dana Bantuan Pemerintah': '2110',
    'Biaya Bahan Baku': '2120',
    'Biaya Operasional': '2130',
    'Biaya Insentif Fasilitas': '2140'
};

function resolveAkunFromCol7(displayName) {
    if (!displayName || typeof displayName !== 'string') return '';
    const s = String(displayName).trim();
    return FINANCE_AKUN_COL7_MAP[s] || s;
}

/** Map Jenis Buku Pembantu to Kas account code (1101 or 1102). */
function resolveAkunKasFromJenis(jenisBukuPembantu) {
    if (!jenisBukuPembantu || typeof jenisBukuPembantu !== 'string') return '1101';
    const j = String(jenisBukuPembantu).toLowerCase();
    if (j.includes('bank') || j.includes('bp bank')) return '1102';
    return '1101';
}

function formatJournalNo() {
    return `JR-${new Date().toISOString().replace(/[-:TZ.]/g, '').slice(0, 14)}-${Math.floor(Math.random() * 10000).toString().padStart(4, '0')}`;
}

async function ensureDefaultGlPeriod() {
    const row = await get("SELECT * FROM gl_periods ORDER BY created_at DESC LIMIT 1");
    if (row) return row;
    const now = new Date();
    const y = now.getFullYear();
    const m = now.getMonth() + 1;
    const first = new Date(Date.UTC(y, m - 1, 1)).toISOString();
    const last = new Date(Date.UTC(y, m, 0, 23, 59, 59)).toISOString();
    const id = crypto.randomUUID();
    const at = new Date().toISOString();
    await run(
        `INSERT INTO gl_periods (id, period_start, period_end, period_label, status, closed_at, closed_by, created_at, updated_at)
         VALUES (?, ?, ?, ?, 'OPEN', NULL, NULL, ?, ?)`,
        [id, first, last, `${y}-${String(m).padStart(2, '0')}`, at, at]
    );
    return await get("SELECT * FROM gl_periods WHERE id = ?", [id]);
}

async function ensureLapkeuDefaultAccounts() {
    const cnt = await get("SELECT COUNT(*) as c FROM gl_accounts");
    if (Number(cnt?.c || 0) > 0) return;

    // Try seed from Saldo Buku rows.
    const defaults = [
        { code: '1000', name: 'BUKU KAS UMUM' },
        { code: '1101', name: 'Petty Cash/Cash in Hand' },
        { code: '1102', name: 'Kas di Bank' },
        { code: '2110', name: 'Dana Bantuan Pemerintah' },
        { code: '2120', name: 'Biaya Bahan Baku' },
        { code: '2130', name: 'Biaya Operasional' },
        { code: '2140', name: 'Biaya Insentif Fasilitas' }
    ];
    const now = new Date().toISOString();
    for (const a of defaults) {
        await run(
            `INSERT OR IGNORE INTO gl_accounts
             (id, account_code, account_name, account_group, normal_balance, parent_code, is_active, source_sheet, created_at, updated_at)
             VALUES (?, ?, ?, ?, ?, NULL, 1, 'DEFAULT', ?, ?)`,
            [
                crypto.randomUUID(),
                a.code,
                a.name,
                classifyAccountGroup(a.code, a.name),
                inferNormalBalance(a.code, a.name),
                now,
                now
            ]
        );
    }
}

async function validateJournalLines(lines) {
    const arr = Array.isArray(lines) ? lines : [];
    if (!arr.length) return { ok: false, error: 'Journal lines required' };
    let debit = 0;
    let credit = 0;
    for (const it of arr) {
        const d = num(it.debit);
        const c = num(it.credit);
        if (d <= 0 && c <= 0) return { ok: false, error: 'Each line needs debit or credit' };
        if (d > 0 && c > 0) return { ok: false, error: 'Line cannot contain debit and credit together' };
        const code = String(it.account_code || '').trim();
        if (!code) return { ok: false, error: 'account_code required' };
        const acc = await get("SELECT account_code, account_name FROM gl_accounts WHERE account_code = ?", [code]);
        if (!acc) return { ok: false, error: `Unknown account code: ${code}` };
        debit += d;
        credit += c;
    }
    if (Math.abs(debit - credit) > 0.0001) return { ok: false, error: 'Journal is not balanced (debit != credit)' };
    return { ok: true, debit, credit };
}

async function fetchLedgerRows({ fromDate, toDate, accountCode }) {
    const where = [];
    const params = [];
    if (fromDate) {
        where.push("j.journal_date >= ?");
        params.push(normalizeDateIso(fromDate));
    }
    if (toDate) {
        where.push("j.journal_date <= ?");
        params.push(normalizeDateIso(toDate));
    }
    if (accountCode) {
        where.push("l.account_code = ?");
        params.push(String(accountCode));
    }
    const sql = `
        SELECT
            j.id as journal_id,
            j.journal_no,
            j.journal_date,
            j.description as journal_description,
            j.status,
            l.line_no,
            l.account_code,
            l.account_name,
            l.debit,
            l.credit,
            l.memo
        FROM gl_journal_lines l
        JOIN gl_journals j ON j.id = l.journal_id
        ${where.length ? `WHERE ${where.join(' AND ')}` : ''}
        ORDER BY j.journal_date ASC, j.journal_no ASC, l.line_no ASC
    `;
    return await all(sql, params);
}

async function computeTrialBalance({ fromDate, toDate }) {
    const rows = await fetchLedgerRows({ fromDate, toDate, accountCode: null });
    const map = new Map();
    for (const r of rows) {
        const code = String(r.account_code || '');
        const name = String(r.account_name || '');
        const old = map.get(code) || { account_code: code, account_name: name, debit: 0, credit: 0, balance: 0, normal_balance: inferNormalBalance(code, name) };
        old.debit += num(r.debit);
        old.credit += num(r.credit);
        old.balance = old.debit - old.credit;
        map.set(code, old);
    }
    const items = Array.from(map.values()).sort((a, b) => String(a.account_code).localeCompare(String(b.account_code)));
    const totals = items.reduce((acc, it) => {
        acc.debit += num(it.debit);
        acc.credit += num(it.credit);
        return acc;
    }, { debit: 0, credit: 0 });
    return { items, totals, balanced: Math.abs(totals.debit - totals.credit) < 0.0001 };
}

async function computeIncomeStatement({ fromDate, toDate }) {
    const tb = await computeTrialBalance({ fromDate, toDate });
    const income = [];
    const expense = [];
    for (const it of tb.items) {
        const g = classifyAccountGroup(it.account_code, it.account_name);
        if (g === 'INCOME') income.push({ ...it, amount: num(it.credit) - num(it.debit) });
        if (g === 'EXPENSE') expense.push({ ...it, amount: num(it.debit) - num(it.credit) });
    }
    const totalIncome = income.reduce((s, x) => s + num(x.amount), 0);
    const totalExpense = expense.reduce((s, x) => s + num(x.amount), 0);
    return {
        income,
        expense,
        total_income: totalIncome,
        total_expense: totalExpense,
        net_surplus: totalIncome - totalExpense
    };
}

async function computeBalanceSheet({ toDate }) {
    const tb = await computeTrialBalance({ fromDate: null, toDate });
    const assets = [];
    const liabilities = [];
    const equity = [];
    for (const it of tb.items) {
        const g = classifyAccountGroup(it.account_code, it.account_name);
        const amount = num(it.debit) - num(it.credit);
        if (g === 'ASSET') assets.push({ ...it, amount });
        if (g === 'LIABILITY') liabilities.push({ ...it, amount: -amount });
        if (g === 'EQUITY') equity.push({ ...it, amount: -amount });
    }
    const totalAssets = assets.reduce((s, x) => s + num(x.amount), 0);
    const totalLiabilities = liabilities.reduce((s, x) => s + num(x.amount), 0);
    const totalEquity = equity.reduce((s, x) => s + num(x.amount), 0);
    return {
        assets,
        liabilities,
        equity,
        total_assets: totalAssets,
        total_liabilities: totalLiabilities,
        total_equity: totalEquity,
        balanced: Math.abs(totalAssets - (totalLiabilities + totalEquity)) < 0.0001
    };
}

async function upsertSetupItem(itemKey, itemValue, sourceRow = 0) {
    const now = new Date().toISOString();
    const val = String(itemValue || '');
    const row = await get('SELECT id FROM lapkeu_setup WHERE item_key = ?', [itemKey]);
    if (row?.id) {
        await run(
            'UPDATE lapkeu_setup SET item_value = ?, source_row = ?, updated_at = ? WHERE item_key = ?',
            [val, Number(sourceRow || 0), now, itemKey]
        );
    } else {
        await run(
            'INSERT INTO lapkeu_setup (id, item_key, item_value, source_row, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?)',
            [crypto.randomUUID(), itemKey, val, Number(sourceRow || 0), now, now]
        );
    }
}

function excelCellToText(v) {
    if (v == null) return '';
    if (typeof v === 'object') {
        if (v.text != null) return String(v.text);
        if (v.result != null) return String(v.result);
        if (v.formula != null) return String(v.result != null ? v.result : '');
        if (v.richText) return v.richText.map(x => x.text).join('');
        return '';
    }
    return String(v);
}

async function importLapkeuMasterWorkbook(filePath, actor = 'system') {
    const wb = new ExcelJS.Workbook();
    await wb.xlsx.readFile(filePath);
    const now = new Date().toISOString();
    const importBatchId = crypto.randomUUID();
    let importedRows = 0;
    let skippedRows = 0;
    let brokenFormulaCount = 0;

    // Full-sheet extraction (no sheet left behind)
    await run("DELETE FROM lapkeu_sheet_rows");
    for (const ws of wb.worksheets) {
        ws.eachRow({ includeEmpty: false }, async () => { });
        for (let r = 1; r <= ws.rowCount; r++) {
            const row = ws.getRow(r);
            const cells = [];
            row.eachCell({ includeEmpty: false }, (cell, colNo) => {
                const raw = cell.value;
                if (raw && typeof raw === 'object' && (raw.formula != null || raw.sharedFormula != null)) {
                    const f = String(raw.formula || raw.sharedFormula || '');
                    if (f.includes('#REF!')) brokenFormulaCount += 1;
                }
                const display = excelCellToText(raw);
                if (!display && !(raw && typeof raw === 'object' && (raw.formula != null || raw.sharedFormula != null))) return;
                cells.push({
                    col: colNo,
                    value: display,
                    formula: (raw && typeof raw === 'object' && raw.formula != null) ? String(raw.formula) : null
                });
            });
            if (!cells.length) continue;
            await run(
                `INSERT INTO lapkeu_sheet_rows (id, import_batch_id, sheet_name, row_no, row_json, created_at)
                 VALUES (?, ?, ?, ?, ?, ?)`,
                [crypto.randomUUID(), importBatchId, ws.name, r, JSON.stringify(cells), now]
            );
            importedRows += 1;
        }
    }

    // Setup
    const wsSetup = wb.getWorksheet('Setup');
    if (wsSetup) {
        for (let r = 6; r <= 40; r++) {
            const keyCell = wsSetup.getRow(r).getCell(2).value;
            const valCell = wsSetup.getRow(r).getCell(3).value;
            const key = excelCellToText(keyCell).trim();
            if (!key) continue;
            let value = '';
            if (valCell && typeof valCell === 'object' && valCell.formula != null) {
                value = excelCellToText(valCell);
            } else {
                value = excelCellToText(valCell);
            }
            await upsertSetupItem(key, value, r);
        }
    }

    // Saldo Buku -> CoA + opening
    const wsSaldo = wb.getWorksheet('Saldo Buku');
    const period = await ensureDefaultGlPeriod();
    if (wsSaldo) {
        for (let r = 8; r <= Math.min(wsSaldo.rowCount, 120); r++) {
            const code = String(wsSaldo.getRow(r).getCell(2).value || '').trim();
            const name = String(wsSaldo.getRow(r).getCell(3).value || '').trim();
            if (!code || !name) { skippedRows += 1; continue; }
            const saldoAwal = num(wsSaldo.getRow(r).getCell(4).value);
            const group = classifyAccountGroup(code, name);
            const normal = inferNormalBalance(code, name);
            await run(
                `INSERT INTO gl_accounts (id, account_code, account_name, account_group, normal_balance, parent_code, is_active, source_sheet, created_at, updated_at)
                 VALUES (?, ?, ?, ?, ?, NULL, 1, 'Saldo Buku', ?, ?)
                 ON CONFLICT(account_code) DO UPDATE SET account_name = excluded.account_name, account_group = excluded.account_group, normal_balance = excluded.normal_balance, updated_at = excluded.updated_at`,
                [crypto.randomUUID(), code, name, group, normal, now, now]
            );
            await run(
                `INSERT INTO gl_opening_balances (id, period_id, account_code, opening_debit, opening_credit, source_sheet, created_at)
                 VALUES (?, ?, ?, ?, ?, 'Saldo Buku', ?)
                 ON CONFLICT(period_id, account_code) DO UPDATE SET opening_debit = excluded.opening_debit, opening_credit = excluded.opening_credit`,
                [crypto.randomUUID(), period.id, code, normal === 'DEBIT' ? saldoAwal : 0, normal === 'CREDIT' ? saldoAwal : 0, now]
            );
        }
    }

    // Ref_Brg
    const wsRef = wb.getWorksheet('Ref_Brg');
    if (wsRef) {
        for (let r = 8; r <= wsRef.rowCount; r++) {
            const code = String(wsRef.getRow(r).getCell(1).value || '').trim();
            const name = String(wsRef.getRow(r).getCell(2).value || '').trim();
            const unit = String(wsRef.getRow(r).getCell(3).value || '').trim();
            if (!code || !name) { skippedRows += 1; continue; }
            const groupCode = code.includes('.') ? code.split('.').slice(0, 2).join('.') : code;
            await run(
                `INSERT INTO lapkeu_ref_brg (id, kode_brg, nama_barang, satuan, kelompok_kode, source_row, created_at, updated_at)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                 ON CONFLICT(kode_brg) DO UPDATE SET nama_barang = excluded.nama_barang, satuan = excluded.satuan, kelompok_kode = excluded.kelompok_kode, source_row = excluded.source_row, updated_at = excluded.updated_at`,
                [crypto.randomUUID(), code, name, unit, groupCode, r, now, now]
            );
        }
    }

    // Transaksi sheet -> auto import literal rows into legacy transactions + posted journal
    const wsTrx = wb.getWorksheet('Transaksi');
    if (wsTrx) {
        for (let r = 11; r <= wsTrx.rowCount; r++) {
            const dateVal = wsTrx.getRow(r).getCell(3).value;
            const noBukti = excelCellToText(wsTrx.getRow(r).getCell(5).value).trim();
            const uraian = excelCellToText(wsTrx.getRow(r).getCell(6).value).trim();
            const debitRaw = wsTrx.getRow(r).getCell(7).value;
            const creditRaw = wsTrx.getRow(r).getCell(8).value;
            const akun = excelCellToText(wsTrx.getRow(r).getCell(11).value).trim();
            const akunKas = excelCellToText(wsTrx.getRow(r).getCell(14).value).trim();
            const debit = num(excelCellToText(debitRaw));
            const credit = num(excelCellToText(creditRaw));
            const hasLiteralCore = (typeof dateVal !== 'object' || !dateVal?.formula) && (noBukti || uraian || debit > 0 || credit > 0);
            if (!hasLiteralCore) continue;
            if (debit <= 0 && credit <= 0) continue;

            const txDate = normalizeDateIso(excelCellToText(dateVal) || now);
            const txId = crypto.randomUUID();
            const refKey = `Transaksi:R${r}`;
            const amount = debit > 0 ? debit : credit;
            await run(
                "INSERT INTO transactions (id, category, amount, currency, description, date, source_ref) VALUES (?, ?, ?, 'IDR', ?, ?, ?)",
                [txId, akun || 'Lapkeu Import', amount, `${noBukti} ${uraian}`.trim(), txDate, refKey]
            );

            await ensureLapkeuDefaultAccounts();
            const primaryAcc = await get("SELECT account_code, account_name FROM gl_accounts WHERE account_name = ? OR account_code = ? LIMIT 1", [akun, akun]);
            const kasAcc = await get("SELECT account_code, account_name FROM gl_accounts WHERE account_name = ? OR account_code = ? LIMIT 1", [akunKas, akunKas])
                || await get("SELECT account_code, account_name FROM gl_accounts WHERE account_code IN ('1101','1102','1000') ORDER BY account_code ASC LIMIT 1");
            if (primaryAcc && kasAcc) {
                const jid = crypto.randomUUID();
                const jno = formatJournalNo();
                await run(
                    `INSERT INTO gl_journals (id, journal_no, journal_date, period_id, source_type, source_ref, description, status, posted_at, posted_by, created_at, updated_at)
                     VALUES (?, ?, ?, ?, 'LAPKEU_SHEET', ?, ?, 'POSTED', ?, ?, ?, ?)`,
                    [jid, jno, txDate, period.id, refKey, `${noBukti} ${uraian}`.trim(), now, actor, now, now]
                );
                // If debit recorded in transaction, primary account debited and cash credited; reverse for kredit.
                if (debit > 0) {
                    await run(`INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at) VALUES (?, ?, 1, ?, ?, ?, 0, ?, ?, ?)`,
                        [crypto.randomUUID(), jid, primaryAcc.account_code, primaryAcc.account_name || akun, debit, uraian, refKey, now]);
                    await run(`INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at) VALUES (?, ?, 2, ?, ?, 0, ?, ?, ?, ?)`,
                        [crypto.randomUUID(), jid, kasAcc.account_code, kasAcc.account_name || akunKas || 'Kas', debit, uraian, refKey, now]);
                } else {
                    await run(`INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at) VALUES (?, ?, 1, ?, ?, ?, 0, ?, ?, ?)`,
                        [crypto.randomUUID(), jid, kasAcc.account_code, kasAcc.account_name || akunKas || 'Kas', credit, uraian, refKey, now]);
                    await run(`INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at) VALUES (?, ?, 2, ?, ?, 0, ?, ?, ?, ?)`,
                        [crypto.randomUUID(), jid, primaryAcc.account_code, primaryAcc.account_name || akun, credit, uraian, refKey, now]);
                }
            }
        }
    }

    await run(
        `INSERT INTO lapkeu_import_audit (id, import_type, source_file, total_rows, imported_rows, skipped_rows, broken_formula_count, notes, imported_by, imported_at)
         VALUES (?, 'MASTER_WORKBOOK', ?, ?, ?, ?, ?, ?, ?, ?)`,
        [
            crypto.randomUUID(),
            filePath,
            importedRows + skippedRows,
            importedRows,
            skippedRows,
            brokenFormulaCount,
            'Imported all workbook sheets (raw), setup, saldo buku, ref_brg, and literal transaksi rows',
            actor,
            now
        ]
    );

    return { imported_rows: importedRows, skipped_rows: skippedRows, broken_formula_count: brokenFormulaCount };
}

async function computeCashflowSimple({ fromDate, toDate }) {
    const rows = await all(
        `SELECT category, SUM(amount) as total
         FROM transactions
         WHERE (? IS NULL OR date >= ?) AND (? IS NULL OR date <= ?)
         GROUP BY category`,
        [fromDate || null, fromDate || null, toDate || null, toDate || null]
    );
    let inflow = 0;
    let outflow = 0;
    const details = [];
    for (const r of rows) {
        const cat = String(r.category || '');
        const total = num(r.total);
        const c = cat.toLowerCase();
        const isIn = c.includes('dana') || c.includes('penerimaan') || c.includes('income');
        if (isIn) inflow += total;
        else outflow += total;
        details.push({ category: cat, amount: total, direction: isIn ? 'INFLOW' : 'OUTFLOW' });
    }
    return { inflow, outflow, net: inflow - outflow, details };
}

