const FINANCE_SALDO_BUKU_ALLOWED = {
    '1000': 'BUKU KAS UMUM',
    '1100': 'BUKU PEMBANTU KAS',
    '1101': 'Petty Cash/Cash in Hand',
    '1102': 'Kas di Bank',
    '2000': 'BUKU PEMBANTU JENIS DANA',
    '2110': 'Dana Bantuan Pemerintah',
    '2120': 'Biaya Bahan Baku',
    '2130': 'Biaya Operasional',
    '2140': 'Biaya Insentif Fasilitas'
};

function isSaldoBukuRowAllowed(code, name) {
    const c = String(code || '').trim();
    const n = String(name || '').trim().toLowerCase().replace(/\s+/g, ' ');
    const allowedName = FINANCE_SALDO_BUKU_ALLOWED[c];
    if (!allowedName) return false;
    const a = allowedName.toLowerCase().replace(/\s+/g, ' ');
    return n === a;
}

app.post('/api/finance/saldo-buku/cleanup', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const allRows = await all(
                `SELECT id, row_no, row_json FROM lapkeu_sheet_rows WHERE sheet_name = 'Saldo Buku'`
            );
            let deleted = 0;
            for (const r of allRows) {
                let cells = [];
                try { cells = JSON.parse(r.row_json || '[]'); } catch (e) { }
                const getVal = (col) => {
                    const c = Array.isArray(cells) ? cells.find(x => Number(x?.col || 0) === col) : null;
                    return String(c?.value || '').trim();
                };
                const code = getVal(2);
                const name = getVal(3);
                if (code && !isSaldoBukuRowAllowed(code, name)) {
                    await run('DELETE FROM lapkeu_sheet_rows WHERE id = ?', [r.id]);
                    deleted += 1;
                }
            }
            res.json({ success: true, deleted });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

