app.put('/api/finance/import/sheets/:sheet/:rowNo', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const sheet = String(req.params.sheet || '').trim();
            const rowNo = Number(req.params.rowNo || 0);
            const cells = Array.isArray(req.body?.cells) ? req.body.cells : [];
            if (!sheet) return res.status(400).json({ error: 'Invalid sheet name' });
            if (!Number.isFinite(rowNo) || rowNo <= 0) return res.status(400).json({ error: 'Invalid row number' });
            const normalized = cells
                .map(c => ({ col: Number(c.col || 0), value: String(c.value || ''), formula: c.formula ? String(c.formula) : null }))
                .filter(c => Number.isFinite(c.col) && c.col > 0);
            const now = new Date().toISOString();
            const existing = await get("SELECT id FROM lapkeu_sheet_rows WHERE sheet_name = ? AND row_no = ? LIMIT 1", [sheet, rowNo]);
            if (existing?.id) {
                await run("UPDATE lapkeu_sheet_rows SET row_json = ?, created_at = ? WHERE id = ?", [JSON.stringify(normalized), now, existing.id]);
            } else {
                await run(
                    `INSERT INTO lapkeu_sheet_rows (id, import_batch_id, sheet_name, row_no, row_json, created_at)
                     VALUES (?, ?, ?, ?, ?, ?)`,
                    [crypto.randomUUID(), 'MANUAL_EDIT', sheet, rowNo, JSON.stringify(normalized), now]
                );
            }

            // Persist edits into the accounting tables that drive official reports.
            const actor = financeActor(req);
            const getVal = (col) => {
                const found = normalized.find(c => Number(c.col) === Number(col));
                return found ? found.value : '';
            };
            const transaksiRefKey = `Transaksi:R${rowNo}`;

            if (sheet === 'Setup') {
                const key = getVal(2);
                const value = getVal(3);
                if (key) await upsertSetupItem(key, value, rowNo);
            }

            if (sheet === 'Saldo Buku') {
                const code = getVal(2);
                const name = getVal(3);
                const saldoAwal = num(getVal(4));
                if (code && name) {
                    const group = classifyAccountGroup(code, name);
                    const normal = inferNormalBalance(code, name);
                    await run(
                        `INSERT INTO gl_accounts (id, account_code, account_name, account_group, normal_balance, parent_code, is_active, source_sheet, created_at, updated_at)
                         VALUES (?, ?, ?, ?, ?, NULL, 1, 'Saldo Buku', ?, ?)
                         ON CONFLICT(account_code) DO UPDATE SET account_name = excluded.account_name, account_group = excluded.account_group, normal_balance = excluded.normal_balance, updated_at = excluded.updated_at`,
                        [crypto.randomUUID(), code, name, group, normal, now, now]
                    );
                    const period = await ensureDefaultGlPeriod();
                    await run(
                        `INSERT INTO gl_opening_balances (id, period_id, account_code, opening_debit, opening_credit, source_sheet, created_at)
                         VALUES (?, ?, ?, ?, ?, 'Saldo Buku', ?)
                         ON CONFLICT(period_id, account_code) DO UPDATE SET opening_debit = excluded.opening_debit, opening_credit = excluded.opening_credit`,
                        [crypto.randomUUID(), period.id, code, normal === 'DEBIT' ? saldoAwal : 0, normal === 'CREDIT' ? saldoAwal : 0, now]
                    );
                }
            }

            if (sheet === 'Ref_Brg') {
                const kode = getVal(1);
                const nama = getVal(2);
                const satuan = getVal(3);
                if (kode && nama) {
                    const groupCode = kode.includes('.') ? kode.split('.').slice(0, 2).join('.') : kode;
                    await run(
                        `INSERT INTO lapkeu_ref_brg (id, kode_brg, nama_barang, satuan, kelompok_kode, source_row, created_at, updated_at)
                         VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                         ON CONFLICT(kode_brg) DO UPDATE SET nama_barang = excluded.nama_barang, satuan = excluded.satuan, kelompok_kode = excluded.kelompok_kode, source_row = excluded.source_row, updated_at = excluded.updated_at`,
                        [crypto.randomUUID(), kode, nama, satuan, groupCode, rowNo, now, now]
                    );
                }
            }

            if (sheet === 'Transaksi') {
                const getValTrx = (newCol, oldCol) => String(getVal(newCol) || getVal(oldCol || newCol) || '').trim();
                const trxDate = normalizeDateIso(getValTrx(1, 3) || now);
                const noBukti = getValTrx(2, 5);
                const uraian = getValTrx(3, 6);
                const debit = num(getVal(4) || getVal(7));
                const kredit = num(getVal(5) || getVal(8));
                const jenisBukuPembantu = getValTrx(6, 9);
                const akunCol7 = getValTrx(7, null);
                const akunPP = resolveAkunFromCol7(akunCol7) || getVal(11).trim();
                const akunKas = getVal(14).trim() || resolveAkunKasFromJenis(jenisBukuPembantu);
                const catatan = getVal(17).trim();

                // Clear accounting artifacts if user empties the row.
                if ((debit <= 0 && kredit <= 0) || !akunPP || !akunKas || !noBukti) {
                    await run(
                        `DELETE FROM gl_journal_lines
                         WHERE journal_id IN (SELECT id FROM gl_journals WHERE source_type = 'LAPKEU_SHEET' AND source_ref = ?)`,
                        [transaksiRefKey]
                    );
                    await run(`DELETE FROM gl_journals WHERE source_type = 'LAPKEU_SHEET' AND source_ref = ?`, [transaksiRefKey]);
                    await run(`DELETE FROM transactions WHERE source_ref = ?`, [transaksiRefKey]);
                    await run(`DELETE FROM lapkeu_transactions WHERE source = ?`, [transaksiRefKey]);
                } else {
                    await ensureLapkeuDefaultAccounts();

                    const period = await ensureDefaultGlPeriod();

                    // Rebuild official journal for this sheet row (idempotent by source_ref).
                    await run(
                        `DELETE FROM gl_journal_lines
                         WHERE journal_id IN (SELECT id FROM gl_journals WHERE source_type = 'LAPKEU_SHEET' AND source_ref = ?)`,
                        [transaksiRefKey]
                    );
                    await run(`DELETE FROM gl_journals WHERE source_type = 'LAPKEU_SHEET' AND source_ref = ?`, [transaksiRefKey]);
                    await run(`DELETE FROM transactions WHERE source_ref = ?`, [transaksiRefKey]);
                    await run(`DELETE FROM lapkeu_transactions WHERE source = ?`, [transaksiRefKey]);

                    // Compatibility: remove any older master-import artifacts that used a different source_ref style.
                    await run(
                        `DELETE FROM gl_journal_lines
                         WHERE journal_id IN (
                           SELECT id FROM gl_journals
                           WHERE source_type = 'LAPKEU_IMPORT' AND journal_date = ? AND description LIKE ?
                         )`,
                        [trxDate, `%${noBukti}%`]
                    );
                    await run(
                        `DELETE FROM gl_journals
                         WHERE source_type = 'LAPKEU_IMPORT' AND journal_date = ? AND description LIKE ?`,
                        [trxDate, `%${noBukti}%`]
                    );
                    await run(
                        `DELETE FROM transactions
                         WHERE date = ? AND description LIKE ?`,
                        [trxDate, `%${noBukti}%`]
                    );

                    const txId = crypto.randomUUID();
                    await run(
                        "INSERT INTO transactions (id, category, amount, currency, description, date, source_ref) VALUES (?, ?, ?, 'IDR', ?, ?, ?)",
                        [txId, akunPP, debit > 0 ? debit : kredit, `${noBukti} ${uraian}`.trim(), trxDate, transaksiRefKey]
                    );

                    await run(
                        `INSERT INTO lapkeu_transactions
                         (id, trx_date, no_bukti, uraian, debit, kredit, jenis_buku_pembantu, akun_penerimaan_pengeluaran, akun_kas, catatan_pengeluaran, source, created_by, created_at, updated_at)
                         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                        [crypto.randomUUID(), trxDate, noBukti, uraian, debit, kredit, jenisBukuPembantu, akunPP, akunKas, catatan, transaksiRefKey, actor, now, now]
                    );

                    const primaryAcc = await get(
                        "SELECT account_code, account_name FROM gl_accounts WHERE account_code = ? OR account_name = ? LIMIT 1",
                        [akunPP, akunPP]
                    );
                    const kasAcc = await get(
                        "SELECT account_code, account_name FROM gl_accounts WHERE account_code = ? OR account_name = ? LIMIT 1",
                        [akunKas, akunKas]
                    ) || await get("SELECT account_code, account_name FROM gl_accounts WHERE account_code IN ('1101','1102','1000') ORDER BY account_code ASC LIMIT 1");

                    if (!primaryAcc || !kasAcc) {
                        throw new Error('Akun tidak ditemukan di CoA. Tambahkan dulu akun terkait.');
                    }

                    const jid = crypto.randomUUID();
                    const jno = formatJournalNo();

                    await run(
                        `INSERT INTO gl_journals (id, journal_no, journal_date, period_id, source_type, source_ref, description, status, posted_at, posted_by, created_at, updated_at)
                         VALUES (?, ?, ?, ?, 'LAPKEU_SHEET', ?, ?, 'POSTED', ?, ?, ?, ?)`,
                        [jid, jno, trxDate, period.id, transaksiRefKey, `${noBukti} ${uraian}`.trim(), now, actor, now, now]
                    );

                    if (debit > 0) {
                        await run(
                            `INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at)
                             VALUES (?, ?, 1, ?, ?, ?, 0, ?, ?, ?)`,
                            [crypto.randomUUID(), jid, primaryAcc.account_code, primaryAcc.account_name || akunPP, debit, uraian || catatan || noBukti, transaksiRefKey, now]
                        );
                        await run(
                            `INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at)
                             VALUES (?, ?, 2, ?, ?, 0, ?, ?, ?, ?)`,
                            [crypto.randomUUID(), jid, kasAcc.account_code, kasAcc.account_name || akunKas || 'Kas', debit, catatan || uraian || noBukti, transaksiRefKey, now]
                        );
                    } else {
                        await run(
                            `INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at)
                             VALUES (?, ?, 1, ?, ?, ?, 0, ?, ?, ?, ?)`,
                            [crypto.randomUUID(), jid, kasAcc.account_code, kasAcc.account_name || akunKas || 'Kas', kredit, uraian || catatan || noBukti, transaksiRefKey, now]
                        );
                        await run(
                            `INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at)
                             VALUES (?, ?, 2, ?, ?, 0, ?, ?, ?, ?)`,
                            [crypto.randomUUID(), jid, primaryAcc.account_code, primaryAcc.account_name || akunPP, kredit, catatan || uraian || noBukti, transaksiRefKey, now]
                        );
                    }
                }
            }

            return res.json({ success: true, sheet, row_no: rowNo, cells: normalized.length });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

