app.post('/api/finance/journals', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            await ensureLapkeuDefaultAccounts();
            const lines = Array.isArray(req.body.lines) ? req.body.lines : [];
            const chk = await validateJournalLines(lines);
            if (!chk.ok) return res.status(400).json({ error: chk.error });

            const now = new Date().toISOString();
            const period = await ensureDefaultGlPeriod();
            const id = crypto.randomUUID();
            const journalNo = String(req.body.journal_no || '').trim() || formatJournalNo();
            const jDate = normalizeDateIso(req.body.journal_date || now);
            await run(
                `INSERT INTO gl_journals (id, journal_no, journal_date, period_id, source_type, source_ref, description, status, posted_at, posted_by, created_at, updated_at)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                [
                    id,
                    journalNo,
                    jDate,
                    period.id,
                    String(req.body.source_type || 'MANUAL'),
                    String(req.body.source_ref || ''),
                    String(req.body.description || ''),
                    req.body.auto_post ? 'POSTED' : 'DRAFT',
                    req.body.auto_post ? now : null,
                    req.body.auto_post ? financeActor(req) : null,
                    now,
                    now
                ]
            );
            for (let i = 0; i < lines.length; i++) {
                const it = lines[i];
                const code = String(it.account_code || '').trim();
                const acc = await get("SELECT account_name FROM gl_accounts WHERE account_code = ?", [code]);
                await run(
                    `INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at)
                     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                    [
                        crypto.randomUUID(),
                        id,
                        i + 1,
                        code,
                        acc?.account_name || '',
                        num(it.debit),
                        num(it.credit),
                        String(it.memo || ''),
                        String(it.ref_key || ''),
                        now
                    ]
                );
            }
            const hdr = await get("SELECT * FROM gl_journals WHERE id = ?", [id]);
            const outLines = await all("SELECT * FROM gl_journal_lines WHERE journal_id = ? ORDER BY line_no ASC", [id]);
            res.json({ success: true, journal: hdr, lines: outLines });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

