app.post('/api/finance/transactions/manual', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            await ensureLapkeuDefaultAccounts();
            const trx_date = normalizeDateIso(req.body?.trx_date);
            const no_bukti = String(req.body?.no_bukti || '').trim();
            const uraian = String(req.body?.uraian || '').trim();
            const jenis_buku_pembantu = String(req.body?.jenis_buku_pembantu || '').trim();
            const akun_penerimaan_pengeluaran = String(req.body?.akun_penerimaan_pengeluaran || '').trim();
            const akun_kas = String(req.body?.akun_kas || '').trim();
            const catatan_pengeluaran = String(req.body?.catatan_pengeluaran || '').trim();
            const debit = num(req.body?.debit);
            const kredit = num(req.body?.kredit);
            if (!no_bukti) return res.status(400).json({ error: 'No bukti wajib diisi' });
            if (!uraian) return res.status(400).json({ error: 'Uraian transaksi wajib diisi' });
            if ((debit <= 0 && kredit <= 0) || (debit > 0 && kredit > 0)) return res.status(400).json({ error: 'Isi salah satu: debit atau kredit' });
            if (!akun_penerimaan_pengeluaran) return res.status(400).json({ error: 'Akun penerimaan/pengeluaran wajib diisi' });

            const now = new Date().toISOString();
            const sheetRowLast = await get("SELECT COALESCE(MAX(row_no), 0) as max_row FROM lapkeu_sheet_rows WHERE sheet_name = 'Transaksi'");
            const rowNo = (Number(sheetRowLast?.max_row || 0) || 0) + 1;
            const refKey = `Transaksi:R${rowNo}`;
            const id = crypto.randomUUID();

            // Persist this manual input into the datasheet row, so it can be edited later.
            const normalizedCells = [
                { col: 3, value: trx_date },
                { col: 5, value: no_bukti },
                { col: 6, value: uraian },
                { col: 7, value: debit > 0 ? String(debit) : '' },
                { col: 8, value: kredit > 0 ? String(kredit) : '' },
                { col: 9, value: jenis_buku_pembantu },
                { col: 11, value: akun_penerimaan_pengeluaran },
                { col: 14, value: akun_kas },
                { col: 17, value: catatan_pengeluaran }
            ].filter(c => Number.isFinite(c.col) && c.col > 0);

            await run(
                `INSERT INTO lapkeu_sheet_rows (id, import_batch_id, sheet_name, row_no, row_json, created_at)
                 VALUES (?, ?, ?, ?, ?, ?)`,
                [crypto.randomUUID(), 'MANUAL_FORM', 'Transaksi', rowNo, JSON.stringify(normalizedCells), now]
            );

            await run(
                `INSERT INTO lapkeu_transactions
                 (id, trx_date, no_bukti, uraian, debit, kredit, jenis_buku_pembantu, akun_penerimaan_pengeluaran, akun_kas, catatan_pengeluaran, source, created_by, created_at, updated_at)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                [id, trx_date, no_bukti, uraian, debit, kredit, jenis_buku_pembantu, akun_penerimaan_pengeluaran, akun_kas, catatan_pengeluaran, refKey, financeActor(req), now, now]
            );

            // Legacy transaction list compatibility
            await run(
                "INSERT INTO transactions (id, category, amount, currency, description, date, source_ref) VALUES (?, ?, ?, 'IDR', ?, ?, ?)",
                [crypto.randomUUID(), akun_penerimaan_pengeluaran, debit > 0 ? debit : kredit, `${no_bukti} - ${uraian}`, trx_date, refKey]
            );

            // Journal posting (double-entry)
            const period = await ensureDefaultGlPeriod();
            const primaryAcc = await get("SELECT account_code, account_name FROM gl_accounts WHERE account_name = ? OR account_code = ? LIMIT 1", [akun_penerimaan_pengeluaran, akun_penerimaan_pengeluaran]);
            const kasAcc = await get("SELECT account_code, account_name FROM gl_accounts WHERE account_name = ? OR account_code = ? LIMIT 1", [akun_kas, akun_kas])
                || await get("SELECT account_code, account_name FROM gl_accounts WHERE account_code IN ('1101','1102','1000') ORDER BY account_code ASC LIMIT 1");
            if (!primaryAcc || !kasAcc) {
                return res.status(400).json({ error: 'Akun tidak ditemukan di CoA. Tambahkan dulu akun terkait.' });
            }

            const jid = crypto.randomUUID();
            const jno = formatJournalNo();
            await run(
                `INSERT INTO gl_journals (id, journal_no, journal_date, period_id, source_type, source_ref, description, status, posted_at, posted_by, created_at, updated_at)
                 VALUES (?, ?, ?, ?, 'LAPKEU_SHEET', ?, ?, 'POSTED', ?, ?, ?, ?)`,
                [jid, jno, trx_date, period.id, refKey, `${no_bukti} ${uraian}`.trim(), now, financeActor(req), now, now]
            );
            if (debit > 0) {
                await run(`INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at) VALUES (?, ?, 1, ?, ?, ?, 0, ?, ?, ?)`,
                    [crypto.randomUUID(), jid, primaryAcc.account_code, primaryAcc.account_name || akun_penerimaan_pengeluaran, debit, catatan_pengeluaran || uraian, refKey, now]);
                await run(`INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at) VALUES (?, ?, 2, ?, ?, 0, ?, ?, ?, ?)`,
                    [crypto.randomUUID(), jid, kasAcc.account_code, kasAcc.account_name || akun_kas || 'Kas', debit, catatan_pengeluaran || uraian, refKey, now]);
            } else {
                await run(`INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at) VALUES (?, ?, 1, ?, ?, ?, 0, ?, ?, ?)`,
                    [crypto.randomUUID(), jid, kasAcc.account_code, kasAcc.account_name || akun_kas || 'Kas', kredit, catatan_pengeluaran || uraian, refKey, now]);
                await run(`INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at) VALUES (?, ?, 2, ?, ?, 0, ?, ?, ?, ?)`,
                    [crypto.randomUUID(), jid, primaryAcc.account_code, primaryAcc.account_name || akun_penerimaan_pengeluaran, kredit, catatan_pengeluaran || uraian, refKey, now]);
            }

            res.json({ success: true, id, journal_id: jid, sheet_row_no: rowNo, ref_key: refKey });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

