app.get('/api/finance/print/:doc', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const doc = String(req.params.doc || '').toLowerCase();
            const setupRows = await all("SELECT item_key, item_value FROM lapkeu_setup");
            const setup = Object.fromEntries(setupRows.map(x => [x.item_key, x.item_value]));
            const from = req.query.from || null;
            const to = req.query.to || null;
            const lrMode = String(req.query.lr_mode || '').toLowerCase().trim();
            const showLrDetail = lrMode === 'detail' || lrMode === '1' || lrMode === 'true';
            let title = 'Dokumen Keuangan';
            let body = '';
            const htmlEscape = (s) => String(s ?? '')
                .replace(/&/g, '&amp;')
                .replace(/</g, '&lt;')
                .replace(/>/g, '&gt;')
                .replace(/\"/g, '&quot;')
                .replace(/'/g, '&#39;');
            const sectionHeader = `
                <div style="margin-bottom:10px">
                    <div>Nama SPPG: <b>${setup['Nama SPPG'] || '-'}</b></div>
                    <div>ID SPPG: <b>${setup['ID SPPG'] || '-'}</b></div>
                    <div>Alamat: <b>${setup['Alamat'] || '-'}</b></div>
                    <div>Periode: <b>${from || setup['Tgl awal periode ini (dd-mm-yyyy; format text)'] || '-'} s.d ${to || '-'}</b></div>
                </div>
            `;
            const signatureBlock = `
                <div style="margin-top:28px; display:flex; justify-content:space-between; gap:20px;">
                    <div style="text-align:center; width:45%;">
                        <div>Pihak Pertama</div>
                        <div style="height:50px"></div>
                        <div><b>${setup['Nama Yayasan'] || setup['Ketua Yayasan/yang mewakili'] || '........................'}</b></div>
                    </div>
                    <div style="text-align:center; width:45%;">
                        <div>Pihak Kedua</div>
                        <div style="height:50px"></div>
                        <div><b>${setup['Nama Akuntan SPPG'] || setup['Nama Kepala SPPG'] || '........................'}</b></div>
                    </div>
                </div>
            `;
            if (doc === 'lr') {
                const lr = await computeIncomeStatement({ fromDate: from, toDate: to });
                title = 'LAPORAN/RESUME PENERIMAAN DAN PENGELUARAN';
                const fmt = (n) => Number(n || 0).toLocaleString('id-ID');
                const htmlEscape = (s) => String(s ?? '')
                    .replace(/&/g, '&amp;')
                    .replace(/</g, '&lt;')
                    .replace(/>/g, '&gt;')
                    .replace(/\"/g, '&quot;')
                    .replace(/'/g, '&#39;');

                let incomeRows = '';
                let expenseRows = '';

                if (showLrDetail) {
                    const templateFp = path.join(__dirname, '..', 'lapkeu_master.xlsx');
                    const cacheKey = 'LR_labels_v1';
                    if (!globalThis.__lapkeuTemplateCache) globalThis.__lapkeuTemplateCache = {};
                    if (!globalThis.__lapkeuTemplateCache[cacheKey]) {
                        const wb = new ExcelJS.Workbook();
                        await wb.xlsx.readFile(templateFp);
                        const ws = wb.getWorksheet('LR');
                        const incomeLabels = [];
                        const expenseLabels = [];
                        let mode = null;
                        for (let r = 1; r <= Math.min(ws.rowCount || 0, 80); r++) {
                            const v = ws.getRow(r).getCell(2).value;
                            let s = '';
                            if (typeof v === 'string') s = v;
                            else if (v && typeof v === 'object') {
                                if (v.text != null) s = String(v.text);
                                else if (v.result != null) s = String(v.result);
                                else if (v.formula != null) s = String(v.formula);
                            } else if (v != null) {
                                s = String(v);
                            }
                            s = (s || '').trim();
                            if (!s) continue;
                            if (s.includes('#REF!')) continue;
                            if (s === 'PENERIMAAN') { mode = 'INCOME'; continue; }
                            if (s === 'PENGELUARAN') { mode = 'EXPENSE'; continue; }
                            if (s === 'BUKU KAS UMUM') break;
                            if (mode === 'INCOME') incomeLabels.push(s);
                            if (mode === 'EXPENSE') expenseLabels.push(s);
                        }
                        globalThis.__lapkeuTemplateCache[cacheKey] = { incomeLabels, expenseLabels };
                    }

                    const { incomeLabels, expenseLabels } = globalThis.__lapkeuTemplateCache[cacheKey] || { incomeLabels: [], expenseLabels: [] };
                    const fromIso = from ? normalizeDateIso(from) : null;
                    const toIso = to ? normalizeDateIso(to) : null;

                    const sumAccountAmount = async (accountNameLabel) => {
                        const label = String(accountNameLabel || '').trim();
                        if (!label) return 0;
                        const acc = await get(
                            "SELECT account_code, account_name, account_group FROM gl_accounts WHERE LOWER(account_name) = LOWER(?) LIMIT 1",
                            [label]
                        );
                        if (!acc) return 0;

                        const sums = await get(
                            `SELECT
                                COALESCE(SUM(l.debit), 0) as debit,
                                COALESCE(SUM(l.credit), 0) as credit
                             FROM gl_journal_lines l
                             JOIN gl_journals j ON j.id = l.journal_id
                             WHERE l.account_code = ?
                               AND (? IS NULL OR j.journal_date >= ?)
                               AND (? IS NULL OR j.journal_date <= ?)`,
                            [acc.account_code, fromIso, fromIso, toIso, toIso]
                        );
                        const debit = num(sums?.debit);
                        const credit = num(sums?.credit);

                        const group = classifyAccountGroup(acc.account_code, acc.account_name);
                        if (group === 'INCOME') return credit - debit;
                        if (group === 'EXPENSE') return debit - credit;
                        return debit - credit;
                    };

                    incomeRows = (incomeLabels || []).map(lbl => lbl).filter(Boolean);
                    expenseRows = (expenseLabels || []).map(lbl => lbl).filter(Boolean);

                    const incomeComputed = await Promise.all(incomeRows.map(async (lbl) => {
                        const amt = await sumAccountAmount(lbl);
                        return `<tr><td>${htmlEscape(lbl)}</td><td>${fmt(amt)}</td></tr>`;
                    }));
                    const expenseComputed = await Promise.all(expenseRows.map(async (lbl) => {
                        const amt = await sumAccountAmount(lbl);
                        return `<tr><td>${htmlEscape(lbl)}</td><td>${fmt(amt)}</td></tr>`;
                    }));
                    incomeRows = incomeComputed.join('');
                    expenseRows = expenseComputed.join('');
                }

                if (!showLrDetail) {
                    body = `${sectionHeader}
                            <table border="1" cellspacing="0" cellpadding="6">
                                <tr><th>Uraian</th><th>Jumlah</th></tr>
                                <tr><td>Total Penerimaan</td><td>${fmt(lr.total_income)}</td></tr>
                                <tr><td>Total Pengeluaran</td><td>${fmt(lr.total_expense)}</td></tr>
                                <tr><td>Surplus/Defisit</td><td>${fmt(lr.net_surplus)}</td></tr>
                            </table>${signatureBlock}`;
                } else {
                    body = `${sectionHeader}
                            <div style="margin-bottom:10px">
                                <table border="1" cellspacing="0" cellpadding="6" style="width:100%">
                                    <tr><th>Uraian</th><th>Jumlah</th></tr>
                                    <tr><td>Total Penerimaan</td><td>${fmt(lr.total_income)}</td></tr>
                                    <tr><td>Total Pengeluaran</td><td>${fmt(lr.total_expense)}</td></tr>
                                    <tr><td>Surplus/Defisit</td><td>${fmt(lr.net_surplus)}</td></tr>
                                </table>
                            </div>
                            <div style="margin-bottom:10px">
                                <div style="font-weight:bold;margin:6px 0 4px 0">PENERIMAAN</div>
                                <table border="1" cellspacing="0" cellpadding="6" style="width:100%">
                                    <tr><th>Uraian</th><th>Jumlah</th></tr>
                                    ${incomeRows || '<tr><td colspan="2">Tidak ada data</td></tr>'}
                                </table>
                            </div>
                            <div>
                                <div style="font-weight:bold;margin:6px 0 4px 0">PENGELUARAN</div>
                                <table border="1" cellspacing="0" cellpadding="6" style="width:100%">
                                    <tr><th>Uraian</th><th>Jumlah</th></tr>
                                    ${expenseRows || '<tr><td colspan="2">Tidak ada data</td></tr>'}
                                </table>
                            </div>
                            ${signatureBlock}`;
                }
            } else if (doc === 'lpa') {
                const lpa = await computeCashflowSimple({ fromDate: from, toDate: to });
                title = 'LAPORAN PENGGUNAAN DANA DUA PEKANAN';
                const nomorLpa = setup['Nomor LPA'] || '';
                const nomorBlock = nomorLpa ? `<p>Nomor: <b>${htmlEscape(nomorLpa)}</b></p>` : '';
                body = `${sectionHeader}
                        ${nomorBlock}
                        <table border="1" cellspacing="0" cellpadding="6">
                            <tr><th>Rincian</th><th>Jumlah</th></tr>
                            <tr><td>Dana Masuk</td><td>${lpa.inflow}</td></tr>
                            <tr><td>Dana Keluar</td><td>${lpa.outflow}</td></tr>
                            <tr><td>Sisa Anggaran</td><td>${lpa.net}</td></tr>
                        </table>${signatureBlock}`;
            } else if (doc === 'sptj') {
                title = 'SURAT PERNYATAAN TANGGUNG JAWAB';
                const lpa = await computeCashflowSimple({ fromDate: from, toDate: to });
                const fmt = (n) => Number(n || 0).toLocaleString('id-ID');
                body = `${sectionHeader}
                        <p>Saya yang bertanda tangan di bawah ini menyatakan bertanggung jawab secara formal dan material atas penerimaan dan pengeluaran dana Program Makan Bergizi Gratis.</p>
                        <p>Nama: <b>${setup['Ketua Yayasan/yang mewakili'] || '-'}</b></p>
                        <p>Yayasan: <b>${setup['Nama Yayasan'] || '-'}</b></p>
                        <p>Tahun Anggaran: <b>${setup['Tahun Anggaran'] || '-'}</b></p>
                        <div style="margin-top:10px">
                            <table border="1" cellspacing="0" cellpadding="6" style="width:100%">
                                <tr><th>Rincian</th><th>Jumlah</th></tr>
                                <tr><td>Jumlah Penerimaan</td><td>${fmt(lpa.inflow)}</td></tr>
                                <tr><td>Jumlah Pengeluaran</td><td>${fmt(lpa.outflow)}</td></tr>
                                <tr><td>Sisa Dana</td><td>${fmt(lpa.net)}</td></tr>
                            </table>
                        </div>
                        ${signatureBlock}`;
            } else if (doc === 'bapsd') {
                title = 'BERITA ACARA PENGALIHAN SISA DANA';
                const lr = await computeIncomeStatement({ fromDate: from, toDate: to });
                const nomorBapsd = setup['Nomor BAPSD'] || '';
                const nomorBlock = nomorBapsd ? `<p>Nomor: <b>${htmlEscape(nomorBapsd)}</b></p>` : '';
                body = `${sectionHeader}
                        ${nomorBlock}
                        <p>Dengan ini disepakati pengalihan sisa dana periode berjalan.</p>
                        <p>Sisa dana: <b>${lr.net_surplus}</b></p>
                        <p>Periode berikutnya dimulai: <b>${setup['Tgl awal periode ini (dd-mm-yyyy; format text)'] || '-'}</b></p>${signatureBlock}`;
            } else if (doc === 'bku') {
                const fromIso = from ? normalizeDateIso(from) : null;
                const toIso = to ? normalizeDateIso(to) : null;
                const tx = await all(
                    `SELECT * FROM transactions
                     WHERE (? IS NULL OR date >= ?) AND (? IS NULL OR date <= ?)
                     ORDER BY date ASC
                     LIMIT 200`,
                    [fromIso, fromIso, toIso, toIso]
                );
                title = 'BUKU KAS UMUM';
                body = `${sectionHeader}<table border="1" cellspacing="0" cellpadding="6"><tr><th>Tanggal</th><th>No Bukti</th><th>Uraian</th><th>Debet</th><th>Kredit</th></tr>${tx.map(t => `<tr><td>${t.date || ''}</td><td>${t.id || ''}</td><td>${t.description || ''}</td><td>${num(t.amount)}</td><td>0</td></tr>`).join('')}</table>${signatureBlock}`;
            } else if (doc === 'bp-bank' || doc === 'bp-petty' || doc === 'bp-bahan' || doc === 'bp-operasional' || doc === 'bp-fasilitas' || doc === 'bp-pajak') {
                const accountFilterMap = {
                    'bp-bank': '1102',
                    'bp-petty': '1101',
                    'bp-bahan': null,
                    'bp-operasional': null,
                    'bp-fasilitas': null,
                    'bp-pajak': '2120'
                };
                const labelMap = {
                    'bp-bank': 'BUKU PEMBANTU KAS DI BANK',
                    'bp-petty': 'BUKU PEMBANTU PETTY CASH',
                    'bp-bahan': 'BUKU PEMBANTU DANA BAHAN BAKU',
                    'bp-operasional': 'BUKU PEMBANTU DANA OPERASIONAL',
                    'bp-fasilitas': 'BUKU PEMBANTU DANA INSENTIF FASILITAS',
                    'bp-pajak': 'BUKU PEMBANTU PAJAK'
                };
                title = labelMap[doc] || 'BUKU PEMBANTU';
                const whereClauses = [];
                const params = [];
                const accountCode = accountFilterMap[doc];
                if (accountCode) {
                    whereClauses.push("l.account_code = ?");
                    params.push(accountCode);
                } else if (doc === 'bp-bahan') {
                    whereClauses.push("LOWER(l.account_name) LIKE '%bahan%'");
                } else if (doc === 'bp-operasional') {
                    whereClauses.push("LOWER(l.account_name) LIKE '%operasional%'");
                } else if (doc === 'bp-fasilitas') {
                    whereClauses.push("LOWER(l.account_name) LIKE '%fasilitas%'");
                }
                if (from) {
                    whereClauses.push("j.journal_date >= ?");
                    params.push(normalizeDateIso(from));
                }
                if (to) {
                    whereClauses.push("j.journal_date <= ?");
                    params.push(normalizeDateIso(to));
                }
                const whereSql = whereClauses.length ? `WHERE ${whereClauses.join(' AND ')}` : '';
                const lines = await all(
                    `SELECT j.journal_date, j.journal_no, j.description, l.account_code, l.account_name, l.debit, l.credit
                     FROM gl_journal_lines l JOIN gl_journals j ON j.id = l.journal_id
                     ${whereSql}
                     ORDER BY j.journal_date ASC, j.journal_no ASC
                     LIMIT 500`,
                    params
                );
                body = `${sectionHeader}
                    <table border="1" cellspacing="0" cellpadding="6">
                        <tr><th>Tanggal</th><th>No Bukti</th><th>Uraian</th><th>Akun</th><th>Debet</th><th>Kredit</th></tr>
                        ${lines.map(r => `<tr><td>${r.journal_date || ''}</td><td>${r.journal_no || ''}</td><td>${r.description || ''}</td><td>${r.account_code || ''} - ${r.account_name || ''}</td><td>${num(r.debit)}</td><td>${num(r.credit)}</td></tr>`).join('')}
                    </table>${signatureBlock}`;
            } else if (doc === 'stock-detail' || doc === 'stock-rekap') {
                title = doc === 'stock-detail' ? 'LAPORAN STOCK BARANG (DETIL)' : 'LAPORAN STOCK BARANG (REKAP)';
                if (doc === 'stock-detail') {
                    const rows = await all(`SELECT kode_brg, nama_barang, satuan, COALESCE(inv.quantity,0) as saldo_akhir FROM lapkeu_ref_brg rb LEFT JOIN ingredients i ON LOWER(i.name)=LOWER(rb.nama_barang) LEFT JOIN inventory inv ON inv.ingredient_id=i.id ORDER BY kode_brg ASC`);
                    body = `${sectionHeader}<table border="1" cellspacing="0" cellpadding="6"><tr><th>Kode</th><th>Nama Barang</th><th>Satuan</th><th>Saldo Akhir</th></tr>${rows.map(r => `<tr><td>${r.kode_brg || ''}</td><td>${r.nama_barang || ''}</td><td>${r.satuan || ''}</td><td>${num(r.saldo_akhir)}</td></tr>`).join('')}</table>`;
                } else {
                    const rows = await all(`SELECT kelompok_kode as kode, COUNT(*) as item_count, COALESCE(SUM(inv.quantity),0) as qty_total FROM lapkeu_ref_brg rb LEFT JOIN ingredients i ON LOWER(i.name)=LOWER(rb.nama_barang) LEFT JOIN inventory inv ON inv.ingredient_id=i.id GROUP BY kelompok_kode ORDER BY kelompok_kode ASC`);
                    body = `${sectionHeader}<table border="1" cellspacing="0" cellpadding="6"><tr><th>Kode Kelompok</th><th>Jumlah Item</th><th>Total Qty</th></tr>${rows.map(r => `<tr><td>${r.kode || ''}</td><td>${num(r.item_count)}</td><td>${num(r.qty_total)}</td></tr>`).join('')}</table>`;
                }
            } else {
                return res.status(400).json({ error: 'Unknown print doc' });
            }
            const html = `<!doctype html><html><head><meta charset="utf-8"/><title>${title}</title><style>body{font-family:Arial,sans-serif;padding:20px;font-size:12px}h1{font-size:16px;margin:0 0 12px 0}p{margin:4px 0}table{border-collapse:collapse;width:100%}th,td{font-size:12px}</style></head><body><h1>${title}</h1>${body}</body></html>`;
            res.setHeader('Content-Type', 'text/html; charset=utf-8');
            res.send(html);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.get('/api/finance/coverage', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const hasSetup = await get("SELECT COUNT(*) as c FROM lapkeu_setup");
            const hasAccounts = await get("SELECT COUNT(*) as c FROM gl_accounts");
            const hasJournals = await get("SELECT COUNT(*) as c FROM gl_journals");
            const hasRefBrg = await get("SELECT COUNT(*) as c FROM lapkeu_ref_brg");
            const sheetCoverage = await all("SELECT sheet_name, COUNT(*) as row_count FROM lapkeu_sheet_rows GROUP BY sheet_name");
            const sheetSet = new Set((sheetCoverage || []).map(x => String(x.sheet_name || '')));
            const requiredSheets = ['Setup', 'Saldo Buku', 'Transaksi', 'BKU', 'BP Bank', 'BP Petty Cash', 'BP Bahan Baku', 'BP Operasional', 'BP Fasilitas', 'BP Pajak', 'LR', 'LPA', 'SPTJ', 'BAPSD', 'Ref_Brg', 'Saldo_Brg', 'Masuk', 'Keluar', 'Stock_Brg (D)', 'Stock_Brg (R)'];
            res.json({
                source_sheets: requiredSheets,
                implemented: {
                    setup: Number(hasSetup?.c || 0) > 0,
                    coa: Number(hasAccounts?.c || 0) > 0,
                    journals: Number(hasJournals?.c || 0) >= 0,
                    inventory_ref: Number(hasRefBrg?.c || 0) > 0,
                    reports: ['lr', 'lpa', 'sptj', 'bapsd', 'bku', 'bp-bank', 'bp-petty', 'bp-bahan', 'bp-operasional', 'bp-fasilitas', 'bp-pajak', 'stock-detail', 'stock-rekap'],
                    extracted_all_sheets: requiredSheets.every(s => sheetSet.has(s))
                },
                extracted_sheet_rows: sheetCoverage
            });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.get('/api/finance/reconciliation-check', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tb = await computeTrialBalance({ fromDate: req.query.from || null, toDate: req.query.to || null });
            const bs = await computeBalanceSheet({ toDate: req.query.to || null });
            const stockDetail = await all(
                `SELECT
                    rb.kode_brg,
                    COALESCE(inv.quantity, 0) as saldo_akhir
                 FROM lapkeu_ref_brg rb
                 LEFT JOIN ingredients i ON LOWER(i.name) = LOWER(rb.nama_barang)
                 LEFT JOIN inventory inv ON inv.ingredient_id = i.id`
            );
            const stockNegative = (stockDetail || []).filter(r => Number(r.saldo_akhir || 0) < 0).length;
            res.json({
                trial_balance: {
                    total_debit: tb.totals.debit,
                    total_credit: tb.totals.credit,
                    balanced: tb.balanced
                },
                balance_sheet: {
                    total_assets: bs.total_assets,
                    total_liabilities_equity: Number(bs.total_liabilities || 0) + Number(bs.total_equity || 0),
                    balanced: bs.balanced
                },
                stock: {
                    item_count: stockDetail.length,
                    negative_item_count: stockNegative,
                    all_non_negative: stockNegative === 0
                }
            });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

