app.post('/api/finance/expense', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        const { category, amount, description, date } = req.body;
        const id = crypto.randomUUID();
        const at = date ? new Date(date).toISOString() : new Date().toISOString();
        try {
            await run("INSERT INTO transactions (id, category, amount, currency, description, date) VALUES (?, ?, ?, 'IDR', ?, ?)",
                [id, category || 'Expense', amount, description || '', at]);

            // Auto-create posted journal for legacy expense so reports stay consistent.
            await ensureLapkeuDefaultAccounts();
            const expAcc = await get("SELECT account_code, account_name FROM gl_accounts WHERE account_group = 'EXPENSE' ORDER BY account_code ASC LIMIT 1");
            const kasAcc = await get("SELECT account_code, account_name FROM gl_accounts WHERE account_code IN ('1101','1102','1000') ORDER BY account_code ASC LIMIT 1");
            if (expAcc && kasAcc) {
                const now = new Date().toISOString();
                const period = await ensureDefaultGlPeriod();
                const jid = crypto.randomUUID();
                const jno = formatJournalNo();
                await run(
                    `INSERT INTO gl_journals (id, journal_no, journal_date, period_id, source_type, source_ref, description, status, posted_at, posted_by, created_at, updated_at)
                     VALUES (?, ?, ?, ?, 'EXPENSE', ?, ?, 'POSTED', ?, ?, ?, ?)`,
                    [jid, jno, at, period.id, id, description || category || 'Expense', now, financeActor(req), now, now]
                );
                await run(
                    `INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at)
                     VALUES (?, ?, 1, ?, ?, ?, 0, ?, ?, ?)`,
                    [crypto.randomUUID(), jid, expAcc.account_code, expAcc.account_name || '', num(amount), description || '', id, now]
                );
                await run(
                    `INSERT INTO gl_journal_lines (id, journal_id, line_no, account_code, account_name, debit, credit, memo, ref_key, created_at)
                     VALUES (?, ?, 2, ?, ?, 0, ?, ?, ?, ?)`,
                    [crypto.randomUUID(), jid, kasAcc.account_code, kasAcc.account_name || '', num(amount), description || '', id, now]
                );
            }

            res.json({ success: true, id });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

