// ---------- surat_jalan ----------
function generateSuratJalanNo(tenantId, date) {
    const ymd = (date || new Date().toISOString().slice(0, 10)).replace(/-/g, '');
    const rand = Math.random().toString(36).slice(2, 6).toUpperCase();
    const tShort = String(tenantId || 'MBG').slice(0, 4).toUpperCase();
    return `SJ-${tShort}-${ymd}-${rand}`;
}
app.get('/api/surat-jalan', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            await ensureProgramReadySchema();
            const tenantId = getTenantIdFromReq(req);
            const from = String(req.query?.from || '').trim();
            const to = String(req.query?.to || '').trim();
            let sql = 'SELECT * FROM surat_jalan WHERE tenant_id = ?';
            const params = [tenantId];
            if (from) { sql += ' AND service_date >= ?'; params.push(from); }
            if (to) { sql += ' AND service_date <= ?'; params.push(to); }
            sql += ' ORDER BY service_date DESC, created_at DESC LIMIT 500';
            res.json(await all(sql, params));
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});
app.post('/api/surat-jalan', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        await requireCanonicalRoles(['kepala_sppg', 'asisten_lapangan', 'admin'])(req, res, async () => {
            try {
                await ensureProgramReadySchema();
                const tenantId = getTenantIdFromReq(req);
                const b = req.body || {};
                const id = crypto.randomUUID();
                const now = new Date().toISOString();
                const serviceDate = b.service_date || now.slice(0, 10);
                const nomor = b.nomor || generateSuratJalanNo(tenantId, serviceDate);
                await run(
                    `INSERT INTO surat_jalan (id, tenant_id, nomor, service_date, route_id, driver_staff_id, vehicle_id, batch_ids_json, total_portions, total_lokasi, kategori_pm, status, created_by, created_at, updated_at)
                     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                    [id, tenantId, nomor, serviceDate, b.route_id || null, b.driver_staff_id || null, b.vehicle_id || null,
                        b.batch_ids ? JSON.stringify(b.batch_ids) : null,
                        parseInt(b.total_portions || 0, 10) || 0,
                        parseInt(b.total_lokasi || 0, 10) || 0,
                        b.kategori_pm || null, String(b.status || 'DRAFT').toUpperCase(),
                        (req.user && req.user.id) || null, now, now]
                );
                const row = await get('SELECT * FROM surat_jalan WHERE id = ?', [id]);
                await writeComplianceAudit(req, { action: 'surat_jalan.create', entity_type: 'surat_jalan', entity_id: id, after: row });
                res.json(row);
            } catch (e) { res.status(500).json({ error: e.message }); }
        });
    });
});
app.patch('/api/surat-jalan/:id', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        await requireCanonicalRoles(['kepala_sppg', 'asisten_lapangan', 'admin'])(req, res, async () => {
            try {
                await ensureProgramReadySchema();
                const tenantId = getTenantIdFromReq(req);
                const id = String(req.params.id || '').trim();
                const before = await get('SELECT * FROM surat_jalan WHERE id = ? AND tenant_id = ?', [id, tenantId]);
                if (!before) return res.status(404).json({ error: 'Not found' });
                const b = req.body || {};
                const fields = ['route_id', 'driver_staff_id', 'vehicle_id', 'total_portions', 'total_lokasi', 'kategori_pm', 'departed_at', 'returned_at', 'status', 'pdf_url'];
                const sets = [], params = [];
                for (const f of fields) if (b[f] !== undefined) { sets.push(`${f} = ?`); params.push(b[f]); }
                if (b.batch_ids !== undefined) { sets.push('batch_ids_json = ?'); params.push(b.batch_ids ? JSON.stringify(b.batch_ids) : null); }
                if (!sets.length) return res.json(before);
                sets.push('updated_at = ?'); params.push(new Date().toISOString());
                params.push(id, tenantId);
                await run(`UPDATE surat_jalan SET ${sets.join(', ')} WHERE id = ? AND tenant_id = ?`, params);
                const row = await get('SELECT * FROM surat_jalan WHERE id = ? AND tenant_id = ?', [id, tenantId]);
                await writeComplianceAudit(req, { action: 'surat_jalan.update', entity_type: 'surat_jalan', entity_id: id, before, after: row });
                res.json(row);
            } catch (e) { res.status(500).json({ error: e.message }); }
        });
    });
});

