app.post('/api/stock-opname/runs', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        await requireCanonicalRoles(['kepala_sppg', 'admin', 'akuntan'])(req, res, async () => {
            try {
                await ensureProgramReadySchema();
                const tenantId = getTenantIdFromReq(req);
                const b = req.body || {};
                const id = crypto.randomUUID();
                const now = new Date().toISOString();
                const opnameDate = b.opname_date || now.slice(0, 10);
                const scope = String(b.scope || 'INGREDIENTS').toUpperCase();
                await run(
                    `INSERT INTO stock_opname_runs (id, tenant_id, opname_date, scope, performed_by, status, note, created_at, updated_at)
                     VALUES (?, ?, ?, ?, ?, 'DRAFT', ?, ?, ?)`,
                    [id, tenantId, opnameDate, scope, (req.user && req.user.id) || null, b.note || null, now, now]
                );
                const entries = Array.isArray(b.entries) ? b.entries : [];
                for (const e of entries) {
                    const eid = crypto.randomUUID();
                    const sysQty = Number(e.system_qty || 0);
                    const phyQty = Number(e.physical_qty || 0);
                    await run(
                        `INSERT INTO stock_opname_entries (id, tenant_id, run_id, item_kind, item_id, item_name, unit, system_qty, physical_qty, variance_qty, created_at)
                         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                        [eid, tenantId, id, String(e.item_kind || 'INGREDIENT').toUpperCase(), String(e.item_id || ''), e.item_name || null, e.unit || null, sysQty, phyQty, phyQty - sysQty, now]
                    );
                }
                const row = await get('SELECT * FROM stock_opname_runs WHERE id = ?', [id]);
                await writeComplianceAudit(req, { action: 'stock_opname.create', entity_type: 'stock_opname_runs', entity_id: id, after: row });
                res.json(row);
            } catch (e) { res.status(500).json({ error: e.message }); }
        });
    });
});
