/**
 * Perpustakaan Juknis BGN: tautan resmi (manifest.json) + daftar PDF lokal
 * di folder frontend/docs/juknis-bgn/ (opsional).
 */
app.get('/api/juknis-library', (_req, res) => {
    try {
        const dir = path.join(__dirname, 'docs', 'juknis-bgn');
        const manifestPath = path.join(dir, 'manifest.json');
        let manifest = null;
        if (fs.existsSync(manifestPath)) {
            manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf8'));
        }
        const localPdfs = [];
        if (fs.existsSync(dir)) {
            for (const name of fs.readdirSync(dir)) {
                if (!name.toLowerCase().endsWith('.pdf')) continue;
                localPdfs.push({
                    filename: name,
                    url: `/docs/juknis-bgn/${encodeURIComponent(name)}`
                });
            }
            localPdfs.sort((a, b) => String(a.filename).localeCompare(String(b.filename)));
        }
        res.json({
            ok: true,
            manifest,
            localPdfs,
            staticIndexUrl: '/docs/juknis-bgn/index.html',
            readmeUrl: '/docs/juknis-bgn/README.txt'
        });
    } catch (e) {
        res.status(500).json({ ok: false, error: e.message });
    }
});

// ---------- HACCP ----------
app.post('/api/batches/:id/haccp-check', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        await requireCanonicalRoles(['ahli_gizi', 'kepala_sppg', 'koordinator_divisi'])(req, res, async () => {
            try {
                await ensureProgramReadySchema();
                const tenantId = getTenantIdFromReq(req);
                const batchId = String(req.params.id || '').trim();
                const b = req.body || {};
                const id = crypto.randomUUID();
                const now = new Date().toISOString();
                const suhu = b.suhu_c !== undefined && b.suhu_c !== null && b.suhu_c !== '' ? Number(b.suhu_c) : null;
                const isCcp = b.is_ccp ? 1 : 0;
                let pass = 1;
                if (isCcp && suhu !== null) {
                    const stepKey = String(b.step_key || '').toLowerCase();
                    if (stepKey.includes('panas') && suhu < 60) pass = 0;
                    if (stepKey.includes('dingin') && suhu > 5) pass = 0;
                }
                await run(
                    `INSERT INTO batch_haccp_checks (id, tenant_id, batch_id, step_key, is_ccp, suhu_c, ph, visual_ok, pass, checked_by, checked_at, note, photo_url, created_at)
                     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                    [id, tenantId, batchId, String(b.step_key || 'unspecified'), isCcp, suhu,
                        b.ph !== undefined && b.ph !== null && b.ph !== '' ? Number(b.ph) : null,
                        b.visual_ok !== undefined ? (b.visual_ok ? 1 : 0) : null,
                        pass, (req.user && req.user.id) || null, now, b.note || null, b.photo_url || null, now]
                );
                res.json(await get('SELECT * FROM batch_haccp_checks WHERE id = ?', [id]));
            } catch (e) { res.status(500).json({ error: e.message }); }
        });
    });
});
