// ---------- SMOKE-CHECK (publish-gate) ----------
app.post('/api/compliance/guardrails/smoke-check', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            await ensureProgramReadySchema();
            try { await ensureReportWorkflowSchema(); } catch (e) { }
            const tenantId = getTenantIdFromReq(req);
            const b = req.body || {};
            const periodDays = Math.max(1, Math.min(90, parseInt(b.period_days || 7, 10) || 7));
            const since = new Date(Date.now() - periodDays * 86400000).toISOString().slice(0, 10);

            const checks = [];
            const add = (code, name, pass, detail, severity) => checks.push({ code, name, pass, severity: severity || 'WARN', detail });
            const safeCount = async (sql, params) => {
                try { return (await get(sql, params))?.c || 0; } catch (e) { return -1; }
            };

            const staffCount = await safeCount('SELECT COUNT(*) AS c FROM staff WHERE tenant_id = ?', [tenantId]);
            add('staff_master', 'Master staff tersedia', staffCount >= 3 || staffCount === -1, { staff_count: staffCount }, 'BLOCK');

            const lokasiCount = await safeCount('SELECT COUNT(*) AS c FROM pm_lokasi WHERE tenant_id = ?', [tenantId]);
            add('pm_lokasi_master', 'Master titik PM tersedia', lokasiCount >= 1 || lokasiCount === -1, { lokasi_count: lokasiCount }, 'BLOCK');

            const distCount = await safeCount('SELECT COUNT(*) AS c FROM pm_distribution_events WHERE tenant_id = ? AND service_date >= ?', [tenantId, since]);
            add('distribution_freshness', `Ada event distribusi dalam ${periodDays} hari terakhir`, distCount >= 1, { event_count: distCount }, 'WARN');

            const dailyCount = await safeCount("SELECT COUNT(*) AS c FROM daily_reports WHERE tenant_id = ? AND period_type = 'daily' AND period_start >= ?", [tenantId, since]);
            add('daily_report_freshness', `Ada laporan harian dalam ${periodDays} hari`, dailyCount >= Math.min(5, periodDays), { report_count: dailyCount }, 'WARN');

            const expiringUntil = new Date(Date.now() + 7 * 86400000).toISOString().slice(0, 10);
            const expiringCount = await safeCount("SELECT COUNT(*) AS c FROM ingredient_lots WHERE tenant_id = ? AND qty_remaining > 0 AND expiry_date IS NOT NULL AND expiry_date <= ?", [tenantId, expiringUntil]);
            add('expiry_alert', 'Monitor bahan mendekati expiry aktif', true, { expiring_7d: expiringCount }, 'INFO');

            const approvedMenu = await safeCount("SELECT COUNT(*) AS c FROM menu WHERE status_approval = 'APPROVED'", []);
            add('menu_approved_exists', 'Minimal 1 menu sudah approved', approvedMenu > 0 || approvedMenu === -1, { approved_count: approvedMenu }, 'WARN');

            const akgCount = await safeCount('SELECT COUNT(*) AS c FROM menu_akg_targets WHERE tenant_id = ? OR tenant_id IS NULL', [tenantId]);
            add('akg_targets_seeded', 'Target AKG per kategori tersedia', akgCount >= 3, { akg_count: akgCount }, 'BLOCK');

            const kpiCount = await safeCount('SELECT COUNT(*) AS c FROM kpi_definitions WHERE is_active = 1', []);
            add('kpi_definitions_loaded', 'Formula KPI tersedia', kpiCount >= 5, { kpi_count: kpiCount }, 'BLOCK');

            const raciCount = await safeCount('SELECT COUNT(*) AS c FROM raci_matrix', []);
            add('raci_loaded', 'Matriks RACI terisi', raciCount >= 40, { raci_count: raciCount }, 'WARN');

            const tracedIng = await safeCount('SELECT COUNT(DISTINCT ingredient_id) AS c FROM ingredient_lots WHERE tenant_id = ? AND qty_remaining > 0', [tenantId]);
            add('ingredient_traceability', 'Traceability lot bahan baku aktif', tracedIng >= 1, { traced_ingredients: tracedIng }, 'INFO');

            const vehicleCount = await safeCount("SELECT COUNT(*) AS c FROM delivery_vehicles WHERE tenant_id = ? AND status = 'AKTIF'", [tenantId]);
            add('vehicle_master', 'Armada distribusi terdaftar', vehicleCount >= 1, { vehicle_count: vehicleCount }, 'WARN');

            const routeCount = await safeCount("SELECT COUNT(*) AS c FROM delivery_routes WHERE tenant_id = ? AND status = 'AKTIF'", [tenantId]);
            add('route_master', 'Rute distribusi terdaftar', routeCount >= 1, { route_count: routeCount }, 'WARN');

            const blocked = checks.filter(c => !c.pass && c.severity === 'BLOCK');
            const warned = checks.filter(c => !c.pass && c.severity === 'WARN');
            const gatePass = blocked.length === 0;

            res.json({
                generated_at: new Date().toISOString(),
                period_days: periodDays,
                tenant_id: tenantId,
                gate_pass: gatePass,
                summary: {
                    total: checks.length,
                    pass: checks.filter(c => c.pass).length,
                    blocked: blocked.length,
                    warned: warned.length
                },
                checks,
                spec_version: typeof MBG_CANONICAL_SPEC_VERSION !== 'undefined' ? MBG_CANONICAL_SPEC_VERSION : 'v1'
            });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.get('/api/reports/divisions/performance', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const rows = await all(
                `SELECT
                    COALESCE(NULLIF(TRIM(b.division_id), ''), 'UNASSIGNED') AS division_id,
                    COUNT(*) AS total_batches,
                    SUM(CASE WHEN UPPER(COALESCE(b.status, '')) IN ('DONE', 'COMPLETED', 'ON_TIME') THEN 1 ELSE 0 END) AS on_time_batches
                 FROM batches b
                 INNER JOIN plans p ON p.id = b.plan_id
                 WHERE p.tenant_id = ?
                 GROUP BY COALESCE(NULLIF(TRIM(b.division_id), ''), 'UNASSIGNED')
                 ORDER BY division_id`,
                [tenantId]
            );
            const report = (rows || []).map((r) => {
                const total = Number(r.total_batches || 0);
                const onTime = Number(r.on_time_batches || 0);
                return {
                    division_id: r.division_id,
                    division_name: r.division_id,
                    total_batches: total,
                    on_time_batches: onTime,
                    on_time_rate: total > 0 ? onTime / total : 0
                };
            });
            res.json(report);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
});

app.get('/api/reports/preview/production', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const queryWarnings = [];
            let plans = [];
            let batches = [];
            try {
                plans = await all(
                    "SELECT id, code, target_portions, target_delivery_time, status, created_at FROM plans WHERE tenant_id = ? ORDER BY created_at DESC LIMIT 10",
                    [tenantId]
                );
            } catch (e) {
                queryWarnings.push(`Query plans gagal: ${String(e.message || e)}`);
            }
            try {
                batches = await all(
                    `SELECT b.id, b.code, b.plan_id, b.menu_item_id, b.batch_number, b.batch_size, b.start_time, b.end_time, b.status, b.division_id
                       FROM batches b
                       INNER JOIN plans p ON p.id = b.plan_id
                      WHERE p.tenant_id = ?
                      ORDER BY b.start_time DESC LIMIT 25`,
                    [tenantId]
                );
            } catch (e) {
                queryWarnings.push(`Query batches gagal: ${String(e.message || e)}`);
            }
            const totalDeliveries = (batches || []).length;
            const onTimeDeliveries = (batches || []).filter(b => ['DONE', 'COMPLETED', 'ON_TIME'].includes(String(b.status || '').toUpperCase())).length;
            const warnings = [];
            if (plans.length === 0) warnings.push('Belum ada data plan produksi');
            warnings.push(...queryWarnings);
            res.json({
                meta: {
                    generated_at: new Date().toISOString(),
                    row_counts: { plans: plans.length, batches: batches.length },
                    warnings
                },
                kpi: {
                    on_time_distribution_rate: totalDeliveries > 0 ? onTimeDeliveries / totalDeliveries : 0
                },
                plans,
                batches
            });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

