app.get('/api/reports/preview/inventory', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const queryWarnings = [];
            let movements = [];
            let low = [];
            try {
                movements = await all(`
                    SELECT m.id, m.at, m.ingredient_id, ing.name as ingredient_name, m.movement_type, m.qty_before, m.qty_after, m.delta, m.note, m.actor_email
                    FROM inventory_movements m
                    LEFT JOIN ingredients ing ON ing.id = m.ingredient_id
                    WHERE m.tenant_id = ?
                    ORDER BY m.at DESC
                    LIMIT 50
                `, [tenantId]);
            } catch (e) {
                queryWarnings.push(`Query inventory_movements gagal: ${String(e.message || e)}`);
            }
            try {
                low = await all(`
                    SELECT i.ingredient_id, ing.name, ing.unit, i.quantity
                    FROM inventory i
                    JOIN ingredients ing ON ing.id = i.ingredient_id
                    WHERE i.tenant_id = ?
                    ORDER BY i.quantity ASC
                    LIMIT 10
                `, [tenantId]);
            } catch (e) {
                queryWarnings.push(`Query inventory low_stock gagal: ${String(e.message || e)}`);
            }
            const warnings = [];
            if (movements.length === 0) warnings.push('Belum ada data pergerakan stok');
            warnings.push(...queryWarnings);
            res.json({
                meta: {
                    generated_at: new Date().toISOString(),
                    row_counts: { movements: movements.length, low_stock: low.length },
                    warnings
                },
                movements,
                low_stock: low
            });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

app.get('/api/reports/preview/staff', async (req, res) => {
    await requireTenantOrPlatform()(req, res, async () => {
        try {
            const tenantId = getTenantIdFromReq(req);
            const queryWarnings = [];
            let stats = [];
            try {
                stats = await all(`
                    SELECT division_id,
                           COUNT(*) as total,
                           SUM(CASE WHEN UPPER(COALESCE(status,'')) IN ('DONE','COMPLETED') THEN 1 ELSE 0 END) as done
                    FROM tasks
                    WHERE tenant_id = ?
                    GROUP BY division_id
                `, [tenantId]);
            } catch (e) {
                queryWarnings.push(`Query tasks performance gagal: ${String(e.message || e)}`);
            }
            const performance = (stats || []).map(s => {
                const total = Number(s.total || 0);
                const done = Number(s.done || 0);
                return {
                    division_id: s.division_id || 'UNASSIGNED',
                    division_name: s.division_id || 'UNASSIGNED',
                    total_tasks: total,
                    done_tasks: done,
                    completion_rate: total > 0 ? (done / total) : 0
                };
            });
            const doneTotal = performance.reduce((sum, r) => sum + Number(r.done_tasks || 0), 0);
            const allTotal = performance.reduce((sum, r) => sum + Number(r.total_tasks || 0), 0);
            const warnings = [];
            if (performance.length === 0) warnings.push('Belum ada data task per divisi');
            warnings.push(...queryWarnings);
            res.json({
                meta: {
                    generated_at: new Date().toISOString(),
                    row_counts: { performance: performance.length },
                    warnings
                },
                kpi: {
                    sppg_sop_compliance_rate: allTotal > 0 ? doneTotal / allTotal : 0
                },
                performance
            });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });
});

const port = process.env.PORT || 3014;
dbReady.then(async () => {
    await resolveSupplierPortalRustBackend();
    app.get('/api/templates/download/:type', async (req, res) => {
        const type = req.params.type;
        const ExcelJS = require('exceljs');
        const wb = new ExcelJS.Workbook();

        if (type === 'food') {
            const ws = wb.addWorksheet('Food_Template');
            // Match Ingredients table structure + Nutrition
            ws.columns = [
                { header: 'Nama_Bahan', key: 'name', width: 30 },
                { header: 'Satuan', key: 'unit', width: 10 },
                { header: 'Harga_Estimasi', key: 'estimated_price', width: 15 },
                { header: 'Kalori_kkal', key: 'calories', width: 10 },
                { header: 'Protein_g', key: 'protein', width: 10 },
                { header: 'Lemak_g', key: 'fat', width: 10 },
                { header: 'Karbo_g', key: 'carbs', width: 12 },
                { header: 'Kategori', key: 'category', width: 15 }
            ];
            ws.addRow(['Beras Putih', 'kg', 13500, 1300, 27, 3, 280, 'Pokok']);
            ws.addRow(['Daging Ayam', 'kg', 45000, 2000, 200, 150, 0, 'Lauk']);

            // Add dropdown validation for category if possible, or just note
            // ExcelJS supports dataValidation

            const noteWs = wb.addWorksheet('Panduan');
            noteWs.addRow(['Panduan Pengisian:']);
            noteWs.addRow(['1. Nama_Bahan: Nama bahan baku (unik).']);
            noteWs.addRow(['2. Satuan: kg, liter, butir, ikat, dll.']);
            noteWs.addRow(['3. Harga_Estimasi: Harga pasar per satuan (angka).']);
            noteWs.addRow(['4. Nilai Gizi: Per 1 satuan (misal per 1 kg).']);
        } else if (type === 'menu') {
            const ws = wb.addWorksheet('Menu_Schedule_Template');
            // Daily Menu Schedule Template
            ws.columns = [
                { header: 'Tanggal', key: 'date', width: 15 },
                { header: 'Waktu_Makan', key: 'meal_time', width: 15 },
                { header: 'Nama_Menu', key: 'menu_name', width: 30 },
                { header: 'Jumlah_Porsi', key: 'portions', width: 15 }
            ];

            const tomorrow = new Date();
            tomorrow.setDate(tomorrow.getDate() + 1);
            const dateStr = tomorrow.toISOString().split('T')[0];

            ws.addRow([dateStr, 'Siang', 'Ayam Goreng', 150]);
            ws.addRow([dateStr, 'Siang', 'Sayur Asem', 150]);
            ws.addRow([dateStr, 'Sore', 'Telur Balado', 150]);

            const noteWs = wb.addWorksheet('Panduan');
            noteWs.addRow(['Panduan Pengisian Menu Harian:']);
            noteWs.addRow(['1. Tanggal: Format YYYY-MM-DD (Excel Date).']);
            noteWs.addRow(['2. Waktu_Makan: Pagi / Siang / Sore / Malam.']);
            noteWs.addRow(['3. Nama_Menu: Nama menu yang akan dimasak.']);
            noteWs.addRow(['4. Jumlah_Porsi: Target porsi untuk waktu tersebut.']);
        } else {
            return res.status(400).json({ error: 'Template not found' });
        }

        res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
        res.setHeader('Content-Disposition', `attachment; filename=template_${type}.xlsx`);
        await wb.xlsx.write(res);
        res.end();
    });

    // Multer for file upload
    const multer = require('multer');
    const upload = multer({ storage: multer.memoryStorage() });

    app.post('/api/import/food/preview', upload.single('file'), async (req, res) => {
        try {
            if (!req.file) return res.status(400).json({ error: 'No file uploaded' });

            const ExcelJS = require('exceljs');
            const wb = new ExcelJS.Workbook();
            await wb.xlsx.load(req.file.buffer);

            const ws = wb.getWorksheet(1); // Assume first sheet
            const items = [];

            ws.eachRow((row, rowNumber) => {
                if (rowNumber === 1) return; // Skip header

                const name = String(row.getCell(1).value || '').trim();
                const unit = String(row.getCell(2).value || '').trim();
                const price = Number(row.getCell(3).value);

                // Validate essential fields
                const valid = name && unit && Number.isFinite(price);

                items.push({
                    name,
                    unit,
                    price,
                    calories: Number(row.getCell(4).value || 0),
                    protein: Number(row.getCell(5).value || 0),
                    fat: Number(row.getCell(6).value || 0),
                    carbs: Number(row.getCell(7).value || 0),
                    category: String(row.getCell(8).value || ''),
                    valid,
                    error: valid ? null : 'Wajib: Nama, Satuan, Harga'
                });
            });

            res.json({ items });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });

    // --- MENU IMPORT ENDPOINTS ---
    app.post('/api/import/menu/preview', upload.single('file'), async (req, res) => {
        try {
            if (!req.file) return res.status(400).json({ error: 'No file uploaded' });

            const ExcelJS = require('exceljs');
            const wb = new ExcelJS.Workbook();
            await wb.xlsx.load(req.file.buffer);

            const ws = wb.getWorksheet(1); // Assume first sheet
            const items = [];

            ws.eachRow((row, rowNumber) => {
                if (rowNumber === 1) return; // Skip header

                // Columns: Date | MealTime | MenuName | Portions
                const dateRaw = row.getCell(1).value;
                const meal_time = String(row.getCell(2).value || '').trim();
                const menu_name = String(row.getCell(3).value || '').trim();
                const portions = Number(row.getCell(4).value);

                let date = '';
                try {
                    if (dateRaw instanceof Date) date = dateRaw.toISOString().split('T')[0];
                    else date = String(dateRaw || '').trim();
                } catch (e) { date = String(dateRaw || ''); }

                const valid = date && meal_time && menu_name && Number.isFinite(portions);

                items.push({
                    date,
                    meal_time,
                    menu_name,
                    portions,
                    valid,
                    error: valid ? null : 'Wajib: Tanggal, Waktu, Menu, Porsi'
                });
            });

            res.json({ items });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });

    app.post('/api/import/menu', async (req, res) => {
        await requireTenantOrPlatform()(req, res, async () => {
            const { items } = req.body;
            const tenantId = getTenantIdFromReq(req);
            if (!items || !items.length) return res.status(400).json({ error: 'No items' });

            let imported = 0;
            try {
                const now = new Date().toISOString();

                // Group by Food (Date + MealTime)
                const foodsMap = new Map(); // Key: "YYYY-MM-DD_Time" -> FoodID

                // Helper to get/create food
                const getFoodId = async (date, time) => {
                    const key = `${date}_${time}`;
                    if (foodsMap.has(key)) return foodsMap.get(key);

                    // Check DB
                    const name = `Menu ${date} ${time}`;
                    const existing = await get("SELECT id FROM foods WHERE tenant_id = ? AND date_served = ? AND name LIKE ?", [tenantId, date, `%${time}%`]);

                    if (existing) {
                        foodsMap.set(key, existing.id);
                        return existing.id;
                    }

                    // Create new Food
                    const id = crypto.randomUUID();
                    await run(
                        "INSERT INTO foods (id, tenant_id, name, created_at, date_served, packaging_type) VALUES (?, ?, ?, ?, ?, ?)",
                        [id, tenantId, name, now, date, 'ompreng'] // Default packaging
                    );
                    foodsMap.set(key, id);
                    return id;
                };

                for (const item of items) {
                    if (!item.valid) continue;

                    const foodId = await getFoodId(item.date, item.meal_time);

                    // Create Menu + Recipe
                    const menuId = generateId('MN');
                    const recipeId = generateId('RC');

                    // Create Implicit Recipe
                    await run("INSERT INTO recipes (id, name, instructions, ingredients, cooking_time, batch_capacity, portion_size, extra_packing_json, packaging_type) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
                        [recipeId, item.menu_name + ' Recipe', 'Auto-generated', '[]', 60, 50, Number(item.portions || 1), null, null]);

                    // Create Menu Item linked to Recipe and Food
                    await run("INSERT INTO menu (id, name, recipe_id, food_id) VALUES (?, ?, ?, ?)",
                        [menuId, item.menu_name, recipeId, foodId]);

                    imported++;
                }

                res.json({ success: true, imported });
            } catch (e) {
                res.status(500).json({ error: e.message });
            }
        });
    });

    app.post('/api/import/food', async (req, res) => {
        await requireTenantOrPlatform()(req, res, async () => {
            const { items } = req.body;
            const tenantId = getTenantIdFromReq(req);
            if (!items || !items.length) return res.status(400).json({ error: 'No items' });

            let imported = 0;
            try {
                const now = new Date().toISOString();
                for (const item of items) {
                    const id = crypto.randomUUID();
                    const nutrInfo = {
                        calories: item.calories,
                        protein: item.protein,
                        fat: item.fat,
                        carbs: item.carbs
                    };

                    // Check if exists
                    // Use tenant-aware check
                    let existing = null;
                    try {
                        existing = await get("SELECT id FROM ingredients WHERE name = ? AND tenant_id = ?", [item.name, tenantId]);
                    } catch (e) {
                        // Fallback if tenant_id missing in older schema (though we fixed it)
                        existing = await get("SELECT id FROM ingredients WHERE name = ?", [item.name]);
                    }

                    if (existing) {
                        await run("UPDATE ingredients SET unit = ?, estimated_price = ?, nutrition_info = ? WHERE id = ?",
                            [item.unit, item.price, JSON.stringify(nutrInfo), existing.id]);
                    } else {
                        await run(
                            "INSERT INTO ingredients (id, tenant_id, name, unit, estimated_price, nutrition_info, created_at) VALUES (?, ?, ?, ?, ?, ?, ?)",
                            [id, tenantId, item.name, item.unit, item.price, JSON.stringify(nutrInfo), now]
                        );
                    }
                    imported++;
                }
                res.json({ success: true, imported });
            } catch (e) {
                res.status(500).json({ error: e.message });
            }
        });
    });

    getProductionSettings()
        .then((s) => {
            setInterval(() => {
                productionTick().catch(() => { });
            }, s.poll_interval_ms);
        })
        .catch(() => { });

    const staticRoot = path.join(__dirname);
    app.use(express.static(staticRoot, {
        setHeaders(res, filePath) {
            const lower = String(filePath || '').toLowerCase();
            const rel = path.relative(staticRoot, filePath).replace(/\\/g, '/').toLowerCase();
            if (lower.endsWith('.html')) {
                res.setHeader('Cache-Control', 'no-store, no-cache, must-revalidate, max-age=0');
            }
            // Disable caching for ANY JS file inside the `js/` tree (views, core,
            // staff_attendance, etc.) so the browser always picks up the freshest
            // build without relying on manual cache-busting query strings.
            if (lower.endsWith('.js') && rel.startsWith('js/')) {
                res.setHeader('Cache-Control', 'no-store, no-cache, must-revalidate, max-age=0');
            }
        }
    }));

    app.listen(port, '0.0.0.0', () => {
        console.log(`SQLite Server running at http://localhost:${port}`);
        console.log(`Platform Database: ${PLATFORM_DB_FILE}`);
        console.log(
            `Gunakan di browser hanya: http://localhost:${port}  (login supplier-portal = Node/SQLite; order/bid = Rust bila ada)`
        );
    });
}).catch((e) => {
    console.error('Startup failed:', e && e.message ? e.message : e);
    process.exit(1);
});
